-- Poems batch 13
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('5cd11e20-5547-48ef-91fc-24bd8bf46140','郡中翫月寄江南李少尹虞部孟員外三首 二','羊士諤','唐','唐诗','tang','','[]','桂華臨洛浦，如挹李膺仙。',48,'全唐诗/poet.tang.17000.json','["桂華臨洛浦，如挹李膺仙。", "茲夕披雲望，還吟擲地篇。", "鳳池分直夜，牛渚泛舟年。", "會是風流賞，惟君內史賢。"]'),
('ba1b9b01-80cd-47be-be65-f70fe8e3b35a','郡中翫月寄江南李少尹虞部孟員外三首 三','羊士諤','唐','唐诗','tang','','[]','圓景曠佳賓，徘徊夜漏頻。',48,'全唐诗/poet.tang.17000.json','["圓景曠佳賓，徘徊夜漏頻。", "金波徒汎酒，瑤瑟已生塵。", "露白移長簟，風清挂幅巾。", "西園舊才子，想見洛陽人。"]'),
('b028e741-70ba-43a1-851c-6361e47fb09e','城隍廟賽雨二首 一','羊士諤','唐','唐诗','tang','','[]','零雨慰斯人，齋心薦綠蘋。',24,'全唐诗/poet.tang.17000.json','["零雨慰斯人，齋心薦綠蘋。", "山風簫鼓響，如祭敬亭神。"]'),
('4de94729-879c-4e15-a1b6-004d27c013a2','城隍廟賽雨二首 二','羊士諤','唐','唐诗','tang','','[]','積潤通千里，推誠奠一巵。',24,'全唐诗/poet.tang.17000.json','["積潤通千里，推誠奠一巵。", "回飆經畫壁，忽似偃雲旗。"]'),
('2bb1e503-05e8-4cb7-a331-d0e16fe7ee11','郡樓晴望二首 一','羊士諤','唐','唐诗','tang','','[]','霽色朝雲盡，亭臯露亦晞。',48,'全唐诗/poet.tang.17000.json','["霽色朝雲盡，亭臯露亦晞。", "褰開臨曲檻，蕭瑟換輕衣。", "地遠秦人望，天晴社燕飛。", "無功慙歲晚，唯念故山歸。"]'),
('f0226faf-8724-49ba-abe6-6c2096447765','郡樓晴望二首 二','羊士諤','唐','唐诗','tang','','[]','一雨晴山郭，驚秋碧樹風。',48,'全唐诗/poet.tang.17000.json','["一雨晴山郭，驚秋碧樹風。", "蘭巵誰與薦，玉斾自無悰。", "雲景嘶賓雁，嵐陰露彩虹。", "閑吟嬾閉閣，旦夕郡樓中。"]'),
('54178e7b-e921-4450-9716-825647f123ef','初移琪樹','羊士諤','唐','唐诗','tang','','[]','愛此丘中物，煙霜盡日看。',24,'全唐诗/poet.tang.17000.json','["愛此丘中物，煙霜盡日看。", "無窮碧雲意，更助綠窗寒。"]'),
('884a25ac-d492-45dc-aeb8-d1e7c987ff0a','燕居','羊士諤','唐','唐诗','tang','','[]','秋齋膏沐暇，旭日照軒墀。',48,'全唐诗/poet.tang.17000.json','["秋齋膏沐暇，旭日照軒墀。", "露重芭蕉葉，香凝橘柚枝。", "簡書隨吏散，寶騎與僧期。", "報國得何力，流年已覺衰。"]'),
('93a445d5-7630-4bcf-91ab-bb2b43d8ef20','寄黔府竇中丞','羊士諤','唐','唐诗','tang','','[]','漢臣旌節貴，萬里護牂牁。',48,'全唐诗/poet.tang.17000.json','["漢臣旌節貴，萬里護牂牁。", "夏月天無暑，秋風水不波。", "朝衣蟠艾綬，戎幕偃雕戈。", "滿歲歸龍闕，良哉佇作歌。"]'),
('daf422be-010a-4bb0-b4f7-65582d7f949e','書樓懷古','羊士諤','唐','唐诗','tang','','[]','何獨文翁化，風流與代深。',48,'全唐诗/poet.tang.17000.json','["何獨文翁化，風流與代深。", "泉雲無舊轍，騷雅有遺音。", "遠目窮巴漢，閑情閱古今。", "忘言意不極，日暮但橫琴。"]'),
('d9997cdc-ee59-4d48-899c-20ace66b7d9b','九月十日郡樓獨酌','羊士諤','唐','唐诗','tang','','[]','掾史當授衣，郡中稀物役。',72,'全唐诗/poet.tang.17000.json','["掾史當授衣，郡中稀物役。", "嘉辰悵已失，殘菊誰爲惜。", "櫺軒一尊泛，天景洞虛碧。", "暮節獨賞心，寒江鳴湍石。", "歸期北州里，舊友東山客。", "飄蕩雲海深，相思桂花白。"]'),
('87abd287-ffb5-4f95-bc4b-8cf3df3fa96f','暮秋言懷','羊士諤','唐','唐诗','tang','','[]','城隅凝綵畫，紅樹帶青山。',48,'全唐诗/poet.tang.17000.json','["城隅凝綵畫，紅樹帶青山。", "遲客金尊晚，談空玉柄閑。", "馳暉三峽水，旅夢百勞關。", "非是淮陽薄，丘中只望還。"]'),
('af11fe29-0546-40fb-be10-2ef8bb92c3fe','題枇杷樹','羊士諤','唐','唐诗','tang','','[]','珍樹寒始花，氛氳九秋月。',48,'全唐诗/poet.tang.17000.json','["珍樹寒始花，氛氳九秋月。", "佳期若有待，芳意常無絕。", "嫋嫋碧海風，濛濛綠枝雪。", "急景自餘妍，春禽幸流悅。"]'),
('f4ff4cbf-b005-4524-b64e-2fb81538e07b','上元日紫極宮門觀州民然燈張樂','羊士諤','唐','唐诗','tang','','[]','山郭通衢隘，瑤壇紫府深。',48,'全唐诗/poet.tang.17000.json','["山郭通衢隘，瑤壇紫府深。", "燈花助春意，舞綬織歡心。", "閑似淮陽臥，恭聞樂職吟。", "唯將聖明化，聊以達飛沈。"]'),
('57d0ccf1-c4d7-4dca-a1a3-adea540990ca','西郊蘭若','羊士諤','唐','唐诗','tang','','[]','雲天宜北戶，塔廟似西方。',48,'全唐诗/poet.tang.17000.json','["雲天宜北戶，塔廟似西方。", "林下僧無事，江清日復長。", "石泉盈掬冷，山實滿枝香。", "寂寞傳心印，玄言亦已忘。"]'),
('94778466-139c-45bb-8d06-f9c341062163','在郡三年今秋見白髮聊以書事','羊士諤','唐','唐诗','tang','','[]','二毛非騎省，朝鏡忽秋風。',48,'全唐诗/poet.tang.17000.json','["二毛非騎省，朝鏡忽秋風。", "絲縷寒衣上，霜華舊簡中。", "承明那足厭，車服媿無功。", "日日山城守，淹留巖桂叢。"]'),
('2b85824f-cde8-4fdb-887b-f10b1d263675','郡中端居有懷袁州王員外使君','羊士諤','唐','唐诗','tang','','[]','憶作同門友，承明奉直廬。',144,'全唐诗/poet.tang.17000.json','["憶作同門友，承明奉直廬。", "禁闈人自異，休澣跡非疎。", "珥筆金華殿，三朝玉璽書。", "恩光榮侍從，文彩應符徐。", "青眼真知我，玄談愧起予。", "蘭巵招促膝，松砌引長裾。", "麗日流鶯早，涼天墜露初。", "前山臨紫閣，曲水眺紅蕖。", "誰爲音塵曠，俄驚歲月除。", "風波移故轍，符守忽離居。", "濟物陰功在，分憂盛業餘。", "弱翁方大用，延首遲雙魚。"]'),
('8abbe576-b214-4c1d-8a04-d47900743de5','山寺題壁','羊士諤','唐','唐诗','tang','','["\u5c71", "\u5bfa\u5e99", "\u5199\u666f"]','物外真何事，幽廊步不窮。',48,'全唐诗/poet.tang.17000.json','["物外真何事，幽廊步不窮。", "一燈心法在，三世影堂空。", "山果青苔上，寒蟬落葉中。", "歸來還閉閣，棠樹幾秋風。"]'),
('316b7da2-d0f1-471b-959e-ad7b18a8403d','暇日適值澄霽江亭遊宴','羊士諤','唐','唐诗','tang','','[]','碧落風如洗，清光鏡不分。',48,'全唐诗/poet.tang.17000.json','["碧落風如洗，清光鏡不分。", "弦歌方對酒，山谷盡無雲。", "振臥淮陽病，悲秋宋玉文。", "今來強攜妓，醉舞石榴裙。"]'),
('62100c8e-32f1-4d7c-be75-bfdf446e6add','玩槿花','羊士諤','唐','唐诗','tang','','[]','何乃詩人興，妍詞屬舜華。',48,'全唐诗/poet.tang.17000.json','["何乃詩人興，妍詞屬舜華。", "風流感異代，窈窕比同車。", "凝豔垂清露，驚秋隔絳紗。", "蟬鳴復蟲思，惆悵竹陰斜。"]'),
('9ab3d7fd-5db8-48d7-a40d-21bcf3c85c61','郡齋讀經','羊士諤','唐','唐诗','tang','','[]','壯齡非濟物，柔翰誤爲儒。',144,'全唐诗/poet.tang.17000.json','["壯齡非濟物，柔翰誤爲儒。", "及此齋心暇，翛然與道俱。", "散材誠獨善，正覺豈無徒。", "半偈蓮生水，幽香桂滿爐。", "息陰慙蔽芾，講義得醍醐。", "跡似桃源客，身攖竹使符。", "華夷參吏事，巴漢混州圖。", "偃草懷君子，移風念嗇夫。", "翳桑俄有績，宿麥復盈租。", "圓寂期超詣，凋殘幸已蘇。", "解空囊不智，滅景谷何愚。", "幾日遵歸轍，東菑殆欲蕪。"]'),
('0c60f223-6df4-496d-97b9-60446bcaf422','州民自言巴土冬濕且多陰晦今茲晴朗苦寒霜頗甚故老或異之因示寮吏','羊士諤','唐','唐诗','tang','','[]','雨霜以成歲，看舊感前聞。',48,'全唐诗/poet.tang.17000.json','["雨霜以成歲，看舊感前聞。", "愛景隨朝日，凝陰積暮雲。", "囗囗囗囗囗，忘言酒暫醺。", "囗囗囗囗囗，囗囗囗囗囗。"]'),
('1a2497cd-1f17-4ed7-9ba8-6a51e436a4ea','齋中有獸皮茵偶成詠','羊士諤','唐','唐诗','tang','','[]','逸才豈凡獸，服猛愚人得。',48,'全唐诗/poet.tang.17000.json','["逸才豈凡獸，服猛愚人得。", "山澤生異姿，蒙戎蔚佳色。", "青氈持與藉，重錦裁爲飾。", "臥閣幸相宜，溫然承宴息。"]'),
('92388528-e94c-4eb4-acab-f105f4423e9b','野夫採鞭於東山偶得元者','羊士諤','唐','唐诗','tang','','[]','追風豈無策，持斧有遐想。',48,'全唐诗/poet.tang.17000.json','["追風豈無策，持斧有遐想。", "鳳去留孤根，嵓懸非朽壤。", "苔斑自天生，玉節垂雲長。", "勿謂山之幽，丹梯亦可上。"]'),
('b59f9bb3-8f6b-4b3f-bcfb-8a36dd1df2f7','守郡累年俄及知命聊以言志','羊士諤','唐','唐诗','tang','','[]','南國疑逋客，東山作老夫。',48,'全唐诗/poet.tang.17000.json','["南國疑逋客，東山作老夫。", "登朝非大隱，出谷是真愚。", "氣直慙龍劒，心清愛玉壺。", "聊持循吏傳，早晚囗爲徒。"]'),
('25b83882-d6df-4662-9463-fdde2af46b26','東渡早梅一樹歲華如雪酣賞成詠','羊士諤','唐','唐诗','tang','','[]','暇日留囗事，期雲亦囗開。',48,'全唐诗/poet.tang.17000.json','["暇日留囗事，期雲亦囗開。", "鄉心持歲酒，津下賞山梅。", "晚實和商鼎，濃香拂壽杯。", "唯應招北客，日日踏青來。"]'),
('10ec309b-8ab4-47c7-b67c-d39a70bf91c1','題郡南山光福寺寺即嚴黃門所置時自給事中京兆少尹出守年三十性樂山水故老云每旬數至後分閫川州門有去思碑即郄拾遺之詞也','羊士諤','唐','唐诗','tang','','[]','傳聞黃閣守，茲地賦長沙。',72,'全唐诗/poet.tang.17000.json','["傳聞黃閣守，茲地賦長沙。", "少壯稱時傑，功名惜歲華。", "巖廊初建剎，賓從亟鳴笳。", "玉帳空嚴道，甘棠見野花。", "碑殘猶墮淚，城古自歸鴉。", "籍籍清風在，懷人諒不遐。"]'),
('1d7c2618-c8d8-4ff5-a7b6-88ffb05263fe','雨中寒食','羊士諤','唐','唐诗','tang','','[]','令節逢煙雨，園亭但掩關。',48,'全唐诗/poet.tang.17000.json','["令節逢煙雨，園亭但掩關。", "佳人宿妝薄，芳樹綵繩閑。", "歸思偏消酒，春寒爲近山。", "花枝不可見，別恨灞陵間。"]'),
('89786f64-930e-45ab-81a2-3d07dd6b050d','晚夏郡中臥疾','羊士諤','唐','唐诗','tang','','[]','事外心如寄，虛齋臥更幽。',48,'全唐诗/poet.tang.17000.json','["事外心如寄，虛齋臥更幽。", "微風生白羽，畏日隔青油。", "用拙懷歸去，沉痾畏借留。", "東山自有計，蓬鬢莫先秋。"]'),
('e8557007-0d0a-48b2-913b-679da7a3e6ab','酬盧司門晚夏過永寧里弊居林亭見寄','羊士諤','唐','唐诗','tang','','[]','自嘆淮陽臥，誰知去國心。',48,'全唐诗/poet.tang.17000.json','["自嘆淮陽臥，誰知去國心。", "幽亭來北戶，高韻得南金。", "苔甃窺泉少，籃輿愛竹深。", "風蟬一清暑，應喜脫朝簪。"]'),
('a588e1ad-df02-4431-af6f-55091191d890','山郭風雨朝齋悵然秋思','羊士諤','唐','唐诗','tang','','[]','桐竹離披曉，涼風似故園。',48,'全唐诗/poet.tang.17000.json','["桐竹離披曉，涼風似故園。", "驚秋對旭日，感物坐前軒。", "江燕飛還盡，山榴落尚繁。", "平生信有意，衰久已忘言。"]'),
('1d1a0edc-1423-4056-939a-01c32cc2de7d','南館林塘','羊士諤','唐','唐诗','tang','','[]','郡閣山斜對，風煙隔短牆。',48,'全唐诗/poet.tang.17000.json','["郡閣山斜對，風煙隔短牆。", "清池如寫月，珍樹盡凌霜。", "行樂知無悶，加餐頗自強。", "心期空歲晚，魚意久相忘。"]'),
('44e2a297-1c3c-4756-9c82-5096aa853854','臘夜對酒','羊士諤','唐','唐诗','tang','','[]','琥珀盃中物，瓊枝席上人。',48,'全唐诗/poet.tang.17000.json','["琥珀盃中物，瓊枝席上人。", "樂聲方助醉，燭影已含春。", "自顧行將老，何辭坐達晨。", "傳觴稱厚德，不問吐車茵。"]'),
('694da900-155b-4c6c-844a-c0b806318797','池上搆小山詠懷','羊士諤','唐','唐诗','tang','','[]','玉立出巖石，風清曲囗囗。',48,'全唐诗/poet.tang.17000.json','["玉立出巖石，風清曲囗囗。", "偶成聊近意，靜對想凝神。", "牛渚中流月，蘭亭上道春。", "古來心可見，寂寞爲斯人。"]'),
('30fc43da-e775-4d1f-a40e-a3fb15cd9fc3','林塘臘候','羊士諤','唐','唐诗','tang','','[]','南國冰霜晚，年華已暗歸。',48,'全唐诗/poet.tang.17000.json','["南國冰霜晚，年華已暗歸。", "閑招別館客，遠念故山薇。", "野艇虛還觸，籠禽倦更飛。", "忘言亦何事，酣賞步清輝。"]'),
('49b8585e-7aec-4518-ad10-190fc67fe9ab','酬禮部崔員外備獨永寧里弊居見寄來詩云圖書鎖塵閣符節守山城','羊士諤','唐','唐诗','tang','','[]','守土親巴俗，腰章囗漢儀。',48,'全唐诗/poet.tang.17000.json','["守土親巴俗，腰章囗漢儀。", "春行樂職詠，秋感伴牢詞。", "舊里藏書閣，閑門閉槿籬。", "遙慙退朝客，下馬獨相思。"]'),
('f454b1c8-d40f-4655-968b-da935b14c351','梁國惠康公主挽歌詞二首 一','羊士諤','唐','唐诗','tang','','[]','湯沐成陳跡，山林遂寂寥。',48,'全唐诗/poet.tang.17000.json','["湯沐成陳跡，山林遂寂寥。", "鵲飛應織素，鳳起獨吹簫。", "玉殿中參罷，雲軿上漢遙。", "皇情非不極，空輟未央朝。"]'),
('f5d8ff7f-0f16-4883-a63e-37c5080d3efb','梁國惠康公主挽歌詞二首 二','羊士諤','唐','唐诗','tang','','[]','授冊榮天使，陳詩感聖恩。',48,'全唐诗/poet.tang.17000.json','["授冊榮天使，陳詩感聖恩。", "山河啓梁國，縞素及于門。", "泉向金巵咽，霜來玉樹繁。", "都人聽哀挽，淚盡望寒原。"]'),
('b7cad7a5-e28e-4248-b122-4467ec9a7bbd','南池晨望','羊士諤','唐','唐诗','tang','','[]','起來林上月，瀟灑故人情。',48,'全唐诗/poet.tang.17000.json','["起來林上月，瀟灑故人情。", "鈴閣人何事，蓮塘曉獨行。", "衣沾竹露爽，茶對石泉清。", "鼓吹前賢薄，羣蛙試一鳴。"]'),
('06df9495-9c5a-4893-8ac8-a520c5cd8ea8','林館避暑','羊士諤','唐','唐诗','tang','','[]','池島清陰裏，無人泛酒船。',48,'全唐诗/poet.tang.17000.json','["池島清陰裏，無人泛酒船。", "山蜩金奏響，荷露水精圓。", "靜勝朝還暮，幽觀白已玄。", "家林正如此，何事賦歸田。"]'),
('c51254d8-3d87-4ee3-94e0-eb31365bbd05','巴南郡齋雨中偶看長曆是日小雪有懷昔年朝謁因成八韻','羊士諤','唐','唐诗','tang','','[]','夷落朝雲候，王正小雪辰。',96,'全唐诗/poet.tang.17000.json','["夷落朝雲候，王正小雪辰。", "緬懷朝紫陌，曾是灑朱輪。", "氣耿簪裾肅，風嚴刻漏頻。", "暗飛金馬仗，寒舞玉京塵。", "豸角隨中憲，龍池列近臣。", "蘂珠凝瑞彩，懸圃淨華茵。", "帝澤千箱慶，天顏萬物春。", "明廷猶咫尺，高詠愧巴人。"]'),
('047a85c3-cc56-463d-9ed2-c43cd0c3b542','褒城驛池塘翫月','羊士諤','唐','唐诗','tang','','[]','夜長秋始半，圓景麗銀河。',48,'全唐诗/poet.tang.17000.json','["夜長秋始半，圓景麗銀河。", "北渚清光溢，西山爽氣多。", "鶴飛聞墜露，魚戲見增波。", "千里家林望，涼飆換綠蘿。"]'),
('9e5cb175-a788-4583-95ba-711b8a12ba63','資陽郡中詠懷','羊士諤','唐','唐诗','tang','','[]','腰章非達士，閉閣是潛夫。',48,'全唐诗/poet.tang.17000.json','["腰章非達士，閉閣是潛夫。", "匣劒寧求試，籠禽但自拘。", "江清牛渚鎮，酒熟步兵廚。", "唯此前賢意，風流似不孤。"]'),
('0e6f466c-3fc6-4930-a25b-3c14172c1b41','寒食宴城北山池即故郡守榮陽鄭鋼目爲折柳亭','羊士諤','唐','唐诗','tang','','[]','別館青山郭，遊人折柳行。',48,'全唐诗/poet.tang.17000.json','["別館青山郭，遊人折柳行。", "落花經上巳，細雨帶清明。", "鶗鴂流芳暗，鴛鴦曲水平。", "歸心何處醉，寶瑟有餘聲。"]'),
('067c9fbc-344f-4505-82f4-9a06fd042851','酬彭州蕭使君秋中言懷','羊士諤','唐','唐诗','tang','','["\u79cb\u5929"]','右職移青綬，雄藩拜紫泥。',48,'全唐诗/poet.tang.17000.json','["右職移青綬，雄藩拜紫泥。", "江回玉壘下，氣爽錦城西。", "臯鶴驚秋律，琴烏怨夜啼。", "離居同舍念，宿昔奉金閨。"]'),
('07665546-70cf-4577-a765-e5adaea4a6d4','資中早春','羊士諤','唐','唐诗','tang','','[]','一雨東風晚，山鶯獨報春。',48,'全唐诗/poet.tang.17000.json','["一雨東風晚，山鶯獨報春。", "淹留巫峽夢，惆悵洛陽人。", "柳意籠丹檻，梅香覆錦茵。", "年華行可惜，瑤瑟莫生塵。"]'),
('fed29882-43d1-43b7-86ca-1fa4c1999975','郡樓懷長安親友','羊士諤','唐','唐诗','tang','','[]','殘暑三巴地，沈陰八月天。',48,'全唐诗/poet.tang.17000.json','["殘暑三巴地，沈陰八月天。", "氣昏高閣雨，夢倦下簾眠。", "愁鬢華簪小，歸心社燕前。", "相思杜陵野，溝水獨潺湲。"]'),
('f515aba3-5d02-403d-b829-c550e84156db','王起居獨遊青龍寺翫紅葉因寄','羊士諤','唐','唐诗','tang','','[]','十畝蒼苔遶畫廊，幾株紅樹過清霜。',32,'全唐诗/poet.tang.17000.json','["十畝蒼苔遶畫廊，幾株紅樹過清霜。", "高情還似看花去，閑對南山步夕陽。"]'),
('bc2d507b-d3f7-46da-9b54-2e8a5b9e8d67','夜聽琵琶三首 一','羊士諤','唐','唐诗','tang','','[]','掩抑危絃咽又通，朔雲邊月想朦朧。',32,'全唐诗/poet.tang.17000.json','["掩抑危絃咽又通，朔雲邊月想朦朧。", "當時誰佩將軍印，長使蛾眉怨不窮。"]'),
('42c97f41-c035-4417-93e4-68430beb37a7','夜聽琵琶三首 二','羊士諤','唐','唐诗','tang','','[]','一曲徘徊星漢稀，夜闌幽怨重依依。',32,'全唐诗/poet.tang.17000.json','["一曲徘徊星漢稀，夜闌幽怨重依依。", "忽似摐金來上馬，南枝棲鳥盡驚飛。"]'),
('79d1b5e4-7deb-41df-9758-3cfb9c5007d4','夜聽琵琶三首 三','羊士諤','唐','唐诗','tang','','[]','破撥聲繁恨已長，低鬟斂黛更摧藏。',32,'全唐诗/poet.tang.17000.json','["破撥聲繁恨已長，低鬟斂黛更摧藏。", "潺湲隴水聽難盡，併覺風沙繞杏梁。"]'),
('7d7be9fe-531f-466b-85b8-5f35da37240d','彭州蕭使君出妓夜宴見送','羊士諤','唐','唐诗','tang','','["\u79bb\u522b", "\u5199\u4eba"]','玉顏紅燭忽驚春，微步凌波暗拂塵。',32,'全唐诗/poet.tang.17000.json','["玉顏紅燭忽驚春，微步凌波暗拂塵。", "自是當歌歛眉黛，不因惆悵爲行人。"]'),
('5e49b0fa-c528-427e-a47b-2f22ce3b2c26','題松江館','羊士諤','唐','唐诗','tang','','[]','津柳江風白浪平，棹移高館古今情。',32,'全唐诗/poet.tang.17000.json','["津柳江風白浪平，棹移高館古今情。", "扁舟一去鴟夷子，應笑分符計日程。"]'),
('48bb2e9d-c59b-4718-9292-caad75646bef','偶題寄獨孤使君','羊士諤','唐','唐诗','tang','','[]','病起淮陽自有時，秋來未覺長年悲。',32,'全唐诗/poet.tang.17000.json','["病起淮陽自有時，秋來未覺長年悲。", "坐逢在日唯相望，嫋嫋涼風滿桂枝。"]'),
('1a6b59be-f9f2-47cf-b9e3-3dcf04d7e651','永寧里小園與沈校書接近悵然題寄','羊士諤','唐','唐诗','tang','','[]','故里心期奈別何，手移芳樹憶庭柯。',32,'全唐诗/poet.tang.17000.json','["故里心期奈別何，手移芳樹憶庭柯。", "東臯黍熟君應醉，梨葉初紅白露多。"]'),
('41dd5fd7-8183-45f5-9f0e-ba43d4d39065','齋中詠懷','羊士諤','唐','唐诗','tang','','[]','無心唯有白雲知，閑臥高齋夢蝶時。',32,'全唐诗/poet.tang.17000.json','["無心唯有白雲知，閑臥高齋夢蝶時。", "不覺東風過寒食，雨來萱草出巴籬。"]'),
('690a3750-d7d5-40e0-9826-e4dcf7f02db6','登郡前山','羊士諤','唐','唐诗','tang','','[]','洛陽歸客滯巴東，處處山櫻雪滿叢。',32,'全唐诗/poet.tang.17000.json','["洛陽歸客滯巴東，處處山櫻雪滿叢。", "峴首當時爲風景，豈將官舍作池籠。"]'),
('9f9e50f5-c661-4ffd-92e2-b39c8f06c032','客有自渠州來說常諫議使君故事悵然成詠','羊士諤','唐','唐诗','tang','','[]','才子長沙暫左遷，能將意氣慰當年。',32,'全唐诗/poet.tang.17000.json','["才子長沙暫左遷，能將意氣慰當年。", "至今猶有東山妓，長使歌詩被管弦。"]'),
('9353a746-6d8e-4308-8338-f8ed2f384420','春日朝罷呈臺中寮友','羊士諤','唐','唐诗','tang','','[]','退食鵷行振羽儀，九霄雙闕迥參差。',64,'全唐诗/poet.tang.17000.json','["退食鵷行振羽儀，九霄雙闕迥參差。", "雲披綵仗春風度，日暖香堦晝刻移。", "玉樹籠煙鳷鵲觀，石渠流水鳳凰池。", "時清執法慚無事，未有長楊漢主知。"]'),
('0a1b0474-eac3-402f-9199-b3de34900240','州民有獻杏者瑰麗溢目因感花未幾聊以成詠','羊士諤','唐','唐诗','tang','','[]','南郭東風賞杏壇，幾株芳樹昨留歡。',64,'全唐诗/poet.tang.17000.json','["南郭東風賞杏壇，幾株芳樹昨留歡。", "却憶落花飄綺席，忽驚如實滿雕盤。", "蛾眉半歛千金薄，鷤鴂初鳴百草闌。", "志士古來悲節換，美人啼鳥亦長嘆。"]'),
('121c87f7-c989-49a3-b25c-fd198002a0e2','西川獨孤侍御見寄七言四韻一首爲郡翰墨都捐逮此詶答誠乖拙速','羊士諤','唐','唐诗','tang','','[]','百雉層城上將壇，列營西照雪峰寒。',64,'全唐诗/poet.tang.17000.json','["百雉層城上將壇，列營西照雪峰寒。", "文章立事須銘鼎，談笑論功恥據鞍。", "草檄清油推健筆，曳裾黃閣聳危冠。", "雙金未比三千字，負弩空慙知者難。"]'),
('1a7842f2-0253-4acd-9995-f328fd55c532','都城從事蕭員外寄海梨花詩盡綺麗至惠然遠及','羊士諤','唐','唐诗','tang','','[]','珠履行臺擁附蟬，外郎高步似神仙。',64,'全唐诗/poet.tang.17000.json','["珠履行臺擁附蟬，外郎高步似神仙。", "陳詞今見唐風盛，從事遙瞻衛國賢。", "擲地好詞凌綵筆，浣花春水膩魚箋。", "東山芳意須同賞，子看囊盛幾日傳。"]'),
('d2f39e83-ead0-49e3-8a3b-17b30991be14','赴資陽經嶓冢山','羊士諤','唐','唐诗','tang','','[]','寧辭舊路駕朱轓，重使疲人感漢恩。',32,'全唐诗/poet.tang.17000.json','["寧辭舊路駕朱轓，重使疲人感漢恩。", "今日鳴騶到嶓峽，還勝博望至河源。"]'),
('3f8541ff-dbdd-42db-b0e5-3c53567b6c5d','郡中言懷寄西川蕭員外','羊士諤','唐','唐诗','tang','','[]','功名無力愧勤王，已近終南得草堂。',64,'全唐诗/poet.tang.17000.json','["功名無力愧勤王，已近終南得草堂。", "身外盡歸天竺偈，腰間唯有會稽章。", "何時臘酒逢山客，可惜梅枝亞石牀。", "歲晚我知仙客意，懸心應在白雲鄉。"]'),
('3ef33157-b307-4b67-afea-bfa3ca1f9ae0','郡齋感物寄長安親友','羊士諤','唐','唐诗','tang','','[]','晴天春意併無窮，過臘江樓日日風。',64,'全唐诗/poet.tang.17000.json','["晴天春意併無窮，過臘江樓日日風。", "瓊樹花香故人別，蘭巵酒色去年同。", "閑吟鈴閣巴歌裏，回首神臯瑞氣中。", "自愧朝衣猶在篋，歸來應是白頭翁。"]'),
('89055736-d733-4953-896e-d9fbd99221ae','息舟荆溪入陽羨南山遊善權寺呈李功曹巨','羊士諤','唐','唐诗','tang','','[]','結纜蘭香渚，柴車上連岡。',120,'全唐诗/poet.tang.17000.json','["結纜蘭香渚，柴車上連岡。", "晏溫值初霽，去遶山河長。", "獻歲冰雪盡，細泉生路傍。", "行披煙杉入，激澗橫石梁。", "層閣表精廬，飛甍切雲翔。", "沖襟得高步，清眺極遠方。", "潭嶂積佳氣，荑英多早芳。", "具觀澤國秀，重使春心傷。", "念遵煩促途，榮利騖隟光。", "勉君脫冠意，共匿無何鄉。"]'),
('fc069bee-3dc3-4408-9f7d-aedf5490a89b','亂後曲江','羊士諤','唐','唐诗','tang','','[]','憶昔曾遊曲水濱，春來長有探春人。',32,'全唐诗/poet.tang.17000.json','["憶昔曾遊曲水濱，春來長有探春人。", "遊春人靜空地在，直至春深不似春。"]'),
('8b41ba79-5526-43ea-8fe6-ed1f2c451370','尋山家','羊士諤','唐','唐诗','tang','','[]','獨訪山家歇還涉，茅屋斜連隔松葉。',32,'全唐诗/poet.tang.17000.json','["獨訪山家歇還涉，茅屋斜連隔松葉。", "主人聞語未開門，繞籬野菜飛黃蝶。"]'),
('6682f8fc-ac0a-4ac0-89b9-09efe55db3c1','寄裴校書','羊士諤','唐','唐诗','tang','','[]','登高何處見瓊枝，白露黃花自繞籬。',32,'全唐诗/poet.tang.17000.json','["登高何處見瓊枝，白露黃花自繞籬。", "惟有樓中好山色，稻畦殘水入秋池。"]'),
('8f76ee2e-ef33-42e9-baa1-03cdcd51c9e6','句','羊士諤','唐','唐诗','tang','','[]','風泉留古韻，笙磬想遺音。',72,'全唐诗/poet.tang.17000.json','["風泉留古韻，笙磬想遺音。", "桂朽有遺馥，鸞飛安可待。", "塵沙藹如霧，長波驚飆度。", "雁起汀洲寒，馬嘶高城暮。", "銀釭倦秋館，綺瑟瞻永路。", "重有攜手期，清光倚玉樹。"]'),
('7d6d4ba9-75d7-4ba7-8301-774273cde941','秋夜閑居即事寄廬山鄭員外蜀郡符處士','楊巨源','唐','唐诗','tang','','["\u5e90\u5c71"]','憂思繁未整，良辰會無由。',96,'全唐诗/poet.tang.17000.json','["憂思繁未整，良辰會無由。", "引領遲佳音，星紀屢以周。", "蓬閬絕華耀，況乃處窮愁。", "墜葉寒擁砌，燈火夜悠悠。", "開琴弄清弦，窺月俯澄流。", "冉冉鴻鴈度，蕭蕭帷箔秋。", "悵懷石門詠，緬慕碧雞遊。", "髣髴蒙顏色，崇蘭隱芳洲。"]'),
('aebc840d-b60a-43ad-8a42-40e37645435b','獨不見','楊巨源','唐','唐诗','tang','','[]','東風豔陽色，柳綠花如霰。',48,'全唐诗/poet.tang.17000.json','["東風豔陽色，柳綠花如霰。", "競理同心鬟，爭持合歡扇。", "香傳賈娘手，粉離何郎面。", "最恨卷簾時，含情獨不見。"]'),
('1179db7f-af39-42de-a692-14574c10df9f','題趙孟莊','楊巨源','唐','唐诗','tang','','[]','管鮑化爲塵，交友存如線。',96,'全唐诗/poet.tang.17000.json','["管鮑化爲塵，交友存如線。", "升堂俱自媚，得路難相見。", "懿君敦三益，頹俗期一變。", "心同襲芝蘭，氣合回霜霰。", "石門雲臥久，玉洞花尋遍。", "王濬愛旌旗，梁竦勞州縣。", "煙鴻秋更遠，天馬寒愈健。", "願事郭先生，青囊書幾卷。"]'),
('74f4363c-5782-47ec-9dc6-38dd37fc1bd7','辭魏博田尚書出境後感恩戀德因登藂臺','楊巨源','唐','唐诗','tang','','[]','薦書及龍鍾，此事鏤心骨。',76,'全唐诗/poet.tang.17000.json','["薦書及龍鍾，此事鏤心骨。", "親知殊悢悢，徒御方咄咄。", "藂臺邯鄲郭，臺上見新月。", "離恨始分明，[歸思]□□更超忽。", "懷仁淚空盡，感事情又發。", "他時躧履聲，曉日照丹闕。"]'),
('595e0520-f7da-4db7-958c-c175cecba4ec','夏日苦熱同長孫主簿過仁壽寺納涼','楊巨源','唐','唐诗','tang','','[]','火入天地罏，南方正何劇。',120,'全唐诗/poet.tang.17000.json','["火入天地罏，南方正何劇。", "四郊長雲紅，六合太陽赤。", "爀爀沸泉壑，燄燄燋砂石。", "思減祝融權，期匡諸子宅。", "因投竹林寺，一問青蓮客。", "心空得清涼，理證等喧寂。", "開襟天籟回，步履雨花積。", "微風動珠簾，惠氣入瑤席。", "境閑性方謐，塵遠趣皆適。", "淹駕殊未還，朱欄敞虛碧。"]'),
('eef8f8d0-8f59-456b-9c07-088bcefcd367','送李虞仲秀才歸東都因寄元李二友','楊巨源','唐','唐诗','tang','','[]','高翼閑未倦，孤雲曠無期。',120,'全唐诗/poet.tang.17000.json','["高翼閑未倦，孤雲曠無期。", "晴霞海西畔，秋草燕南時。", "鄴中多上才，耿耿丹霄姿。", "顧我於逆旅，與君發光儀。", "同將儒者方，獲忝攜人知。", "幽蘭與芳佩，寒玉鏘美詞。", "舊友在伊洛，鳴蟬思山陂。", "到來再春風，夢盡雙瓊枝。", "素業且無負，青冥殊未遲。", "南橋天氣好，脈脈一相思。"]'),
('498f3303-9455-45fb-a789-a4af2f1ae201','和盧諫議朝回書情即事寄兩省閣老兼呈二起居諫院諸院長','楊巨源','唐','唐诗','tang','','[]','寵位資寂用，回頭憐二疎。',240,'全唐诗/poet.tang.17000.json','["寵位資寂用，回頭憐二疎。", "超遙比鶴性，皎潔同僧居。", "華組澹無累，單牀歡有餘。", "題詩天風灑，屬思紅霞舒。", "藹藹延閤東，晨光映林初。", "爐香深內殿，山色明前除。", "對客默焚稾，何人知諫書。", "全仁氣逾勁，大辨言甚徐。", "逸步寄青璅，閑吟親綺疏。", "清輝被鸞渚，瑞藹含龍渠。", "謝監營野墅，陶公愛吾廬。", "悠然遠者懷，聖代飄長裾。", "端弼緝元化，至音生太虛。", "一戎殄欃槍，重譯充儲胥。", "借地種寒竹，看雲憶春蔬。", "靈機棲杳冥，談笑登軒車。", "晚迹識麒麟，秋英見芙蕖。", "危言直且莊，曠抱鬱以攄。", "志業耿冰雪，光容粲璠璵。", "時賢儼仙掖，氣謝心何如。"]'),
('d38a3179-65f5-4314-a9dd-5b99454d713b','奉酬竇郎中早入省苦寒見寄','楊巨源','唐','唐诗','tang','','[]','玄冥怒含風，羣物戒嚴節。',180,'全唐诗/poet.tang.17000.json','["玄冥怒含風，羣物戒嚴節。", "空山頑石破，幽澗層冰裂。", "題詩金華彥，接武丹霄烈。", "曠懷玉京雲，孤唱粉垣雪。", "窮陰總凝沍，正氣直肅殺。", "天狼看墜地，霜兔敢拒穴。", "悠然蓬蒿士，亦得奉朝謁。", "羸驂苦遲遲，單僕怨切切。", "端闈仙階邃，廣陌凍橋滑。", "旭日鴛鴦行，瑞煙芙蓉闕。", "司寒申鄭重，成歲在凜冽。", "謝監逢酒時，袁生閉門月。", "漸思霜霰減，欲報陽和發。", "誰家挾纊心，何地當罏熱。", "慘舒能一改，恭聽遠者說。"]'),
('db0b70c0-b894-426a-b7a1-e5136dedd031','野園獻果呈員外','楊巨源','唐','唐诗','tang','','[]','西園果初熟，上客心逾愜。',48,'全唐诗/poet.tang.17000.json','["西園果初熟，上客心逾愜。", "凝粉乍辭枝，飄紅仍帶葉。", "幽姿寫瓊實，殷彩呈妝頰。", "持此贈佳期，清芬羅袖裛。"]'),
('bddf2874-e96b-43b9-85d9-e4d7d89d25b9','大堤曲','楊巨源','唐','唐诗','tang','','[]','二八嬋娟大堤女，開壚相對依江渚。',128,'全唐诗/poet.tang.17000.json','["二八嬋娟大堤女，開壚相對依江渚。", "待客登樓向水看，邀郎捲幔臨花語。", "細雨濛濛濕芰荷，巴東商侶挂帆多。", "自傳芳酒涴紅袖，誰調妍妝回翠娥。", "珍簟華燈夕陽後，當壚理瑟矜纖手。", "月落星微五鼓聲，春風搖蕩牕前柳。", "歲歲逢迎沙岸間，北人多識綠雲鬟。", "無端嫁與五陵少，離別煙波傷玉顏。"]'),
('328b8671-623b-4496-9d14-8db6fe0e79ee','楊花落','楊巨源','唐','唐诗','tang','','["\u6625\u5929", "\u559c\u60a6", "\u82b1", "\u5199\u82b1"]','北斗南回春物老，紅英落盡綠尚早。',112,'全唐诗/poet.tang.17000.json','["北斗南回春物老，紅英落盡綠尚早。", "韶風澹蕩無所依，偏惜垂楊作春好。", "此時可憐楊柳花，滎盈豔曳滿人家。", "人家女兒出羅幕，靜掃玉庭待花落。", "寶環纖手捧更飛，翠羽輕裾承不著。", "歷歷瑤琴舞金陳，菲紅拂黛憐玉人。", "東園桃李芳已歇，獨有楊花嬌暮春。"]'),
('d0be6b0d-6be7-4235-9db2-55ab10e437fd','月宮詞','楊巨源','唐','唐诗','tang','','[]','宮中月明何所似，如積如流滿田地。',192,'全唐诗/poet.tang.17000.json','["宮中月明何所似，如積如流滿田地。", "逈過前殿曾學眉，回照長門慣催淚。", "昭陽昨夜秋風來，綺閣金鋪情影開。", "藻井浮花共陵亂，玉階零露相裴回。", "稍映明河泛仙馭，滿牕猶在更衣處。", "管弦回燭無限情，環珮憑欄不能去。", "皎皎蒼蒼千里同，穿煙飄葉九門通。", "珠簾欲卷畏成水，瑤席初陳驚似空。", "復值君王事歡宴，宮女三千一時見。", "飛蓋愁看素暈低，稱觴願踏清輝遍。", "江上無雲夜可憐，冒沙披浪自嬋娟。", "若共心賞風流夜，那比高高太液前。"]'),
('4d2f261c-4519-45c6-b0a4-202baf147773','贈從弟茂卿','楊巨源','唐','唐诗','tang','','[]','吾從驥足楊茂卿，性靈且奇才甚清。',96,'全唐诗/poet.tang.17000.json','["吾從驥足楊茂卿，性靈且奇才甚清。", "海內方微風雅道，鄴中更有文章盟。", "扣寂由來在淵思，搜奇本自通禪智。", "王維證時符水月，杜甫狂處遺天地。", "流水東西岐路分，幽州迢遰舊來聞。", "若爲向北驅疲馬，山似寒空塞似雲。"]'),
('3cefcd9d-136e-441e-ad94-113b8c15181b','烏啼曲贈張評事','楊巨源','唐','唐诗','tang','','[]','可憐楊葉復楊花，雪淨煙深碧玉家。',48,'全唐诗/poet.tang.17000.json','["可憐楊葉復楊花，雪淨煙深碧玉家。", "烏棲不定枝條弱，城頭夜半聲啞啞。", "浮萍流蕩門前水，任罥芙蓉莫墮沙。"]'),
('93dc913e-1b3a-4406-90a7-d9f4149bc1ef','端午日伏蒙內侍賜晨服','楊巨源','唐','唐诗','tang','','[]','綵縷纖仍麗，凌風卷復開。',48,'全唐诗/poet.tang.17000.json','["綵縷纖仍麗，凌風卷復開。", "方應五日至，應自九天來。", "在笥清光發，當軒暑氣回。", "遙知及時節，刀尺火雲催。"]'),
('b3078c95-ad0b-4381-9d0f-767484fac386','胡姬詞','楊巨源','唐','唐诗','tang','','[]','妍豔照江頭，春風好客留。',48,'全唐诗/poet.tang.17000.json','["妍豔照江頭，春風好客留。", "當壚知妾慣，送酒爲郎羞。", "香渡傳蕉扇，妝成上竹樓。", "數錢憐皓腕，非是不能留。"]'),
('a67ba24d-99e2-43d0-8366-a60811bfa7ae','春日有贈','楊巨源','唐','唐诗','tang','','[]','堤暖柳絲斜，風光屬謝家。',48,'全唐诗/poet.tang.17000.json','["堤暖柳絲斜，風光屬謝家。", "晚心應戀水，春恨定因花。", "步遠憐芳草，歸遲見綺霞。", "由來感情思，獨自惜年華。"]'),
('9245cc97-4e85-4619-9437-afc450f43f1e','襄陽樂','楊巨源','唐','唐诗','tang','','[]','閑隨少年去，試上大堤遊。',48,'全唐诗/poet.tang.17000.json','["閑隨少年去，試上大堤遊。", "畫角棲烏起，清弦過客愁。", "碑沈楚山石，珠徹漢江秋。", "處處風情好，盧家更上樓。"]'),
('02bd5366-b3b8-4d23-92f9-5857e9256ce2','關山月','楊巨源','唐','唐诗','tang','','[]','蒼茫臨故關，迢遰照秋山。',48,'全唐诗/poet.tang.17000.json','["蒼茫臨故關，迢遰照秋山。", "萬里平蕪靜，孤城落葉閑。", "露濃棲鴈起，天遠戍兵還。", "復映征西府，光深組練間。"]'),
('1853d1e9-e305-49d9-894f-5ff235b537c1','長城聞笛','楊巨源','唐','唐诗','tang','','[]','孤城笛滿林，斷續共霜砧。',48,'全唐诗/poet.tang.17000.json','["孤城笛滿林，斷續共霜砧。", "夜月降羌淚，秋風老將心。", "靜過寒壘遍，暗入故關深。", "惆悵梅花落，山川不可尋。"]'),
('089973d6-706d-44a0-8a2f-31924e6045fb','春晚東歸留贈李功曹','楊巨源','唐','唐诗','tang','','[]','芳田岐路斜，脈脈惜年華。',48,'全唐诗/poet.tang.17000.json','["芳田岐路斜，脈脈惜年華。", "雲路青絲騎，香含翠幰車。", "歌聲仍隔水，醉色未侵花。", "唯有懷鄉客，東飛羨曙鵶。"]'),
('364a33f8-53ef-46c3-92df-7ae656cca792','送殷員外使北蕃','楊巨源','唐','唐诗','tang','','[]','二軒將雨露，萬里入煙沙。',48,'全唐诗/poet.tang.17000.json','["二軒將雨露，萬里入煙沙。", "和氣生中國，薰風屬外家。", "塞蘆隨鴈影，關柳拂駝花。", "努力黃雲北，僊曹有雉車。"]'),
('28d3990e-8a80-4c9f-b24e-b72f01eb2cd0','送許侍御充雲南哀冊使判官','楊巨源','唐','唐诗','tang','','[]','萬里永昌城，威儀奉聖明。',48,'全唐诗/poet.tang.17000.json','["萬里永昌城，威儀奉聖明。", "冰心瘴江冷，霜憲漏天晴。", "荒外開亭候，雲南降斾旌。", "他時功自許，絕域轉哀榮。"]'),
('dd03ef17-b6d9-42de-afd8-89faa7d76e27','秋日題陳宗儒圃亭悽然感舊','楊巨源','唐','唐诗','tang','','[]','曾隨何水部，待月東亭宿。',48,'全唐诗/poet.tang.17000.json','["曾隨何水部，待月東亭宿。", "今日重凭欄，清風空在竹。", "前山依舊碧，閑草經秋綠。", "時物方宛然，蛛絲一何速。"]'),
('a2fd13a1-7e42-4a9c-a4f8-ffdeb9d40f17','和鄭少師相公題慈恩寺禪院','楊巨源','唐','唐诗','tang','','[]','舊寺長桐孫，朝天是聖恩。',48,'全唐诗/poet.tang.17000.json','["舊寺長桐孫，朝天是聖恩。", "謝公詩更老，蕭傅道方尊。", "白法知深得，蒼生要重論。", "若爲將此望，心地向空門。"]'),
('f8b2dd6c-6fed-4b8b-b847-be25c04b059a','同趙校書題普救寺','楊巨源','唐','唐诗','tang','','[]','東門高處天，一望幾悠然。',48,'全唐诗/poet.tang.17000.json','["東門高處天，一望幾悠然。", "白浪過城下，青山滿寺前。", "塵光分驛道，嵐色到人煙。", "氣象須文字，逢君大雅篇。"]'),
('11ba6660-7fdc-431c-9c8d-8c95b37bb50c','春日與劉評事過故證上人院','楊巨源','唐','唐诗','tang','','[]','曾共劉諮議，同時事道林。',48,'全唐诗/poet.tang.17000.json','["曾共劉諮議，同時事道林。", "與君方掩淚，來客是知心。", "堦雪凌春積，鐘煙向夕深。", "依然舊童子，相送出花陰。"]'),
('6c18667b-708f-4a2a-9c20-d4a104e36904','春雪題興善寺廣宣上人竹院','楊巨源','唐','唐诗','tang','','[]','皎潔青蓮客，焚香對雪朝。',48,'全唐诗/poet.tang.17000.json','["皎潔青蓮客，焚香對雪朝。", "竹風催淅瀝，花雨讓飄颻。", "觸石和雲積，縈池拂水消。", "只應將日月，顏色不相饒。"]'),
('a96f1b0d-7c85-4f6a-98f9-b26e3ca2dfd2','清明日后土祠送田徹','楊巨源','唐','唐诗','tang','','[]','清明千萬家，處處是年華。',48,'全唐诗/poet.tang.17000.json','["清明千萬家，處處是年華。", "榆柳芳辰火，梧桐今日花。", "祭祠結雲綺，遊陌擁香車。", "惆悵田郎去，原回煙樹斜。"]'),
('3c4f87ef-3508-44ca-9d12-a6bf110a81e8','酬令狐員外直夜書懷見寄','楊巨源','唐','唐诗','tang','','[]','花枝暖欲舒，粉署夜方初。',48,'全唐诗/poet.tang.17000.json','["花枝暖欲舒，粉署夜方初。", "世職推傳盛，春刑是減餘。", "芸香能護字，鉛槧善呈書。", "此地從頭白，經年望雉車。"]'),
('c31fbe9c-bc54-455e-9c18-bf7c065eee35','題表丈三大夫書齋','楊巨源','唐','唐诗','tang','','[]','盛府自蓮花，羣公是歲華。',48,'全唐诗/poet.tang.17000.json','["盛府自蓮花，羣公是歲華。", "蘭姿丈人圃，松色大夫家。", "素卷堆瑤席，朱弦映絳紗。", "詩題三百首，高韻照春霞。"]'),
('d719fd0e-bbf4-49b5-83f7-e04ad1d1b9d3','春日送沈贊府歸潯陽覲叔父','楊巨源','唐','唐诗','tang','','[]','潯陽阮咸宅，九派竹林前。',48,'全唐诗/poet.tang.17000.json','["潯陽阮咸宅，九派竹林前。", "花嶼高如浪，雲峰遠似天。", "江聲在南巷，海氣入東田。", "才子今朝去，風濤思渺然。"]'),
('27d08ec0-f76c-4855-9671-c2b4a4559795','與李文仲秀才同賦泛酒花詩','楊巨源','唐','唐诗','tang','','[]','若道春無賴，飛花合逐風。',48,'全唐诗/poet.tang.17000.json','["若道春無賴，飛花合逐風。", "巧知人意裏，解入酒杯中。", "香濕勝含露，光搖似泛空。", "請君回首看，幾片舞芳叢。"]'),
('c67b0e78-53ba-4ed1-96d4-da38c7e0809f','登寧州城樓','楊巨源','唐','唐诗','tang','','[]','宋玉本悲秋，今朝更上樓。',48,'全唐诗/poet.tang.17000.json','["宋玉本悲秋，今朝更上樓。", "清波城下去，此意重悠悠。", "晚菊臨杯思，寒山滿郡愁。", "故關非內地，一爲漢家羞。"]'),
('7cf67235-a1bb-402f-bd49-4b6c03d83a0c','同薛侍御登黎陽縣樓眺黃河','楊巨源','唐','唐诗','tang','','["\u9ec4\u6cb3"]','倚檻恣流目，高城臨大川。',48,'全唐诗/poet.tang.17000.json','["倚檻恣流目，高城臨大川。", "九回紆白浪，一半在青天。", "氣肅晴空外，光翻曉日邊。", "開襟值佳景，懷抱更悠然。"]'),
('03832c09-0b93-4df0-b4b5-39b6f8208d46','和權相公南園閑涉寄廣宣上人','楊巨源','唐','唐诗','tang','','[]','浩氣抱天和，閑園載酒過。',48,'全唐诗/poet.tang.17000.json','["浩氣抱天和，閑園載酒過。", "步因秋景曠，心向晚雲多。", "翠玉思回鳳，玄珠肯在鵝。", "問師登幾地，空性奈詩何。"]'),
('0ab2e477-66f2-4f1d-a642-ff3f157b1cde','供奉定法師歸安南','楊巨源','唐','唐诗','tang','','[]','故鄉南越外，萬里白雲峰。',48,'全唐诗/poet.tang.17000.json','["故鄉南越外，萬里白雲峰。", "經論辭天去，香花入海逢。", "鷺濤清梵徹，蜃閣化城重。", "心到長安陌，交州後夜鐘。"]'),
('a2833e0a-d45e-4103-9604-e22a620a016b','池上竹','楊巨源','唐','唐诗','tang','','[]','一叢嬋娟色，四面清冷波。',48,'全唐诗/poet.tang.17000.json','["一叢嬋娟色，四面清冷波。", "氣潤晚煙重，光閑秋露多。", "翠筠入疎柳，清影拂圓荷。", "歲晏琅玕實，心期有鳳過。"]'),
('21bdc7ed-bb33-4021-a078-7e5aab4c44d1','長安春遊','楊巨源','唐','唐诗','tang','','[]','鳳城春報曲江頭，上客年年是勝遊。',64,'全唐诗/poet.tang.17000.json','["鳳城春報曲江頭，上客年年是勝遊。", "日暖雲山當廣陌，天清絲管在高樓。", "蘢蔥樹色分僊閣，縹緲花香汎御溝。", "桂壁朱門新邸第，漢家恩澤問酇侯。"]'),
('1ca57010-dc25-47bf-8811-a84c71023ddb','送定法師歸蜀法師即紅樓院供奉廣宣上人兄弟','楊巨源','唐','唐诗','tang','','[]','鳳城初日照紅樓，禁寺公卿識惠休。',64,'全唐诗/poet.tang.17000.json','["鳳城初日照紅樓，禁寺公卿識惠休。", "詩引棣華沾一雨，經分貝葉向雙流。", "孤猿學定前山夕，遠鴈傷離幾地秋。", "空性碧雲無處所，約公曾許剡溪遊。"]'),
('5c08602c-77e8-4f62-b04c-8312f8783443','早朝','楊巨源','唐','唐诗','tang','','[]','鐘聲清禁纔應徹，漏報仙闈儼已開。',64,'全唐诗/poet.tang.17000.json','["鐘聲清禁纔應徹，漏報仙闈儼已開。", "雙闕薄煙籠菡萏，九成初日照蓬萊。", "朝時但向丹墀拜，仗下方從碧殿回。", "聖道逍遙更何事，願將巴曲贊康哉。"]'),
('b7637c62-e5ce-45cb-a092-a9b31da8fc3b','贈張將軍','楊巨源','唐','唐诗','tang','','[]','關西諸將揖容光，獨立營門劒有霜。',64,'全唐诗/poet.tang.17000.json','["關西諸將揖容光，獨立營門劒有霜。", "知愛魯連歸海上，肯令王翦在頻陽。", "天晴紅幟當山滿，日暮清笳入塞長。", "年少功高人最羨，漢家壇樹月蒼蒼。"]'),
('fea12b95-a957-43ee-9e8e-d5949c20b205','和侯大夫秋原山觀征人回','楊巨源','唐','唐诗','tang','','[]','兩河戰罷萬方清，原上軍回識舊營。',64,'全唐诗/poet.tang.17000.json','["兩河戰罷萬方清，原上軍回識舊營。", "立馬望雲秋塞靜，射鵰臨水晚天晴。", "戍閑部伍分岐路，地遠家鄉寄斾旌。", "聖代止戈資廟略，諸侯不復更長征。"]'),
('8131ca14-2dba-4241-8bd1-89a1c91911e1','送人過衛州','楊巨源','唐','唐诗','tang','','[]','憶昔征南府內遊，君家東閤最淹留。',64,'全唐诗/poet.tang.17000.json','["憶昔征南府內遊，君家東閤最淹留。", "縱橫聯句長侵曉，次第看花直到秋。", "論舊舉杯先下淚，傷離臨水更登樓。", "相思前路幾回首，滿眼青山過衛州。"]'),
('f13eab4c-c322-4d11-9c66-5054847c1301','寄中書同年舍人','楊巨源','唐','唐诗','tang','','[]','晴明紫閣最高峰，仙掖開簾范彥龍。',64,'全唐诗/poet.tang.17000.json','["晴明紫閣最高峰，仙掖開簾范彥龍。", "五色天書詞煥爛，九華春殿語從客。", "綵毫應染爐煙細，清珮仍含玉漏重。", "二十年前同日喜，碧霄何路得相逢。"]'),
('025d356a-a58e-4b6b-a8b0-85d8e541c99b','酬于駙馬二首 一','楊巨源','唐','唐诗','tang','','[]','綺陌塵香曙色分，碧山如畫又逢君。',64,'全唐诗/poet.tang.17000.json','["綺陌塵香曙色分，碧山如畫又逢君。", "蛟藏秋月一片水，驥鎖晴空千尺雲。", "戚里舊知何駙馬，詩家今得鮑參軍。", "陽和本是煙霄曲，須向花間次第聞。"]'),
('e97554f5-b802-487a-97bd-22d16887ceb2','酬于駙馬二首 二','楊巨源','唐','唐诗','tang','','[]','芳時碧落心應斷，今日清詞事不同。',64,'全唐诗/poet.tang.17000.json','["芳時碧落心應斷，今日清詞事不同。", "瑤草秋殘仙圃在，綵雲天遠鳳樓空。", "晴花煖送金羈影，涼葉寒生玉簟風。", "長得聞詩歡自足，會看春露濕蘭叢。"]'),
('a5b26daa-bc57-4760-9966-a50d6f5a7175','將歸東都寄令狐舍人','楊巨源','唐','唐诗','tang','','[]','綠楊紅杏滿城春，一騎悠悠萬井塵。',64,'全唐诗/poet.tang.17000.json','["綠楊紅杏滿城春，一騎悠悠萬井塵。", "岐路未關今日事，風光欲醉長年人。", "閑過綺陌尋高寺，強對朱門謁近臣。", "多病晚來還有策，雒陽山色舊相親。"]'),
('a0ee48d6-4af5-4bc8-87c0-cfec42caacc2','寄江州白司馬','楊巨源','唐','唐诗','tang','','[]','江州司馬平安否，惠遠東林住得無。',64,'全唐诗/poet.tang.17000.json','["江州司馬平安否，惠遠東林住得無。", "湓浦曾聞似衣帶，廬峰見說勝香爐。", "題詩歲晏離鴻斷，望闕天遙病鶴孤。", "莫謾拘牽雨花社，青雲依舊是前途。"]'),
('49af4682-5a7e-4f86-8035-471cc839d8f9','薛司空自青州歸朝','楊巨源','唐','唐诗','tang','','["\u9ec4\u6cb3"]','天眷君陳久（一作「舊」）在東，歸朝人看大司空。',71,'全唐诗/poet.tang.17000.json','["天眷君陳久（一作「舊」）在東，歸朝人看大司空。", "黃河岸畔長無事，滄海東邊獨有功。", "已變畏途成雅俗，仍過舊里揖秋風。", "一門累葉凌煙閣，次第儀形漢上公。"]'),
('d8ed792c-b061-4e84-8d14-c3f3164128f3','送章孝標校書歸杭州因寄白舍人','楊巨源','唐','唐诗','tang','','[]','曾過靈隱江邊寺，獨宿東樓看海門。',64,'全唐诗/poet.tang.17000.json','["曾過靈隱江邊寺，獨宿東樓看海門。", "潮色銀河鋪碧落，日光金柱出紅盆。", "不妨公事資高臥，無限詩情要細論。", "若訪郡人徐孺子，應須騎馬到沙村。"]'),
('0e85e47b-336d-4c32-a797-ddbff22177a2','述舊紀勳太原寄李光顏侍中二首 一','楊巨源','唐','唐诗','tang','','[]','玉塞含悽見鴈行，北垣新詔拜龍驤。',64,'全唐诗/poet.tang.17000.json','["玉塞含悽見鴈行，北垣新詔拜龍驤。", "弟兄間世真飛將，貔虎歸時似故鄉。", "鼓角因風飄朔氣，旌旗映水發秋光。", "河源收地心猶壯，笑向天西萬里霜。"]'),
('6c9acc43-e0e0-4509-94b9-2f877ea705e1','述舊紀勳太原寄李光顏侍中二首 二','楊巨源','唐','唐诗','tang','','[]','倚天長劒截雲孤，報國縱橫見丈夫。',64,'全唐诗/poet.tang.17000.json','["倚天長劒截雲孤，報國縱橫見丈夫。", "五載登壇真宰相，六重分閫正司徒。", "曾聞轉戰平堅寇，共說題詩壓腐儒。", "料敵知機在方寸，不勞心力講陰符。"]'),
('473000b9-20f8-4dd5-a7c6-8943aa51e756','酬盧員外','楊巨源','唐','唐诗','tang','','[]','謝傅旌旗控上游，盧郎罇俎借前籌。',64,'全唐诗/poet.tang.17000.json','["謝傅旌旗控上游，盧郎罇俎借前籌。", "舜城風土臨清廟，魏國山川在白樓。", "雲寺當時接高步，水亭今日又同遊。", "滿筵舊府笙歌在，獨有羊曇最淚流。"]'),
('e70f0a58-0ea9-4fba-ade5-57a4657f44e4','古意贈王常侍','楊巨源','唐','唐诗','tang','','[]','繡戶紗窗北里深，香風暗動鳳凰簪。',64,'全唐诗/poet.tang.17000.json','["繡戶紗窗北里深，香風暗動鳳凰簪。", "組紃常在佳人手，刀尺空搖寒女心。", "欲學齊謳逐雲管，還思楚練拂霜砧。", "東家少婦當機織，應念無衣雪滿林。"]'),
('e67dde25-ec74-4d61-91c9-451a7fbef56b','送裴中丞出使','楊巨源','唐','唐诗','tang','','[]','一清淮甸假朝綱，金印初迎細柳黃。',64,'全唐诗/poet.tang.17000.json','["一清淮甸假朝綱，金印初迎細柳黃。", "辭闕天威和雨露，出關春色避風霜。", "龍韜何必陳三略，虎旅由來肅萬方。", "宣諭生靈真重任，回軒應問石渠郎。"]'),
('f273bbf4-e006-4910-96e3-9a4a039110ed','送絳州盧使君','楊巨源','唐','唐诗','tang','','[]','應將清淨結心期，又共陽和到郡時。',64,'全唐诗/poet.tang.17000.json','["應將清淨結心期，又共陽和到郡時。", "絳老問年須算字，庾公逢月要題詩。", "朱欄迢遰因高勝，粉堞清明欲下遲。", "他日徴還作霖雨，不須求賽敬亭祠。"]'),
('198fe56d-802d-4f47-ae39-6e99956200ea','贈李傅','楊巨源','唐','唐诗','tang','','[]','知因公望掩能文，誓激明誠在致君。',64,'全唐诗/poet.tang.17000.json','["知因公望掩能文，誓激明誠在致君。", "曾罷雙旌瞻白日，猶將一劒許黃雲。", "搖牕竹色留僧語，入院松聲共鶴聞。", "莫被此心生晚計，鎮南人憶杜將軍。"]'),
('684f5ff0-0ef2-4639-ad16-ec08ca6e6209','上裴中丞','楊巨源','唐','唐诗','tang','','[]','六年西掖弘湯誥，三捷東堂總漢科。',64,'全唐诗/poet.tang.17000.json','["六年西掖弘湯誥，三捷東堂總漢科。", "政引風霜成物色，語回天地到陽和。", "清威更助朝端重，聖澤曾隨筆下多。", "應笑白鬚揚執戟，可憐春日老如何。"]'),
('68a1a7f0-df25-4c99-aa6e-9040cbb67964','和人與人分惠賜冰','楊巨源','唐','唐诗','tang','','[]','天水藏來玉墮空，先頒密署幾人同。',64,'全唐诗/poet.tang.17000.json','["天水藏來玉墮空，先頒密署幾人同。", "映盤皎潔非資月，披扇清涼不在風。", "瑩質方從綸閣內，凝輝更向畫堂中。", "麗詞珍貺難雙有，迢遰金輿殿角東。"]'),
('2b6a59fe-a78a-4fd7-bbf3-d3c208deb63d','觀打毬有作','楊巨源','唐','唐诗','tang','','[]','親掃毬場如砥平，龍驤驟馬曉光晴。',64,'全唐诗/poet.tang.17000.json','["親掃毬場如砥平，龍驤驟馬曉光晴。", "入門百拜瞻雄勢，動地三軍唱好聲。", "玉勒回時霑赤汗，花鬉分處拂紅纓。", "欲令四海氛煙靜，杖底纖塵不敢生。"]'),
('ecd926ae-08d4-436e-af8c-dbd3af3dba93','早春即事呈劉員外','楊巨源','唐','唐诗','tang','','[]','明朝晴暖即相隨，肯信春光被雨欺。',64,'全唐诗/poet.tang.17000.json','["明朝晴暖即相隨，肯信春光被雨欺。", "且任文書堆案上，免令杯酒負花時。", "馬蹄經歷須應徧，鶯語叮嚀已怪遲。", "更待雜芳成豔錦，鄴中爭唱仲宣詩。"]'),
('62105508-0128-49a3-b02d-8e0a68c7149b','送司徒童子','楊巨源','唐','唐诗','tang','','[]','衛多君子魯多儒，七歲聞天笑舞雩。',64,'全唐诗/poet.tang.17000.json','["衛多君子魯多儒，七歲聞天笑舞雩。", "光彩春風初轉蕙，性靈秋水不藏珠。", "兩經在口知名小，百拜垂髫稟氣殊。", "況復元侯旌爾善，桂林枝上得鵷雛。"]'),
('a8293f49-0cba-47a8-9f1f-6e08a83ee973','寄昭應王丞','楊巨源','唐','唐诗','tang','','[]','武皇金輅輾香塵，每歲朝元及此辰。',64,'全唐诗/poet.tang.17000.json','["武皇金輅輾香塵，每歲朝元及此辰。", "光動泉心初浴日，氣蒸山腹總成春。", "謳歌已入雲韶曲，詞賦方歸侍從臣。", "瑞靄朝朝猶望幸，天敎赤縣有詩人。"]'),
('ffd9a717-6d20-447f-b45c-509bef3291e2','酬崔博士','楊巨源','唐','唐诗','tang','','[]','自知頑叟更何能，唯學雕蟲謬見稱。',64,'全唐诗/poet.tang.17000.json','["自知頑叟更何能，唯學雕蟲謬見稱。", "長被有情邀唱和，近來無力更祗承。", "青松樹杪三千鶴，白玉壺中一片冰。", "今日爲君書壁右，孤城莫怕世人憎。"]'),
('961c2d6b-321d-4dd6-9abb-ad9c507f6945','酬裴舍人見寄','楊巨源','唐','唐诗','tang','','[]','誰道重遷是舊班，自將霄漢比鄉關。',64,'全唐诗/poet.tang.17000.json','["誰道重遷是舊班，自將霄漢比鄉關。", "二妃樓下宜臨水，五老祠西好看山。", "再葺吾廬心已足，每來公府路常閑。", "詩陪亞相逾三紀，石笥煙霞不共攀。"]'),
('2e2e8b3a-7eda-4add-bb4a-c13a05e3035a','和劉員外陪韓僕射野亭公宴','楊巨源','唐','唐诗','tang','','[]','好客風流玳瑁簪，重簷高幕曉沈沈。',64,'全唐诗/poet.tang.17000.json','["好客風流玳瑁簪，重簷高幕曉沈沈。", "綺筵霜重旌旗滿，玉帳天清絲管聲。", "繁戲徒過魯儒目，衆歡方集漢郎心。", "寒笳一曲嚴城暮，雲騎連嘶香外林。"]'),
('a8ddc5ef-63e7-4857-b165-6372ec3f2852','酬崔駙馬惠箋百張兼貽四韻','楊巨源','唐','唐诗','tang','','[]','百張雲樣亂花開，七字文頭豔錦回。',64,'全唐诗/poet.tang.17000.json','["百張雲樣亂花開，七字文頭豔錦回。", "浮碧空從天上得，殷紅應自日邊來。", "捧持價重凌雲葉，封裹香深笑海苔。", "滿篋清光應照眼，欲題凡韻輒裴回。"]'),
('26d41f5f-d0fa-43d3-8a90-0b254d1f9e99','贈史開封','楊巨源','唐','唐诗','tang','','[]','天低荒草誓師壇，鄧艾心知戰地寬。',64,'全唐诗/poet.tang.17000.json','["天低荒草誓師壇，鄧艾心知戰地寬。", "鼓角逈臨霜野曙，旌旗高對雪峰寒。", "五營向水紅塵起，一劒當風白日看。", "曾從伏波征絕域，磧西蕃部怯金鞍。"]'),
('d8f41582-077a-4ded-892e-cacb96194359','奉寄通州元九侍御','楊巨源','唐','唐诗','tang','','[]','大明宮殿鬱蒼蒼，紫禁龍樓直署香。',64,'全唐诗/poet.tang.17000.json','["大明宮殿鬱蒼蒼，紫禁龍樓直署香。", "九陌華軒爭道路，一枝寒玉任煙霜。", "須聽瑞雪傳心語，莫被啼猨續淚行。", "共說聖朝容直氣，期君新歲奉恩光。"]'),
('c7843577-ded5-4519-a7b7-fd384d98ece4','贈渾鉅中允','楊巨源','唐','唐诗','tang','','[]','公子髫年四海聞，城南侍獵雪雰雰。',64,'全唐诗/poet.tang.17000.json','["公子髫年四海聞，城南侍獵雪雰雰。", "馬盤曠野弦開月，鴈落寒原箭在雲。", "曾向天西穿虜陣，慣遊花下領儒羣。", "一枝瓊萼朝光好，綵服飄飄從冠軍。"]'),
('4bd2bb04-2396-431d-9eeb-84ed85ee615d','重送胡大夫赴振武','楊巨源','唐','唐诗','tang','','[]','向年擢桂儒生業，今日分茅聖主恩。',64,'全唐诗/poet.tang.17000.json','["向年擢桂儒生業，今日分茅聖主恩。", "旌斾仍將過鄉路，軒車爭看出都門。", "人間文武能雙捷，天下安危待一論。", "布惠宣威大夫事，不妨詩思許琴尊。"]'),
('efab7c09-c36f-4cbc-b10c-0ab2fd32dd22','送陳判官罷舉赴江外','楊巨源','唐','唐诗','tang','','[]','練思多時冰雪清，拂衣無語別書生。',64,'全唐诗/poet.tang.17000.json','["練思多時冰雪清，拂衣無語別書生。", "莫將甲乙爲前累，不廢煙霄是此行。", "定愛紅雲燃楚色，應看白雨打江聲。", "心期玉帳親台位，魏勃因君說姓名。"]'),
('f8d11ac8-d2bc-40db-b959-fec9911df427','奉和裴相公','楊巨源','唐','唐诗','tang','','[]','竹寺題名一半空，衰榮三十六人中。',64,'全唐诗/poet.tang.17000.json','["竹寺題名一半空，衰榮三十六人中。", "在生本要求知己，垂老應憐值相公。", "敢望燮和回舊律，任應時節到春風。", "若爲問得蒼蒼意，造化無言自是功。"]'),
('3b548cc1-f164-4eee-a85e-e639d17a5333','和大夫邊春呈長安親故','楊巨源','唐','唐诗','tang','','[]','嚴城吹笛思寒梅，二月冰河一半開。',64,'全唐诗/poet.tang.17000.json','["嚴城吹笛思寒梅，二月冰河一半開。", "紫陌詩情依舊在，黑山弓力畏春來。", "遊人曲岸看花發，走馬平沙獵雪回。", "旌斾朝天不知晚，將星高處近三台。"]'),
('b3faddf1-cd7b-460f-87d3-e17fc2cc92d5','張郎中段員外初直翰林報寄長句','楊巨源','唐','唐诗','tang','','[]','秋空如練瑞雲明，天上人間莫問程。',64,'全唐诗/poet.tang.17000.json','["秋空如練瑞雲明，天上人間莫問程。", "丹鳳詞頭供二妙，金鑾殿角直三清。", "方瞻北極臨星月，猶向南班滯姓名。", "啓沃朝朝深禁裏，香爐煙外是公卿。"]'),
('1143a4c3-a712-42e6-a5b0-07d4d664809d','奉酬端公春雪見寄','楊巨源','唐','唐诗','tang','','[]','造化多情狀物親，剪花鋪玉萬重新。',64,'全唐诗/poet.tang.17000.json','["造化多情狀物親，剪花鋪玉萬重新。", "閑飄上路呈豐歲，狂舞中庭學醉春。", "興逸何妨尋剡客，唱高還肯寄巴人。", "遙知獨立芝蘭閣，滿眼清光壓俗塵。"]'),
('8dbcc618-65cb-4f0c-9325-590bcb99f022','盧郎中拜陵遇雪蒙見召因寄','楊巨源','唐','唐诗','tang','','[]','南宮使者有光輝，欲拜諸陵瑞雪飛。',64,'全唐诗/poet.tang.17000.json','["南宮使者有光輝，欲拜諸陵瑞雪飛。", "蘋葉已修青玉薦，柳花仍拂赤車衣。", "應同谷口尋春去，定似山陰帶月歸。", "寒冷出郊猶未得，羨公將事看芳菲。"]'),
('62aa9125-a433-4f39-9c5a-85aee1be1b03','冬夜陪丘侍御先輩聽崔校書彈琴','楊巨源','唐','唐诗','tang','','[]','雪滿中庭月映林，謝家幽賞在瑤琴。',64,'全唐诗/poet.tang.17000.json','["雪滿中庭月映林，謝家幽賞在瑤琴。", "楚妃波浪天南遠，蔡女煙沙漠北深。", "顧盼何曾因誤曲，殷勤終是感知音。", "若將雅調開詩興，未抵丘遲一片心。"]'),
('3cced284-9452-486d-9721-9bde4caa33c8','元日含元殿下立仗丹鳳樓門下宣赦相公稱賀二首 一','楊巨源','唐','唐诗','tang','','[]','天垂台耀掃欃槍，壽獻香山祝聖明。',64,'全唐诗/poet.tang.17000.json','["天垂台耀掃欃槍，壽獻香山祝聖明。", "丹鳳樓前歌九奏，金雞竿下鼓千聲。", "衣冠南面薰風動，文字東方喜氣生。", "從此登封資廟略，兩河連海一時清。"]'),
('7fc66539-b184-47ee-8a8f-cc8beae12002','元日含元殿下立仗丹鳳樓門下宣赦相公稱賀二首 二','楊巨源','唐','唐诗','tang','','[]','臨軒啓扇似雲收，率土朝天劇水流。',64,'全唐诗/poet.tang.17000.json','["臨軒啓扇似雲收，率土朝天劇水流。", "瑞色含春當正殿，香煙捧日在高樓。", "三朝氣蚤迎恩澤，萬歲聲長繞冕旒。", "請問漢家功第一，麒麟閣上識酇侯。"]'),
('c7c59319-bb0e-4250-8a6d-4ce2dfb836cf','元日觀朝','楊巨源','唐','唐诗','tang','','[]','北極長尊報聖期，周家何用問元龜。',64,'全唐诗/poet.tang.17000.json','["北極長尊報聖期，周家何用問元龜。", "天顏入曙千官拜，元日迎春萬物知。", "閶闔迴臨黃道正，衣裳高對碧山垂。", "微臣願獻堯人祝，壽酒年年太液池。"]'),
('7c2fd9c3-7847-463c-902c-7a71028930aa','題賈巡官林亭','楊巨源','唐','唐诗','tang','','[]','白鳥閑棲亭樹枝，綠罇仍對菊花籬。',64,'全唐诗/poet.tang.17000.json','["白鳥閑棲亭樹枝，綠罇仍對菊花籬。", "許詢本愛交禪侶，陳寔由來是好兒。", "明月出雲秋館思，遠泉經雨夜牕知。", "門前長者無虛轍，一片寒光動水池。"]'),
('59f461d6-4cec-496f-8a52-22c12169b7b6','和元員外題昇平里新齋','楊巨源','唐','唐诗','tang','','[]','自知休沐諸幽勝，遂肯高齋枕廣衢。',64,'全唐诗/poet.tang.17000.json','["自知休沐諸幽勝，遂肯高齋枕廣衢。", "舊地已開新玉圃，春山仍展綠雲圖。", "心源邀得閑詩證，肺氣宜將慢酒扶。", "此外唯應任真宰，同塵敢是道門樞。"]'),
('a831a090-6fc7-4424-b36e-8eaa1270bfde','送澹公歸嵩山龍潭寺葬本師','楊巨源','唐','唐诗','tang','','[]','野煙秋水蒼茫遠，禪境真機去住閑。',64,'全唐诗/poet.tang.17000.json','["野煙秋水蒼茫遠，禪境真機去住閑。", "雙樹爲家思舊壑，千花成塔禮寒山。", "洞宮曾向龍邊宿，雲徑應從鳥外還。", "莫戀本師金骨地，空門無處復無關。"]'),
('e1d66952-9960-4122-afa2-67caf07c3494','邵州陪王郎中宴','楊巨源','唐','唐诗','tang','','[]','西塞無塵多玉筵，貔貅鴛鷺儼相連。',64,'全唐诗/poet.tang.17000.json','["西塞無塵多玉筵，貔貅鴛鷺儼相連。", "紅茵照水開罇俎，翠幕當雲發管弦。", "歌態曉臨團扇靜，舞容春映薄衫妍。", "魯儒縱使他時有，不似歡娛及少年。"]'),
('8e2f586b-9ef4-4672-af24-723a5ec87773','和令狐舍人酬峰上人題山欄孤竹','楊巨源','唐','唐诗','tang','','[]','滿院冰姿粉籜殘，一莖青翠近簾端。',64,'全唐诗/poet.tang.17000.json','["滿院冰姿粉籜殘，一莖青翠近簾端。", "離叢自欲親香火，抱節何妨共歲寒。", "能讓繁聲任真籟，解將孤影對芳蘭。", "范雲許訪西林寺，枝葉須和彩鳳看。"]'),
('884c530d-c487-4626-81e2-514c065aff9a','寄贈田倉曹灣','楊巨源','唐','唐诗','tang','','[]','芳蘭媚庭除，灼灼紅英舒。',72,'全唐诗/poet.tang.17000.json','["芳蘭媚庭除，灼灼紅英舒。", "身爲陋巷客，門有絳轅車。", "朝覽夷吾傳，暮習潁陽書。", "眄雲高羽翼，待賈蘊璠璵。", "纓弁雖云阻，音塵豈復疎。", "若因風雨晦，應念寂寥居。"]'),
('bfef684c-5c4c-41ce-9d13-d87a676190ee','上劉侍中','楊巨源','唐','唐诗','tang','','[]','命代生申甫，承家翊禹湯。',288,'全唐诗/poet.tang.17000.json','["命代生申甫，承家翊禹湯。", "廟謨膺間氣，師律動清霜。", "鐘鼎勳庸大，山河誡誓長。", "英姿凌虎視，逸步壓龍驤。", "道協陶鈞力，恩回日月光。", "一言弘社稷，九命備珪璋。", "政洽軍逾肅，仁敷物已康。", "朱門重棨戟，丹詔半縑緗。", "位總雲龍野，師臨涿鹿鄉。", "射雕天更碧，吹角塞仍黃。", "深入平夷路，橫行闢漢疆。", "功垂貞石遠，名映色絲香。", "斷磧瞻貔武，臨池識鳳凰。", "舞腰凝綺榭，歌響拂彫梁。", "杯淨傳鸚鵡，裘鮮照鷫鸘。", "吟詩白羽扇，校獵綠沈槍。", "風景佳人地，煙沙壯士場。", "幕中邀謝鑒，麾下得周郎。", "珠影含空徹，瓊枝映座芳。", "王渾知武子，陳寔獎元方。", "富貴春無限，歡娛夜未央。", "管弦隨玉帳，尊俎奉金章。", "俗理寧因勸，邊城詎假防。", "軍容雄朔漠，公望冠巖廊。"]'),
('89086a0f-8cb5-4f91-91cb-de3b532e0439','贈侯侍御','楊巨源','唐','唐诗','tang','','[]','步逸辭羣迹，機真結遠心。',96,'全唐诗/poet.tang.17000.json','["步逸辭羣迹，機真結遠心。", "敦詩揚大雅，映古酌高音。", "逃禍棲蝸舍，因醒解豸簪。", "紫蘭秋露濕，黃鶴晚天陰。", "舊業餘荒草，寒山出遠林。", "月明多宿寺，世亂重悲琴。", "霄漢時應在，詩書道未沈。", "坐期閶闔霽，雲暖一開襟。"]'),
('9cb063de-38ae-4189-b4e9-1d8ed3e7d75d','懷德抒情寄上信州座主','楊巨源','唐','唐诗','tang','','[]','五馬江天郡，諸生淚共垂。',120,'全唐诗/poet.tang.17000.json','["五馬江天郡，諸生淚共垂。", "讌餘明主德，恩在侍臣知。", "悵望緘雙鯉，龍鍾假一枝。", "玉峰遙寄夢，雲海暗傷離。", "幢蓋全家去，琴書首路隨。", "滄州值康樂，明月向元規。", "鵷鳳終凌漢，蛟龍會出池。", "蕙香因曙發，松色肯寒移。", "舉世瞻風藻，當朝揖羽儀。", "加餐門下意，溪水綠逶迤。"]'),
('7075f90a-bd11-4c1a-b346-8b65e2b8bc20','送杜郎中使君赴虔州','楊巨源','唐','唐诗','tang','','[]','迢遰南康路，清輝得使君。',72,'全唐诗/poet.tang.17000.json','["迢遰南康路，清輝得使君。", "虎符秋領俗，鵷署早辭羣。", "地遠仍連戍，城嚴本帶軍。", "傍江低檻月，當嶺滿牕雲。", "境勝閭閻間，天清水陸分。", "和詩將惠政，頌述九衢聞。"]'),
('7dd4cb50-450f-4d79-a73f-2fb80f98e1c5','別鶴詞送令狐校書之桂府','楊巨源','唐','唐诗','tang','','[]','海鶴一爲別，高程方窅然。',96,'全唐诗/poet.tang.17000.json','["海鶴一爲別，高程方窅然。", "影搖江漢路，思結瀟湘天。", "皎然仰白日，真姿棲紫煙。", "含情九霄際，顧侶五雲前。", "遐心屬清都，淒響激朱弦。", "超遙聞風雨，迢遰各山川。", "東南信多水，會合當有年。", "雌飛唳冥冥，此意何由傳。"]'),
('fde9c6ba-5144-40b7-a5c8-284a4ac67b80','夏日裴尹員外西齋看花','楊巨源','唐','唐诗','tang','','[]','笑向東來客，看花枉在前。',98,'全唐诗/poet.tang.17000.json','["笑向東來客，看花枉在前。", "始知清夏月，更勝豔陽天。", "露濕呈妝汙，風吹畏火燃。", "蔥蘢和葉盛，爛熳壓枝鮮。", "紅彩當[鈴]閣，清香到玉筵。", "蝶棲驚曙色，鶯語滯晴煙。", "得地殊堪賞，過時倍覺妍。", "芳菲遲最好，唯是謝家憐。"]'),
('2eba7eb3-5f7b-4790-9d19-7092da5806a4','贈鄰家老將','楊巨源','唐','唐诗','tang','','[]','白首羽林郎，丁年戍朔方。',168,'全唐诗/poet.tang.17000.json','["白首羽林郎，丁年戍朔方。", "陰天瞻磧落，秋日渡遼陽。", "大漠寒山黑，孤城夜月黃。", "十年依蓐食，萬里帶金瘡。", "拂雪陳師祭，衝風立敎場。", "箭飛瓊羽合，旗動火雲張。", "虎翼分營勢，魚鱗擁陣行。", "誓心清塞色，鬬血雜沙光。", "戰地晴輝薄，軍門曉氣長。", "寇深爭暗襲，關逈勒春防。", "身賤竟何訴，天高徒自傷。", "功成封寵將，力盡到貧鄉。", "雀老方悲海，鷹衰却念霜。", "空餘孤劒在，開匣一霑裳。"]'),
('656213da-6880-4334-8d4f-889a846a229b','和呂舍人喜張員外自北番回至境上先寄二十韻','楊巨源','唐','唐诗','tang','','[]','割愛天文動，敦和國步安。',240,'全唐诗/poet.tang.17000.json','["割愛天文動，敦和國步安。", "仙姿歸舊好，戎意結新歡。", "並命瞻鵷鷺，同心揖蕙蘭。", "玉簫臨祖帳，金牓引征鞍。", "廣陌雙旌去，平沙萬里看。", "海雲侵鬢起，邊月向眉殘。", "突兀陰山迥，蒼茫朔野寬。", "毳廬同甲帳，韋橐比琱盤。", "義著親胡俗，儀全識漢官。", "地鄰冰鼠淨，天映燭龍寒。", "節異蘇卿執，弦殊蔡女彈。", "磧分黃渺渺，塞極黑漫漫。", "歡味羶腥列，徴聲佅僸攢。", "歸期先鴈候，登路劇鵬搏。", "上客離心遠，西宮草詔殫。", "麗詞傳錦綺，珍價掩琅玕。", "百兩開戎壘，千蹄入御欄。", "瑞光麟閣上，喜氣鳳城端。", "尚德曾辭劒，柔凶本舞干。", "茫茫斗星北，威服古來難。"]'),
('c5bc9791-07cd-4386-8028-4101ad7412dd','春日奉獻聖壽無疆詞十首 一','楊巨源','唐','唐诗','tang','','[]','文物京華盛，謳歌國步康。',72,'全唐诗/poet.tang.17000.json','["文物京華盛，謳歌國步康。", "瑤池供壽酒，銀漢麗宸章。", "靈雨含雙闕，雷霆肅萬方。", "代推仙祚遠，春共聖恩長。", "鳳扆臨花暖，龍罏旁日香。", "遙知千萬歲，天意奉君王。"]'),
('c4e27f9d-3fb9-4963-b2ec-53f33c617bee','春日奉獻聖壽無疆詞十首 二','楊巨源','唐','唐诗','tang','','[]','鴛鷺彤庭際，軒車綺陌前。',72,'全唐诗/poet.tang.17000.json','["鴛鷺彤庭際，軒車綺陌前。", "九城多好色，萬井半祥煙。", "人醉逢堯酒，鶯歌荅舜弦。", "花明御溝水，香暖禁城天。", "賜宴文逾盛，徴歌物更妍。", "無窮豔陽月，長照太平年。"]'),
('938159b0-ec3c-45ca-97f4-1d2868ec9b52','春日奉獻聖壽無疆詞十首 三','楊巨源','唐','唐诗','tang','','[]','雲陛臨黃道，天門在碧虛。',72,'全唐诗/poet.tang.17000.json','["雲陛臨黃道，天門在碧虛。", "大明含睿藻，元氣抱宸居。", "戈偃征苗後，詩傳宴鎬初。", "年華富仙苑，時哲滿公車。", "化入絪緼大，恩垂渙汗餘。", "悠然萬方靜，風俗揖華胥。"]'),
('2de91cae-cb48-44e4-9f7f-7559c2a47419','春日奉獻聖壽無疆詞十首 四','楊巨源','唐','唐诗','tang','','[]','玉漏飄青璅，金鋪麗紫宸。',72,'全唐诗/poet.tang.17000.json','["玉漏飄青璅，金鋪麗紫宸。", "雲山九門曙，天地一家春。", "瑞靄方呈賞，暄風本配仁。", "巖廊開鳳翼，水殿壓鼇身。", "文雅逢明代，歡娛及賤臣。", "年年未央闕，恩共物華新。"]'),
('6d22a64c-c978-4d39-b00b-f9998d2bdc37','春日奉獻聖壽無疆詞十首 五','楊巨源','唐','唐诗','tang','','[]','垂拱乾坤正，歡心品類同。',72,'全唐诗/poet.tang.17000.json','["垂拱乾坤正，歡心品類同。", "紫煙含北極，玄澤付東風。", "珠綴留晴景，金莖直曉空。", "發生資盛德，交泰讓全功。", "間氣登三事，祥光啓四聰。", "遐荒似川水，天外亦朝宗。"]'),
('36356bd0-5a81-457f-ba21-89aaabe9190a','春日奉獻聖壽無疆詞十首 六','楊巨源','唐','唐诗','tang','','[]','代是文明晝，春當宴喜時。',72,'全唐诗/poet.tang.17000.json','["代是文明晝，春當宴喜時。", "罏煙添柳重，宮漏出花遲。", "漢典方寬律，周官正採詩。", "碧宵傳鳳吹，紅旭在龍旗。", "造化膺神契，陽和沃聖思。", "無因隨百獸，率舞奉丹墀。"]'),
('ee05d7f0-55b0-446d-8624-13ac06f5e860','春日奉獻聖壽無疆詞十首 七','楊巨源','唐','唐诗','tang','','[]','睿德符玄化，芳情翊太和。',72,'全唐诗/poet.tang.17000.json','["睿德符玄化，芳情翊太和。", "日輪皇鑒遠，天仗聖朝多。", "曙色含金牓，晴光轉玉珂。", "中宮陳廣樂，元老進賡歌。", "蓮葉看龜上，桐花識鳳過。", "小臣空擊壤，滄海是恩波。"]'),
('02148c8b-5445-4c35-bf56-7787ccec972c','春日奉獻聖壽無疆詞十首 八','楊巨源','唐','唐诗','tang','','[]','物象朝高殿，簪裾溢上京。',72,'全唐诗/poet.tang.17000.json','["物象朝高殿，簪裾溢上京。", "春當九衢好，天向萬方明。", "樂報簫韶發，杯看沆瀣生。", "芙蓉丹闕暖，楊柳玉樓晴。", "閶闔開中禁，衣裳儼太清。", "南山同聖壽，長對鳳皇城。"]'),
('668e1376-fc01-490e-ab20-09b81e663792','春日奉獻聖壽無疆詞十首 九','楊巨源','唐','唐诗','tang','','[]','日上蒼龍闕，香含紫禁林。',72,'全唐诗/poet.tang.17000.json','["日上蒼龍闕，香含紫禁林。", "晴光五雲疊，春色九重深。", "賞叶元和德，文垂雅頌音。", "景雲隨御輦，顥氣在宸襟。", "永保無疆壽，長懷不戰心。", "聖朝多慶賜，瓊樹粉牆陰。"]'),
('eeeeeb98-2769-44bd-82b7-0efe63346c5c','春日奉獻聖壽無疆詞十首 十','楊巨源','唐','唐诗','tang','','[]','化洽生成遂，功宣動植知。',72,'全唐诗/poet.tang.17000.json','["化洽生成遂，功宣動植知。", "瑞凝三秀草，春入萬年枝。", "鳳掖嘉言進，鴛行喜氣隨。", "仗臨丹地近，衣對碧山垂。", "渥澤方柔遠，聰明本聽卑。", "願同東觀士，長對漢威儀。"]'),
('fa239c0f-618e-4907-bb00-c1bae5253bc5','銜魚翠鳥','楊巨源','唐','唐诗','tang','','[]','有意蓮葉間，瞥然下高樹。',24,'全唐诗/poet.tang.17000.json','["有意蓮葉間，瞥然下高樹。", "擘破得全魚，一點翠光去。"]'),
('2a5a1280-f6fe-4ef2-ab16-477a76e79235','和鄭相公尋宣上人不遇','楊巨源','唐','唐诗','tang','','[]','方尋蓮境去，又值竹房空。',24,'全唐诗/poet.tang.17000.json','["方尋蓮境去，又值竹房空。", "幾韻飄寒玉，餘清不在風。"]'),
('2acc5a00-860e-4556-b57c-c1067baaf226','題范陽金臺驛','楊巨源','唐','唐诗','tang','','[]','六國唯求客，千金遂築臺。',24,'全唐诗/poet.tang.17000.json','["六國唯求客，千金遂築臺。", "若令逢聖代，憔悴郭生回。"]'),
('6661c096-e1ec-4f32-837f-1083ff079269','寄薛侍御','楊巨源','唐','唐诗','tang','','[]','世上無窮事，生涯莫廢詩。',24,'全唐诗/poet.tang.17000.json','["世上無窮事，生涯莫廢詩。", "何曾好風月，不是憶君時。"]'),
('cf1004cf-3917-4820-9997-4a561ca0231f','賦得灞岸柳留辭鄭員外','楊巨源','唐','唐诗','tang','','[]','楊柳含煙灞岸春，年年攀折爲行人。',32,'全唐诗/poet.tang.17000.json','["楊柳含煙灞岸春，年年攀折爲行人。", "好風儻借低枝便，莫遣青絲掃路塵。"]'),
('e304a48f-1dae-47df-835b-ca5067182979','折楊柳','楊巨源','唐','唐诗','tang','','["\u6298\u67f3", "\u9001\u522b", "\u60dc\u522b"]','水邊楊柳麴塵絲，立馬煩君折一枝。',32,'全唐诗/poet.tang.17000.json','["水邊楊柳麴塵絲，立馬煩君折一枝。", "惟有春風最相惜，殷勤更向手中吹。"]'),
('274b344d-ab48-4980-bd2a-525fe00dda88','雪中聽箏','楊巨源','唐','唐诗','tang','','[]','玉柱泠泠對寒雪，清商怨徴聲何切。',32,'全唐诗/poet.tang.17000.json','["玉柱泠泠對寒雪，清商怨徴聲何切。", "誰憐楚客向隅時，一片愁心與弦絕。"]'),
('2835b1b4-eb6e-4f3e-863e-53eec479943a','盧龍塞行送韋掌記二首 一','楊巨源','唐','唐诗','tang','','[]','雨雪粉粉黑水外。',32,'全唐诗/poet.tang.17000.json','["雨雪粉粉黑水外。", "行人共指盧龍塞，萬里飛沙壓鼓鼙。", "三軍殺氣凝旌斾。"]'),
('f7a7d5b1-5027-499d-9dd2-324fbd10a08a','盧龍塞行送韋掌記二首 二','楊巨源','唐','唐诗','tang','','[]','陳琳書記本翩翩，料敵能兵奪酒泉。',32,'全唐诗/poet.tang.17000.json','["陳琳書記本翩翩，料敵能兵奪酒泉。", "聖主好文兼好武，封侯莫比漢皇年。"]'),
('5ab2021b-5249-46d6-9bc9-1b1d65ed1283','題五老峰下費君書院','楊巨源','唐','唐诗','tang','','[]','解向花間栽碧松，門前不負老人峰。',32,'全唐诗/poet.tang.17000.json','["解向花間栽碧松，門前不負老人峰。", "已將心事隨身隱，認得溪雲第幾重。"]'),
('e37713ed-c386-4d3e-80c0-b64cc30fc014','僧院聽琴','楊巨源','唐','唐诗','tang','','[]','禪思何妨在玉琴，真僧不見聽時心。',32,'全唐诗/poet.tang.17000.json','["禪思何妨在玉琴，真僧不見聽時心。", "離聲怨調秋堂夕，雲向蒼梧湘水深。"]'),
('5f07c371-ee22-44c7-9c3a-9afa1bb028bf','和武相公春曉聞鶯','楊巨源','唐','唐诗','tang','','[]','語恨飛遲天欲明，殷勤似訴有餘情。',32,'全唐诗/poet.tang.17000.json','["語恨飛遲天欲明，殷勤似訴有餘情。", "仁風已及芳菲節，猶向花溪鳴幾聲。"]'),
('579c6c7f-d7c9-4926-9fa1-bec76cbd30d8','唐昌觀玉蘂花','楊巨源','唐','唐诗','tang','','[]','晴空素豔照霞新，香灑天風不到塵。',32,'全唐诗/poet.tang.17000.json','["晴空素豔照霞新，香灑天風不到塵。", "持贈昔聞將白雪，蘂珠宮上玉花春。"]'),
('e132d470-4f32-4fcb-b4d8-2cd75f95ae17','山中主人','楊巨源','唐','唐诗','tang','','[]','十里青山有一家，翠屏深處更添霞。',32,'全唐诗/poet.tang.17000.json','["十里青山有一家，翠屏深處更添霞。", "若爲說得溪中事，錦石和煙四面花。"]'),
('4ec62cc0-90c2-4aa3-9f82-391697829fd6','太原贈李屬侍御','楊巨源','唐','唐诗','tang','','[]','路入桑乾塞鴈飛，棗郎年少有光輝。',32,'全唐诗/poet.tang.17000.json','["路入桑乾塞鴈飛，棗郎年少有光輝。", "春風走馬三千里，不廢看花君繡衣。"]'),
('3247080d-bd0e-4e72-8419-1b94416972cc','崔娘詩','楊巨源','唐','唐诗','tang','','[]','清潤潘郎玉不如，中庭蕙草雪消初。',32,'全唐诗/poet.tang.17000.json','["清潤潘郎玉不如，中庭蕙草雪消初。", "風流才子多春思，腸斷蕭娘一紙書。"]'),
('8803af85-ca60-49fd-a3d6-2e9154ff885c','題雲師山房','楊巨源','唐','唐诗','tang','','[]','雲公蘭若深山裏，月明松殿微風起。',32,'全唐诗/poet.tang.17000.json','["雲公蘭若深山裏，月明松殿微風起。", "試問空門清淨心，蓮花不著秋潭水。"]'),
('15cb1b7c-d295-49e3-a1a8-e596d5add553','城東早春','楊巨源','唐','唐诗','tang','','["\u54f2\u7406", "\u6625\u5929", "\u5199\u666f"]','詩家清景在新春，綠柳纔黃半未勻。',32,'全唐诗/poet.tang.17000.json','["詩家清景在新春，綠柳纔黃半未勻。", "若待上林花似錦，出門俱是看花人。"]'),
('704bd164-4532-4515-8864-ec2233553d87','秋日登亭贈薛侍御','楊巨源','唐','唐诗','tang','','[]','潦倒從軍何取益，東西走馬暫同遊。',32,'全唐诗/poet.tang.17000.json','["潦倒從軍何取益，東西走馬暫同遊。", "梁王舊客皆能賦，今日因何獨怨秋。"]'),
('d01527bb-853e-44cc-9676-62b63e635774','石水詞二首 一','楊巨源','唐','唐诗','tang','','[]','銀罌深鏁貯清光，無限來人不得嘗。',32,'全唐诗/poet.tang.17000.json','["銀罌深鏁貯清光，無限來人不得嘗。", "知共金丹爭氣力，一杯全勝五雲漿。"]'),
('eb271943-c601-4207-8b5a-c3ac170c1569','石水詞二首 二','楊巨源','唐','唐诗','tang','','[]','山叟和雲斸翠屏，煎時分日檢仙經。',32,'全唐诗/poet.tang.17000.json','["山叟和雲斸翠屏，煎時分日檢仙經。", "天人持此扶衰病，勝得瑤池水一瓶。"]'),
('e8db7a58-9ef1-40fa-ac91-fea395888ba1','荅振武李逢吉判官','楊巨源','唐','唐诗','tang','','[]','近來時輩都無興，把酒皆言肺病同。',32,'全唐诗/poet.tang.17000.json','["近來時輩都無興，把酒皆言肺病同。", "唯有單于李評事，不將華髮負春風。"]'),
('a640ca36-8003-477d-baf9-1e306c257a20','宮燕詞','楊巨源','唐','唐诗','tang','','[]','毛衣似錦語如弦，日煖爭高綺陌天。',32,'全唐诗/poet.tang.17000.json','["毛衣似錦語如弦，日煖爭高綺陌天。", "幾處野花留不得，雙雙飛向御爐前。"]'),
('172c8af8-df46-4fe3-93fa-f6aacfc8a355','贈崔駙馬','楊巨源','唐','唐诗','tang','','[]','百尺梧桐畫閣齊，簫聲落處翠雲低。',32,'全唐诗/poet.tang.17000.json','["百尺梧桐畫閣齊，簫聲落處翠雲低。", "平陽不惜黃金埒，細雨花驄踏作泥。"]'),
('5c50fb26-2ba6-46ba-9cef-a5248f262832','聽李憑彈箜篌二首 一','楊巨源','唐','唐诗','tang','','[]','聽奏繁弦玉殿清，風傳曲度禁林明。',32,'全唐诗/poet.tang.17000.json','["聽奏繁弦玉殿清，風傳曲度禁林明。", "君王聽樂棃園煖，翻到雲門第幾聲。"]'),
('84e2b526-43e6-4cf6-8f4d-2124b5583bac','聽李憑彈箜篌二首 二','楊巨源','唐','唐诗','tang','','[]','花咽嬌鶯玉漱泉，名高半在御筵前。',32,'全唐诗/poet.tang.17000.json','["花咽嬌鶯玉漱泉，名高半在御筵前。", "漢王欲助人間樂，從遣新聲墜九天。"]'),
('a76e6729-3841-4964-a0c5-dfe57469922e','臨水看花','楊巨源','唐','唐诗','tang','','[]','一樹紅花暎綠波，晴明騎馬好經過。',32,'全唐诗/poet.tang.17000.json','["一樹紅花暎綠波，晴明騎馬好經過。", "今朝幾許風吹落，聞道蕭郎最惜多。"]'),
('dc77b7b9-f1ae-4a47-9a43-1d72471a1c10','觀妓人入道二首 一','楊巨源','唐','唐诗','tang','','[]','荀令歌鐘北里亭，翠娥紅粉敞雲屏。',32,'全唐诗/poet.tang.17000.json','["荀令歌鐘北里亭，翠娥紅粉敞雲屏。", "舞衣施盡餘香在，今日花前學誦經。"]'),
('794028d7-8844-447d-9d0d-f5d14ccf06a4','觀妓人入道二首 二','楊巨源','唐','唐诗','tang','','[]','碧玉芳年事冠軍，清歌空得隔花聞。',32,'全唐诗/poet.tang.17000.json','["碧玉芳年事冠軍，清歌空得隔花聞。", "春來削髮芙蓉寺，蟬鬢臨風墮綠雲。"]'),
('ac2180be-799b-4116-b6f8-6d0501572a38','方城驛逢孟侍御','楊巨源','唐','唐诗','tang','','[]','走馬溫湯直隼飛，相逢矍鑠理征衣。',32,'全唐诗/poet.tang.17000.json','["走馬溫湯直隼飛，相逢矍鑠理征衣。", "軍中得力兒男事，入驛從容見落暉。"]'),
('d55ccd0b-3c31-4426-a9e4-d1af082bd642','題清涼寺','楊巨源','唐','唐诗','tang','','[]','憑檻霏微松樹煙，陶潛曾用道林錢。',32,'全唐诗/poet.tang.17000.json','["憑檻霏微松樹煙，陶潛曾用道林錢。", "一聲寒磬空心曉，花雨知從第幾天。"]'),
('fa9bde41-de31-4a73-8589-c923ae74ed10','酬令狐舍人','楊巨源','唐','唐诗','tang','','[]','曉禁蒼蒼換直還，暫低鸞翼向人間。',32,'全唐诗/poet.tang.17000.json','["曉禁蒼蒼換直還，暫低鸞翼向人間。", "亦知受業公門事，數仞丘牆不見山。"]'),
('36c04e97-8fb5-42bc-b123-fd4aa108f884','和令狐郎中','楊巨源','唐','唐诗','tang','','[]','題詩一代占清機，秉筆三年直紫微。',32,'全唐诗/poet.tang.17000.json','["題詩一代占清機，秉筆三年直紫微。", "自稟道情齠齓異，不同蘧玉學知非。"]'),
('5bd3f70d-8d74-4f43-b562-60e42970e500','美人春怨','楊巨源','唐','唐诗','tang','','[]','妾家巫峽陽，羅幌寢蘭堂。',48,'全唐诗/poet.tang.17000.json','["妾家巫峽陽，羅幌寢蘭堂。", "曉日臨窗久，春風引夢長。", "落釵仍挂鬢，微汗欲銷黃。", "縱便朦朧覺，魂猶逐楚王。"]'),
('6b2ae326-c8b4-4224-8cc2-11beebbd941b','豔女詞','楊巨源','唐','唐诗','tang','','[]','露井桃花發，雙雙燕並飛。',48,'全唐诗/poet.tang.17000.json','["露井桃花發，雙雙燕並飛。", "美人姿態裏，春色上羅衣。", "自愛頻開鏡，時羞欲掩扉。", "心知行路客，遙惹五香歸。"]'),
('d5e0c4a8-2946-45c7-96ac-3a99370a9b55','名姝詠','楊巨源','唐','唐诗','tang','','[]','阿嬌年未多，體弱性能和。',48,'全唐诗/poet.tang.17000.json','["阿嬌年未多，體弱性能和。", "怕重愁拈鏡，憐輕喜曳羅。", "臨津雙洛浦，對月兩嫦娥。", "獨有荆王殿，時時暮雨過。"]'),
('afdbc718-fc07-45f8-8d16-c292396e6b7d','送太和公主和蕃','楊巨源','唐','唐诗','tang','','[]','北路古來難，年光獨認寒。',48,'全唐诗/poet.tang.17000.json','["北路古來難，年光獨認寒。", "朔雲侵鬢起，邊月向眉殘。", "蘆井尋沙到，花門度磧看。", "薰風一萬里，來處是長安。"]'),
('4bd37eb1-7e6a-40c7-87d4-339753904fbe','秋日韋少府廳池上詠石','楊巨源','唐','唐诗','tang','','[]','主人得幽石，日覺公堂清。',48,'全唐诗/poet.tang.17000.json','["主人得幽石，日覺公堂清。", "一片池上色，孤峰雲外情。", "舊溪紅蘚在，秋水綠痕生。", "何必澄湖徹，移來有令名。"]'),
('d0d4bf68-5b1c-4645-a7db-1054b921c7dd','失題','楊巨源','唐','唐诗','tang','','[]','何事慰朝夕，不踰詩酒情。',48,'全唐诗/poet.tang.17000.json','["何事慰朝夕，不踰詩酒情。", "山河空道路，蕃漢共刀兵。", "禮樂新朝市，園林舊弟兄。", "向風一點淚，塞晚暮江平。"]'),
('f076e777-de3d-4c3f-bd69-5aac890e9ab8','春日題龍門香山寺','楊巨源','唐','唐诗','tang','','[]','衆香天上梵王宮，鐘磬寥寥半碧空。',64,'全唐诗/poet.tang.17000.json','["衆香天上梵王宮，鐘磬寥寥半碧空。", "清景乍開松嶺月，亂流長響石樓風。", "山河杳映春雲外，城闕參差曉樹中。", "欲盡出尋那可得，三千世界本無窮。"]'),
('a8add04a-83cc-4e89-a9b8-85a61071cf7b','寄申州盧拱使君','楊巨源','唐','唐诗','tang','','[]','領郡仍聞總虎貔，致身還是見男兒。',64,'全唐诗/poet.tang.17000.json','["領郡仍聞總虎貔，致身還是見男兒。", "小船隔水催桃葉，大鼓當風舞柘枝。", "酒坐微酣諸客倒，毬場慢撥幾人隨。", "從來樂事憎詩苦，莫放窗中遠岫知。"]'),
('8c9bb358-89d9-4880-92db-57b0b9da5084','郊居秋日酬奚贊府見寄','楊巨源','唐','唐诗','tang','','[]','繁菊照深居，芳香春不如。',96,'全唐诗/poet.tang.17000.json','["繁菊照深居，芳香春不如。", "聞尋周觸士，知伴庾尚書。", "日晚汀洲曠，天晴草木疎。", "閑言揮麈柄，清步掩蝸廬。", "野老能親牧，高人念遠漁。", "幽叢臨古岸，輕葉度寒渠。", "暮色無狂蝶，秋華有嫩蔬。", "若爲酬郢曲，從此愧璠璵。"]'),
('2ba7943e-8d62-4fe0-97c1-546431f6a3c5','聖恩洗雪鎮州寄獻裴相公','楊巨源','唐','唐诗','tang','','[]','天借春光洗綠林，戰塵收盡見花陰。',64,'全唐诗/poet.tang.17000.json','["天借春光洗綠林，戰塵收盡見花陰。", "好生本是君王德，忍死何妨壯士心。", "曾賀截雲翻柵遠，仍聞劚凍下營深。", "井陘昨日雙旗入，蕭相無言淚濕襟。"]'),
('4b9d7ccd-0943-4e41-9146-6df9d2e7870e','賀田僕射子弟榮拜金吾','楊巨源','唐','唐诗','tang','','[]','五侯恩澤不同年，叔姪朱門䂍矟連。',64,'全唐诗/poet.tang.17000.json','["五侯恩澤不同年，叔姪朱門䂍矟連。", "鳳沼九重相喜氣，鴈行一半入祥煙。", "街衢燭影侵寒月，文武珂聲疊曉天。", "爲數麒麟高閣上，誰家父子勒燕然。"]'),
('bb2710f0-6afb-4c19-a1f4-634e6378d655','和裴舍人觀田尚書出獵','楊巨源','唐','唐诗','tang','','[]','聖代司空比玉清，雄藩觀獵見皇情。',64,'全唐诗/poet.tang.17000.json','["聖代司空比玉清，雄藩觀獵見皇情。", "雲禽已覺高無益，霜兔應知狡不成。", "飛鞚擁塵寒草盡，彎弓開月朔風生。", "今朝始賀將軍貴，紫禁詩人看斾旌。"]'),
('11dc4672-dfe8-40b0-97e2-419133063297','送李舍人歸蘭陵里','楊巨源','唐','唐诗','tang','','[]','清詞舉世皆藏篋，美酒當山爲滿罇。',64,'全唐诗/poet.tang.17000.json','["清詞舉世皆藏篋，美酒當山爲滿罇。", "三畝嫩蔬臨綺陌，四行高樹擁朱門。", "家貧境勝心無累，名重官閑口不論。", "惟有道情常自足，啓期天地易知恩。"]'),
('40155463-e840-4235-a854-1150a58cd190','同太常尉遲博士闕下待漏','楊巨源','唐','唐诗','tang','','[]','沈沈延閣抱丹墀，松色苔花顥露滋。',64,'全唐诗/poet.tang.17000.json','["沈沈延閣抱丹墀，松色苔花顥露滋。", "爽氣曉來青玉甃，薰風宿在翠花旗。", "方瞻御陌三條廣，猶覺仙門一刻遲。", "此地含香從白首，馮唐何事怨明時。"]'),
('05f0715e-52e0-460b-958f-2349f14154c7','見薛侍御戴不損裹帽子因贈','楊巨源','唐','唐诗','tang','','[]','潘郎對青鏡，烏帽似新裁。',72,'全唐诗/poet.tang.17000.json','["潘郎對青鏡，烏帽似新裁。", "曉露鴉初洗，春荷葉半開。", "堪將護巾櫛，不獨隔塵埃。", "已見籠蟬翼，無因映鹿胎。", "何人呈巧思，好手自西來。", "有意憐衰醜，煩君致一枚。"]'),
('04fc2f75-917c-414d-af2f-e3dfe04fdaae','胡二十拜戶部兼判度支','楊巨源','唐','唐诗','tang','','[]','清機果被公材撓，雄拜知承聖主恩。',64,'全唐诗/poet.tang.17000.json','["清機果被公材撓，雄拜知承聖主恩。", "廟略已調天府實，國征方覺地官尊。", "徒言玉節將分閫，定是沙隄欲到門。", "爲愛山前新卜第，不妨風月事琴罇。"]'),
('32e7e766-c424-4232-8188-8f65fdceead0','元日呈李逢吉舍人','楊巨源','唐','唐诗','tang','','[]','華夷文物賀新年，霜仗遙排鳳闕前。',64,'全唐诗/poet.tang.17000.json','["華夷文物賀新年，霜仗遙排鳳闕前。", "一片彩霞迎曙日，萬條紅燭動春天。", "稱觴山色和元氣，端冕爐香疊瑞煙。", "共說正初當聖澤，試過西掖問羣賢。"]'),
('cb4fd2ed-c987-4317-af07-59ba076ea2a1','和杜中丞西禪院看花','楊巨源','唐','唐诗','tang','','[]','一林堆錦映千燈，照眼牽情欲不勝。',128,'全唐诗/poet.tang.17000.json','["一林堆錦映千燈，照眼牽情欲不勝。", "知倚晴明嬌自足，解將顏色醉相仍。", "好風輕引香煙入，甘露纔和粉豔凝。", "深處最憐鶯蹂踐，嬾時先被蝶侵凌。", "對持真境應無取，分付空門又未能。", "迎日似翻紅燒斷，臨流疑映綺霞層。", "幽含晚態憐丹桂，盛績春光識紫藤。", "每到花枝獨惆悵，山東惟有杜中丞。"]'),
('39698dc7-0888-4fa9-9972-56430754c3f5','句','楊巨源','唐','唐诗','tang','','[]','三刀夢益州，一箭取遼城。',24,'全唐诗/poet.tang.17000.json','["三刀夢益州，一箭取遼城。", "伊陟無聞祖，韋賢不到孫。"]'),
('470907da-027c-466a-bf33-15db8d8377a1','夏至日衡陽郡齋書懷','令狐楚','唐','唐诗','tang','','[]','一來江城守，七見江月圓。',60,'全唐诗/poet.tang.17000.json','["一來江城守，七見江月圓。", "齒髮將六十，鄉關越三千。", "褰帷罕遊觀，閉閤多沉眠。", "新節還復至，故交盡相捐。", "何時羾閶闔，上訴高高天。"]'),
('73f537b4-febf-4032-8737-e1be2e1f681f','八月十七日夜書懷','令狐楚','唐','唐诗','tang','','[]','三五既不留，二八又還過。',60,'全唐诗/poet.tang.17000.json','["三五既不留，二八又還過。", "金蟾著未出，玉樹悲稍破。", "誰向西園遊，空歸北堂臥。", "佳期信難得，永夕無可奈。", "撫枕獨高歌，煩君爲予和。"]'),
('67f144e3-8928-46c7-b95f-168c6a2657c7','九日言懷','令狐楚','唐','唐诗','tang','','[]','二九即重陽，天清野菊黃。',48,'全唐诗/poet.tang.17000.json','["二九即重陽，天清野菊黃。", "近來逢此日，多是在他鄉。", "晚色霞千片，秋聲鴈一行。", "不能高處望，恐斷老人腸。"]'),
('3c33f395-b5aa-47d5-aff5-6480bce2df80','和寄竇七中丞','令狐楚','唐','唐诗','tang','','[]','仙吏秦峨別，新詩鄂渚來。',48,'全唐诗/poet.tang.17000.json','["仙吏秦峨別，新詩鄂渚來。", "才推今北斗，職賦舊三台。", "雕鏤心偏許，緘封手自開。", "何年相贈荅，却得到中臺。"]'),
('826794a6-84fd-43a1-af20-4375d0839e35','立秋日悲懷','令狐楚','唐','唐诗','tang','','[]','清曉上高臺，秋風今日來。',48,'全唐诗/poet.tang.17000.json','["清曉上高臺，秋風今日來。", "又添新節恨，猶抱故年哀。", "淚豈揮能盡，泉終閉不開。", "更傷春月過，私服示無縗。"]'),
('a0a6f0fe-e5dd-43f8-85ea-36d6f915f584','秋懷寄錢侍郎','令狐楚','唐','唐诗','tang','','[]','晚歲俱爲郡，新秋各異鄉。',48,'全唐诗/poet.tang.17000.json','["晚歲俱爲郡，新秋各異鄉。", "燕鴻一聲呌，郢樹盡青蒼。", "山霞侵衣潤，江風捲簟涼。", "相思如漢水，日夜向潯陽。"]'),
('42ee9d0e-3e52-42f6-9776-4bafea4d2bf6','立秋日','令狐楚','唐','唐诗','tang','','[]','平日本多恨，新秋偏易悲。',48,'全唐诗/poet.tang.17000.json','["平日本多恨，新秋偏易悲。", "燕詞如惜別，柳意已呈衰。", "事國終無補，還家未有期。", "心中舊氣味，苦校去年時。"]'),
('1124628e-1cfc-4f5a-86d7-be07cb307e73','贈毛仙翁','令狐楚','唐','唐诗','tang','','[]','宣州渾是上清宮，客有真人貌似童。',64,'全唐诗/poet.tang.17000.json','["宣州渾是上清宮，客有真人貌似童。", "紺髮垂纓光髧髧，細髯緣頷綠茸茸。", "壺中藥物梯霞訣，肘後方書縮地功。", "既許焚香爲弟子，願敎年紀共椿同。"]'),
('791da1d7-ca84-47fa-aa2a-fda1635a2f79','遊義興寺寄上李逢吉相公','令狐楚','唐','唐诗','tang','','[]','柳營無事詣蓮宮，步步猶疑是夢中。',64,'全唐诗/poet.tang.17000.json','["柳營無事詣蓮宮，步步猶疑是夢中。", "勞役徒爲萬夫長，閑遊曾與二人同。", "鳳鸞飛去仙巢在，龍象潛來講席空。", "松下花飛頻佇立，一心千里憶梁公。"]'),
('bca74224-6f2d-4d98-8513-f79c95596188','遊晉祠上李逢吉相公','令狐楚','唐','唐诗','tang','','[]','不立晉祠三十年，白頭重到一淒然。',64,'全唐诗/poet.tang.17000.json','["不立晉祠三十年，白頭重到一淒然。", "泉聲自昔鏘寒玉，草色雖秋耀翠鈿。", "少壯同遊寧有數，尊榮再會便無緣。", "相思臨水下雙淚，寄入幷汾向洛川。"]'),
('435ff308-9160-4964-96ad-0eaa26fa8258','節度宣武酬樂天夢得','令狐楚','唐','唐诗','tang','','[]','蓬萊仙監客曹郎，曾枉高車客大梁。',64,'全唐诗/poet.tang.17000.json','["蓬萊仙監客曹郎，曾枉高車客大梁。", "見擁旌旄治軍旅，知親筆硯事文章。", "愁看柳色懸離恨，憶遞花枝助酒狂。", "洛下相逢肯相寄，南金璀錯玉淒涼。"]'),
('c38714c1-2218-4035-8026-d433f8b9d34f','奉和嚴司空重陽日同崔常侍崔郎及諸公登龍山落帽臺佳宴','令狐楚','唐','唐诗','tang','','[]','謝公秋思渺天涯，蠟屐登高爲菊花。',64,'全唐诗/poet.tang.17000.json','["謝公秋思渺天涯，蠟屐登高爲菊花。", "貴重近臣光綺席，笑憐從事落烏紗。", "萸房暗綻紅珠朵，茗碗寒供白露芽。", "詠碎龍山歸出號，馬奔流電妓奔車。"]'),
('4bd43eca-d6ea-45f6-9cda-7baa44bbe426','立春後言懷招汴州李匡衙推','令狐楚','唐','唐诗','tang','','[]','閑齋夜擊唾壺歌，試望夷門奈遠何。',64,'全唐诗/poet.tang.17000.json','["閑齋夜擊唾壺歌，試望夷門奈遠何。", "每聽塞笳離夢斷，時窺清鑑旅愁多。", "初驚宵漏丁丁促，已覺春風習習和。", "海內故人君最老，花開鞭馬更相過。"]'),
('5092435e-edbc-4702-8493-d938128db1ee','奉和僕射相公酬忠武李相公見寄之作','令狐楚','唐','唐诗','tang','','[]','麗藻飛來自相庭，五文相錯八音清。',64,'全唐诗/poet.tang.17000.json','["麗藻飛來自相庭，五文相錯八音清。", "初瞻綺色連霞色，又聽金聲繼玉聲。", "才出山西文與武，歡從塞北弟兼兄。", "白頭老尹三川上，雙和陽春喜復驚。"]'),
('cf912dac-30ed-4f16-a951-ddecd90387ed','郡齋左偏栽竹百餘竿炎涼已周青翠不改而爲墻垣所蔽有乖愛賞假日命去齋居之東墻由是俯臨軒階低映帷戶日夕相對頗有翛然之趣','令狐楚','唐','唐诗','tang','','[]','齋居栽竹北窗邊，素壁新開映碧鮮。',64,'全唐诗/poet.tang.17000.json','["齋居栽竹北窗邊，素壁新開映碧鮮。", "青藹近當行藥處，綠陰深到臥帷前。", "風驚曉葉如聞雨，月過春枝似帶煙。", "老子憶山心暫緩，退公閑坐對嬋娟。"]'),
('4919ada6-5b90-4a82-9cec-81b67f64c524','省中直夜對雪寄李師素侍郎','令狐楚','唐','唐诗','tang','','[]','密雪紛初降，重城杳未開。',144,'全唐诗/poet.tang.17000.json','["密雪紛初降，重城杳未開。", "雜花飛爛熳，連蝶舞徘徊。", "灑散千株葉，銷凝九陌埃。", "素華凝粉署，清氣繞霜臺。", "明覺侵窗積，寒知度塞來。", "謝家爭擬絮，越嶺悞驚梅。", "暗魄微茫照，嚴飆次第催。", "稍封黃竹亞，先集紫蘭摧。", "孫室臨書幌，梁園泛酒杯。", "靜懷瓊樹倚，醉憶玉山頹。", "翠陌飢烏噪，蒼雲遠鴈哀。", "此時方夜直，想望意悠哉。"]'),
('d5232b91-25fb-4ebf-ab67-e96902f4376a','南宮夜直宿見李給事封題其所下制敕知奏直在東省因以詩寄','令狐楚','唐','唐诗','tang','','[]','番直同遙夜，嚴扃限幾重。',96,'全唐诗/poet.tang.17000.json','["番直同遙夜，嚴扃限幾重。", "青編書白雀，黃紙降蒼龍。", "北極絲綸句，東垣翰墨蹤。", "尚垂玄露點，猶濕紫泥封。", "炫眼凝仙燭，馳心裊禁鍾。", "定應形夢寐，暫似接音容。", "玉樹春枝動，金樽臘釀醲。", "在朝君最舊，休澣許過從。"]'),
('2e5a9fc9-3055-486a-8eb4-4c641670a93b','將赴洛下旅次漢南獻上相公二十兄言懷八韻','令狐楚','唐','唐诗','tang','','[]','台室名曾繼，旌門節暫過。',96,'全唐诗/poet.tang.17000.json','["台室名曾繼，旌門節暫過。", "歡情老去少，苦事別離多。", "便爲開樽俎，應憐出網羅。", "百憂今已失，一醉孰知他。", "帝德千年日，君恩萬里波。", "許隨黃綺輩，閑唱紫芝歌。", "龍衮期重補，梅羹佇再和。", "嵩丘來攜手，君子意如何。"]'),
('f03a6855-e60d-4b75-8881-e59ea03599a7','青雲干呂','令狐楚','唐','唐诗','tang','','[]','郁郁復紛紛，青霄干呂雲。',72,'全唐诗/poet.tang.17000.json','["郁郁復紛紛，青霄干呂雲。", "色令天下見，候向管中分。", "遠覆無人境，遙彰有德君。", "瑞容驚不散，冥感信稀聞。", "湛露羞依草，南風耻帶薰。", "恭惟漢武帝，餘烈尚氛氳。"]'),
('9656e10f-301d-40c1-86a9-54ce992f86cb','聖明樂','令狐楚','唐','唐诗','tang','','[]','海浪恬丹徼，邊塵靜異山。',24,'全唐诗/poet.tang.17000.json','["海浪恬丹徼，邊塵靜異山。", "從今萬里外，不復鎖蕭關。"]'),
('e320cbef-225b-4d78-a2e9-ac02e9a092aa','春閨思','令狐楚','唐','唐诗','tang','','[]','戴勝飛晴野，凌澌下濁河。',24,'全唐诗/poet.tang.17000.json','["戴勝飛晴野，凌澌下濁河。", "春風樓上望，誰見淚痕多。"]'),
('b7f0ad38-9713-4ae2-8697-c04a1429bbef','宮中樂五首 一','令狐楚','唐','唐诗','tang','','[]','楚塞金陵靖，巴山玉壘空。',24,'全唐诗/poet.tang.17000.json','["楚塞金陵靖，巴山玉壘空。", "萬方無一事，端拱大明宮。"]'),
('5b8245c6-adaa-49cf-a1ce-9037c01a4311','宮中樂五首 二','令狐楚','唐','唐诗','tang','','[]','雪霽長楊苑，冰開太液池。',24,'全唐诗/poet.tang.17000.json','["雪霽長楊苑，冰開太液池。", "宮中行樂日，天下盛明時。"]'),
('86676d89-8a49-49c5-a5e4-a72a260eb0be','宮中樂五首 三','令狐楚','唐','唐诗','tang','','[]','柳色煙相似，梨花雪不如。',24,'全唐诗/poet.tang.17000.json','["柳色煙相似，梨花雪不如。", "春風真有意，一一麗皇居。"]'),
('83e4c143-6765-4a3b-941a-20af4e623317','宮中樂五首 四','令狐楚','唐','唐诗','tang','','[]','月上宮花靜，煙含苑樹深。',24,'全唐诗/poet.tang.17000.json','["月上宮花靜，煙含苑樹深。", "銀臺門已閉，仙漏夜沉沉。"]'),
('9d78410c-e75c-4af5-8729-4a8ebe0891a7','宮中樂五首 五','令狐楚','唐','唐诗','tang','','[]','九重青瑣闥，百尺碧雲樓。',24,'全唐诗/poet.tang.17000.json','["九重青瑣闥，百尺碧雲樓。", "明月秋風起，珠簾上玉鉤。"]'),
('1d221d17-e090-435c-9745-7299f5c27efa','春遊曲三首 一','令狐楚','唐','唐诗','tang','','[]','曉遊臨碧殿，日上望春亭。',24,'全唐诗/poet.tang.17000.json','["曉遊臨碧殿，日上望春亭。", "芳樹羅仙仗，晴山展翠屏。"]'),
('21ed4fe8-65f1-4c6c-b812-749768b549af','春遊曲三首 二','令狐楚','唐','唐诗','tang','','[]','一夜好風吹，新花一萬枝。',24,'全唐诗/poet.tang.17000.json','["一夜好風吹，新花一萬枝。", "風前調玉管，花下簇金羈。"]'),
('fdd140eb-32ee-4ae9-b073-5ee77ef21123','春遊曲三首 三','令狐楚','唐','唐诗','tang','','[]','閶闔春風起，蓬萊雪水消。',24,'全唐诗/poet.tang.17000.json','["閶闔春風起，蓬萊雪水消。", "相將折楊柳，爭取最長條。"]'),
('1d7d1b5d-eb29-43d5-b118-4f67e94b5fac','遠別離二首 一','令狐楚','唐','唐诗','tang','','[]','楊柳黃金穗，梧桐碧玉枝。',24,'全唐诗/poet.tang.17000.json','["楊柳黃金穗，梧桐碧玉枝。", "春來消息斷，早晚是歸期。"]'),
('e7a8d208-1c29-42c8-9702-3409395028be','遠別離二首 二','令狐楚','唐','唐诗','tang','','[]','玳織鴛鴦履，金裝翡翠篸。',24,'全唐诗/poet.tang.17000.json','["玳織鴛鴦履，金裝翡翠篸。", "畏人相問著，不擬到城南。"]'),
('f9902f83-33d4-426e-abe1-7599b7213602','閨人贈遠二首 一','令狐楚','唐','唐诗','tang','','[]','君行登隴上，妾夢在閨中。',24,'全唐诗/poet.tang.17000.json','["君行登隴上，妾夢在閨中。", "玉筯千行落，銀牀一半空。"]'),
('8d7c97b7-554f-41c8-8bda-4905568bff87','閨人贈遠二首 二','令狐楚','唐','唐诗','tang','','[]','綺席春眠覺，紗窗曉望迷。',24,'全唐诗/poet.tang.17000.json','["綺席春眠覺，紗窗曉望迷。", "朦朧殘夢裏，猶自在遼西。"]'),
('61881aae-99b0-421a-9e40-461b5577bdd0','從軍詞五首 一','令狐楚','唐','唐诗','tang','','[]','荒雞隔水啼，汗馬逐風嘶。',24,'全唐诗/poet.tang.17000.json','["荒雞隔水啼，汗馬逐風嘶。", "終日隨征斾，何時罷鼓鼙。"]'),
('4ac3a05c-e82c-4618-ba14-baa5e81fb52a','從軍詞五首 二','令狐楚','唐','唐诗','tang','','[]','孤心眠夜雪，滿眼是秋沙。',24,'全唐诗/poet.tang.17000.json','["孤心眠夜雪，滿眼是秋沙。", "萬里猶防塞，三年不見家。"]'),
('d18e1018-c4c2-43e6-9d84-59d72479ba32','從軍詞五首 三','令狐楚','唐','唐诗','tang','','[]','却望冰河闊，前登雪嶺高。',24,'全唐诗/poet.tang.17000.json','["却望冰河闊，前登雪嶺高。", "征人幾多在，又擬戰臨洮。"]'),
('5d27bc90-4397-414b-838b-351dae2db9e0','從軍詞五首 四','令狐楚','唐','唐诗','tang','','[]','胡風千里驚，漢月五更明。',24,'全唐诗/poet.tang.17000.json','["胡風千里驚，漢月五更明。", "縱有還家夢，猶聞出塞聲。"]'),
('5957c111-ca5d-4fd9-bb2a-2bbeb2c999ec','從軍詞五首 五','令狐楚','唐','唐诗','tang','','[]','暮雪連青海，陰霞覆白山。',24,'全唐诗/poet.tang.17000.json','["暮雪連青海，陰霞覆白山。", "可憐班定遠，生入玉門關。"]'),
('7f035b62-bdd6-43fd-a6bf-0ddd1152974d','思君恩','令狐楚','唐','唐诗','tang','','[]','小苑鶯歌歇，長門蝶舞多。',24,'全唐诗/poet.tang.17000.json','["小苑鶯歌歇，長門蝶舞多。", "眼看春又去，翠輦不經過。"]'),
('fcb5eda2-fc75-45ba-9688-78a84da4765c','王昭君','令狐楚','唐','唐诗','tang','','[]','錦車天外去，毳幕雪中開。',24,'全唐诗/poet.tang.17000.json','["錦車天外去，毳幕雪中開。", "魏闕蒼龍遠，蕭關赤鴈哀。"]'),
('06dc389e-07c6-4cb8-b989-01f814d70569','發潭州寄李寧常侍','令狐楚','唐','唐诗','tang','','[]','君今侍紫垣，我已墮青天。',48,'全唐诗/poet.tang.17000.json','["君今侍紫垣，我已墮青天。", "委廢從茲日，旋歸在幾年。", "心爲西靡樹，眼是北流泉。", "更過長沙去，江風滿驛船。"]'),
('71241dbb-d128-4c4f-ad76-6ab8d2a25659','李相薨後題斷金集','令狐楚','唐','唐诗','tang','','[]','一覽斷金集，載悲埋玉人。',24,'全唐诗/poet.tang.17000.json','["一覽斷金集，載悲埋玉人。", "牙弦千古絕，珠淚萬行新。"]'),
('dc298162-a2f5-4294-83ac-d9d4802324ed','年少行四首 一','令狐楚','唐','唐诗','tang','','[]','少小邊州慣放狂，驏騎蕃馬射黃羊。',32,'全唐诗/poet.tang.17000.json','["少小邊州慣放狂，驏騎蕃馬射黃羊。", "如今年老無筋力，猶倚營門數鴈行。"]'),
('3d99244c-884a-4fdb-8e5e-1f28f4916dd3','年少行四首 二','令狐楚','唐','唐诗','tang','','[]','家本清河住五城，須憑弓箭得功名。',32,'全唐诗/poet.tang.17000.json','["家本清河住五城，須憑弓箭得功名。", "等閑飛鞚秋原上，獨向寒雲試射聲。"]'),
('63ff323f-75cb-4c3b-9b10-7a6581ef3f6f','年少行四首 三','令狐楚','唐','唐诗','tang','','["\u7231\u56fd", "\u51fa\u5f81", "\u58ee\u5fd7"]','弓背霞明劒照霜，秋風走馬出咸陽。',32,'全唐诗/poet.tang.17000.json','["弓背霞明劒照霜，秋風走馬出咸陽。", "未收天子河湟地，不擬回頭望故鄉。"]'),
('1186edbd-673b-4513-8940-d72170efa4d3','年少行四首 四','令狐楚','唐','唐诗','tang','','[]','霜滿中庭月滿樓，金樽玉柱對清秋。',32,'全唐诗/poet.tang.17000.json','["霜滿中庭月滿樓，金樽玉柱對清秋。", "當年稱意須行樂，不到天明不肯休。"]'),
('10d6554f-1643-4b92-9755-710cfa425a3d','塞下曲二首 一','令狐楚','唐','唐诗','tang','','[]','雪滿衣裳冰滿鬚，曉隨飛將伐單于。',32,'全唐诗/poet.tang.17000.json','["雪滿衣裳冰滿鬚，曉隨飛將伐單于。", "平生意氣今何在，把得家書淚似珠。"]'),
('07a5b7af-0096-4a0c-ba4f-a4f972e9e365','塞下曲二首 二','令狐楚','唐','唐诗','tang','','[]','邊草蕭條塞鴈飛，征人南望淚沾衣。',32,'全唐诗/poet.tang.17000.json','["邊草蕭條塞鴈飛，征人南望淚沾衣。", "黃塵滿面長須戰，白髮生頭未得歸。"]'),
('d65a0f84-3f75-4d4e-bb8b-1a275c1cf586','遊春詞','令狐楚','唐','唐诗','tang','','[]','高樓曉見一花開，便覺春光四面來。',32,'全唐诗/poet.tang.17000.json','["高樓曉見一花開，便覺春光四面來。", "暖日晴雲知次第，東風不用更相催。"]'),
('cff4c658-ee2e-42d6-9d1e-4a336e80047d','漢苑行','令狐楚','唐','唐诗','tang','','[]','雲霞五采浮天闕，梅柳千般夾御溝。',32,'全唐诗/poet.tang.17000.json','["雲霞五采浮天闕，梅柳千般夾御溝。", "不上黃花南北望，豈知春色滿神州。"]'),
('853bcd83-f155-4a45-ad4f-491ba6cd0eaa','中元日贈張尊師','令狐楚','唐','唐诗','tang','','[]','偶來人世值中元，不獻玄都永日閑。',32,'全唐诗/poet.tang.17000.json','["偶來人世值中元，不獻玄都永日閑。", "寂寂焚香在仙觀，知師遙禮玉京山。"]'),
('057539ad-9727-429a-8be1-f292f65e6fd6','赴東都別牡丹','令狐楚','唐','唐诗','tang','','[]','十年不見小庭花，紫萼臨開又別家。',32,'全唐诗/poet.tang.17000.json','["十年不見小庭花，紫萼臨開又別家。", "上馬出門回首望，何時更得到京華。"]'),
('d445f406-1dc3-4fb6-a450-9de1e5cf5c36','寄禮部劉郎中','令狐楚','唐','唐诗','tang','','[]','一別三年在上京，仙垣終日選羣英。',32,'全唐诗/poet.tang.17000.json','["一別三年在上京，仙垣終日選羣英。", "除書每下皆先看，唯有劉郎無姓名。"]'),
('f18c052e-4df5-4c24-ae21-eac858b65ed8','坐中聞思帝鄉有感','令狐楚','唐','唐诗','tang','','[]','年年不見帝鄉春，白日尋思夜夢頻。',32,'全唐诗/poet.tang.17000.json','["年年不見帝鄉春，白日尋思夜夢頻。", "上酒忽聞吹此曲，坐中惆悵更何人。"]'),
('a83b0b1a-e2d2-4c3a-be9d-f63eff04d1ad','春思寄夢得樂天','令狐楚','唐','唐诗','tang','','[]','花滿中庭酒滿樽，平明獨坐到黃昏。',32,'全唐诗/poet.tang.17000.json','["花滿中庭酒滿樽，平明獨坐到黃昏。", "春來詩思偏何處，飛過函關入鼎門。"]'),
('cd9b3b55-83f4-4931-9520-5c78ba2dc073','皇城中花園譏劉白賞春不及','令狐楚','唐','唐诗','tang','','[]','五鳳樓西花一園，低枝小樹盡芳繁。',32,'全唐诗/poet.tang.17000.json','["五鳳樓西花一園，低枝小樹盡芳繁。", "洛陽才子何曾愛，下馬貪趨廣運門。"]'),
('c9ff6835-1024-4b44-bbbd-e89cb8913ffa','相思河','令狐楚','唐','唐诗','tang','','[]','誰把相思號比河，塞垣車馬往來多。',32,'全唐诗/poet.tang.17000.json','["誰把相思號比河，塞垣車馬往來多。", "只應自古征人淚，灑向空洲作碧波。"]'),
('9ccdcda9-4793-4bc5-863b-00c69dc7d692','三月晦日會李員外座中頻以老大不醉見譏因有此贈','令狐楚','唐','唐诗','tang','','[]','三月唯殘一日春，玉山傾倒白鷗馴。',32,'全唐诗/poet.tang.17000.json','["三月唯殘一日春，玉山傾倒白鷗馴。", "不辭便學山公醉，花下無人作主人。"]'),
('5ac3e55f-2010-415a-b261-59355c6e4756','賦山','令狐楚','唐','唐诗','tang','','["\u5199\u5c71", "\u5c71", "\u63cf\u5199\u5c71"]','山，聳峻，回環。',68,'全唐诗/poet.tang.17000.json','["山，聳峻，回環。", "滄海上，白雲間。", "商老深尋，謝公遠攀。", "古巖泉滴滴，幽谷鳥關關。", "樹島西連隴塞，猨聲南徹荆蠻。", "世人只向簪裾老，芳草空餘麋鹿閑。"]'),
('8d00f416-f540-421b-95b2-0cdb5fe21daa','句','令狐楚','唐','唐诗','tang','','[]','何日居三署，終年尾百僚。',88,'全唐诗/poet.tang.17000.json','["何日居三署，終年尾百僚。", "移石幾迴敲廢印，開箱何處送新圖。", "唯應四仲祭，使者暫悲嗟。", "偶逢蒲家郎，乃是葛仙客。", "行常乘青竹，飢即煮白石。", "腰間嫌大組，心內保尺宅。", "我願從之遊，深卜鍊上液。"]'),
('d3994414-ab96-48c8-ad91-dc2755cd96e5','享惠昭太子廟樂章','裴度','唐','唐诗','tang','','[]','重輪始發祥，齒胄方興學。',48,'全唐诗/poet.tang.17000.json','["重輪始發祥，齒胄方興學。", "冥然升紫府，鏗爾薦清樂。", "奠斝致馨香，在庭紛羽籥。", "禮成神既醉，髣髴緱山鶴。"]'),
('5dcc7d56-6cb5-40fe-8261-18b2923542bb','夏日對雨','裴度','唐','唐诗','tang','','[]','登樓逃盛夏，萬象正埃塵。',48,'全唐诗/poet.tang.17000.json','["登樓逃盛夏，萬象正埃塵。", "對面雷嗔樹，當街雨趁人。", "簷疎蛛網重，地溼燕泥新。", "吟罷清風起，荷香滿四鄰。"]'),
('fc08e47a-6fac-4073-b5e0-1f035dee25d0','白二十二侍郎有雙鶴留在洛下予西園多野水長松可以栖息遂以詩請之','裴度','唐','唐诗','tang','','[]','聞君有雙鶴，羈旅洛城東。',48,'全唐诗/poet.tang.17000.json','["聞君有雙鶴，羈旅洛城東。", "未放歸仙去，何如乞老翁。", "且將臨野水，莫閉在樊籠。", "好是長鳴處，西園白露中。"]'),
('e3027811-f99a-444a-b8dd-378cd05be12f','竇七中丞見示初至夏口獻元戎詩輒戲和之','裴度','唐','唐诗','tang','','[]','出佐青油幕，來吟白雪篇。',48,'全唐诗/poet.tang.17000.json','["出佐青油幕，來吟白雪篇。", "須爲九臯鶴，莫上五湖船。", "故態君應在，新詩我亦便。", "元侯看再入，好被暫流連。"]'),
('dc10fb4f-5e6c-4ab4-82ee-904929155fbf','酬張秘書因寄馬贈詩','裴度','唐','唐诗','tang','','[]','滿城馳逐皆求馬，古寺閑行獨與君。',64,'全唐诗/poet.tang.17000.json','["滿城馳逐皆求馬，古寺閑行獨與君。", "代步本慙非逸足，緣情何幸枉高文。", "若逢佳麗從將換，莫共駑駘角出羣。", "飛控著鞭能顧我，當時王粲亦從軍。"]'),
('82fd4dc3-e911-4f44-aaba-0124c39d363b','真慧寺','裴度','唐','唐诗','tang','','[]','遍尋真蹟躡莓苔，世事全拋不忍回。',64,'全唐诗/poet.tang.17000.json','["遍尋真蹟躡莓苔，世事全拋不忍回。", "上界不知何處去，西天移向此間來。", "巖前芍藥師親種，嶺上青松佛手栽。", "更有一般人不見，白蓮花向半天開。"]'),
('c483097d-225a-4508-b8f2-2d0a055e9d2d','中書即事','裴度','唐','唐诗','tang','','[]','有意效承平，無功荅聖明。',72,'全唐诗/poet.tang.17000.json','["有意效承平，無功荅聖明。", "灰心緣忍事，霜鬢爲論兵。", "道直身還在，恩深命轉輕。", "鹽梅非擬議，葵藿是平生。", "白日長懸照，蒼蠅謾發聲。", "高陽舊田里，終使謝歸耕。"]'),
('561556a9-9bd2-450a-9d38-622e35baa029','中和節詔賜公卿尺','裴度','唐','唐诗','tang','','[]','陽和行慶賜，尺度及羣公。',72,'全唐诗/poet.tang.17000.json','["陽和行慶賜，尺度及羣公。", "荷寵承佳節，傾心立大中。", "短長思合製，遠近貴攸同。", "共仰財成德，將酬分寸功。", "作程施有政，垂範播無窮。", "願續南山壽，千春奉聖躬。"]'),
('0f4d92f2-7130-41c1-a5f9-dcb72c9c42ad','至日登樂遊園','裴度','唐','唐诗','tang','','[]','陰律隨寒改，陽和應節生。',72,'全唐诗/poet.tang.17000.json','["陰律隨寒改，陽和應節生。", "祥雲觀魏闕，瑞氣映秦城。", "驗炭論時政，書雲受歲盈。", "晷移長日至，霧斂遠霄清。", "景暖仙梅動，風柔御柳傾。", "那堪封得意，空對物華情。"]'),
('3f7c03e7-3e18-4e74-ba29-7d1dd2ab1963','奉酬中書相公至日圓丘攝事合於中書後閣宿齋移止於集賢院敘懷見寄之作','裴度','唐','唐诗','tang','','[]','翼亮登三命，謨猷本一心。',72,'全唐诗/poet.tang.17000.json','["翼亮登三命，謨猷本一心。", "致齋移秘府，祗事見沖襟。", "皓月當延閣，祥風自禁林。", "相庭方積玉，王度已如金。", "運偶唐虞盛，情同丙魏深。", "幽蘭與白雪，何處寄庸音。"]'),
('9cee4958-7cfa-47af-b997-474f07026a79','太原題廳壁','裴度','唐','唐诗','tang','','[]','危事經非一，浮榮得是空。',24,'全唐诗/poet.tang.17000.json','["危事經非一，浮榮得是空。", "白頭官舍裏，今日又春風。"]'),
('2758358b-0b09-4d28-a760-c7bad0e24604','溪居','裴度','唐','唐诗','tang','','[]','門徑俯清溪，茅簷古木齊。',26,'全唐诗/poet.tang.17000.json','["門徑俯清溪，茅簷古木齊。", "紅塵飄不到，時有水禽[啼]。"]'),
('9cf58d4c-891c-428a-aded-f7a152f484c4','喜遇劉二十八','裴度','唐','唐诗','tang','','[]','病來佳興少，老去舊遊稀。',24,'全唐诗/poet.tang.17000.json','["病來佳興少，老去舊遊稀。", "笑語縱橫作，盃觴絡繹飛。"]'),
('bcd50811-3a5f-4243-b5c6-76142813cf1f','送劉','裴度','唐','唐诗','tang','','[]','不歸丹掖去，銅竹漫云云。',24,'全唐诗/poet.tang.17000.json','["不歸丹掖去，銅竹漫云云。", "惟喜因過我，須知未賀君。"]'),
('0738c2d1-fb75-4b8b-855e-55a75fa55f79','再送','裴度','唐','唐诗','tang','','[]','頃來多謔浪，此夕任喧紛。',24,'全唐诗/poet.tang.17000.json','["頃來多謔浪，此夕任喧紛。", "故態猶應在，行期未要聞。"]'),
('cfd56ceb-779a-4207-b29b-252041b08edb','涼風亭睡覺','裴度','唐','唐诗','tang','','[]','飽食緩行新睡覺，一甌新茗侍兒煎。',32,'全唐诗/poet.tang.17000.json','["飽食緩行新睡覺，一甌新茗侍兒煎。", "脫巾斜倚繩牀坐，風送水聲來耳邊。"]'),
('0e3a9d6c-5437-4b81-93f6-ccb33c11bdbd','雪中訝諸公不相訪','裴度','唐','唐诗','tang','','[]','憶昨雨多泥又深，猶能攜妓遠過尋。',32,'全唐诗/poet.tang.17000.json','["憶昨雨多泥又深，猶能攜妓遠過尋。", "滿空亂雪花相似，何事居然無賞心。"]'),
('9fbd455e-35f0-4785-9671-9b31bdd3db9d','傍水閑行','裴度','唐','唐诗','tang','','[]','閑餘何處覺身輕，暫脫朝衣傍水行。',32,'全唐诗/poet.tang.17000.json','["閑餘何處覺身輕，暫脫朝衣傍水行。", "鷗鳥亦知人意靜，故來相近不相驚。"]'),
('e95c7ae1-b846-4b76-b889-3b8ab60bfa15','句','裴度','唐','唐诗','tang','','[]','兩人同日事征西，今日君先奉紫泥。',64,'全唐诗/poet.tang.17000.json','["兩人同日事征西，今日君先奉紫泥。", "待平賊壘報天子，莫指仙山示武夫。", "野人不識中書令，喚作陶家與謝家。", "君若有心求逸足，我還留意在名姝。"]'),
('0fe7cee2-1f29-42af-84f5-c464844e1e0c','元和聖德詩','韓愈','唐','唐诗','tang','','[]','皇帝即阼，物無違拒。',240,'全唐诗/poet.tang.17000.json','["皇帝即阼，物無違拒。", "曰暘而暘，曰雨而雨。", "維是元年，有盜在夏。", "欲覆其州，以踵近武。", "皇帝曰嘻，豈不在我。", "負鄙爲艱，縱則不可。", "出師征之，其衆十旅。", "軍其城下，告以福禍。", "腹敗枝披，不敢保聚。", "擲首陴外，降旛夜豎。", "疆外之險，莫過蜀土。", "韋臯去鎮，劉闢守後。", "血人於牙，不肯吐口。", "開庫啗士，曰隨所取。", "汝張汝弓，汝鼓汝鼓。", "汝爲表書，求我帥汝。", "事始上聞，在列咸怒。", "皇帝曰然，嗟遠士女。", "苟附而安，則且付與。", "讀命於庭，出節少府。", "朝發京師，夕至其部。", "闢喜謂黨，汝振而伍。", "蜀可全有，此不當受。", "萬牛臠炙，萬甕行酒。"]'),
('654b2cd5-a026-4e0c-94a1-4353e22f66fe','琴操十首','韓愈','唐','唐诗','tang','','[]','秋之水兮，其色幽幽。',67,'全唐诗/poet.tang.17000.json','["秋之水兮，其色幽幽。", "我將濟兮，不得其由。", "涉其淺兮，石齧我足。", "乘其深兮，龍入我舟。", "我濟而悔兮，將安歸尤。", "歸兮歸兮，無與石鬬兮，無應龍求。"]'),
('b575e455-6047-48b7-9324-944c351954d9','琴操十首','韓愈','唐','唐诗','tang','','[]','蘭之猗猗，揚揚其香。',80,'全唐诗/poet.tang.17000.json','["蘭之猗猗，揚揚其香。", "不採而佩，於蘭何傷。", "今天之旋，其曷爲然。", "我行四方，以日以年。", "雪霜貿貿，薺麥之茂。", "子如不傷，我不爾覯。", "薺麥之茂，薺麥之有。", "君子之傷，君子之守。"]'),
('a346c963-e9c5-4eb9-a051-ce9713bd5aac','琴操十首','韓愈','唐','唐诗','tang','','[]','龜之氛兮，不能雲雨。',51,'全唐诗/poet.tang.17000.json','["龜之氛兮，不能雲雨。", "龜之枿兮，不中梁柱。", "龜之大兮，祗以奄魯。", "知將隳兮，哀莫余伍。", "周公有鬼兮，嗟余歸輔。"]'),
('d21c567b-1289-4d1d-9587-62086220f8e1','琴操十首','韓愈','唐','唐诗','tang','','[]','雨之施物以孳，我何意於彼爲。',74,'全唐诗/poet.tang.17000.json','["雨之施物以孳，我何意於彼爲。", "自周之先，其艱其勤。", "以有疆宇，私我後人。", "我祖在上，四方在下。", "厥臨孔威，敢戲以侮。", "孰荒於門，孰治於田。", "四海既均，越裳是臣。"]'),
('82c329e7-e0e2-44ab-b767-b522a9eef1b3','琴操十首','韓愈','唐','唐诗','tang','','[]','目窈窈兮，其凝其盲。',58,'全唐诗/poet.tang.17000.json','["目窈窈兮，其凝其盲。", "耳肅肅兮，聽不聞聲。", "朝不日出兮，夜不見月與星。", "有知無知兮，爲死爲生。", "嗚呼！臣罪當誅兮，天王聖明。"]'),
('b1cd230f-4948-445a-af00-52b2b8553815','琴操十首','韓愈','唐','唐诗','tang','','[]','我家於豳，自我先公。',60,'全唐诗/poet.tang.17000.json','["我家於豳，自我先公。", "伊我承序，敢有不同。", "今狄之人，將土我疆。", "民爲我戰，誰使死傷。", "彼岐有岨，我往獨處。", "爾莫余追，無思我悲。"]'),
('b8891be4-edc5-48ef-9720-42d2f9cc9557','琴操十首','韓愈','唐','唐诗','tang','','[]','父兮兒寒，母兮兒飢。',80,'全唐诗/poet.tang.17000.json','["父兮兒寒，母兮兒飢。", "兒罪當笞，逐兒何爲。", "兒在中野，以宿以處。", "四無人聲，誰與兒語。", "兒寒何衣，兒飢何食。", "兒行於野，履霜以足。", "母生衆兒，有母憐之。", "獨無母憐，兒寧不悲。"]'),
('c04667c7-3b68-477e-9fd6-a4119e40fcca','琴操十首','韓愈','唐','唐诗','tang','','[]','雉之飛，於朝日。',62,'全唐诗/poet.tang.17000.json','["雉之飛，於朝日。", "羣雌孤雄，意氣橫出。", "當東而西，當啄而飛。", "隨飛隨啄，羣雌粥粥。", "嗟我雖人，曾不如彼雉雞。", "生身七十年，無一妾與妃。"]'),
('0c6e4aa0-b89a-47ba-9b1e-df99778e0de5','琴操十首','韓愈','唐','唐诗','tang','','[]','雄鵠銜枝來，雌鵠啄泥歸。',50,'全唐诗/poet.tang.17000.json','["雄鵠銜枝來，雌鵠啄泥歸。", "巢成不生子，大義當乖離。", "江漢水之大，鵠身鳥之微。", "更無相逢日，且可繞樹相隨飛。"]'),
('41df718e-bcaf-4cef-8b2d-3ea668ddac93','琴操十首','韓愈','唐','唐诗','tang','','[]','有獸維貍兮，我夢得之。',44,'全唐诗/poet.tang.17000.json','["有獸維貍兮，我夢得之。", "其身孔明兮，而頭不知。", "吉凶何爲兮，覺坐而思。", "巫咸上天兮，識者其誰。"]'),
('e6a2da11-7374-4d2c-abce-6029793c24e5','南山詩','韓愈','唐','唐诗','tang','','["\u5199\u5c71", "\u63cf\u5199\u5c71"]','吾聞京城南，茲惟羣山囿。',288,'全唐诗/poet.tang.17000.json','["吾聞京城南，茲惟羣山囿。", "東西兩際海，巨細難悉究。", "山經及地志，茫昧非受授。", "團辭試提挈，挂一念萬漏。", "欲休諒不能，粗敘所經覯。", "嘗昇崇丘望，戢戢見相湊。", "晴明出稜角，縷脈碎分繡。", "蒸嵐相澒洞，表裏忽通透。", "無風自飄簸，融液煦柔茂。", "橫雲時平凝，點點露數岫。", "天空浮修眉，濃綠畫新就。", "孤撐有巉絕，海浴褰鵬噣。", "春陽潛沮洳，濯濯吐深秀。", "巖巒雖嵂崒，軟弱類含酎。", "夏炎百木盛，蔭鬱增埋覆。", "神靈日歊歔，雲氣爭結構。", "秋霜喜刻轢，磔卓立癯瘦。", "參差相疊重，剛耿陵宇宙。", "冬行雖幽墨，冰雪工琢鏤。", "新曦照危峨，億丈恒高袤。", "明昏無停態，頃刻異狀候。", "西南雄太白，突起莫間簉。", "藩都配德運，分宅占丁戊。", "逍遙越坤位，詆訐陷乾竇。"]'),
('0ba5fed4-43d1-4d38-a68e-a791b68c2a9e','謝自然詩','韓愈','唐','唐诗','tang','','[]','果州南充縣，寒女謝自然。',288,'全唐诗/poet.tang.17000.json','["果州南充縣，寒女謝自然。", "童騃無所識，但聞有神僊。", "輕生學其術，乃在金泉山。", "繁華榮慕絕，父母慈愛捐。", "凝心感魑魅，慌惚難具言。", "一朝坐空室，雲霧生其間。", "如聆笙竽韻，來自冥冥天。", "白日變幽晦，蕭蕭風景寒。", "簷楹蹔明滅，五色光屬聯。", "觀者徒傾駭，躑躅詎敢前。", "須臾自輕舉，飄若風中煙。", "茫茫八紘大，影響無由緣。", "里胥上其事，郡守驚且歎。", "驅車領官吏，甿俗爭相先。", "入門無所見，冠履同蛻蟬。", "皆云神僊事，灼灼信可傳。", "余聞古夏后，象物知神姦。", "山林民可入，魍魎莫逢旃。", "逶迤不復振，後世恣欺謾。", "幽明紛雜亂，人鬼更相殘。", "秦皇雖篤好，漢武洪其源。", "自從二主來，此禍竟連連。", "木石生怪變，狐貍騁妖患。", "莫能盡性命，安得更長延。"]'),
('03afc4d5-6c21-4d39-b6f8-2b3065f74216','秋懷詩十一首 一','韓愈','唐','唐诗','tang','','[]','窗前兩好樹，衆葉光薿薿。',96,'全唐诗/poet.tang.17000.json','["窗前兩好樹，衆葉光薿薿。", "秋風一拂披，策策鳴不已。", "微燈照空牀，夜半偏入耳。", "愁憂無端來，感歎成坐起。", "天明視顏色，與故不相似。", "羲和驅日月，疾急不可恃。", "浮生雖多塗，趨死惟一軌。", "胡爲浪自苦，得酒且歡喜。"]'),
('22b831d2-e67b-442e-95d6-88f2247bfa0a','秋懷詩十一首 二','韓愈','唐','唐诗','tang','','[]','白露下百草，蕭蘭共雕悴。',60,'全唐诗/poet.tang.17000.json','["白露下百草，蕭蘭共雕悴。", "青青四牆下，已復生滿地。", "寒蟬暫寂寞，蟋蟀鳴自恣。", "運行無窮期，稟受氣苦異。", "適時各得所，松栢不必貴。"]'),
('d3791123-b34e-48cf-a640-e28e3d52609f','秋懷詩十一首 三','韓愈','唐','唐诗','tang','','[]','彼時何卒卒，我志何曼曼。',84,'全唐诗/poet.tang.17000.json','["彼時何卒卒，我志何曼曼。", "犀首空好飲，廉頗尚能飯。", "學堂日無事，驅馬適所願。", "茫茫出門路，欲去聊自勸。", "歸還閱書史，文字浩千萬。", "陳跡竟誰尋，賤嗜非貴獻。", "丈夫意有在，女子乃多怨。"]'),
('d9ceb6a0-47e1-436d-bb9a-adbcda63dd80','秋懷詩十一首 四','韓愈','唐','唐诗','tang','','[]','秋氣日惻惻，秋空日凌凌。',72,'全唐诗/poet.tang.17000.json','["秋氣日惻惻，秋空日凌凌。", "上無枝上蜩，下無盤中蠅。", "豈不感時節，耳目去所憎。", "清曉卷書坐，南山見高稜。", "其下澄湫水，有蛟寒可罾。", "惜哉不得往，豈謂吾無能。"]'),
('ddf17534-3921-4fa9-bbff-258ef28fa1ee','秋懷詩十一首 五','韓愈','唐','唐诗','tang','','[]','離離挂空悲，慼慼抱虛警。',72,'全唐诗/poet.tang.17000.json','["離離挂空悲，慼慼抱虛警。", "露泫秋樹高，蟲弔寒夜永。", "歛退就新懦，趨營悼前猛。", "歸愚識夷塗，汲古得修綆。", "名浮猶有耻，味薄真自幸。", "庶幾遺悔尤，即此是幽屏。"]'),
('b885b956-4a98-4db3-8095-236c932c5c06','秋懷詩十一首 六','韓愈','唐','唐诗','tang','','[]','今晨不成起，端坐盡日景。',60,'全唐诗/poet.tang.17000.json','["今晨不成起，端坐盡日景。", "蟲鳴室幽幽，月吐窗冏冏。", "喪懷若迷方，浮念劇含梗。", "塵埃慵伺候，文字浪馳騁。", "尚須勉其頑，王事有朝請。"]'),
('9907f486-7772-410b-8c3e-70bd19cdbe0d','秋懷詩十一首 七','韓愈','唐','唐诗','tang','','[]','秋夜不可晨，秋日苦易暗。',108,'全唐诗/poet.tang.17000.json','["秋夜不可晨，秋日苦易暗。", "我無汲汲志，何以有此憾。", "寒雞空在棲，缺月煩屢瞰。", "有琴具徽絃，再鼓聽愈淡。", "古聲久埋滅，無由見真濫。", "低心逐時趨，苦勉祗能暫。", "有如乘風船，一縱不可纜。", "不如覰文字，丹鉛事點勘。", "豈必求贏餘，所要石與甔。"]'),
('0476e322-b94e-4a68-85fe-972017812b8d','秋懷詩十一首 八','韓愈','唐','唐诗','tang','','[]','卷卷落地葉，隨風走前軒。',120,'全唐诗/poet.tang.17000.json','["卷卷落地葉，隨風走前軒。", "鳴聲若有意，顛倒相追奔。", "空堂黃昏暮，我坐默不言。", "童子自外至，吹燈當我前。", "問我我不應，饋我我不餐。", "退坐西壁下，讀詩盡數編。", "作者非今士，相去時已千。", "其言有感觸，使我復悽酸。", "願謂汝童子，置書且安眠。", "丈夫屬有念，事業無窮年。"]'),
('741bfdb1-9279-4bb5-977f-0b063dcd43db','秋懷詩十一首 九','韓愈','唐','唐诗','tang','','[]','霜風侵梧桐，衆葉著樹乾。',84,'全唐诗/poet.tang.17000.json','["霜風侵梧桐，衆葉著樹乾。", "空堦一片下，琤若摧琅玕。", "謂是夜氣滅，望舒霣其團。", "青冥無依倚，飛轍危難安。", "驚起出戶視，倚楹久汍瀾。", "憂愁費晷景，日月如跳丸。", "迷復不計遠，爲君駐塵鞍。"]'),
('3f2ec192-f117-4f53-a433-844d8f56052e','秋懷詩十一首 十','韓愈','唐','唐诗','tang','','[]','暮暗來客去，羣囂各收聲。',84,'全唐诗/poet.tang.17000.json','["暮暗來客去，羣囂各收聲。", "悠悠偃宵寂，斖斖抱秋明。", "世累忽進慮，外憂遂侵誠。", "強懷張不滿，弱念缺已盈。", "詰屈避語穽，冥茫觸心兵。", "敗虞千金棄，得比寸草榮。", "知耻足爲勇，晏然誰汝令。"]'),
('11fe203c-8fbb-4287-b319-0eff081a3e1c','秋懷詩十一首 十一','韓愈','唐','唐诗','tang','','[]','鮮鮮霜中菊，既晚何用好。',60,'全唐诗/poet.tang.17000.json','["鮮鮮霜中菊，既晚何用好。", "揚揚弄芳蝶，爾生還不早。", "運窮兩值遇，婉孌死相保。", "西風蟄龍蛇，衆木日凋槁。", "由來命分爾，泯滅豈足道。"]'),
('c325ca32-5efc-4c90-89d3-853ca1782713','赴江陵途中寄贈王二十補闕李十一拾遺李二十六員外翰林三學士','韓愈','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','孤臣昔放逐，血泣追愆尤。',288,'全唐诗/poet.tang.17000.json','["孤臣昔放逐，血泣追愆尤。", "汗漫不省識，怳如乘桴浮。", "或自疑上疏，上疏豈其由。", "是年京師旱，田畝少所收。", "上憐民無食，征賦半已休。", "有司恤經費，未免煩徵求。", "富者既云急，貧者固已流。", "傳聞閭里間，赤子棄渠溝。", "持男易斗粟，掉臂莫肯酬。", "我時出衢路，餓者何其稠。", "親逢道邊死，佇立久咿嚘。", "歸舍不能食，有如魚中鉤。", "適會除御史，誠當得言秋。", "拜疏移閤門，爲忠寧自謀。", "上陳人疾苦，無令絕其喉。", "下陳畿甸內，根本理宜優。", "積雪騐豐熟，幸寬待蠶麰。", "天子惻然感，司空歎綢繆。", "謂言即施設，乃反遷炎州。", "同官盡才俊，偏善柳與劉。", "或慮語言洩，傳之落冤讐。", "二子不宜爾，將疑斷還不。", "中使臨門遣，頃刻不得留。", "病妹臥牀褥，分知隔明幽。"]'),
('ac10786c-b760-4114-bc0a-ef4b4a8169f1','暮行河堤上','韓愈','唐','唐诗','tang','','[]','暮行河堤上，四顧不見人。',48,'全唐诗/poet.tang.17000.json','["暮行河堤上，四顧不見人。", "衰草際黃雲，感歎愁我神。", "夜歸孤舟臥，展轉空及晨。", "謀計竟何就，嗟嗟世與身。"]'),
('c5d58781-aacb-4f28-b3c2-03c8b81d820c','夜歌','韓愈','唐','唐诗','tang','','[]','靜夜有清光，閑堂仍獨息。',36,'全唐诗/poet.tang.17000.json','["靜夜有清光，閑堂仍獨息。", "念身幸無恨，志氣方自得。", "樂哉何所憂，所憂非我力。"]'),
('e99bb3c6-6ea1-4d0c-b50d-dd9c9a401566','重雲李觀疾贈之','韓愈','唐','唐诗','tang','','[]','天行失其度，陰氣來干陽。',108,'全唐诗/poet.tang.17000.json','["天行失其度，陰氣來干陽。", "重雲閉白日，炎燠成寒涼。", "小人但咨怨，君子惟憂傷。", "飲食爲減少，身體豈寧康。", "此志誠足貴，懼非職所當。", "藜羹尚如此，肉食安可嘗。", "窮冬百草死，幽桂乃芬芳。", "且況天地間，大運自有常。", "勸君善飲食，鸞鳳本高翔。"]'),
('bd67771f-6ce5-4d1a-bf33-b9aeae8cf25b','江漢答孟郊','韓愈','唐','唐诗','tang','','[]','江漢雖云廣，乘舟渡無艱。',84,'全唐诗/poet.tang.17000.json','["江漢雖云廣，乘舟渡無艱。", "流沙信難行，馬足常往還。", "淒風結衝波，狐裘能禦寒。", "終宵處幽室，華燭光爛爛。", "苟能行忠信，可以居夷蠻。", "嗟余與夫子，此義每所敦。", "何爲復見贈，繾綣在不諼。"]'),
('d39658f3-b254-4985-abf0-48751db03198','長安交遊者贈孟郊','韓愈','唐','唐诗','tang','','[]','長安交遊者，貧富各有徒。',48,'全唐诗/poet.tang.17000.json','["長安交遊者，貧富各有徒。", "親朋相過時，亦各有以娛。", "陋室有文史，高門有笙竽。", "何能辨榮悴，且欲分賢愚。"]'),
('88a4d16e-ae4f-4e05-b202-2e87d05ddb2f','岐山下二首 一','韓愈','唐','唐诗','tang','','[]','誰謂我有耳，不聞鳳皇鳴。',24,'全唐诗/poet.tang.17000.json','["誰謂我有耳，不聞鳳皇鳴。", "朅來岐山下，日暮邊鴻驚。"]'),
('4dc40063-1872-4321-9f83-dd57dd94c52e','岐山下二首 二','韓愈','唐','唐诗','tang','','[]','丹穴五色羽，其名爲鳳皇。',72,'全唐诗/poet.tang.17000.json','["丹穴五色羽，其名爲鳳皇。", "昔周有盛德，此鳥鳴高岡。", "和聲隨祥風，窅窕相飄揚。", "聞者亦何事，但知時俗康。", "自從公旦死，千載閟其光。", "吾君亦勤理，遲爾一來翔。"]'),
('4fce632a-061a-469b-b5f8-7dd73ba93127','北極贈李觀','韓愈','唐','唐诗','tang','','[]','北極有羈羽，南溟有沈鱗。',108,'全唐诗/poet.tang.17000.json','["北極有羈羽，南溟有沈鱗。", "川源浩浩隔，影響兩無因。", "風雲一朝會，變化成一身。", "誰言道里遠，感激疾如神。", "我年二十五，求友昧其人。", "哀歌西京市，乃與夫子親。", "所尚苟同趨，賢愚豈異倫。", "方爲金石姿，萬世無緇磷。", "無爲兒女態，憔悴悲賤貧。"]'),
('c70ab6f4-5915-40f9-84c3-beaefa04c55b','此日足可惜贈張籍','韓愈','唐','唐诗','tang','','[]','此日足可惜，此酒不足嘗。',288,'全唐诗/poet.tang.17000.json','["此日足可惜，此酒不足嘗。", "捨酒去相語，共分一日光。", "念昔未知子，孟君自南方。", "自矜有所得，言子有文章。", "我名屬相府，欲往不得行。", "思之不可見，百端在中腸。", "維時月魄死，冬日朝在房。", "驅馳公事退，聞子適及城。", "命車載之至，引坐於中堂。", "開懷聽其說，往往副所望。", "孔丘歿已遠，仁義路久荒。", "紛紛百家起，詭怪相披猖。", "長老守所聞，後生習爲常。", "少知誠難得，純粹古已亡。", "譬彼植園木，有根易爲長。", "留之不遣去，館置城西旁。", "歲時未云幾，浩浩觀湖江。", "衆夫指之笑，謂我知不明。", "兒童畏雷電，魚鼈驚夜光。", "州家舉進士，選試繆所當。", "馳辭對我策，章句何煒煌。", "相公朝服立，工席歌鹿鳴。", "禮終樂亦闋，相拜送於庭。", "之子去須臾，赫赫流盛名。"]'),
('75e8e864-7f92-42e9-9467-8988475bdf49','幽懷','韓愈','唐','唐诗','tang','','[]','幽懷不能寫，行此春江潯。',84,'全唐诗/poet.tang.17000.json','["幽懷不能寫，行此春江潯。", "適與佳節會，士女競光陰。", "凝妝耀洲渚，繁吹蕩人心。", "間關林中鳥，亦知和爲音。", "豈無一尊酒，自酌還自吟。", "但悲時易失，四序迭相侵。", "我歌君子行，視古猶視今。"]'),
('8564b270-5b39-41d3-a7ab-78fb21eb9784','君子法天運','韓愈','唐','唐诗','tang','','[]','君子法天運，四時可前知。',48,'全唐诗/poet.tang.17000.json','["君子法天運，四時可前知。", "小人惟所遇，寒暑不可期。", "利害有常勢，取捨無定姿。", "焉能使我心，皎皎遠憂疑。"]'),
('1f411fea-83c6-4e86-aadb-3e0fd0827366','落葉送陳羽','韓愈','唐','唐诗','tang','','[]','落葉不更息，斷蓬無復歸。',48,'全唐诗/poet.tang.17000.json','["落葉不更息，斷蓬無復歸。", "飄颻終自異，邂逅暫相依。", "悄悄深夜語，悠悠寒月輝。", "誰云少年別，流淚各沾衣。"]'),
('2897aade-bb54-46a4-83c1-c27b6060bbf1','歸彭城','韓愈','唐','唐诗','tang','','[]','天下兵又動，太平竟何時。',240,'全唐诗/poet.tang.17000.json','["天下兵又動，太平竟何時。", "訏謨者誰子，無乃失所宜。", "前年關中旱，閭井多死飢。", "去歲東郡水，生民爲流屍。", "上天不虛應，禍福各有隨。", "我欲進短策，無由至彤墀。", "刳肝以爲紙，瀝血以書辭。", "上言陳堯舜，下言引龍夔。", "言詞多感激，文字少葳蕤。", "一讀已自怪，再尋良自疑。", "食芹雖云美，獻御固已癡。", "緘封在骨髓，耿耿空自奇。", "昨者到京城，屢陪高車馳。", "周行多俊異，議論無瑕疵。", "見待頗異禮，未能去毛皮。", "到口不敢吐，徐徐俟其巘。", "歸來戎馬間，驚顧似羈雌。", "連日或不語，終朝見相欺。", "乘閑輙騎馬，茫茫詣空陂。", "遇酒即酩酊，君知我爲誰。"]'),
('683c0d72-400f-4807-9cd9-b619b5e80c85','醉後','韓愈','唐','唐诗','tang','','[]','煌煌東方星，奈此衆客醉。',48,'全唐诗/poet.tang.17000.json','["煌煌東方星，奈此衆客醉。", "初喧或忿爭，中靜雜嘲戲。", "淋漓身上衣，顛倒筆下字。", "人生如此少，酒賤且勤置。"]'),
('4518d55f-9277-4e8a-a975-2790eac6b3c9','醉贈張秘書','韓愈','唐','唐诗','tang','','[]','人皆勸我酒，我若耳不聞。',240,'全唐诗/poet.tang.17000.json','["人皆勸我酒，我若耳不聞。", "今日到君家，呼酒持勸君。", "爲此座上客，及余各能文。", "君詩多態度，藹藹春空雲。", "東野動驚俗，天葩吐奇芬。", "張籍學古淡，軒鶴避雞羣。", "阿買不識字，頗知書八分。", "詩成使之寫，亦足張吾軍。", "所以欲得酒，爲文俟其醺。", "酒味既冷冽，酒氣又氛氳。", "性情漸浩浩，諧笑方云云。", "此誠得酒意，餘外徒繽紛。", "長安衆富兒，盤饌羅羶葷。", "不解文字飲，惟能醉紅裙。", "雖得一餉樂，有如聚飛蚊。", "今我及數子，固無蕕與薰。", "險語破鬼膽，高詞嫓皇墳。", "至寶不雕琢，神功謝鋤耘。", "方今向太平，元凱承華勛。", "吾徒幸無事，庶以窮朝曛。"]'),
('ac52d797-2192-4024-a66f-7e5749f3d08c','同冠峽','韓愈','唐','唐诗','tang','','[]','南方二月半，春物亦已少。',72,'全唐诗/poet.tang.17000.json','["南方二月半，春物亦已少。", "維舟山水間，晨坐聽百鳥。", "宿雲尚含姿，朝日忽升曉。", "羇旅感和鳴，囚拘念輕矯。", "潺湲淚久迸，詰曲思增繞。", "行矣且無然，蓋棺事乃了。"]'),
('252b4e33-b8d1-462d-a8e9-55a9766df5cf','送惠師','韓愈','唐','唐诗','tang','','["\u8861\u5c71", "\u6d1e\u5ead\u6e56"]','惠師浮屠者，乃是不羇人。',288,'全唐诗/poet.tang.17000.json','["惠師浮屠者，乃是不羇人。", "十五愛山水，超然謝朋親。", "脫冠翦頭髮，飛步遺蹤塵。", "發跡入四明，梯空上秋旻。", "遂登天台望，衆壑皆嶙峋。", "夜宿最高頂，舉頭看星辰。", "光芒相照燭，南北爭羅陳。", "茲地絕翔走，自然嚴且神。", "微風吹木石，澎湃聞韶鈞。", "夜半起下視，溟波銜日輪。", "魚龍驚踴躍，呌嘯成悲辛。", "怪氣或紫赤，敲磨共輪囷。", "金鴉既騰翥，六合俄清新。", "常聞禹穴奇，東去窺甌閩。", "越俗不好古，流傳失其真。", "幽蹤邈難得，聖路嗟長堙。", "回臨浙江濤，屹起高峨岷。", "壯志死不息，千年如隔晨。", "是非竟何有，棄去非吾倫。", "凌江詣廬嶽，浩蕩極遊巡。", "崔崒沒雲表，陂陀浸湖淪。", "是時雨初霽，懸瀑垂天紳。", "前年往羅浮，步戛南海漘。", "大哉陽德盛，榮茂恒留春。"]'),
('5bca537d-3b97-4aec-bcb3-1884ce9ca87b','送靈師','韓愈','唐','唐诗','tang','','[]','佛法入中國，爾來六百年。',288,'全唐诗/poet.tang.17000.json','["佛法入中國，爾來六百年。", "齊民逃賦役，高士著幽禪。", "官吏不之制，紛紛聽其然。", "耕桑日失隸，朝署時遣賢。", "靈師皇甫姓，胤胄本蟬聯。", "少小涉書史，早能綴文篇。", "中間不得意，失跡成延遷。", "逸志不拘敎，軒騰斷牽攣。", "圍棊鬬白黑，生死隨機權。", "六博在一擲，梟盧叱回旋。", "戰詩誰與敵，浩汗橫戈鋋。", "飲酒盡百𧣴，嘲詣思逾鮮。", "有時醉花月，高唱清且緜。", "四座咸寂默，杳如奏湘弦。", "尋勝不憚險，黔江屢洄沿。", "瞿塘五六月，驚電讓歸船。", "怒水忽中裂，千尋墮幽泉。", "環回勢益急，仰見團團天。", "投身豈得計，性命甘徒捐。", "浪沫蹙翻涌，漂浮再生全。", "同行二十人，魂骨俱坑填。", "靈師不挂懷，冒涉道轉延。", "開忠二州牧，詩賦時多傳。", "失職不把筆，珠璣爲君編。"]'),
('4e9ac5c4-8f12-40f3-acce-39567d0bdfc5','縣齋有懷','韓愈','唐','唐诗','tang','','[]','少小尚奇偉，平生足悲吒。',293,'全唐诗/poet.tang.17000.json','["少小尚奇偉，平生足悲吒。", "猶嫌子夏儒，肯學樊遲稼。", "事業窺臯稷，文章蔑曹謝。", "濯纓起江湖，綴佩雜蘭麝。", "悠悠指長道，去去策高駕。", "誰爲傾國媒，自許連城價。", "初隨計吏貢，屢入澤宮射。", "雖免十上勞，何能一戰霸。", "人情忌殊異，世路多權詐。", "蹉跎顏遂低，摧折氣愈下。", "冶長信非罪，侯生或遭駡。", "懷書出皇都，銜淚渡清灞。", "身將老寂寞，志欲死閑暇。", "朝食不盈腸，冬衣纔掩髂。", "軍書既頻召，戎馬乃連跨。", "大梁從相公，彭城赴僕射。", "弓箭圍狐兔，絲竹羅酒{炙火=肉}。", "兩府變荒涼，三年就休假。", "求官去東洛，犯雪過西華。", "塵埃紫陌春，風雨靈臺夜。", "名聲荷朋友，援引乏姻婭。", "雖陪彤庭臣，詎縱青冥靶。", "寒空聳危闕，曉色曜脩架。", "捐軀辰在丁，鎩翮時方蜡。"]'),
('5cb1d784-de31-45d5-a95d-0f1e92b00341','合江亭','韓愈','唐','唐诗','tang','','[]','紅亭枕湘江，蒸水會其左。',240,'全唐诗/poet.tang.17000.json','["紅亭枕湘江，蒸水會其左。", "瞰臨眇空闊，綠淨不可唾。", "維昔經營初，邦君實王佐。", "翦林遷神祠，買地費家貨。", "梁棟宏可愛，結構麗匪過。", "伊人去軒騰，茲宇遂頹挫。", "老郎來何暮，高唱久乃和。", "樹蘭盈九畹，栽竹逾萬个。", "長綆汲滄浪，幽蹊下坎坷。", "波濤夜俯聽，雲樹朝對臥。", "初如遺宦情，終乃最郡課。", "人生誠無幾，事往悲豈奈。", "蕭條緜歲時，契闊繼庸懦。", "勝事誰復論，醜聲日已播。", "中丞黜凶邪，天子閔窮餓。", "君侯至之初，閭里自相賀。", "淹滯樂閑曠，勤苦勸慵惰。", "爲余掃塵階，命樂醉衆座。", "窮秋感平分，新月憐半破。", "願書巖上石，勿使泥塵涴。"]'),
('07bec374-ff61-4d05-842c-c57c25f1d888','陪杜侍御遊湘西兩寺獨宿有題一首因獻楊常侍','韓愈','唐','唐诗','tang','','[]','長沙千里平，勝地猶在險。',288,'全唐诗/poet.tang.17000.json','["長沙千里平，勝地猶在險。", "況當江闊處，斗起勢匪漸。", "深林高玲瓏，青山上琬琰。", "路窮臺殿闢，佛事煥且儼。", "剖竹走泉源，開廊架崖广。", "是時秋之殘，暑氣尚未歛。", "羣行忘後先，朋息棄拘檢。", "客堂喜空涼，華榻有清簟。", "澗蔬煮蒿芹，水果剝菱芡。", "伊余夙所慕，陪賞亦云忝。", "幸逢車馬歸，獨宿門不掩。", "山樓黑無月，漁火燦星點。", "夜風一何喧，杉檜屢磨颭。", "猶疑在波濤，怵惕夢成魘。", "靜思屈原沈，遠憶賈誼貶。", "椒蘭爭妬忌，絳灌共讒諂。", "誰令悲生腸，坐使淚盈臉。", "翻飛乏羽翼，指摘困瑕玷。", "珥貂藩維重，政化類分陝。", "禮賢道何優，奉己事苦儉。", "大廈棟方隆，巨川檝行剡。", "經營誠少暇，遊宴固已歉。", "旅程愧淹留，徂歲嗟荏苒。", "平生每多感，柔翰遇頻染。"]'),
('262d09ef-c986-4c06-81a4-9a75c6d83719','岳陽樓別竇司直','韓愈','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','洞庭九州間，厥大誰與讓。',288,'全唐诗/poet.tang.17000.json','["洞庭九州間，厥大誰與讓。", "南匯羣崖水，北注何奔放。", "瀦爲七百里，吞納各殊狀。", "自古澄不清，環混無歸向。", "炎風日搜攪，幽怪多冗長。", "軒然大波起，宇宙隘而妨。", "巍峩拔嵩華，騰踔較健壯。", "聲音一何宏，轟輵車萬兩。", "猶疑帝軒轅，張樂就空曠。", "蛟螭露筍簴，縞練吹組帳。", "鬼神非人世，節奏頗跌踼。", "陽施見誇麗，陰閉感悽愴。", "朝過宜春口，極北缺隄障。", "夜纜巴陵洲，叢芮纔可傍。", "星河盡涵泳，俯仰迷下上。", "餘瀾怒不已，喧聒鳴甕盎。", "明登岳陽樓，輝煥朝日亮。", "飛廉戢其威，清晏息纖纊。", "泓澄湛凝綠，物影巧相況。", "江豚時出戲，驚波忽蕩瀁。", "時當冬之孟，隙竅縮寒漲。", "前臨指近岸，側坐眇難望。", "滌濯神魂醒，幽懷舒以暢。", "主人孩童舊，握手乍忻悵。"]'),
('42a51a2c-f1b6-4e71-a991-23f0d1f9804e','送文暢師北遊','韓愈','唐','唐诗','tang','','[]','昔在四門館，晨有僧來謁。',291,'全唐诗/poet.tang.17000.json','["昔在四門館，晨有僧來謁。", "自言本吳人，少小學城闕。", "已窮佛根源，粗識事輗軏。", "攣拘屈吾真，戒轄思遠發。", "薦紳秉筆徒，聲譽耀前閥。", "從求送行詩，屢造忍顛蹶。", "今成十餘卷，浩汗羅斧鉞。", "先生閟窮巷，未得窺剞劂。", "又聞識大道，何路補剠刖。", "出其囊中文，滿聽實清越。", "謂僧當少安，草序頗排訐。", "上論古之初，所以施賞罰。", "下開迷惑胸，窙豁劚株橜。", "僧時不聽瑩，若飲水救暍。", "風塵一出門，時日多如髮。", "三年竄荒嶺，守縣坐深樾。", "徴租聚異物，詭製怛巾襪。", "幽窮誰共語，思想甚含噦。", "昨來得京官，照壁喜見蝎。", "況逢舊親識，無不比鶼蟨。", "長安多門戶，弔慶少休歇。", "而能勤來過，重惠安可揭。", "當今聖政初，恩澤完{羽戊}狘。", "胡爲不自暇，飄戾逐鸇𪆙。"]'),
('4b1eba88-6a05-45fa-a6a5-fdc07f93d248','答張徹','韓愈','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','辱贈不知報，我歌爾其聆。',288,'全唐诗/poet.tang.17000.json','["辱贈不知報，我歌爾其聆。", "首敘始識面，次言後分形。", "道途緜萬里，日月垂十齡。", "浚郊避兵亂，睢岸連門停。", "肝膽一古劒，波濤兩浮萍。", "漬墨竄舊史，磨丹注前經。", "義苑手秘寶，文堂耳驚霆。", "暄晨躡露舃，暑夕眠風櫺。", "結友子讓抗，請師我慚丁。", "初味猶噉蔗，遂通斯建瓴。", "搜奇日有富，嗜善心無寧。", "石梁平侹侹，沙水光泠泠。", "乘枯摘野豔，沈細抽潛腥。", "遊寺去陟巘，尋徑返穿汀。", "緣雲竹竦竦，失路麻冥冥。", "淫潦忽翻野，平蕪眇開溟。", "防泄塹夜塞，懼衝城晝扃。", "及去事戎轡，相逢宴軍伶。", "觥秋縱兀兀，獵旦馳駉駉。", "從賦始分手，朝京忽同舲。", "急時促暗櫂，戀月留虛亭。", "畢事驅傳馬，安居守窗螢。", "梅花灞水別，宮燭驪山醒。", "省選逮投足，鄉賓尚摧翎。"]'),
('2083af19-c093-4389-8493-46de8922dbea','薦士','韓愈','唐','唐诗','tang','','[]','周詩三百篇，雅麗理訓誥。',288,'全唐诗/poet.tang.17000.json','["周詩三百篇，雅麗理訓誥。", "曾經聖人手，議論安敢到。", "五言出漢時，蘇李首更號。", "東都漸瀰漫，派別百川導。", "建安能者七，卓犖變風操。", "逶迤抵晉宋，氣象日凋耗。", "中間數鮑謝，比近最清奧。", "齊梁及陳隋，衆作等蟬噪。", "搜春摘花卉，沿襲傷剽盜。", "國朝盛文章，子昂始高蹈。", "勃興得李杜，萬類困陵暴。", "後來相繼生，亦各臻閫奧。", "有窮者孟郊，受材實雄驁。", "冥觀洞古今，象外逐幽好。", "橫空盤硬語，妥帖力排奡。", "敷柔肆紆餘，奮猛卷海潦。", "榮華肖天秀，捷疾逾響報。", "行身踐規矩，甘辱恥媚竈。", "孟軻分邪正，眸子看瞭眊。", "杳然粹而清，可以鎮浮躁。", "酸寒溧陽尉，五十幾何耄。", "孜孜營甘旨，辛苦久所冒。", "俗流知者誰，指注競嘲慠。", "聖皇索遺逸，髦士日登造。"]'),
('b17e7f46-07c8-4596-9a54-6e6e88f40bae','喜侯喜至贈張籍張徹','韓愈','唐','唐诗','tang','','[]','昔我在南時，數君常在念。',240,'全唐诗/poet.tang.17000.json','["昔我在南時，數君常在念。", "搖搖不可止，諷詠日喁噞。", "如以膏濯衣，每漬垢逾染。", "又如心中疾，鍼石非所砭。", "常思得遊處，至死無倦厭。", "地遐物奇怪，水鏡涵石劒。", "荒花窮漫亂，幽獸工騰閃。", "礙目不忍窺，忽忽坐昏墊。", "逢神多所祝，豈忘靈即驗。", "依依夢歸路，歷歷想行店。", "今者誠自幸，所懷無一欠。", "孟生去雖索，侯氏來還歉。", "欹眠聽新詩，屋角月豔豔。", "雜作承間騁，交驚舌互舚。", "繽紛指瑕疵，拒捍阻城塹。", "以余經摧挫，固請發鉛槧。", "居然妄推讓，見謂爇天燄。", "比疎語徒妍，悚息不敢占。", "呼奴具盤餐，飣餖魚菜贍。", "人生但如此，朱紫安足僭。"]'),
('200b2b04-581a-4327-bb3e-aab077bf8c37','古風','韓愈','唐','唐诗','tang','','[]','今日曷不樂，幸時不用兵。',84,'全唐诗/poet.tang.17000.json','["今日曷不樂，幸時不用兵。", "無曰既蹙矣，乃尚可以生。", "彼州之賦，去汝不顧。", "此州之役，去我奚適。", "一邑之水，可走而違。", "天下湯湯，曷其而歸。", "好我衣服，甘我飲食。", "無念百年，聊樂一日。"]'),
('70f9e020-b7c4-42d5-8986-ae2f7f8b30e0','駑驥','韓愈','唐','唐诗','tang','','[]','駑駘誠齷齪，市者何其稠。',240,'全唐诗/poet.tang.17000.json','["駑駘誠齷齪，市者何其稠。", "力小若易制，價微良易酬。", "渴飲一斗水，飢食一束芻。", "嘶鳴當大路，志氣若有餘。", "騏驥生絕域，自矜無匹儔。", "牽驅入市門，行者不爲留。", "借問價幾何，黃金比嵩丘。", "借問行幾何，咫尺視九州。", "飢食玉山禾，渴飲醴泉流。", "問誰能爲御，曠世不可求。", "惟昔穆天子，乘之極遐遊。", "王良執其轡，造父挾其輈。", "因言天外事，茫惚使人愁。", "駑駘謂騏驥，餓死余爾羞。", "有能必見用，有德必見收。", "孰云時與命，通塞皆自由。", "騏驥不敢言，低徊但垂頭。", "人皆劣騏驥，共以駑駘優。", "喟余獨興歎，才命不同謀。", "寄詩同心子，爲我商聲謳。"]'),
('f0f85e4e-6083-4d1a-ae90-e8623eeb1c21','馬厭穀','韓愈','唐','唐诗','tang','','[]','馬厭穀兮，士不厭糠籺。',53,'全唐诗/poet.tang.17000.json','["馬厭穀兮，士不厭糠籺。", "土被文繡兮，士無短褐。", "彼其得志兮，不我虞。", "一朝失志兮，其何如。", "已焉哉，嗟嗟乎鄙夫！。"]'),
('fe8d13c5-7dbc-419c-b628-19508a95e2ac','出門','韓愈','唐','唐诗','tang','','[]','長安百萬家，出門無所之。',72,'全唐诗/poet.tang.17000.json','["長安百萬家，出門無所之。", "豈敢尚幽獨，與世實參差。", "古人雖已死，書上有其辭。", "開卷讀且想，千載若相期。", "出門各有道，我道方未夷。", "且於此中息，天命不吾欺。"]'),
('3750468c-5a67-4cbb-a237-77444d2163dc','嗟哉董生行','韓愈','唐','唐诗','tang','','[]','淮水出桐柏，山東馳遙遙。',268,'全唐诗/poet.tang.17000.json','["淮水出桐柏，山東馳遙遙。", "千里不能休，淝水出其側。", "不能千里百里入淮流，壽州屬縣有安豐。", "唐貞元時縣人董生召南隱居行義於其中，刺史不能薦。", "天子不聞名聲，爵祿不及門。", "門外惟有吏，日來徴租更索錢。", "嗟哉董生朝出耕，夜歸讀古人書。", "盡日不得息，或山而樵。", "或水而漁，入廚具甘旨。", "上堂問起居，父母不慼慼。", "妻子不咨咨，嗟哉董生孝且慈。", "人不識，惟有天翁知。", "生祥下瑞無時期，家有狗乳出求食。", "雞來哺其兒，啄啄庭中拾蟲蟻。", "哺之不食鳴聲悲，徬徨躑躅久不去。", "以翼來覆待狗歸，嗟哉董生。", "誰將與儔，時之人。", "夫妻相虐，兄弟爲讐。", "食君之祿，而令父母愁。", "亦獨何心，嗟哉董生無與儔。"]'),
('b49395d3-2826-4e8d-a78f-b9ac7b4a8629','烽火','韓愈','唐','唐诗','tang','','[]','登高望烽火，誰謂塞塵飛。',60,'全唐诗/poet.tang.17000.json','["登高望烽火，誰謂塞塵飛。", "王城富且樂，曷不事光輝。", "勿言日已暮，相見恐行稀。", "願君熟念此，秉燭夜中歸。", "我歌寧自感，乃獨淚霑衣。"]'),
('2b596522-409c-4275-946f-c2d690037e4c','汴州亂二首 一','韓愈','唐','唐诗','tang','','[]','汴州城門朝不開，天狗墮地聲如雷。',48,'全唐诗/poet.tang.17000.json','["汴州城門朝不開，天狗墮地聲如雷。", "健兒爭誇殺留後，連屋累棟燒成灰。", "諸侯咫尺不能救，孤士何者自興哀。"]'),
('53e33fb7-1422-4979-a25e-54d4ca820c76','汴州亂二首 二','韓愈','唐','唐诗','tang','','[]','母從子走者爲誰，大夫夫人留後兒。',48,'全唐诗/poet.tang.17000.json','["母從子走者爲誰，大夫夫人留後兒。", "昨日乘車騎大馬，坐者起趨乘者下。", "廟堂不肯用干戈，嗚呼奈汝母子何。"]'),
('4457599b-144f-4707-85f1-efd47cc89c03','利劒','韓愈','唐','唐诗','tang','','[]','利劒光耿耿，佩之使我無邪心。',72,'全唐诗/poet.tang.17000.json','["利劒光耿耿，佩之使我無邪心。", "故人念我寡徒侶，持用贈我比知音。", "我心如冰劒如雪，不能刺讒夫。", "使我心腐劒鋒折，決雲中斷開青天。", "噫，劒與我俱變化歸黃泉。"]'),
('b4a96752-93b2-4088-bdb3-4c45a5584e78','齪齪','韓愈','唐','唐诗','tang','','[]','齪齪當世士，所憂在飢寒。',144,'全唐诗/poet.tang.17000.json','["齪齪當世士，所憂在飢寒。", "但見賤者悲，不聞貴者歎。", "大賢事業異，遠抱非俗觀。", "報國心皎潔，念時涕汍瀾。", "妖姬坐左右，柔指發哀彈。", "酒肴雖日陳，感激寧爲歡。", "秋陰欺白日，泥潦不少乾。", "河堤決東郡，老弱隨驚湍。", "天意固有屬，誰能詰其端。", "願辱太守薦，得充諫諍官。", "排雲呌閶闔，披腹呈琅玕。", "致君豈無術，自進誠獨難。"]'),
('b5c8234e-7102-45e6-91cf-9409e797be87','河之水二首寄子姪老成 一','韓愈','唐','唐诗','tang','','[]','河之水，去悠悠，我不如，水東流。',58,'全唐诗/poet.tang.17000.json','["河之水，去悠悠，我不如，水東流。", "我有孤姪在海陬，三年不見兮使我生憂。", "日復日，夜復夜，三年不見汝，使我鬢髮未老而先化。"]'),
('ac2a0a60-ef91-46f9-8cc5-85e53ab6cb6e','河之水二首寄子姪老成 二','韓愈','唐','唐诗','tang','','[]','河之水，悠悠去，我不如，水東注。',54,'全唐诗/poet.tang.17000.json','["河之水，悠悠去，我不如，水東注。", "我有孤姪在海浦，三年不見兮使我心苦。", "采蕨於山，緡魚於淵。", "我徂京師，不遠其還。"]'),
('e73e2743-3752-4ba3-938a-fb59cd3965ee','山石','韓愈','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u7eaa\u6e38", "\u5199\u666f", "\u6292\u60c5", "\u4e03\u8a00\u53e4\u8bd7"]','山石犖確行徑微，黃昏到寺蝙蝠飛。',160,'全唐诗/poet.tang.17000.json','["山石犖確行徑微，黃昏到寺蝙蝠飛。", "升堂坐階新雨足，芭蕉葉大支子肥。", "僧言古壁佛畫好，以火來照所見稀。", "鋪牀拂席置羹飯，疎糲亦足飽我飢。", "夜深靜臥百蟲絕，清月出嶺光入扉。", "天明獨去無道路，出入高下窮煙霏。", "山紅澗碧紛爛漫，時見松櫪皆十圍。", "當流赤足蹋澗石，水聲激激風吹衣。", "人生如此自可樂，豈必局束爲人鞿。", "嗟哉吾黨二三子，安得至老不更歸。"]'),
('20dea002-e0ee-453b-89a0-f54b746aa435','天星送楊凝郎中賀正','韓愈','唐','唐诗','tang','','[]','天星牢落雞喔咿，僕夫起餐車載脂。',64,'全唐诗/poet.tang.17000.json','["天星牢落雞喔咿，僕夫起餐車載脂。", "正當窮冬寒未已，借問君子行安之。", "會朝元正無不至，受命上宰須及期。", "侍從近臣有虛位，公今此去歸何時。"]'),
('b331937f-9771-430b-a036-810ffc42bc17','汴泗交流贈張僕射','韓愈','唐','唐诗','tang','','[]','汴泗交流郡城角，築場十步平如削。',160,'全唐诗/poet.tang.17000.json','["汴泗交流郡城角，築場十步平如削。", "短垣三面繚逶迤，擊鼓騰騰樹赤旗。", "新秋朝涼未見日，公早結束來何爲。", "分曹決勝約前定，百馬攢蹄近相暎。", "毬驚杖奮合且離，紅牛纓紱黃金羈。", "側身轉臂著馬腹，霹靂應手神珠馳。", "超遙散漫兩閑暇，揮霍紛紜爭變化。", "發難得巧意氣麤，讙聲四合壯士呼。", "此誠習戰非爲劇，豈若安坐行良圖。", "當今忠臣不可得，公馬莫走須殺賊。"]'),
('0ca666d1-7adb-409b-97d6-ec3761cb62b1','忽忽','韓愈','唐','唐诗','tang','','[]','忽忽乎余未知生之爲樂也，願脫去而無因。',59,'全唐诗/poet.tang.17000.json','["忽忽乎余未知生之爲樂也，願脫去而無因。", "安得長翮大翼如雲生我身，乘風振奮出六合，絕浮塵。", "死生哀樂兩相棄，是非得失付閑人。"]'),
('ba0e5915-5198-4cf2-b744-7e09636ed846','鳴雁','韓愈','唐','唐诗','tang','','[]','嗷嗷鳴雁鳴且飛，窮秋南去春北歸。',80,'全唐诗/poet.tang.17000.json','["嗷嗷鳴雁鳴且飛，窮秋南去春北歸。", "去寒就暖識所依，天長地闊棲息稀。", "風霜酸苦稻粱微，毛羽摧落身不肥。", "裴回反顧羣侶違，哀鳴欲下洲渚非。", "江南水闊朝雲多，草長沙軟無網羅。"]'),
('b039de2e-47b6-4186-aae8-a127314e75a6','龍移','韓愈','唐','唐诗','tang','','[]','天昏地黑蛟龍移，雷驚電激雄雌隨。',32,'全唐诗/poet.tang.17000.json','["天昏地黑蛟龍移，雷驚電激雄雌隨。", "清泉百丈化爲土，魚鼈枯死吁可悲。"]'),
('f9447c07-1419-4545-81e2-7b172defd810','雉帶箭','韓愈','唐','唐诗','tang','','[]','原頭火燒靜兀兀，野雉畏鷹出復沒。',80,'全唐诗/poet.tang.17000.json','["原頭火燒靜兀兀，野雉畏鷹出復沒。", "將軍欲以巧伏人，盤馬彎弓惜不發。", "地形漸窄觀者多，雉驚弓滿勁箭加。", "衝人決起百餘尺，紅翎白鏃相傾斜。", "將軍仰笑軍吏賀，五色離披馬前墮。"]'),
('0a7096f2-fea3-4d20-856c-dc77eec999b4','條山蒼','韓愈','唐','唐诗','tang','','["\u63cf\u5199\u6c34", "\u63cf\u5199\u5c71", "\u5199\u5c71", "\u5199\u6c34"]','條山蒼，河水黃。',20,'全唐诗/poet.tang.17000.json','["條山蒼，河水黃。", "浪波沄沄去，松柏在山岡。"]'),
('563399e5-c9e7-4d62-9bc9-002d005e95ae','贈鄭兵曹','韓愈','唐','唐诗','tang','','[]','尊酒相逢十載前，君爲壯夫我少年。',80,'全唐诗/poet.tang.17000.json','["尊酒相逢十載前，君爲壯夫我少年。", "尊酒相逢十載後，我爲壯夫君白首。", "我材與世不相當，戢鱗委翅無復望。", "當今賢俊皆周行，君何爲乎亦遑遑。", "桮行到君莫停手，破除萬事無過酒。"]'),
('746089bc-7a9d-46f1-8ff4-7636f0403347','桃源圖','韓愈','唐','唐诗','tang','','[]','神僊有無何渺茫，桃源之說誠荒唐。',304,'全唐诗/poet.tang.17000.json','["神僊有無何渺茫，桃源之說誠荒唐。", "流水盤迴山百轉，生綃數幅垂中堂。", "武陵太守好事者，題封遠寄南宮下。", "南宮先生忻得之，波濤入筆驅文辭。", "文工畫妙各臻極，異境恍惚移於斯。", "架巖鑿谷開宮室，接屋連牆千萬日。", "嬴顛劉蹶了不聞，地坼天分非所恤。", "種桃處處惟開花，川原近遠蒸紅霞。", "初來猶自念鄉邑，歲久此地還成家。", "漁舟之子來何所，物色相猜更問語。", "大蛇中斷喪前王，羣馬南渡開新主。", "聽終辭絕共悽然，自說經今六百年。", "當時萬事皆眼見，不知幾許猶流傳。", "爭持酒食來相饋，禮數不同樽俎異。", "月明伴宿玉堂空，骨冷魂清無夢寐。", "夜半金雞啁哳鳴，火輪飛出客心驚。", "人間有累不可住，依然離別難爲情。", "船開櫂進一迴顧，萬里蒼蒼煙水暮。", "世俗寧知僞與真，至今傳者武陵人。"]'),
('59dd1b2c-1a22-4b38-b7e3-317385d03d69','東方半明','韓愈','唐','唐诗','tang','','[]','東方半明大星沒，獨有太白配殘月。',50,'全唐诗/poet.tang.17000.json','["東方半明大星沒，獨有太白配殘月。", "嗟爾殘月勿相疑，同光共影須臾期。", "殘月暉暉，太白睒睒。", "雞三號，更五點。"]'),
('76fe79f6-b932-454a-bc36-c44768ec3b1e','贈唐衢','韓愈','唐','唐诗','tang','','[]','虎有爪兮牛有角，虎可搏兮牛可觸。',64,'全唐诗/poet.tang.17000.json','["虎有爪兮牛有角，虎可搏兮牛可觸。", "奈何君獨抱奇材，手把鋤犁餓空谷。", "當今天子急賢良，匭函朝出開明光。", "胡不上書自薦達，坐令四海如虞唐。"]'),
('f7ff814c-b1c6-4b1a-bbb5-c6ebc3c0611c','貞女峽','韓愈','唐','唐诗','tang','','[]','江盤峽束春湍豪，風雷戰鬬魚龍逃。',48,'全唐诗/poet.tang.17000.json','["江盤峽束春湍豪，風雷戰鬬魚龍逃。", "懸流轟轟射水府，一瀉百里翻雲濤。", "漂船擺石萬瓦裂，咫尺性命輕鴻毛。"]'),
('a8a78c3e-05d9-4ccd-823b-6014df3fc388','贈侯喜','韓愈','唐','唐诗','tang','','[]','吾黨侯生字叔起，呼我持竿釣溫水。',240,'全唐诗/poet.tang.17000.json','["吾黨侯生字叔起，呼我持竿釣溫水。", "平明鞭馬出都門，盡日行行荆棘裏。", "溫水微茫絕又流，深如車轍闊容輈。", "蝦蟆跳過雀兒浴，此縱有魚何足求。", "我爲侯生不能已，盤針擘粒投泥滓。", "晡時堅坐到黃昏，手倦目勞方一起。", "暫動還休未可期，蝦行蛭渡似皆疑。", "舉竿引線忽有得，一寸纔分鱗與鬐。", "是日侯生與韓子，良久歎息相看悲。", "我今行事盡如此，此事正好爲吾規。", "半世遑遑就舉選，一名始得紅顏衰。", "人間事勢豈不見，徒自辛苦終何爲。", "便當提攜妻與子，南入箕潁無還時。", "叔起君今氣方銳，我言至切君勿嗤。", "君欲釣魚須遠去，大魚豈肯居沮洳。"]'),
('7be03a6d-ac09-47a6-a6e3-0df5447664ad','古意','韓愈','唐','唐诗','tang','','[]','太華峰頭玉井蓮，開花十丈藕如船。',64,'全唐诗/poet.tang.17000.json','["太華峰頭玉井蓮，開花十丈藕如船。", "冷比雪霜甘比蜜，一片入口沈痾痊。", "我欲求之不憚遠，青壁無路難夤緣。", "安得長梯上摘實，下種七澤根株連。"]'),
('88e98bed-27fa-4dbe-8d6e-e7cb8c3e4d97','八月十五夜贈張功曹','韓愈','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u6d1e\u5ead\u6e56", "\u4e2d\u79cb\u8282", "\u4e03\u8a00\u53e4\u8bd7", "\u6292\u6000", "\u996e\u9152"]','纖雲四卷天無河，清風吹空月舒波。',208,'全唐诗/poet.tang.17000.json','["纖雲四卷天無河，清風吹空月舒波。", "沙平水息聲影絕，一桮相屬君當歌。", "君歌聲酸辭且苦，不能聽終淚如雨。", "洞庭連天九疑高，蛟龍出沒猩鼯號。", "十生九死到官所，幽居默默如藏逃。", "下牀畏蛇食畏藥，海氣濕蟄熏腥臊。", "昨者州前搥大鼓，嗣皇繼聖登夔臯。", "赦書一日行萬里，罪從大辟皆除死。", "遷者追廻流者還，滌瑕蕩垢清朝班。", "州家申名使家抑，坎軻祗得移荆蠻。", "判司卑官不堪說，未免捶楚塵埃間。", "同時輩流多上道，天路幽險難追攀。", "君歌且休聽我歌，我歌今與君殊科。"]'),
('14ae27a0-2641-41e6-8c0a-60a9185f8b6d','謁衡嶽廟遂宿嶽寺題門樓','韓愈','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u767b\u9ad8", "\u4e03\u8a00\u53e4\u8bd7", "\u5bfa\u5e99"]','五嶽祭秩皆三公，四方環鎮嵩當中。',256,'全唐诗/poet.tang.17000.json','["五嶽祭秩皆三公，四方環鎮嵩當中。", "火維地荒足妖怪，天假神柄專其雄。", "噴雲泄霧藏半腹，雖有絕頂誰能窮。", "我來正逢秋雨節，陰氣晦昧無清風。", "潛心默禱若有應，豈非正直能感通。", "須臾靜掃衆峰出，仰見突兀撐青空。", "紫蓋連延接天柱，石廩騰擲堆祝融。", "森然魄動下馬拜，松柏一逕趨靈宮。", "粉牆丹柱動光彩，鬼物圖畫填青紅。", "升階傴僂薦脯酒，欲以菲薄明其衷。", "廟令老人識神意，睢盱偵伺能鞠躬。", "手持桮珓導我擲，云此最吉餘難同。", "竄逐蠻荒幸不死，衣食纔足甘長終。", "侯王將相望久絕，神縱欲福難爲功。", "夜投佛寺上高閣，星月掩暎雲朣朧。", "猿鳴鐘動不知曙，杲杲寒日生於東。"]'),
('fbf39485-2f70-4257-b954-dfbbad49b405','岣嶁山','韓愈','唐','唐诗','tang','','[]','岣嶁山尖神禹碑，字青石赤形模奇。',72,'全唐诗/poet.tang.17000.json','["岣嶁山尖神禹碑，字青石赤形模奇。", "科斗拳身薤倒披，鸞飄鳳泊拏虎螭。", "事嚴跡秘鬼莫窺，道人獨上偶見之。", "我來咨嗟涕漣洏，千搜萬索何處有，森森綠樹猿猱悲。"]'),
('a2f34256-4855-4cd4-9687-7f469e349afa','永貞行','韓愈','唐','唐诗','tang','','[]','君不見太皇諒陰未出令，小人乘時偷國柄。',315,'全唐诗/poet.tang.17000.json','["君不見太皇諒陰未出令，小人乘時偷國柄。", "北軍百萬虎與貔，天子自將非他師。", "一朝奪印付私黨，懍懍朝士何能爲。", "狐鳴梟噪爭署置，睗睒跳踉相嫵媚。", "夜作詔書朝拜官，超資越序曾無難。", "公然白日受賄賂，火齊磊落堆金盤。", "元臣故老不敢語，晝臥涕泣何汍瀾。", "董賢三公誰復惜，侯景九錫行可歎。", "國家功高德且厚，天位未許庸夫干。", "嗣皇卓犖信英主，文如太宗武高祖。", "膺圖受禪登明堂，共流幽州鯀死羽。", "四門肅穆賢俊登，數君匪親豈其朋。", "郎官清要爲世稱，荒郡迫野嗟可矜。", "湖波連天日相騰，蠻俗生梗瘴癘烝。", "江氛嶺祲昏若凝，一蛇兩頭見未曾。", "怪鳥鳴喚令人憎，蟲蟲羣飛夜撲燈。", "雄虺毒螫墮股肱，食中置藥肝心崩。", "左右使令詐難憑，慎勿浪信常兢兢。", "吾嘗同僚情可勝，具書目見非妄徵，嗟爾既往宜爲懲。"]'),
('d9892fa9-0e3e-499c-8351-97cfb1b21f6d','洞庭湖阻風贈張十一署','韓愈','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56", "\u79bb\u522b", "\u98ce", "\u5199\u98ce"]','十月陰氣盛，北風無時休。',120,'全唐诗/poet.tang.17000.json','["十月陰氣盛，北風無時休。", "蒼茫洞庭岸，與子維雙舟。", "霧雨晦爭泄，波濤怒相投。", "犬雞斷四聽，糧絕誰與謀。", "相去不容步，險如礙山丘。", "清談可以飽，夢想接無由。", "男女喧左右，飢啼但啾啾。", "非懷北歸興，何用勝羇愁。", "雲外有白日，寒光自悠悠。", "能令暫開霽，過是吾無求。"]'),
('8236d0ab-42ac-46ca-bc05-8d925e2e1145','李花贈張十一署','韓愈','唐','唐诗','tang','','[]','江陵城西二月尾，花不見桃惟見李。',152,'全唐诗/poet.tang.17000.json','["江陵城西二月尾，花不見桃惟見李。", "風揉雨練雪羞比，波濤翻空杳無涘。", "君知此處花何似，白花倒燭天夜明。", "羣雞驚鳴官吏起，金烏海底初飛來。", "朱輝散射青霞開，迷魂亂眼看不得。", "照耀萬樹繁如堆，念昔少年著遊燕。", "對花豈省曾辭桮，自從流落憂感集。", "欲去未到先思廻，祗今四十已如此。", "後日更老誰論哉，力攜一尊獨就醉，不忍虛擲委黃埃。"]'),
('23700eca-9b4c-4f1d-a75d-3ea1c8b70909','杏花','韓愈','唐','唐诗','tang','','[]','居鄰北郭古寺空，杏花兩株能白紅。',160,'全唐诗/poet.tang.17000.json','["居鄰北郭古寺空，杏花兩株能白紅。", "曲江滿園不可到，看此寧避雨與風。", "二年流竄出嶺外，所見草木多異同。", "冬寒不嚴地恒泄，陽氣發亂無全功。", "浮花浪蘂鎮長有，纔開還落瘴霧中。", "山榴躑躅少意思，照耀黃紫徒爲叢。", "鷓鴣鉤輈猿呌歇，杳杳深谷攢青楓。", "豈如此樹一來翫，若在京國情何窮。", "今旦胡爲忽惆悵，萬片飄泊隨西東。", "明年更發應更好，道人莫忘鄰家翁。"]'),
('5e4dbc15-db20-492e-9de7-d5ebb5111e15','感春四首 一','韓愈','唐','唐诗','tang','','[]','我所思兮在何所，情多地遐兮徧處處。',65,'全唐诗/poet.tang.17000.json','["我所思兮在何所，情多地遐兮徧處處。", "東西南北皆欲往，千江隔兮萬山阻。", "春風吹園雜花開，朝日照屋百鳥語。", "三桮取醉不復論，一生長恨奈何許。"]'),
('91833140-4a32-4508-b50e-2d5e57c4940d','感春四首 二','韓愈','唐','唐诗','tang','','[]','皇天平分成四時，春氣漫誕最可悲。',160,'全唐诗/poet.tang.17000.json','["皇天平分成四時，春氣漫誕最可悲。", "雜花妝林草蓋地，白日坐上傾天維。", "蜂喧鳥咽留不得，紅萼萬片從風吹。", "豈如秋霜雖慘冽，摧落老物誰惜之。", "爲此徑須沽酒飲，自外天地棄不疑。", "近憐李杜無檢束，爛漫長醉多文辭。", "屈原離騷二十五，不肯餔啜糟與醨。", "惜哉此子巧言語，不到聖處寧非癡。", "幸逢堯舜明四目，條理品彙皆得宜。", "平明出門暮歸舍，酩酊馬上知爲誰。"]'),
('921befa8-bb39-4bf2-962d-62e91fa15c50','感春四首 三','韓愈','唐','唐诗','tang','','[]','朝騎一馬出，暝就一牀臥。',48,'全唐诗/poet.tang.17000.json','["朝騎一馬出，暝就一牀臥。", "詩書漸欲拋，節行久已惰。", "冠敧感髮禿，語誤驚齒墮。", "孤負平生心，已矣知何奈。"]'),
('0c77e255-86e3-4307-b43b-d0c05a85103e','感春四首 四','韓愈','唐','唐诗','tang','','[]','我恨不如江頭人，長網橫江遮紫鱗。',128,'全唐诗/poet.tang.17000.json','["我恨不如江頭人，長網橫江遮紫鱗。", "獨宿荒陂射鳧雁，賣納租賦官不嗔。", "歸來歡笑對妻子，衣食自給寧羞貧。", "今者無端讀書史，智慧祗足勞精神。", "畫蛇著足無處用，兩鬢霜白趨埃塵。", "乾愁漫解坐自累，與衆異趣誰相親。", "數桮澆腸雖暫醉，皎皎萬慮醒還新。", "百年未滿不得死，且可勤買拋青春。"]'),
('2ae550b6-e1b7-406d-9834-8ffeb33e8824','寒食日出遊','韓愈','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','李花初發君始病，我往看君花轉盛。',320,'全唐诗/poet.tang.17000.json','["李花初發君始病，我往看君花轉盛。", "走馬城西惆悵歸，不忍千株雪相暎。", "邇來又見桃與梨，交開紅白如爭競。", "可憐物色阻攜手，空展霜縑吟九詠。", "紛紛落盡泥與塵，不共新妝比端正。", "桐華最晚今已繁，君不強起時難更。", "關山遠別固其理，寸步難見始知命。", "憶昔與君同貶官，夜渡洞庭看斗柄。", "豈料生還得一處，引袖拭淚悲且慶。", "各言生死兩追隨，直置心親無貌敬。", "念君又署南荒吏，路指鬼門幽且敻。", "三公盡是知音人，曷不薦賢陛下聖。", "囊空甑倒誰救之，我今一食日還併。", "自然憂氣損天和，安得康強保天性。", "斷鶴兩翅鳴何哀，縶驥四足氣空橫。", "今朝寒食行野外，綠楊帀岸蒲生迸。", "宋玉庭邊不見人，輕浪參差魚動鏡。", "自嗟孤賤足瑕疵，特見放縱荷寬政。", "飲酒寧嫌𧣴底深，題詩尚倚筆鋒勁。", "明宵故欲相就醉，有月莫愁當火令。"]'),
('1ce009e2-990c-44a5-b952-c2a8f6e66a65','憶昨行和張十一','韓愈','唐','唐诗','tang','','[]','憶昨夾鍾之呂初吹灰，上公禮罷元侯廻。',322,'全唐诗/poet.tang.17000.json','["憶昨夾鍾之呂初吹灰，上公禮罷元侯廻。", "車載牲牢甕舁酒，並召賓客延鄒枚。", "腰金首翠光照耀，絲竹迥發清以哀。", "青天白日花草麗，玉斝屢舉傾金罍。", "張君名聲座所屬，起舞先醉長松摧。", "宿酲未解舊痁作，深室靜臥聞風雷。", "自期殞命在春序，屈指數日憐嬰孩。", "危辭苦語感我耳，淚落不揜何漼漼。", "念昔從君渡湘水，大帆夜劃窮高桅。", "陽山鳥路出臨武，驛馬拒地驅頻隤。", "踐蛇茹蠱不擇死，忽有飛詔從天來。", "伾文未揃崖州熾，雖得赦宥恒愁猜。", "近者三姦悉破碎，羽窟無底幽黃能。", "眼中了了見鄉國，知有歸日眉方開。", "今君縱署天涯吏，投檄北去何難哉。", "無妄之憂勿藥喜，一善自足禳千災。", "頭輕目朗肌骨健，古劒新劚磨塵埃。", "殃消禍散百福併，從此直至耉與鮐。", "嵩山東頭伊洛岸，勝事不假須穿栽。", "君當先行我待滿，沮溺可繼窮年推。"]'),
('a72f002a-1c4a-4196-8f07-53c3465a185f','劉生詩','韓愈','唐','唐诗','tang','','[]','生名師命其姓劉，自少軒輊非常儔。',253,'全唐诗/poet.tang.17000.json','["生名師命其姓劉，自少軒輊非常儔。", "棄家如遺來遠遊，東走梁宋暨揚州。", "遂凌大江極東陬，洪濤舂天禹穴幽。", "越女一笑三年留，南逾橫嶺入炎州。", "青鯨高磨波山浮，怪魅炫曜堆蛟虬。", "山㺑讙譟猩猩遊，毒氣爍體黃膏流。", "問胡不歸良有由，美酒傾水{炙火=肉}肥牛。", "妖歌慢舞爛不收，倒心廻腸爲青眸。", "千金邀顧不可酬，乃獨遇之盡綢繆。", "瞥然一餉成十秋，昔鬚未生今白頭。", "五管歷徧無賢侯，迴望萬里還家羞。", "陽山窮邑惟猿猴，手持釣竿遠相投。", "我爲羅列陳前修，芟蒿斬蓬利鋤耰。", "天星廻環數纔周，文學穰穰囷倉稠。", "車輕御良馬力優，咄哉識路行勿休，往取將相酬恩讐。"]'),
('2d58b48b-9486-4f1a-bbef-7d62b62a9104','鄭羣贈簟','韓愈','唐','唐诗','tang','','[]','蘄州笛竹天下知，鄭君所寶尤瓌奇。',192,'全唐诗/poet.tang.17000.json','["蘄州笛竹天下知，鄭君所寶尤瓌奇。", "攜來當晝不得臥，一府傳看黃琉璃。", "體堅色淨又藏節，盡眼凝滑無瑕疵。", "法曹貧賤衆所易，腰腹空大何能爲。", "自從五月困暑濕，如坐深甑遭蒸炊。", "手磨袖拂心語口，慢膚多汗真相宜。", "日暮歸來獨惆悵，有賣直欲傾家資。", "誰謂故人知我意，卷送八尺含風漪。", "呼奴掃地鋪未了，光彩照耀驚童兒。", "青蠅側翅蚤蝨避，肅肅疑有清飆吹。", "倒身甘寢百疾愈，却願天日恒炎曦。", "明珠青玉不足報，贈子相好無時衰。"]'),
('31aafe00-bc07-4f3e-bcfe-bb2591ef1268','豐陵行','韓愈','唐','唐诗','tang','','[]','羽衛煌煌一百里，曉出都門葬天子。',160,'全唐诗/poet.tang.18000.json','["羽衛煌煌一百里，曉出都門葬天子。", "羣臣雜沓馳後先，宮官穰穰來不已。", "是時新秋七月初，金神按節炎氣除。", "清風飄飄輕雨灑，偃蹇旗斾卷以舒。", "逾梁下坂笳鼓咽，嵽嵲遂走玄宮閭。", "哭聲訇天百鳥噪，幽坎晝閉空靈輿。", "皇帝孝心深且遠，資送禮備無贏餘。", "設官置衛鎖嬪妓，供養朝夕象平居。", "臣聞神道尚清淨，三代舊制存諸書。", "墓藏廟祭不可亂，欲言非職知何如。"]'),
('f35849f3-6334-49a3-8733-5fa7b8693356','遊青龍寺贈崔大補闕','韓愈','唐','唐诗','tang','','[]','秋灰初吹季月管，日出卯南暉景短。',320,'全唐诗/poet.tang.18000.json','["秋灰初吹季月管，日出卯南暉景短。", "友生招我佛寺行，正值萬株紅葉滿。", "光華閃壁見神鬼，赫赫炎官張火傘。", "然雲燒樹火實駢，金烏下啄赬虬卵。", "魂翻眼倒忘處所，赤氣沖融無間斷。", "有如流傳上古時，九輪照燭乾坤旱。", "二三道士席其間，靈液屢進玻黎盌。", "忽驚顏色變韶稚，却信靈僊非怪誕。", "桃源迷路竟茫茫，棗下悲歌徒纂纂。", "前年嶺隅鄉思發，躑躅成山開不算。", "去歲羇帆湘水明，霜楓千里隨歸伴。", "猿呼鼯嘯鷓鴣啼，惻耳酸腸難濯澣。", "思君攜手安能得，今者相從敢辭懶。", "由來鈍騃寡參尋，況是儒官飽閑散。", "惟君與我同懷抱，鋤去陵谷置平坦。", "年少得途未要忙，時清諫疏尤宜罕。", "何人有酒身無事，誰家多竹門可款。", "須知節候即風寒，幸及亭午猶妍暖。", "南山逼冬轉清瘦，刻畫圭角出崖窾。", "當憂復被冰雪埋，汲汲來窺戒遲緩。"]'),
('e0f33af0-78ba-4a07-bb14-ff45aeea00c2','贈崔立之評事','韓愈','唐','唐诗','tang','','[]','崔侯文章苦捷敏，高浪駕天輸不盡。',384,'全唐诗/poet.tang.18000.json','["崔侯文章苦捷敏，高浪駕天輸不盡。", "曾從關外來上都，隨身卷軸車連軫。", "朝爲百賦猶鬱怒，暮作千詩轉遒緊。", "搖毫擲簡自不供，頃刻青紅浮海蜃。", "才豪氣猛易語言，往往蛟螭雜螻蚓。", "知音自古稱難遇，世俗乍見那妨哂。", "勿嫌法官未登朝，猶勝赤尉長趨尹。", "時命雖乖心轉壯，技能虛富家逾窘。", "念昔塵埃兩相逢，爭名齟齬持矛楯。", "子時專場誇觜距，余始張軍嚴韅靷。", "爾來但欲保封疆，莫學龐涓怯孫臏。", "竄逐新歸厭聞鬧，齒髮早衰嗟可閔。", "頻蒙怨句刺棄遺，豈有閑官敢推引。", "深藏篋笥時一發，戢戢已多如束筍。", "可憐無益費精神，有似黃金擲虛牝。", "當今聖人求侍從，拔擢杞梓收楛箘。", "東馬嚴徐已奮飛，枚臯即召窮且忍。", "復聞王師西討蜀，霜風冽冽摧朝菌。", "走章馳檄在得賢，燕雀紛拏要鷹隼。", "竊料二途必處一，豈比恒人長蠢蠢。", "勸君韜養待徴招，不用雕琢愁肝腎。", "牆根菊花好沽酒，錢帛縱空衣可準。", "暉暉簷日暖且鮮，摵摵井梧疎更殞。", "高士例須憐麯糵，丈夫終莫生畦畛。"]'),
('5a123c44-bba1-4f01-9dc9-715a25da8eea','送區弘南歸','韓愈','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','穆昔南征軍不歸，蟲沙猿鶴伏以飛。',320,'全唐诗/poet.tang.18000.json','["穆昔南征軍不歸，蟲沙猿鶴伏以飛。", "洶洶洞庭莽翠微，九疑鑱天荒是非。", "野有象犀水貝璣，分散百寶人士稀。", "我遷於南日周圍，來見者衆莫伊俙。", "爰有區子熒熒暉，觀以彝訓或從違。", "我念前人譬葑菲，落以斧引以纆徽。", "雖有不逮驅騑騑，或採於薄漁於磯。", "服役不辱言不譏，從我荆州來京畿。", "離其母妻絕因依，嗟我道不能自肥。", "子雖勤苦終何希，王都觀闕雙巍巍。", "騰蹋衆駿事鞍鞿，佩服上色紫與緋。", "獨子之節可嗟唏，母附書至妻寄衣。", "開書拆衣淚痕晞，雖不敕還情庶幾。", "朝暮盤羞惻庭闈，幽房無人感伊威。", "人生此難餘可祈，子去矣時若發機。", "蜃沈海底氣昇霏，彩雉野伏朝扇翬。", "處子窈窕王所妃，苟有令德隱不腓。", "況今天子鋪德威，蔽能者誅薦受禨。", "出送撫背我涕揮，行行正直慎脂韋。", "業成志樹來頎頎，我當爲子言天扉。"]'),
('98b0fd3d-e436-43bb-98b3-3949c75a902a','三星行','韓愈','唐','唐诗','tang','','[]','我生之辰，月宿南斗。',92,'全唐诗/poet.tang.18000.json','["我生之辰，月宿南斗。", "牛奮其角，箕張其口。", "牛不見服箱，斗不挹酒漿。", "箕獨有神靈，無時停簸揚。", "無善名已聞，無惡聲已讙。", "名聲相乘除，得少失有餘。", "三星各在天，什伍東西陳。", "嗟汝牛與斗，汝獨不能神。"]'),
('30cacc20-7b61-4c3b-af5b-cd0e154a9672','剝啄行','韓愈','唐','唐诗','tang','','[]','剝剝啄啄，有客至門。',190,'全唐诗/poet.tang.18000.json','["剝剝啄啄，有客至門。", "我不出應，客去而嗔。", "從者語我，子胡爲然。", "我不厭客，困於語言。", "欲不出納，以堙其源。", "空堂幽幽，有秸有莞。", "門以兩板，叢書於間。", "窅窅深塹，其墉甚完。", "彼寧可隳，此不可干。", "從者語我，嗟子誠難。", "子雖云爾，其口益蕃。", "我爲子謀，有萬其全。", "凡今之人，急名與官。", "子不引去，與爲波瀾。", "雖不開口，雖不開關。", "變化咀嚼，有鬼有神。", "今去不勇，其如後艱。", "我謝再拜，汝無復云。", "往追不及，來不有年。"]'),
('30e1b184-2377-472a-a27d-5151bc27b391','青青水中蒲三首 一','韓愈','唐','唐诗','tang','','[]','青青水中蒲，下有一雙魚。',24,'全唐诗/poet.tang.18000.json','["青青水中蒲，下有一雙魚。", "君今上隴去，我在與誰居。"]'),
('9f7b9119-e202-4288-b6b0-91642072dbf4','青青水中蒲三首 二','韓愈','唐','唐诗','tang','','[]','青青水中蒲，長在水中居。',24,'全唐诗/poet.tang.18000.json','["青青水中蒲，長在水中居。", "寄語浮萍草，相隨我不如。"]'),
('46f0b9f1-9390-4b75-9386-54b48ec57b5f','青青水中蒲三首 三','韓愈','唐','唐诗','tang','','[]','青青水中蒲，葉短不出水。',24,'全唐诗/poet.tang.18000.json','["青青水中蒲，葉短不出水。", "婦人不下堂，行子在萬里。"]'),
('530ab82c-db31-45ed-bab1-01599eb9d5fe','孟東野失子','韓愈','唐','唐诗','tang','','[]','失子將何尤，吾將上尤天。',288,'全唐诗/poet.tang.18000.json','["失子將何尤，吾將上尤天。", "女實主下人，與奪一何偏。", "彼於女何有，乃令蕃且延。", "此獨何罪辜，生死旬日間。", "上呼無時聞，滴地淚到泉。", "地祇爲之悲，瑟縮久不安。", "乃呼大靈龜，騎雲款天門。", "問天主下人，薄厚胡不均。", "天曰天地人，由來不相關。", "吾懸日與月，吾繫星與辰。", "日月相噬齧，星辰踣而顛。", "吾不女之罪，知非女由因。", "且物各有分，孰能使之然。", "有子與無子，禍福未可原。", "魚子滿母腹，一一欲誰憐。", "細腰不自乳，舉族常孤鰥。", "鴟梟啄母腦，母死子始翻。", "蝮蛇生子時，坼裂腸與肝。", "好子雖云好，未還恩與勤。", "惡子不可說，鴟梟蝮蛇然。", "有子且勿喜，無子固勿歎。", "上聖不待敎，賢聞語而遷。", "下愚聞語惑，雖敎無由悛。", "大靈頓頭受，即日以命還。"]'),
('63043fd8-cf4d-402e-86a0-209e54a5338d','陸渾山火和皇甫湜用其韻','韓愈','唐','唐诗','tang','','[]','皇甫補官古賁渾，時當玄冬澤乾源。',384,'全唐诗/poet.tang.18000.json','["皇甫補官古賁渾，時當玄冬澤乾源。", "山狂谷很相吐吞，風怒不休何軒軒。", "擺磨出火以自燔，有聲夜中驚莫原。", "天跳地踔顛乾坤，赫赫上照窮崖垠。", "截然高周燒四垣，神焦鬼爛無逃門。", "三光弛隳不復暾，虎熊麋豬逮猴猿。", "水龍鼉龜魚與黿，鴉鴟雕鷹雉鵠鵾。", "燖炰煨爊孰飛奔，祝融告休酌卑尊。", "錯陳齊玫闢華園，芙蓉披猖塞鮮繁。", "千鍾萬鼓咽耳喧，攢雜啾嚄沸篪塤。", "彤幢絳旃紫纛旛，炎官熱屬朱冠褌。", "髹其肉皮通䏶臀，頹胸垤腹車掀轅。", "緹顏靺股豹兩鞬，霞車虹靷日轂轓。", "丹蕤縓蓋緋繙㠾，紅帷赤幕羅脤膰。", "𥁃池波風肉陵屯，谽呀鉅壑頗黎盆。", "豆登五山瀛四尊，熙熙釂醻笑語言。", "雷公擘山海水翻，齒牙嚼齧舌腭反。", "電光䃸磹赬目䁔，頊冥收威避玄根。", "斥棄輿馬背厥孫，縮身潛喘拳肩跟。", "君臣相憐加愛恩，命黑螭偵焚其元。", "天闕悠悠不可援，夢通上帝血面論。", "側身欲進叱於閽，帝賜九河湔涕痕。", "又詔巫陽反其魂，徐命之前問何冤。", "火行於冬古所存，我如禁之絕其飧。"]'),
('e7daab7d-768f-40a6-9cdc-73b79b0760d4','縣齋讀書','韓愈','唐','唐诗','tang','','[]','出宰山水縣，讀書松桂林。',96,'全唐诗/poet.tang.18000.json','["出宰山水縣，讀書松桂林。", "蕭條捐末事，邂逅得初心。", "哀狖醒俗耳，清泉潔塵襟。", "詩成有共賦，酒熟無孤斟。", "青竹時默釣，白雲日幽尋。", "南方本多毒，北客恒懼侵。", "謫譴甘自守，滯留愧難任。", "投章類縞帶，佇答逾兼金。"]'),
('1d70922b-4e1b-4eb5-ae5b-79df44859f57','新竹','韓愈','唐','唐诗','tang','','[]','筍添南堦竹，日日成清閟。',96,'全唐诗/poet.tang.18000.json','["筍添南堦竹，日日成清閟。", "縹節已儲霜，黃苞猶揜翠。", "出欄抽五六，當戶羅三四。", "高標陵秋嚴，貞色奪春媚。", "稀生巧補林，併出疑爭地。", "縱橫乍依行，爛熳忽無次。", "風枝未飄吹，露粉先涵淚。", "何人可攜翫，清景空瞪視。"]'),
('7ff205d9-e2f9-4721-910c-90213458841a','晚菊','韓愈','唐','唐诗','tang','','[]','少年飲酒時，踊躍見菊花。',48,'全唐诗/poet.tang.18000.json','["少年飲酒時，踊躍見菊花。", "今來不復飲，每見恒咨嗟。", "佇立摘滿手，行行把歸家。", "此時無與語，棄置奈悲何。"]'),
('01239a8e-37d4-4f39-bd57-5b8c7227618d','落齒','韓愈','唐','唐诗','tang','','[]','去年落一牙，今年落一齒。',216,'全唐诗/poet.tang.18000.json','["去年落一牙，今年落一齒。", "俄然落六七，落勢殊未已。", "餘存皆動搖，盡落應始止。", "憶初落一時，但念豁可恥。", "及至落二三，始憂衰即死。", "每一將落時，懔懔恒在已。", "叉牙妨食物，顛倒怯漱水。", "終焉捨我落，意與崩山比。", "今來落既熟，見落空相似。", "餘存二十餘，次第知落矣。", "儻常歲落一，自足支兩紀。", "如其落併空，與漸亦同指。", "人言齒之落，壽命理難恃。", "我言生有涯，長短俱死爾。", "人言齒之豁，左右驚諦視。", "我言莊周云，水雁各有喜。", "語訛默固好，嚼廢軟還美。", "因歌遂成詩，持用詫妻子。"]'),
('e6213326-0c71-4a26-b5ee-344172e0656f','哭楊兵部凝陸歙州參','韓愈','唐','唐诗','tang','','[]','人皆期七十，纔半豈蹉跎。',48,'全唐诗/poet.tang.18000.json','["人皆期七十，纔半豈蹉跎。", "併出知己淚，自然白髮多。", "晨興爲誰慟，還坐久滂沱。", "論文與晤語，已矣可如何。"]'),
('81c89efe-d541-488b-b257-b03b53ea66d6','苦寒','韓愈','唐','唐诗','tang','','[]','四時各平分，一氣不可兼。',288,'全唐诗/poet.tang.18000.json','["四時各平分，一氣不可兼。", "隆寒奪春序，顓頊固不廉。", "太昊弛維綱，畏避但守謙。", "遂令黃泉下，萌牙夭句尖。", "草木不復抽，百味失苦甜。", "凶飆攪宇宙，鋩刃甚割砭。", "日月雖云尊，不能活烏蟾。", "羲和送日出，恇怯頻窺覘。", "炎帝持祝融，呵噓不相炎。", "而我當此時，恩光何由沾。", "肌膚生鱗甲，衣被如刀鐮。", "氣寒鼻莫齅，血凍指不拈。", "濁醪沸入喉，口角如銜箝。", "將持匕箸食，觸指如排籤。", "侵爐不覺暖，熾炭屢已添。", "探湯無所益，何況纊與縑。", "虎豹僵穴中，蛟螭死幽潛。", "熒惑喪纏次，六龍冰脫髯。", "芒碭大包內，生類恐盡殲。", "啾啾窗間雀，不知已微纖。", "舉頭仰天鳴，所願晷刻淹。", "不如彈射死，却得親炰燖。", "鸞皇苟不存，爾固不在占。", "其餘蠢動儔，俱死誰恩嫌。"]'),
('518d5f1a-fe1e-4fdd-8631-d707c55f836d','和虞部盧四酬翰林錢七赤藤杖歌','韓愈','唐','唐诗','tang','','[]','赤藤爲杖世未窺，臺郎始攜自滇池。',176,'全唐诗/poet.tang.18000.json','["赤藤爲杖世未窺，臺郎始攜自滇池。", "滇王掃宮避使者，跪進再拜語嗢咿。", "繩橋拄過免傾墮，性命造次蒙扶持。", "途經百國皆莫識，君臣聚觀逐旌麾。", "共傳滇神出水獻，赤龍拔鬚血淋漓。", "又云羲和操火鞭，暝到西極睡所遺。", "幾重包裹自題署，不以珍怪誇荒夷。", "歸來捧贈同舍子，浮光照手欲把疑。", "空堂晝眠倚牖戶，飛電著壁搜蛟螭。", "南宮清深禁闈密，唱和有類吹塤篪。", "妍辭麗句不可繼，見寄聊且慰分司。"]'),
('b0e75248-a3b6-4d4e-922b-26db7503b686','崔十六少府攝伊陽以詩及書見投因酬三十韻','韓愈','唐','唐诗','tang','','[]','崔君初來時，相識頗未慣。',288,'全唐诗/poet.tang.18000.json','["崔君初來時，相識頗未慣。", "但聞赤縣尉，不比博士慢。", "賃屋得連牆，往來忻莫間。", "我時亦新居，觸事苦難辦。", "蔬飱要同喫，破襖請來綻。", "謂言安堵後，貸借更何患。", "不知孤遺多，舉族仰薄宦。", "有時未朝餐，得米日已晏。", "隔牆聞讙呼，衆口極鵝雁。", "前計頓乖張，居然見真贋。", "嬌兒好眉眼，褲脚凍兩骭。", "捧書隨諸兄，累累兩角丱。", "冬惟茹寒齏，秋始識瓜瓣。", "問之不言飢，飫若厭芻豢。", "才名三十年，久合居給諫。", "白頭趨走裏，閉口絕謗訕。", "府公舊同袍，拔擢宰山澗。", "寄詩雜詼俳，有類說鵬鷃。", "上言酒味酸，冬衣竟未擐。", "下言人吏稀，惟足彪與虥。", "又言致豬鹿，此語乃善幻。", "三年國子師，腸肚習藜莧。", "況住洛之涯，魴鱒可罩汕。", "肯效屠門嚼，久嫌弋者篡。"]'),
('161aef05-ddfa-4aa0-a282-75018f245eaf','送侯參謀赴河中幕','韓愈','唐','唐诗','tang','','[]','憶昔初及第，各以少年稱。',290,'全唐诗/poet.tang.18000.json','["憶昔初及第，各以少年稱。", "君頤始生鬚，我齒清如冰。", "爾時心氣壯，百事謂己能。", "一別詎幾何，忽如隔晨興。", "我齒豁可鄙，君顏老可憎。", "相逢風塵中，相視迭嗟矜。", "幸同學省官，末路再得朋。", "東司絕敎授，遊[宴]以爲恒。", "秋漁蔭密樹，夜博然明燈。", "雪逕抵樵叟，風廊折談僧。", "陸渾桃花間，有湯沸如烝。", "三月崧少步，躑躅紅千層。", "洲沙厭晚坐，嶺壁窮晨升。", "沈冥不計日，爲樂不可勝。", "遷滿一已異，乖離坐難憑。", "行行事結束，人馬何蹻騰。", "感激生膽勇，從軍豈嘗曾。", "洸洸司徒公，天子爪與肱。", "提師十萬餘，四海欽風稜。", "河北兵未進，蔡州師新薨。", "曷不請掃除，活彼黎與烝。", "鄙夫誠怯弱，受恩媿徒弘。", "猶思脫儒冠，棄死取先登。", "又欲面言事，上書求詔徴。"]'),
('1f3bb0ed-fd03-487b-8d59-519db3076dc0','東都遇春','韓愈','唐','唐诗','tang','','[]','少年氣真狂，有意與春競。',288,'全唐诗/poet.tang.18000.json','["少年氣真狂，有意與春競。", "行逢二三月，九州花相暎。", "川原曉服鮮，桃李晨妝靚。", "荒乘不知疲，醉死豈辭病。", "飲噉惟所便，文章倚豪橫。", "爾來曾幾時，白髮忽滿鏡。", "舊遊喜乖張，新輩足嘲評。", "心腸一變化，羞見時節盛。", "得閑無所作，貴欲辭視聽。", "深居疑避仇，默臥如當暝。", "朝曦入牖來，鳥喚昏不醒。", "爲生鄙計算，鹽米告屢罄。", "坐疲都忘起，冠側懶復正。", "幸蒙東都官，獲離機與穽。", "乖慵遭傲僻，漸染生弊性。", "既去焉能追，有來猶莫騁。", "有船魏王池，往往縱孤泳。", "水容與天色，此處皆綠淨。", "岸樹共紛披，渚牙相緯經。", "懷歸苦不果，即事取幽迸。", "貪求匪名利，所得亦已併。", "悠悠度朝昏，落落捐季孟。", "羣公一何賢，上戴天子聖。", "謀謨收禹績，四面出雄勁。"]'),
('5fd5aa26-9bbd-4f6c-964e-6d91f2491865','感春五首 一','韓愈','唐','唐诗','tang','','[]','辛夷高花最先開，青天露坐始此廻。',64,'全唐诗/poet.tang.18000.json','["辛夷高花最先開，青天露坐始此廻。", "已呼孺人戛鳴瑟，更遣稚子傳清杯。", "選壯軍興不爲用，坐狂朝論無由陪。", "如今到死得閑處，還有詩賦歌康哉。"]'),
('0ac43513-de5f-451f-b968-71d3ff89ac64','感春五首 二','韓愈','唐','唐诗','tang','','[]','洛陽東風幾時來，川波岸柳春全廻。',64,'全唐诗/poet.tang.18000.json','["洛陽東風幾時來，川波岸柳春全廻。", "宮門一鎖不復啓，雖有九陌無塵埃。", "策馬上橋朝日出，樓闕赤白正崔嵬。", "孤吟屢闋莫與和，寸恨至短誰能裁。"]'),
('03fc8e4c-ad4a-4d6e-8896-50768d9c3b05','感春五首 三','韓愈','唐','唐诗','tang','','[]','春田可耕時已催，王師北討何當廻。',64,'全唐诗/poet.tang.18000.json','["春田可耕時已催，王師北討何當廻。", "放車載草農事濟，戰馬苦飢誰念哉。", "蔡州納節舊將死，起居諫議聯翩來。", "朝廷未省有遺策，肯不垂意缾與罍。"]'),
('1ba6448d-dc28-4d31-88be-43e29951be6d','感春五首 四','韓愈','唐','唐诗','tang','','[]','前隨杜尹拜表廻，笑言溢口何歡咍。',64,'全唐诗/poet.tang.18000.json','["前隨杜尹拜表廻，笑言溢口何歡咍。", "孔丞別我適臨汝，風骨峭峻遺塵埃。", "音容不接祗隔夜，凶訃詎可相尋來。", "天公高居鬼神惡，欲保性命誠難哉。"]'),
('d096b273-f8f4-4c86-bd39-4e915e2390a4','感春五首 五','韓愈','唐','唐诗','tang','','[]','辛夷花房忽全開，將衰正盛須頻來。',64,'全唐诗/poet.tang.18000.json','["辛夷花房忽全開，將衰正盛須頻來。", "清晨輝輝燭霞日，薄暮耿耿和煙埃。", "朝明夕暗已足歎，況乃滿地成摧頹。", "迎繁送謝別有意，誰肯留戀少環廻。"]'),
('a3a4ba02-d97f-4284-a5ad-2f2519423a66','酬裴十六功曹巡府西驛塗中見寄','韓愈','唐','唐诗','tang','','[]','相公罷論道，聿至活東人。',168,'全唐诗/poet.tang.18000.json','["相公罷論道，聿至活東人。", "御史坐言事，作吏府中塵。", "遂令河南治，今古無儔倫。", "四海日富庶，道途隘蹄輪。", "府西三百里，候館同魚鱗。", "相公謂御史，勞子去自巡。", "是時山水秋，光景何鮮新。", "哀鴻鳴清耳，宿霧褰高旻。", "遺我行旅詩，軒軒有風神。", "譬如黃金盤，照耀荆璞真。", "我來亦已幸，事賢友其仁。", "持竿洛水側，孤坐屢窮辰。", "多才自勞苦，無用祗因循。", "辭免期匪遠，行行及山春。"]'),
('990f8b56-0bff-467c-8a10-ddc620c9db41','燕河南府秀才得生字','韓愈','唐','唐诗','tang','','[]','吾皇紹祖烈，天下再太平。',240,'全唐诗/poet.tang.18000.json','["吾皇紹祖烈，天下再太平。", "詔下諸郡國，歲貢鄉曲英。", "元和五年冬，房公尹東京。", "功曹上言公，是月當登名。", "乃選二十縣，試官得鴻生。", "羣儒負己材，相賀簡擇精。", "怒起簸羽翮，引吭吐鏗轟。", "此都自周公，文章繼名聲。", "自非絕殊尤，難使耳目驚。", "今者遭震薄，不能出聲鳴。", "鄙夫忝縣尹，愧慄難爲情。", "惟求文章寫，不敢妬與爭。", "還家敕妻兒，具此煎炰烹。", "柿紅蒲萄紫，肴果相扶檠。", "芳荼出蜀門，好酒濃且清。", "何能充歡燕，庶以露厥誠。", "昨聞詔書下，權公作邦楨。", "文人得其職，文道當大行。", "陰風攪短日，冷雨澀不晴。", "勉哉戒徒馭，家國遲子榮。"]'),
('374ebe7b-244f-4d37-b7dc-baa3da2a3556','送李翺','韓愈','唐','唐诗','tang','','[]','廣州萬里途，山重江逶迤。',84,'全唐诗/poet.tang.18000.json','["廣州萬里途，山重江逶迤。", "行行何時到，誰能定歸期。", "揖我出門去，顏色異恒時。", "雖云有追送，足跡絕自茲。", "人生一世間，不自張與弛。", "譬如浮江木，縱橫豈自知。", "寧懷別時苦，勿作別後思。"]'),
('af65cc35-b1d3-4469-8614-4a2277ea2436','送石洪處士赴河陽幕得起字','韓愈','唐','唐诗','tang','','[]','長把種樹書，人云避世士。',72,'全唐诗/poet.tang.18000.json','["長把種樹書，人云避世士。", "忽騎將軍馬，自號報恩子。", "風雲入壯懷，泉石別幽耳。", "鉅鹿師欲老，常山險猶恃。", "豈惟彼相憂，固是吾徒恥。", "去去事方急，酒行可以起。"]'),
('fe066ba7-1212-4923-a9ab-49488d245b29','送湖南李正字歸','韓愈','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','長沙入楚深，洞庭值秋晚。',72,'全唐诗/poet.tang.18000.json','["長沙入楚深，洞庭值秋晚。", "人隨鴻雁少，江共蒹葭遠。", "歷歷余所經，悠悠子當返。", "孤遊懷耿介，旅宿夢婉娩。", "風土稍殊音，魚蝦日異飯。", "親交俱在此，誰與同息偃。"]'),
('1bbb6433-3602-4ed6-a136-c44d90bf46d6','辛卯年雪','韓愈','唐','唐诗','tang','','[]','元和六年春，寒氣不肯歸。',120,'全唐诗/poet.tang.18000.json','["元和六年春，寒氣不肯歸。", "河南二月末，雪花一尺圍。", "崩騰相排拶，龍鳳交橫飛。", "波濤何飄揚，天風吹旛旂。", "白帝盛羽衛，鬖髿振裳衣。", "白霓先啓途，從以萬玉妃。", "翕翕陵厚載，譁譁弄陰機。", "生平未曾見，何暇議是非。", "或云豐年祥，飽食可庶幾。", "善禱吾所慕，誰言寸誠微。"]'),
('7a75f95e-9e6a-4060-8b7e-511bcde7fad3','醉留東野','韓愈','唐','唐诗','tang','','["\u6292\u60c5", "\u53cb\u8c0a"]','昔年因讀李白杜甫詩，長恨二人不相從。',116,'全唐诗/poet.tang.18000.json','["昔年因讀李白杜甫詩，長恨二人不相從。", "吾與東野生並世，如何復躡二子蹤。", "東野不得官，白首誇龍鍾。", "韓子稍姦黠，自慙青蒿倚長松。", "低頭拜東野，願得終始如駏蛩。", "東野不廻頭，有如寸筳撞鉅鐘。", "我願身爲雲，東野變爲龍。", "四方上下逐東野，雖有離別無由逢。"]'),
('d45b2bb2-b2ab-4027-b8b0-293cf3d0c0b9','李花二首 一','韓愈','唐','唐诗','tang','','[]','平旦入西園，梨花數株若矜夸。',124,'全唐诗/poet.tang.18000.json','["平旦入西園，梨花數株若矜夸。", "旁有一株李，顏色慘慘似含嗟。", "問之不肯道所以，獨繞百帀至日斜。", "忽憶前時經此樹，正見芳意初萌牙。", "奈何趁酒不省錄，不見玉枝攢霜葩。", "泫然爲汝下雨淚，無由反斾羲和車。", "東風來吹不解顏，蒼茫夜氣生相遮。", "冰盤夏薦碧實脆，斥去不御慚其花。"]'),
('07b07804-4b6a-41f7-8a62-542e60a6a2a9','李花二首 二','韓愈','唐','唐诗','tang','','[]','當春天地爭奢華，洛陽園苑尤紛拏。',112,'全唐诗/poet.tang.18000.json','["當春天地爭奢華，洛陽園苑尤紛拏。", "誰將平地萬堆雪，翦刻作此連天花。", "日光赤色照未好，明月暫入都交加。", "夜領張徹投盧仝，乘雲共至玉皇家。", "長姬香御四羅列，縞裙練帨無等差。", "靜濯明妝有所奉，顧我未肯置齒牙。", "清寒瑩骨肝膽醒，一生思慮無由邪。"]'),
('d2a64b68-43ba-4194-94ea-8db5169d73ee','招楊之罘','韓愈','唐','唐诗','tang','','[]','柏生兩石間，萬歲終不大。',216,'全唐诗/poet.tang.18000.json','["柏生兩石間，萬歲終不大。", "野馬不識人，難以駕車蓋。", "柏移就平地，馬羈入廄中。", "馬思自由悲，柏有傷根容。", "傷根柏不死，千丈日以至。", "馬悲罷還樂，振迅矜鞍轡。", "之罘南山來，文字得我驚。", "館置使讀書，日有求歸聲。", "我令之罘歸，失得柏與馬。", "之罘別我去，計出柏馬下。", "我自之罘歸，入門思而悲。", "之罘別我去，能不思我爲。", "灑埽縣中居，引水經竹間。", "囂譁所不及，何異山中閑。", "前陳百家書，食有肉與魚。", "先王遺文章，綴緝實在余。", "禮稱獨學陋，易貴不遠復。", "作詩招之罘，晨夕抱飢渴。"]'),
('e1404531-b21b-4e48-b715-9a9ead6cf56c','寄盧仝','韓愈','唐','唐诗','tang','','[]','玉川先生洛城裏，破屋數間而已矣。',384,'全唐诗/poet.tang.18000.json','["玉川先生洛城裏，破屋數間而已矣。", "一奴長鬚不裹頭，一婢赤脚老無齒。", "辛勤奉養十餘人，上有慈親下妻子。", "先生結髮憎俗徒，閉門不出動一紀。", "至今鄰僧乞米送，僕忝縣尹能不恥。", "俸錢供給公私餘，時致薄少助祭祀。", "勸參留守謁大尹，言語纔及輙掩耳。", "水北山人得名聲，去年去作幕下士。", "水南山人又繼往，鞍馬僕從塞閭里。", "少室山人索價高，兩以諫官徴不起。", "彼皆刺口論世事，有力未免遭驅使。", "先生事業不可量，惟用法律自繩己。", "春秋三傳束高閣，獨抱遺經究終始。", "往年弄筆嘲同異，怪辭驚衆謗不已。", "近來自說尋坦途，猶上虛空跨綠駬。", "去年生兒名添丁，意令與國充耘耔。", "國家丁口連四海，豈無農夫親耒耜。", "先生抱才終大用，宰相未許終不仕。", "假如不在陳力列，立言垂範亦足恃。", "苗裔當蒙十世宥，豈謂貽厥無基阯。", "故知忠孝生天性，潔身亂倫安足擬。", "昨晚長鬚來下狀，隔牆惡少惡難似。", "每騎屋山下窺闞，渾舍驚怕走折趾。", "憑依婚媾欺官吏，不信令行能禁止。"]'),
('ef723493-47e5-4466-bc49-c2cecd0bcb63','酬司門盧四兄雲夫院長望秋作','韓愈','唐','唐诗','tang','','[]','長安雨洗新秋出，極目寒鏡開塵函。',240,'全唐诗/poet.tang.18000.json','["長安雨洗新秋出，極目寒鏡開塵函。", "終南曉望蹋龍尾，倚天更覺青巉巉。", "自知短淺無所補，從事久此穿朝衫。", "歸來得便即遊覽，暫似壯馬脫重銜。", "曲江荷花蓋十里，江湖生目思莫緘。", "樂遊下矚無遠近，綠槐萍合不可芟。", "白首寓居誰借問，平地寸步扃雲巖。", "雲夫吾兄有狂氣，嗜好與俗殊酸鹹。", "日來省我不肯去，論詩說賦相諵諵。", "望秋一章已驚絕，猶言低抑避謗讒。", "若使乘酣騁雄怪，造化何以當鐫劖。", "嗟我小生值強伴，怯膽變勇神明鑒。", "馳坑跨谷終未悔，爲利而止真貪饞。", "高揖羣公謝名譽，遠追甫白感至諴。", "樓頭完月不共宿，其奈就缺行攕攕。"]'),
('3e9f5dd2-0524-495f-8a52-94212ad97ed4','誰氏子','韓愈','唐','唐诗','tang','','[]','非癡非狂誰氏子，去入王屋稱道士。',160,'全唐诗/poet.tang.18000.json','["非癡非狂誰氏子，去入王屋稱道士。", "白頭老母遮門啼，挽斷衫袖留不止。", "翠眉新婦年二十，載送還家哭穿市。", "或云欲學吹鳳笙，所慕靈妃嫓蕭史。", "又云時俗輕尋常，力行險怪取貴仕。", "神僊雖然有傳說，知者盡知其妄矣。", "聖君賢相安可欺，乾死窮山竟何俟。", "嗚呼余心誠豈弟，願往敎誨究終始。", "罰一勸百政之經，不從而誅未晚耳。", "誰其友親能哀憐，寫吾此詩持送似。"]'),
('6d44bf2d-b57a-447f-a0ee-57f512d2727d','河南令舍池臺','韓愈','唐','唐诗','tang','','[]','灌池纔盈五六丈，築臺不過七八尺。',64,'全唐诗/poet.tang.18000.json','["灌池纔盈五六丈，築臺不過七八尺。", "欲將層級壓籬落，未許波瀾量斗石。", "規摹雖巧何足誇，景趣不遠真可惜。", "長令人吏遠趨走，已有蛙黽助狼籍。"]'),
('76461079-8151-4e54-9be8-f650b406a657','送無本師歸范陽','韓愈','唐','唐诗','tang','','[]','無本於爲文，身大不及膽。',240,'全唐诗/poet.tang.18000.json','["無本於爲文，身大不及膽。", "吾嘗示之難，勇往無不敢。", "蛟龍弄角牙，造次欲手攬。", "衆鬼囚大幽，下覰襲玄窞。", "天陽熙四海，注視首不頷。", "鯨鵬相摩窣，兩舉快一噉。", "夫豈能必然，固已謝黯黮。", "狂詞肆滂葩，低昂見舒慘。", "姦窮怪變得，往往造平澹。", "蠭蟬碎錦纈，綠池披菡萏。", "芝英擢荒榛，孤翮起連菼。", "家住幽都遠，未識氣先感。", "來尋吾何能，無殊嗜昌歜。", "始見洛陽春，桃枝綴紅糝。", "遂來長安里，時卦轉習坎。", "老嬾無鬬心，久不事鉛槧。", "欲以金帛酬，舉室常顑頷。", "念當委我去，雪霜刻以憯。", "獰飆攪空衢，天地與頓撼。", "勉率吐歌詩，慰女別後覽。"]'),
('1b9b8047-2410-47ae-a24c-aad7342b338f','石鼓歌','韓愈','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4e03\u8a00\u53e4\u8bd7", "\u9898\u548f"]','張生手持石鼓文，勸我試作石鼓歌。',384,'全唐诗/poet.tang.18000.json','["張生手持石鼓文，勸我試作石鼓歌。", "少陵無人謫仙死，才薄將奈石鼓何。", "周綱陵遲四海沸，宣王憤起揮天戈。", "大開明堂受朝賀，諸侯劒佩鳴相磨。", "蒐于岐陽騁雄俊，萬里禽獸皆遮羅。", "鐫功勒成告萬世，鑿石作鼓隳嵯峨。", "從臣才藝咸第一，揀選撰刻留山阿。", "雨淋日炙野火燎，鬼物守護煩撝呵。", "公從何處得紙本，毫髮盡備無差訛。", "辭嚴義密讀難曉，字體不類隸與科。", "年深豈免有缺畫，快劒斫斷生蛟鼉。", "鸞翔鳳翥衆僊下，珊瑚碧樹交枝柯。", "金繩鐵索鎖紐壯，古鼎躍水龍騰梭。", "陋儒編詩不收入，二雅褊迫無委蛇。", "孔子西行不到秦，掎摭星宿遺羲娥。", "嗟予好古生苦晚，對此涕淚雙滂沱。", "憶昔初蒙博士徴，其年始改稱元和。", "故人從軍在右輔，爲我度量掘臼科。", "濯冠沐浴告祭酒，如此至寶存豈多。", "氊包席裹可立致，十鼓祗載數駱駝。", "薦諸太廟比郜鼎，光價豈止百倍過。", "聖恩若許留太學，諸生講解得切磋。", "觀經鴻都尚填咽，坐見舉國來奔波。", "剜苔剔蘚露節角，安置妥帖平不頗。"]'),
('2b07aab6-3a5c-44ca-b474-70083158bed5','雙鳥詩','韓愈','唐','唐诗','tang','','[]','雙鳥海外來，飛飛到中州。',288,'全唐诗/poet.tang.18000.json','["雙鳥海外來，飛飛到中州。", "一鳥落城市，一鳥集巖幽。", "不得相伴鳴，爾來三千秋。", "兩鳥各閉口，萬象銜口頭。", "春風卷地起，百鳥皆飄浮。", "兩鳥忽相逢，百日鳴不休。", "有耳聒皆聾，有口反自羞。", "百舌舊饒聲，從此恒低頭。", "得病不呻喚，泯默至死休。", "雷公告天公，百物須膏油。", "自從兩鳥鳴，聒亂雷聲收。", "鬼神怕嘲詠，造化皆停留。", "草木有微情，挑抉示九州。", "蟲鼠誠微物，不堪苦誅求。", "不停兩鳥鳴，百物皆生愁。", "不停兩鳥鳴，自此無春秋。", "不停兩鳥鳴，日月難旋輈。", "不停兩鳥鳴，大法失九疇。", "周公不爲公，孔丘不爲丘。", "天公怪兩鳥，各捉一處囚。", "百蟲與百鳥，然後鳴啾啾。", "兩鳥既別處，閉聲省愆尤。", "朝食千頭龍，暮食千頭牛。", "朝飲河生塵，暮飲海絕流。"]'),
('a2aa754f-6e6a-4eea-8361-bfef283409ec','贈劉師服','韓愈','唐','唐诗','tang','','[]','羨君齒牙牢且潔，大肉硬餅如刀截。',160,'全唐诗/poet.tang.18000.json','["羨君齒牙牢且潔，大肉硬餅如刀截。", "我今呀豁落者多，所存十餘皆兀臲。", "匙抄爛飯穩送之，合口軟嚼如牛呞。", "妻兒恐我生悵望，盤中不飣栗與棃。", "祗今年纔四十五，後日懸知漸莽鹵。", "朱顏皓頸訝莫親，此外諸餘誰更數。", "憶昔太公仕進初，口含兩齒無贏餘。", "虞翻十三比豈少，遂自惋恨形於書。", "丈夫命存百無害，誰能點檢形骸外。", "巨緡東釣儻可期，與子共飽鯨魚膾。"]'),
('3badf1e6-af73-4e46-8567-eb4a61673057','題炭谷湫祠堂','韓愈','唐','唐诗','tang','','[]','萬生都陽明，幽暗鬼所寰。',240,'全唐诗/poet.tang.18000.json','["萬生都陽明，幽暗鬼所寰。", "嗟龍獨何智，出入人鬼間。", "不知誰爲助，若執造化關。", "厭處平地水，巢居插天山。", "列峰若攢指，石盂仰環環。", "巨靈高其捧，保此一掬慳。", "森沈固含蓄，本以儲陰奸。", "魚鼈蒙擁護，羣嬉傲天頑。", "翾翾棲託禽，飛飛一何閑。", "祠堂像侔真，擢玉紆煙鬟。", "羣怪儼伺候，恩威在其顏。", "我來日正中，悚惕思先還。", "寄立尺寸地，敢言來途艱。", "吁無吹毛刃，血此牛蹄殷。", "至令乘水旱，鼓舞寡與鰥。", "林叢鎮冥冥，窮年無由刪。", "妍英雜豔實，星瑣黃朱斑。", "石級皆險滑，顛躋莫牽攀。", "龍區雛衆碎，付與宿已頒。", "棄去可奈何，吾其死茅菅。"]'),
('1a8adc45-8900-4717-9037-020169e0df9f','聽穎師彈琴','韓愈','唐','唐诗','tang','','[]','昵昵兒女語，恩怨相爾汝。',118,'全唐诗/poet.tang.18000.json','["昵昵兒女語，恩怨相爾汝。", "劃然變軒昂，勇士赴敵場。", "浮雲柳絮無根蔕，天地闊遠隨飛揚。", "喧啾百鳥羣，忽見孤鳳皇。", "躋攀分寸不可上，失勢一落千丈強。", "嗟余有兩耳，未省聽絲篁。", "自聞穎師彈，起坐在一旁。", "推手遽止之，濕衣淚滂滂。", "穎乎爾誠能，無以冰炭置我腸。"]'),
('9b10808b-630a-4551-860f-abe2ecc4c051','送陸暢歸江南','韓愈','唐','唐诗','tang','','[]','舉舉江南子，名以能詩聞。',144,'全唐诗/poet.tang.18000.json','["舉舉江南子，名以能詩聞。", "一來取高第，官佐東宮軍。", "迎婦丞相府，誇映秀士羣。", "鸞鳴桂樹間，觀者何繽紛。", "人事喜顛倒，旦夕異所云。", "蕭蕭青雲幹，遂逐荆棘焚。", "歲晚鴻雁過，鄉思見新文。", "踐此秦關雪，家彼吳洲雲。", "悲啼上車女，骨肉不可分。", "感慨都門別，丈夫酒方醺。", "我實門下士，力薄蚋與蚊。", "受恩不即報，永負湘中墳。"]'),
('22420c03-fb25-4ce7-a428-093f04461ebf','送進士劉師服東歸','韓愈','唐','唐诗','tang','','[]','猛虎落檻穽，坐食如孤㹠。',144,'全唐诗/poet.tang.18000.json','["猛虎落檻穽，坐食如孤㹠。", "丈夫在富貴，豈必守一門。", "公心有勇氣，公口有直言。", "奈何任埋沒，不自求騰軒。", "僕本亦進士，頗嘗究根源。", "由來骨鯁材，喜被軟弱吞。", "低頭受侮笑，隱忍硉兀冤。", "泥雨城東路，夏槐作雲屯。", "還家雖闕短，指日親晨飧。", "攜持令名歸，自足貽家尊。", "時節不可翫，親交可攀援。", "勉來取金紫，勿久休中園。"]'),
('0c486e4f-38fd-4f61-848a-9ed6da82a49e','嘲魯連子','韓愈','唐','唐诗','tang','','[]','魯連細而黠，有似黃鷂子。',60,'全唐诗/poet.tang.18000.json','["魯連細而黠，有似黃鷂子。", "田巴兀老蒼，憐汝矜爪觜。", "開端要驚人，雄跨吾厭矣。", "高拱禪鴻聲，若輟一杯水。", "獨稱唐虞賢，顧未知之耳。"]'),
('8ee65924-3f5e-46f7-9e44-bfa0e8938679','贈張籍','韓愈','唐','唐诗','tang','','[]','吾老著讀書，餘事不挂眼。',216,'全唐诗/poet.tang.18000.json','["吾老著讀書，餘事不挂眼。", "有兒雖甚憐，敎示不免簡。", "君來好呼出，踉蹡越門限。", "懼其無所知，見則先媿赧。", "昨因有緣事，上馬插手版。", "留君住廳食，使立侍盤𧣴。", "薄暮歸見君，迎我笑而莞。", "指渠相賀言，此是黃金產。", "吾愛其風骨，粹美無可揀。", "試將詩義授，如以肉貫丳。", "開祛露毫末，自得高蹇嵼。", "我身蹈丘軻，爵位不早綰。", "固宜長有人，文章紹編剗。", "感荷君子德，怳若乘朽棧。", "召令吐所記，解摘了瑟僴。", "顧視窗壁間，親戚競覘矕。", "喜氣排寒冬，逼耳鳴睍睆。", "如今更誰恨，便可耕灞滻。"]'),
('c9f275d5-d466-4ba0-8293-3889e7db130b','調張籍','韓愈','唐','唐诗','tang','','[]','李杜文章在，光燄萬丈長。',240,'全唐诗/poet.tang.18000.json','["李杜文章在，光燄萬丈長。", "不知羣兒愚，那用故謗傷。", "蚍蜉撼大樹，可笑不自量。", "伊我生其後，舉頸遙相望。", "夜夢多見之，晝思反微茫。", "徒觀斧鑿痕，不矚治水航。", "想當施手時，巨刃磨天揚。", "垠崖劃崩豁，乾坤擺雷硠。", "惟此兩夫子，家居率荒涼。", "帝欲長吟哦，故遣起且僵。", "翦翎送籠中，使看百鳥翔。", "平生千萬篇，金薤垂琳琅。", "仙官敕六丁，雷電下取將。", "流落人間者，太山一毫芒。", "我願生兩翅，捕逐出八荒。", "精誠忽交通，百怪入我腸。", "刺手拔鯨牙，舉瓢酌天漿。", "騰身跨汗漫，不著織女襄。", "顧語地上友，經營無太忙。", "乞君飛霞佩，與我高頡頏。"]'),
('f69d1917-b86e-48a6-a8f3-079cef0064aa','盧郎中雲夫寄示送盤谷子詩兩章歌以和之','韓愈','唐','唐诗','tang','','[]','昔尋李愿向盤谷，正見高崖巨壁爭開張。',244,'全唐诗/poet.tang.18000.json','["昔尋李愿向盤谷，正見高崖巨壁爭開張。", "是時新晴天井溢，誰把長劒倚太行。", "衝風吹破落天外，飛雨白日灑洛陽。", "東蹈燕川食曠野，有饋木蕨芽滿筐。", "馬頭溪深不可厲，借車載過水入箱。", "平沙綠浪榜方口，雁鴨飛起穿垂楊。", "窮探極覽頗恣橫，物外日月本不忙。", "歸來辛苦欲誰爲，坐令再往之計墮眇芒。", "閉門長安三日雪，推書撲筆歌慨慷。", "旁無壯士遣屬和，遠憶盧老詩顛狂。", "開緘忽覩送歸作，字向紙上皆軒昂。", "又知李侯竟不顧，方冬獨入崔嵬藏。", "我今進退幾時決，十年蠢蠢隨朝行。", "家請官供不報答，何異雀鼠偷太倉。", "行抽手版付丞相，不待彈劾還耕桑。"]'),
('7b75633a-02a2-42f6-9e63-189fc17c34d2','寄皇甫湜','韓愈','唐','唐诗','tang','','[]','敲門驚晝睡，問報睦州吏。',60,'全唐诗/poet.tang.18000.json','["敲門驚晝睡，問報睦州吏。", "手把一封書，上有皇甫字。", "拆書放牀頭，涕與淚垂四。", "昏昏還就枕，惘惘夢相值。", "悲哉無奇術，安得生兩翅。"]'),
('5a4cd89d-4903-4e4f-9c7f-07d4be7f0f1d','病中贈張十八','韓愈','唐','唐诗','tang','','[]','中虛得暴下，避冷臥北窗。',264,'全唐诗/poet.tang.18000.json','["中虛得暴下，避冷臥北窗。", "不蹋曉鼓朝，安眠聽逢逢。", "籍也處閭里，抱能未施邦。", "文章自娛戲，金石日擊撞。", "龍文百斛鼎，筆力可獨扛。", "談舌久不掉，非君亮誰雙。", "扶几導之言，曲節初摐摐。", "半途喜開鑿，派別失大江。", "吾欲盈其氣，不令見麾幢。", "牛羊滿田野，解斾束空杠。", "傾尊與斟酌，四壁堆罌缸。", "玄帷隔雪風，照爐釘明釭。", "夜闌縱捭闔，哆口疏眉厖。", "勢侔高陽翁，坐約齊橫降。", "連日挾所有，形軀頓胮肛。", "將歸乃徐謂，子言得無哤。", "回軍與角逐，斫樹收窮龐。", "雌聲吐款要，酒壺綴羊腔。", "君乃崑崙渠，籍乃嶺頭瀧。", "譬如蟻蛭微，詎可陵崆㟅。", "幸願終賜之，斬拔枿與樁。", "從此識歸處，東流水淙淙。"]'),
('f3869758-c131-425c-b942-75c5b902355b','雜詩','韓愈','唐','唐诗','tang','','[]','古史散左右，詩書置後前。',156,'全唐诗/poet.tang.18000.json','["古史散左右，詩書置後前。", "豈殊蠹書蟲，生死文字間。", "古道自愚憃，古言自包纏。", "當今固殊古，誰與爲欣歡。", "獨攜無言子，共升崑崙顛。", "長風飄襟裾，遂起飛高圓。", "下視禹九州，一塵集豪端。", "遨嬉未云幾，下已億萬年。", "向者夸奪子，萬墳厭其巔。", "惜哉抱所見，白黑未及分。", "慷慨爲悲咤，淚如九河飜。", "指摘相告語，雖還今誰親。", "翩然下大荒，被髮騎騏驎。"]'),
('d8d9851e-ed86-4b43-96a4-cee84889e1c6','寄崔二十六立之','韓愈','唐','唐诗','tang','','[]','西城員外丞，心迹兩屈奇。',288,'全唐诗/poet.tang.18000.json','["西城員外丞，心迹兩屈奇。", "往歲戰詞賦，不將勢力隨。", "下驢入省門，左右驚紛披。", "傲兀坐試席，深叢見孤羆。", "文如飜水成，初不用意爲。", "四座各低面，不敢捩眼窺。", "升階揖侍郎，歸舍日未敧。", "佳句喧衆口，考官敢瑕疵。", "連年收科第，若摘頷底髭。", "回首卿相位，通途無他岐。", "豈論校書郎，袍笏光參差。", "童穉見稱說，祝身得如斯。", "儕輩妒且熱，喘如竹筒吹。", "老婦願嫁女，約不論財貲。", "老翁不量分，累月笞其兒。", "攪攪爭附託，無人角雄雌。", "由來人間事，翻覆不可知。", "安有巢中鷇，插翅飛天陲。", "駒麛著爪牙，猛虎借與皮。", "汝頭有韁繫，汝脚有索縻。", "陷身泥溝間，誰復稟指撝。", "不脫吏部選，可見偶與奇。", "又作朝士貶，得非命所施。", "客居京城中，十日營一炊。"]'),
('de7ae571-5241-4ea9-82f7-0d49eeebd710','月蝕詩效玉川子作','韓愈','唐','唐诗','tang','','[]','元和庚寅斗插子，月十四日三更中。',341,'全唐诗/poet.tang.18000.json','["元和庚寅斗插子，月十四日三更中。", "森森萬木夜僵立，寒氣屓奰頑無風。", "月形如白盤，完完上天東。", "忽然有物來噉之，不知是何蟲。", "如何至神物，遭此狼狽凶。", "星如撒沙出，攢集爭強雄。", "油燈不照席，是夕吐燄如長虹。", "玉川子，涕泗下，中庭獨行。", "念此日月者，爲天之眼睛。", "此猶不自保，吾道何由行。", "嘗聞古老言，疑是蝦蟆精。", "徑圓千里納女腹，何處養女百醜形。", "杷沙脚手鈍，誰使女解緣青冥。", "黃帝有四目，帝舜重其明。", "今天祗兩目，何故許食使偏盲。", "堯呼大水浸十日，不惜萬國赤子魚頭生。", "女於此時若食日，雖食八九無嚵名。", "赤龍黑鳥燒口熱，翎鬣倒側相搪撐。", "婪酣大肚遭一飽，飢腸徹死無由鳴。", "後時食月罪當死，天羅磕帀何處逃汝刑。", "玉川子立於庭而言曰，地行賤臣仝。", "再拜敢告上天公，臣有一寸刃。", "可刳凶蟆腸，無梯可上天。", "天階無由有臣蹤，寄牋東南風。"]'),
('81d2c0f7-48ad-4b35-b142-9ed40165e8e2','孟生詩','韓愈','唐','唐诗','tang','','["\u6cf0\u5c71"]','孟生江海士，古貌又古心。',288,'全唐诗/poet.tang.18000.json','["孟生江海士，古貌又古心。", "嘗讀古人書，謂言古猶今。", "作詩三百首，窅默咸池音。", "騎驢到京國，欲和熏風琴。", "豈識天子居，九重鬱沈沈。", "一門百夫守，無籍不可尋。", "晶光蕩相射，旗戟翩以森。", "遷延乍却走，驚怪靡自任。", "舉頭看白日，泣涕下霑襟。", "朅來遊公卿，莫肯低華簪。", "諒非軒冕族，應對多差參。", "萍蓬風波急，桑榆日月侵。", "奈何從進士，此路轉嶇嶔。", "異質忌處羣，孤芳難寄林。", "誰憐松桂性，競愛桃李陰。", "朝悲辭樹葉，夕感歸巢禽。", "顧我多慷慨，窮檐時見臨。", "清宵靜相對，髮白聆苦吟。", "采蘭起幽念，眇然望東南。", "秦吳修且阻，兩地無數金。", "我論徐方牧，好古天下欽。", "竹實鳳所食，德馨神所歆。", "求觀衆丘小，必上泰山岑。", "求觀衆流細，必泛滄溟深。"]'),
('7b9b330b-4d3f-4de9-96bd-610bdd918133','射訓狐','韓愈','唐','唐诗','tang','','[]','有鳥夜飛名訓狐，矜凶挾狡誇自呼。',176,'全唐诗/poet.tang.18000.json','["有鳥夜飛名訓狐，矜凶挾狡誇自呼。", "乘時陰黑止我屋，聲勢慷慨非常麤。", "安然大喚誰畏忌，造作百怪非無須。", "聚鬼徵妖自朋扇，擺掉栱桷頹塈塗。", "慈母抱兒怕入席，那暇更護雞窠雛。", "我念乾坤德泰大，卵此惡物常勤劬。", "縱之豈即遽有害，斗柄行拄西南隅。", "誰謂停奸計尤劇，意欲唐突羲和烏。", "侵更歷漏氣彌厲，何由僥倖休須臾。", "咨余往射豈得已，候女兩眼張睢盱。", "梟驚墮梁蛇走竇，一夫斬頸羣雛枯。"]'),
('c8b0a242-4a1f-483b-9b13-63f488d66822','將歸贈孟東野房蜀客','韓愈','唐','唐诗','tang','','[]','君門不可入，勢利互相推。',84,'全唐诗/poet.tang.18000.json','["君門不可入，勢利互相推。", "借問讀書客，胡爲在京師。", "舉頭未能對，閉眼聊自思。", "倏忽十六年，終朝苦寒飢。", "宦途竟寥落，鬢髮坐差池。", "潁水清且寂，箕山坦而夷。", "如今便當去，咄咄無自疑。"]'),
('bd7f6507-833d-42b2-b311-8643337f1767','答孟郊','韓愈','唐','唐诗','tang','','[]','規模背時利，文字覰天巧。',96,'全唐诗/poet.tang.18000.json','["規模背時利，文字覰天巧。", "人皆餘酒肉，子獨不得飽。", "纔春思已亂，始秋悲又攪。", "朝餐動及午，夜諷恒至卯。", "名聲暫羶腥，腸肚鎮煎煼。", "古心雖自鞭，世路終難拗。", "弱拒喜張臂，猛拏閑縮爪。", "見倒誰肯扶，從嗔我須齩。"]'),
('577f012c-8d67-4550-85df-204fd765b488','從仕','韓愈','唐','唐诗','tang','','[]','居閑食不足，從仕力難任。',48,'全唐诗/poet.tang.18000.json','["居閑食不足，從仕力難任。", "兩事皆害性，一生恒苦心。", "黃昏歸私室，惆悵起歎音。", "棄置人間世，古來非獨今。"]'),
('73e9346a-f26a-43b0-8b93-a0eeaf09b90d','短燈檠歌','韓愈','唐','唐诗','tang','','[]','長檠八尺空自長，短檠二尺便且光。',128,'全唐诗/poet.tang.18000.json','["長檠八尺空自長，短檠二尺便且光。", "黃簾綠幕朱戶閉，風露氣入秋堂涼。", "裁衣寄遠淚眼暗，搔頭頻挑移近牀。", "太學儒生東魯客，二十辭家來射策。", "夜書細字綴語言，兩目眵昏頭雪白。", "此時提攜當案前，看書到曉那能眠。", "一朝富貴還自恣，長檠高張照珠翠。", "吁嗟世事無不然，牆角君看短檠棄。"]'),
('e3f212e6-2886-49c3-8bfb-9bcacbfb3cae','送劉師服','韓愈','唐','唐诗','tang','','[]','夏半陰氣始，淅然雲景秋。',84,'全唐诗/poet.tang.18000.json','["夏半陰氣始，淅然雲景秋。", "蟬聲入客耳，驚起不可留。", "草草具盤饌，不待酒獻酬。", "士生爲名累，有似魚中鈎。", "齎材入市賣，貴者恒難售。", "豈不畏顦顇，爲功忌中休。", "勉哉耘其業，以待歲晚收。"]'),
('bb1104a6-5946-4226-93c3-d75d4a1e8b84','符讀書城南','韓愈','唐','唐诗','tang','','[]','木之就規矩，在梓匠輪輿。',288,'全唐诗/poet.tang.18000.json','["木之就規矩，在梓匠輪輿。", "人之能爲人，由腹有詩書。", "詩書勤乃有，不勤腹空虛。", "欲知學之力，賢愚同一初。", "由其不能學，所入遂異閭。", "兩家各生子，提孩巧相如。", "少長聚嬉戲，不殊同隊魚。", "年至十二三，頭角稍相疎。", "二十漸乖張，清溝映汙渠。", "三十骨骼成，乃一龍一豬。", "飛黃騰踏去，不能顧蟾蜍。", "一爲馬前卒，鞭背生蟲蛆。", "一爲公與相，潭潭府中居。", "問之何因爾，學與不學歟。", "金璧雖重寶，費用難貯儲。", "學問藏之身，身在則有餘。", "君子與小人，不繫父母且。", "不見公與相，起身自犂鉏。", "不見三公後，寒飢出無驢。", "文章豈不貴，經訓乃菑畬。", "潢潦無根源，朝滿夕已除。", "人不通古今，馬牛而襟裾。", "行身陷不義，況望多名譽。", "時秋積雨霽，新涼入郊墟。"]'),
('aa81c8f9-094a-45a0-ab24-166c99217b5d','示爽','韓愈','唐','唐诗','tang','','[]','宣城去京國，里數逾三千。',192,'全唐诗/poet.tang.18000.json','["宣城去京國，里數逾三千。", "念汝欲別我，解裝具盤筵。", "日昏不能散，起坐相引牽。", "冬夜豈不長，達旦燈燭然。", "座中悉親故，誰肯捨汝眠。", "念汝將一身，西來曾幾年。", "名科揜衆俊，州考居吏前。", "今從府公召，府公又時賢。", "時輩千百人，孰不謂汝妍。", "汝來江南近，里閭故依然。", "昔日同戲兒，看汝立路邊。", "人生但如此，其實亦可憐。", "吾老世味薄，因循致留連。", "強顏班行內，何實非罪愆。", "才短難自力，懼終莫洗湔。", "臨分不汝誑，有路即歸田。"]'),
('ff6d4609-5b29-4244-8ee5-feed483a96f4','人日城南登高','韓愈','唐','唐诗','tang','','[]','初正候纔兆，涉七氣已弄。',120,'全唐诗/poet.tang.18000.json','["初正候纔兆，涉七氣已弄。", "靄靄野浮陽，暉暉水披凍。", "聖朝身不廢，佳節古所用。", "親交既許來，子妷亦可從。", "盤蔬冬春雜，尊酒清濁共。", "令徵前事爲，觴詠新詩送。", "扶杖凌圮阯，刺船犯枯葑。", "戀池羣鴨回，釋嶠孤雲縱。", "人生本坦蕩，誰使妄倥傯。", "直指桃李闌，幽尋寧止重。"]'),
('aac9f803-f3db-4ab1-a5be-41d37fa1eb5b','病鴟','韓愈','唐','唐诗','tang','','[]','屋東惡水溝，有鴟墮鳴悲。',240,'全唐诗/poet.tang.18000.json','["屋東惡水溝，有鴟墮鳴悲。", "青泥揜兩翅，拍拍不得離。", "羣童呌相召，瓦礫爭先之。", "計校生平事，殺却理亦宜。", "奪攘不媿耻，飽滿盤天嬉。", "晴日占光景，高風恣追隨。", "遂凌鸞鳳羣，肯顧鴻鵠卑。", "今者命運窮，遭逢巧丸兒。", "中汝要害處，汝能不得施。", "於吾乃何有，不忍乘其危。", "丐汝將死命，浴以清水池。", "朝餐輟魚肉，暝宿防狐貍。", "自知無以致，蒙德久猶疑。", "飽入深竹叢，飢來傍階基。", "亮無責報心，固以聽所爲。", "昨日有氣力，飛跳弄藩籬。", "今晨忽徑去，曾不報我知。", "僥倖非汝福，天衢汝休窺。", "京城事彈射，豎子不易欺。", "勿諱泥坑辱，泥坑乃良規。"]'),
('01254379-b998-4526-a356-2ace1e5ea7fd','華山女','韓愈','唐','唐诗','tang','','[]','街東街西講佛經，撞鐘吹螺鬧宮庭。',240,'全唐诗/poet.tang.18000.json','["街東街西講佛經，撞鐘吹螺鬧宮庭。", "廣張罪福資誘脅，聽衆狎恰排浮萍。", "黃衣道士亦講說，座下寥落如明星。", "華山女兒家奉道，欲驅異敎歸僊靈。", "洗粧拭面著冠帔，白咽紅頰長眉青。", "遂來陞座演真訣，觀門不許人開扃。", "不知誰人暗相報，訇然振動如雷霆。", "掃除衆寺人跡絕，驊騮塞路連椔軿。", "觀中人滿坐觀外，後至無地無由聽。", "抽簪脫釧解環佩，堆金疊玉光青熒。", "天門貴人傳詔召，六宮願識師顏形。", "玉皇頷首許歸去，乘龍駕鶴去青冥。", "豪家少年豈知道，來遶百帀脚不停。", "雲牕霧閣事恍惚，重重翠幕深金屏。", "僊梯難攀俗緣重，浪憑青鳥通丁寧。"]'),
('c9136ef2-3660-4fee-bcf9-fd3d3fb0ee75','讀皇甫湜公安園池詩書其後二首 一','韓愈','唐','唐诗','tang','','[]','晉人目二子，其猶吹一吷。',86,'全唐诗/poet.tang.18000.json','["晉人目二子，其猶吹一吷。", "區區自其下，顧肯挂牙舌。", "春秋書王法，不誅其人身。", "爾雅注蟲魚，定非磊落人。", "湜也困公安，不自閑窮年。", "枉智思掎摭，糞壤污穢豈有臧。", "誠不如兩忘，但以一概量。"]'),
('6c6f9211-995d-4707-9a2c-2cd1ccfcb17b','讀皇甫湜公安園池詩書其後二首 二','韓愈','唐','唐诗','tang','','[]','我有一池水，蒲葦生其間。',72,'全唐诗/poet.tang.18000.json','["我有一池水，蒲葦生其間。", "蟲魚沸相嚼，日夜不得閑。", "我初往觀之，其後益不觀。", "觀之亂我意，不如不觀完。", "用將濟諸人，捨得業孔顏。", "百年詎幾時，君子不可閑。"]'),
('b56cefd7-b197-4f95-a7ef-ecc9fce835f3','路傍堠','韓愈','唐','唐诗','tang','','[]','堆堆路傍堠，一雙復一隻。',72,'全唐诗/poet.tang.18000.json','["堆堆路傍堠，一雙復一隻。", "迎我出秦關，送我入楚澤。", "千以高山遮，萬以遠水隔。", "吾君勤聽治，照與日月敵。", "臣愚幸可哀，臣罪庶可釋。", "何當迎送歸，緣路高歷歷。"]'),
('7af68c9e-81a1-4d1f-bcee-de44b015366c','食曲河驛','韓愈','唐','唐诗','tang','','[]','晨及曲河驛，悽然自傷情。',72,'全唐诗/poet.tang.18000.json','["晨及曲河驛，悽然自傷情。", "羣烏巢庭樹，乳燕飛簷楹。", "而我抱重罪，孑孑萬里程。", "親戚頓乖角，圖史棄縱橫。", "下負明義重，上孤朝命榮。", "殺身諒無補，何用答生成。"]'),
('7ca0d65f-bea4-453b-9675-6b5b22b22f88','過南陽','韓愈','唐','唐诗','tang','','[]','南陽郭門外，桑下麥青青。',48,'全唐诗/poet.tang.18000.json','["南陽郭門外，桑下麥青青。", "行子去未已，春鳩鳴不停。", "秦商邈既遠，湖海浩將經。", "孰忍生以慼，吾其寄餘齡。"]'),
('b3b3eba8-1805-453c-acba-8b80dea48929','瀧吏','韓愈','唐','唐诗','tang','','[]','南行逾六旬，始下昌樂瀧。',288,'全唐诗/poet.tang.18000.json','["南行逾六旬，始下昌樂瀧。", "險惡不可狀，船石相舂撞。", "往問瀧頭吏，潮州尚幾里。", "行當何時到，土風復何似。", "瀧吏垂手笑，官何問之愚。", "譬官居京邑，何由知東吳。", "東吳遊宦鄉，官知自有由。", "潮州底處所，有罪乃竄流。", "儂幸無負犯，何由到而知。", "官今行自到，那遽妄問爲。", "不虞卒見困，汗出媿且駭。", "吏曰聊戲官，儂嘗使往罷。", "嶺南大抵同，官去道苦遼。", "下此三千里，有州始名潮。", "惡溪瘴毒聚，雷電常洶洶。", "鱷魚大於船，牙眼怖殺儂。", "州南數十里，有海無天地。", "颶風有時作，掀簸真差事。", "聖人於天下，於物無不容。", "比聞此州囚，亦在生還儂。", "官無嫌此州，固罪人所徙。", "官當明時來，事不待說委。", "官不自謹慎，宜即引分往。", "胡爲此水邊，神色久戃慌。"]'),
('a3b11e88-8115-4a9b-8a18-8aa74515d39b','贈別元十八協律六首 一','韓愈','唐','唐诗','tang','','[]','知識久去眼，吾行其既遠。',144,'全唐诗/poet.tang.18000.json','["知識久去眼，吾行其既遠。", "瞢瞢莫訾省，默默但寢飯。", "子兮何爲者，冠珮立憲憲。", "何氏之從學，蘭蕙已滿畹。", "於何翫其光，以至歲向晚。", "治惟尚和同，無俟於謇謇。", "或師絕學賢，不以藝自輓。", "子兮獨如何，能自媚婉娩。", "金石出聲音，宮室發關楗。", "何人識章甫，而知駿蹄踠。", "惜乎吾無居，不得留息偃。", "臨當背面時，裁詩示繾綣。"]'),
('6ce23af5-4a29-4f10-ae1d-ff0a17933f17','贈別元十八協律六首 二','韓愈','唐','唐诗','tang','','[]','英英桂林伯，實惟文武特。',72,'全唐诗/poet.tang.18000.json','["英英桂林伯，實惟文武特。", "遠勞從事賢，來弔逐臣色。", "南裔多山海，道里屢紆直。", "風波無程期，所憂動不測。", "子行誠艱難，我去未窮極。", "臨別且何言，有淚不可拭。"]'),
('3da8ee23-30f7-4767-a3e5-ffdcff9034ae','贈別元十八協律六首 三','韓愈','唐','唐诗','tang','','[]','吾友柳子厚，其人藝且賢。',72,'全唐诗/poet.tang.18000.json','["吾友柳子厚，其人藝且賢。", "吾未識子時，已覽贈子篇。", "寤寐想風采，於今已三年。", "不意流竄路，旬日同食眠。", "所聞昔已多，所得今過前。", "如何又須別，使我抱悁悁。"]'),
('18e6afd4-d6dd-4347-b20b-c2133154a437','贈別元十八協律六首 四','韓愈','唐','唐诗','tang','','[]','勢要情所重，排斥則埃塵。',96,'全唐诗/poet.tang.18000.json','["勢要情所重，排斥則埃塵。", "骨肉未免然，又況四海人。", "嶷嶷桂林伯，矯矯義勇身。", "生平所未識，待我逾交親。", "遺我數幅書，繼以藥物珍。", "藥物防瘴癘，書勸養形神。", "不知四罪地，豈有再起辰。", "窮途致感激，肝膽還輪囷。"]'),
('e2f34d14-a94c-46d1-a049-34ae7e28a62a','贈別元十八協律六首 五','韓愈','唐','唐诗','tang','','[]','讀書患不多，思義患不明。',60,'全唐诗/poet.tang.18000.json','["讀書患不多，思義患不明。", "患足已不學，既學患不行。", "子今四美具，實大華亦榮。", "王官不可闕，未宜後諸生。", "嗟我擯南海，無由助飛鳴。"]'),
('a9144589-d38d-42f5-a834-7fddfc0a063c','贈別元十八協律六首 六','韓愈','唐','唐诗','tang','','[]','寄書龍城守，君驥何時秣。',84,'全唐诗/poet.tang.18000.json','["寄書龍城守，君驥何時秣。", "峽山逢颶風，雷電助撞捽。", "乘潮簸扶胥，近岸指一髮。", "兩巖雖云牢，水石互飛發。", "屯門雖云高，亦映波浪沒。", "余罪不足惜，子生未宜忽。", "胡爲不忍別，感謝情至骨。"]'),
('cf2697a5-7914-4440-be16-db76bb88be26','初南食貽元十八協律','韓愈','唐','唐诗','tang','','[]','鱟實如惠文，骨眼相負行。',168,'全唐诗/poet.tang.18000.json','["鱟實如惠文，骨眼相負行。", "蠔相黏爲山，百十各自生。", "蒲魚尾如蛇，口眼不相營。", "蛤即是蝦蟆，同實浪異名。", "章舉馬甲柱，鬬以怪自呈。", "其餘數十種，莫不可歎驚。", "我來禦魑魅，自宜味南烹。", "調以鹹與酸，芼以椒與橙。", "腥臊始發越，咀吞面汗騂。", "惟蛇舊所識，實憚口眼獰。", "開籠聽其去，鬱屈尚不平。", "賣爾非我罪，不屠豈非情。", "不祈靈珠報，幸無嫌怨幷。", "聊歌以記之，又以告同行。"]'),
('335314f2-aa38-4f25-a0c3-6d8e375daec6','宿曾江口示姪孫湘二首 一','韓愈','唐','唐诗','tang','','[]','雲昏水奔流，天水漭相圍。',96,'全唐诗/poet.tang.18000.json','["雲昏水奔流，天水漭相圍。", "三江滅無口，其誰識涯圻。", "暮宿投民村，高處水半扉。", "犬雞俱上屋，不復走與飛。", "篙舟入其家，暝聞屋中唏。", "問知歲常然，哀此爲生微。", "海風吹寒晴，波揚衆星輝。", "仰視北斗高，不知路所歸。"]'),
('15d1bdba-d2a0-4c84-aa2f-dd4df8598766','宿曾江口示姪孫湘二首 二','韓愈','唐','唐诗','tang','','[]','舟行忘故道，屈曲高林間。',48,'全唐诗/poet.tang.18000.json','["舟行忘故道，屈曲高林間。", "林間無所有，奔流但潺潺。", "嗟我亦拙謀，致身落南蠻。", "茫然失所詣，無路何能還。"]'),
('5af8728f-fca2-4092-a9a1-b554bfbd0a8f','答柳柳州食蝦蟆','韓愈','唐','唐诗','tang','','[]','蝦蟆雖水居，水特變形貌。',204,'全唐诗/poet.tang.18000.json','["蝦蟆雖水居，水特變形貌。", "強號爲蛙蛤，於實無所校。", "雖然兩股長，其奈脊皴皰。", "跳躑雖云高，意不離濘淖。", "鳴聲相呼和，無理只取鬧。", "周公所不堪，灑灰垂典敎。", "我棄愁海濱，恒願眠不覺。", "叵堪朋類多，沸耳作驚爆。", "端能敗笙磬，仍工亂學校。", "雖蒙句踐禮，竟不聞報效。", "大戰元鼎年，孰強孰敗橈。", "居然當鼎味，豈不辱釣罩。", "余初不下喉，近亦能稍稍。", "常懼染蠻夷，失平生好樂。", "而君復何爲，甘食比豢豹。", "獵較務同俗，全身斯爲孝。", "哀哉思慮深，未見許回櫂。"]'),
('3c8b4a6f-8aad-458d-9ca3-43dff3b224bd','別趙子','韓愈','唐','唐诗','tang','','[]','我遷於揭陽，君先揭陽居。',204,'全唐诗/poet.tang.18000.json','["我遷於揭陽，君先揭陽居。", "揭陽去京華，其里萬有餘。", "不謂小郭中，有子可與娛。", "心平而行高，兩通詩與書。", "婆娑海水南，簸弄明月珠。", "及我遷宜春，意欲攜以俱。", "擺頭笑且言，我豈不足歟。", "又奚爲於北，往來以紛如。", "海中諸山中，幽子頗不無。", "相期風濤觀，已久不可渝。", "又嘗疑龍蝦，果誰雄牙鬚。", "蚌蠃魚鼈蟲，瞿瞿以狙狙。", "識一已忘十，大同細自殊。", "欲一窮究之，時歲屢謝除。", "今子南且北，豈非亦有圖。", "人心未嘗同，不可一理區。", "宜各從所務，未用相賢愚。"]'),
('571d0836-d8bc-4bc6-91a5-a35b7db77bc4','除官赴闕至江州寄鄂岳李大夫','韓愈','唐','唐诗','tang','','[]','盆城去鄂渚，風便一日耳。',168,'全唐诗/poet.tang.18000.json','["盆城去鄂渚，風便一日耳。", "不枉故人書，無因帆江水。", "故人辭禮闈，旌節鎮江圻。", "而我竄逐者，龍鍾初得歸。", "別來已三歲，望望長迢遞。", "咫尺不相聞，平生那可計。", "我齒落且盡，君鬢白幾何。", "年皆過半百，來日苦無多。", "少年樂新知，衰暮思故友。", "譬如親骨肉，寧免相可不。", "我昔實愚惷，不能降色辭。", "子犯亦有言，臣猶自知之。", "公其務貰過，我亦請改事。", "桑榆儻可收，願寄相思字。"]'),
('9f7df79d-4efe-48f6-9fca-f55ee33f5510','南山有高樹行贈李宗閔','韓愈','唐','唐诗','tang','','[]','南山有高樹，花葉何衰衰。',240,'全唐诗/poet.tang.18000.json','["南山有高樹，花葉何衰衰。", "上有鳳皇巢，鳳皇乳且棲。", "四旁多長枝，羣鳥所托依。", "黃鵠據其高，衆鳥接其卑。", "不知何山鳥，羽毛有光輝。", "飛飛擇所處，正得衆所希。", "上承鳳皇恩，自期永不衰。", "中與黃鵠羣，不自隱其私。", "下視衆鳥羣，汝徒竟何爲。", "不知挾丸子，心默有所規。", "彈汝枝葉間，汝翅不覺摧。", "或言由黃鵠，黃鵠豈有之。", "慎勿猜衆鳥，衆鳥不足猜。", "無人語鳳皇，汝屈安得知。", "黃鵠得汝去，婆娑弄毛衣。", "前汝下視鳥，各議汝瑕疵。", "汝豈無朋匹，有口莫肯開。", "汝落蒿艾間，幾時復能飛。", "哀哀故山友，中夜思汝悲。", "路遠翅翎短，不得持汝歸。"]'),
('e3d209ca-7919-4442-836f-97a406c8a208','猛虎行','韓愈','唐','唐诗','tang','','[]','猛虎雖云惡，亦各有匹儕。',192,'全唐诗/poet.tang.18000.json','["猛虎雖云惡，亦各有匹儕。", "羣行深谷間，百獸望風低。", "身食黃熊父，子食赤豹麛。", "擇肉於熊豹，肯視兔與貍。", "正晝當谷眠，眼有百步威。", "自矜無當對，氣性縱以乖。", "朝怒殺其子，暮還食其妃。", "匹儕四散走，猛虎還孤棲。", "狐鳴門兩旁，烏鵲從噪之。", "出逐猴入居，虎不知所歸。", "誰云猛虎惡，中路正悲啼。", "豹來銜其尾，熊來攫其頤。", "猛虎死不辭，但慚前所爲。", "虎坐無助死，況如汝細微。", "故當結以信，親當結以私。", "親故且不保，人誰信汝爲。"]'),
('fb827220-205f-431b-8488-2aadba1434d2','雪後寄崔二十六丞公','韓愈','唐','唐诗','tang','','[]','藍田十月雪塞關，我興南望愁羣山。',176,'全唐诗/poet.tang.18000.json','["藍田十月雪塞關，我興南望愁羣山。", "攢天嵬嵬凍相映，君乃寄命於其間。", "秩卑俸薄食口衆，豈有酒食開容顏。", "殿前羣公賜食罷，驊騮蹋路驕且閑。", "稱多量少鑒裁密，豈念幽桂遺榛菅。", "幾欲犯嚴出薦口，氣象硉兀未可攀。", "歸來殞涕揜關臥，心之紛亂誰能刪。", "詩翁憔悴斸荒棘，清玉刻佩聯玦環。", "腦脂遮眼臥壯士，大弨挂壁無由彎。", "乾坤惠施萬物遂，獨於數子懷偏慳。", "朝欷暮唶不可解，我心安得如石頑。"]'),
('8cd18d6f-fdeb-4e04-94f0-24722019866f','送僧澄觀','韓愈','唐','唐诗','tang','','[]','浮屠西來何施爲，擾擾四海爭奔馳。',288,'全唐诗/poet.tang.18000.json','["浮屠西來何施爲，擾擾四海爭奔馳。", "構樓架閣切星漢，誇雄鬬麗止者誰。", "僧伽後出淮泗上，勢到衆佛尤恢奇。", "越商胡賈脫身罪，珪璧滿船寧計資。", "清淮無波平如席，欄柱傾扶半天赤。", "火燒水轉掃地空，突兀便高三百尺。", "影沈潭底龍驚遁，當晝無雲跨虛碧。", "借問經營本何人，道人澄觀名籍籍。", "愈昔從軍大梁下，往來滿屋賢豪者。", "皆言澄觀雖僧徒，公才吏用當今無。", "後從徐州辟書至，紛紛過客何由記。", "人言澄觀乃詩人，一座競吟詩句新。", "向風長歎不可見，我欲收歛加冠巾。", "洛陽窮秋厭窮獨，丁丁啄門疑啄木。", "有僧來訪呼使前，伏犀插腦高頰權。", "惜哉已老無所及，坐睨神骨空潸然。", "臨淮太守初到郡，遠遣州民送音問。", "好奇賞俊直難逢，去去爲致思從容。"]'),
('70eca4ac-4132-4c1c-a72d-7237eb0a5288','山南鄭相公樊員外酬答爲詩其末咸有見及語樊封以示愈依賦十四韻以獻','韓愈','唐','唐诗','tang','','[]','梁維西南屏，山厲水刻屈。',168,'全唐诗/poet.tang.18000.json','["梁維西南屏，山厲水刻屈。", "稟生肖剿剛，難諧在民物。", "滎公鼎軸老，烹斡力健倔。", "帝咨女予往，牙纛前岔坲。", "威風挾惠氣，蓋壤兩劘拂。", "茫漫華黑間，指畫變怳歘。", "誠既富而美，章彙霍炳蔚。", "日延講大訓，龜判錯衮黻。", "樊子坐賓署，演孔刮老佛。", "金舂撼玉應，厥臭劇蕙鬱。", "遺我一言重，跽受惕齋慄。", "辭慳義卓闊，呀豁疚掊掘。", "如新去耵聹，雷霆逼颶䫻。", "綴此豈爲訓，俚言紹莊屈。"]'),
('97782c86-fb89-436b-a76f-934bc872acb0','奉和武相公鎮蜀時詠使宅韋太尉所養孔雀','韓愈','唐','唐诗','tang','','[]','穆穆鸞鳳友，何年來止茲。',48,'全唐诗/poet.tang.18000.json','["穆穆鸞鳳友，何年來止茲。", "飄零失故態，隔絕抱長思。", "翠角高獨聳，金華煥相差。", "坐蒙恩顧重，畢命守堦墀。"]'),
('f1fc910c-a0e0-4c8b-af3a-1bba24f25e71','感春三首 一','韓愈','唐','唐诗','tang','','[]','偶坐藤樹下，暮春下旬間。',60,'全唐诗/poet.tang.18000.json','["偶坐藤樹下，暮春下旬間。", "藤陰已可庇，落蘂還漫漫。", "亹亹新葉大，瓏瓏晚花乾。", "青天高寥寥，兩蝶飛翻翻。", "時節適當爾，懷悲自無端。"]'),
('d94a17f7-e838-45a8-a08d-8ee9f80237d6','感春三首 二','韓愈','唐','唐诗','tang','','[]','黃黃蕪菁花，桃李事已退。',48,'全唐诗/poet.tang.18000.json','["黃黃蕪菁花，桃李事已退。", "狂風簸枯榆，狼籍九衢內。", "春序一如此，汝顏安足賴。", "誰能駕飛車，相從觀海外。"]'),
('056b0cfb-aaa2-462d-8e22-61b6b4c92b5a','感春三首 三','韓愈','唐','唐诗','tang','','[]','晨遊百花林，朱朱兼白白。',96,'全唐诗/poet.tang.18000.json','["晨遊百花林，朱朱兼白白。", "柳枝弱而細，懸樹垂百尺。", "左右同來人，金紫貴顯劇。", "嬌童爲我歌，哀響跨箏笛。", "豔姬蹋筵舞，清眸刺劒戟。", "心懷平生友，莫一在燕席。", "死者長眇芒，生者困乖隔。", "少年真可喜，老大百無益。"]'),
('6d54e31f-b5b7-462a-b9d0-17d45f49ac5a','早赴街西行香贈盧李二中舍人','韓愈','唐','唐诗','tang','','[]','天街東西異，祗命遂成遊。',48,'全唐诗/poet.tang.18000.json','["天街東西異，祗命遂成遊。", "月明御溝曉，蟬吟堤樹秋。", "老僧情不薄，僻寺境還幽。", "寂寥二三子，歸騎得相收。"]'),
('6ab50975-6bf6-4537-ace4-a28f46037462','晚寄張十八助敎周郎博士','韓愈','唐','唐诗','tang','','[]','日薄風景曠，出歸偃前簷。',48,'全唐诗/poet.tang.18000.json','["日薄風景曠，出歸偃前簷。", "晴雲如擘絮，新月似磨鐮。", "田野興偶動，衣冠情久厭。", "吾生可攜手，歎息歲將淹。"]'),
('1b869632-0dcf-4e3c-98f5-291aaa1b3884','題張十八所居','韓愈','唐','唐诗','tang','','[]','君居泥溝上，溝濁萍青青。',48,'全唐诗/poet.tang.18000.json','["君居泥溝上，溝濁萍青青。", "蛙讙橋未掃，蟬嘒門長扃。", "名秩後千品，詩文齊六經。", "端來問奇字，爲我講聲形。"]'),
('e6bf25ce-19e9-4316-bd35-cdc6bb050c61','奉酬盧給事雲夫四兄曲江荷花行見寄幷呈上錢七兄閣老張十八助敎','韓愈','唐','唐诗','tang','','[]','曲江千頃秋波淨，平鋪紅雲蓋明鏡。',152,'全唐诗/poet.tang.18000.json','["曲江千頃秋波淨，平鋪紅雲蓋明鏡。", "大明宮中給事歸，走馬來看立不正。", "遺我明珠九十六，寒光映骨睡驪目。", "我今官閑得婆娑，問言何處芙蓉多。", "撐舟昆明度雲錦，脚敲兩舷呌吳歌。", "太白山高三百里，負雪崔嵬插花裏。", "玉山前却不復來，曲江汀瀅水平盃。", "我時相思不覺一回首，天門九扇相當開。", "上界真人足官府，豈如散仙鞭笞鸞鳳終日相追陪。"]'),
('b8f3a223-3b9a-4163-8814-78733007a6b9','奉和錢七兄曹長盆池所植','韓愈','唐','唐诗','tang','','[]','翻翻江浦荷，而今生在此。',48,'全唐诗/poet.tang.18000.json','["翻翻江浦荷，而今生在此。", "擢擢菰葉長，芳根復誰徙。", "露涵兩鮮翠，風蕩相磨倚。", "但取主人知，誰言盆盎是。"]'),
('453424e2-ef15-4710-956b-3ec491c17ec1','記夢','韓愈','唐','唐诗','tang','','[]','夜夢神官與我言，羅縷道妙角與根。',224,'全唐诗/poet.tang.18000.json','["夜夢神官與我言，羅縷道妙角與根。", "挈攜陬維口瀾翻，百二十刻須臾間。", "我聽其言未云足，捨我先度橫山腹。", "我徒三人共追之，一人前度安不危。", "我亦平行蹋𠿕𧇠，神完骨蹻脚不掉。", "側身上視溪谷盲，杖撞玉版聲彭𦨻。", "神官見我開顏笑，前對一人壯非少。", "石壇坡陀可坐臥，我手承頦肘拄座。", "隆樓傑閣磊嵬高，天風飄飄吹我過。", "壯非少者哦七言，六字常語一字難。", "我以指撮白玉丹，行且咀噍行詰盤。", "口前截斷第二句，綽虐顧我顏不歡。", "乃知仙人未賢聖，護短憑愚邀我敬。", "我能屈曲自世間，安能從汝巢神山。"]'),
('adfed685-daa4-41cd-85cf-6cb3dd9a7a02','南內朝賀歸呈同官','韓愈','唐','唐诗','tang','','[]','薄雲蔽秋曦，清雨不成泥。',228,'全唐诗/poet.tang.18000.json','["薄雲蔽秋曦，清雨不成泥。", "罷賀南內衙，歸涼曉淒淒。", "綠槐十二街，渙散馳輪蹄。", "余惟戇書生，孤身無所齎。", "三黜竟不去，致官九列齊。", "豈惟一身榮，佩玉冠簪犀。", "滉蕩天門高，著籍朝厥妻。", "文才不如人，行又無町畦。", "問之朝廷事，略不知東西。", "況於經籍深，豈究端與倪。", "君恩太山重，不見酬稗稊。", "所職事無多，又不自提撕。", "明庭集孔鸞，曷取於鳧鷖。", "樹以松與柏，不宜間蒿藜。", "婉孌自媚好，幾時不見擠。", "貪食以忘軀，尠不調鹽醯。", "法吏多少年，磨淬出角圭。", "將舉汝愆尤，以爲己階梯。", "收身歸關東，期不到死迷。"]'),
('cee85ef6-fa41-4448-b06d-15dc3ccdcc76','朝歸','韓愈','唐','唐诗','tang','','[]','峩峩進賢冠，耿耿水蒼佩。',84,'全唐诗/poet.tang.18000.json','["峩峩進賢冠，耿耿水蒼佩。", "服章豈不好，不與德相對。", "顧影聽其聲，赬顏汗漸背。", "進乏犬雞效，又不勇自退。", "坐食取其肥，無堪等聾瞶。", "長風吹天墟，秋日萬里曬。", "抵暮但昏眠，不成歌慷慨。"]'),
('e9c79a46-c520-4e2d-ac07-bab0b16c0685','雜詩四首 一','韓愈','唐','唐诗','tang','','[]','朝蠅不須驅，暮蚊不可拍。',48,'全唐诗/poet.tang.18000.json','["朝蠅不須驅，暮蚊不可拍。", "蠅蚊滿八區，可盡與相格。", "得時能幾時，與汝恣啖咋。", "涼風九月到，掃不見蹤跡。"]'),
('aeb17101-1f54-4814-b625-6870432ced12','雜詩四首 二','韓愈','唐','唐诗','tang','','[]','鵲鳴聲楂楂，烏噪聲擭擭。',48,'全唐诗/poet.tang.18000.json','["鵲鳴聲楂楂，烏噪聲擭擭。", "爭鬬庭宇間，持身博彈射。", "黃鵠能忍飢，兩翅久不擘。", "蒼蒼雲海路，歲晚將無獲。"]'),
('0425716c-30c2-4fa6-9b52-0ac8078a0f69','雜詩四首 三','韓愈','唐','唐诗','tang','','[]','截橑爲欂櫨，斵楹以爲椽。',72,'全唐诗/poet.tang.18000.json','["截橑爲欂櫨，斵楹以爲椽。", "束蒿以代之，小大不相權。", "雖無風雨災，得不覆且顛。", "解轡棄騏麟，蹇驢鞭使前。", "崑崙高萬里，歲盡道苦邅。", "停車臥輪下，絕意於神僊。"]'),
('6062fcb5-fc32-4697-b068-783cd0d2797b','雜詩四首 四','韓愈','唐','唐诗','tang','','[]','雀鳴朝營食，鳩鳴暮覓羣。',48,'全唐诗/poet.tang.18000.json','["雀鳴朝營食，鳩鳴暮覓羣。", "獨有知時鶴，雖鳴不緣身。", "喑蟬終不鳴，有抱不列陳。", "蛙黽鳴無謂，閤閤祗亂人。"]'),
('531a437b-02ea-4c51-b84f-d8ed49d83fce','讀東方朔雜事','韓愈','唐','唐诗','tang','','[]','嚴嚴王母宮，下維萬仙家。',216,'全唐诗/poet.tang.18000.json','["嚴嚴王母宮，下維萬仙家。", "噫欠爲飄風，濯手大雨沱。", "方朔乃豎子，驕不加禁訶。", "偷入雷電室，輷輘掉狂車。", "王母聞以笑，衛官助呀呀。", "不知萬萬人，生身埋泥沙。", "簸頓五山踣，流漂八維蹉。", "曰吾兒可憎，奈此狡獪何。", "方朔聞不喜，褫身絡蛟蛇。", "瞻相北斗柄，兩手自相挼。", "羣仙急乃言，百犯庸不科。", "向觀睥睨處，事在不可赦。", "欲不布露言，外口實諠譁。", "王母不得已，顏嚬口齎嗟。", "頷頭可其奏，送以紫玉珂。", "方朔不懲創，挾恩更矜誇。", "詆欺劉天子，正晝溺殿衙。", "一旦不辭訣，攝身凌蒼霞。"]'),
('7e04e92f-e561-401b-b645-d7da15568455','譴瘧鬼','韓愈','唐','唐诗','tang','','[]','屑屑水帝魂，謝謝無餘輝。',204,'全唐诗/poet.tang.18000.json','["屑屑水帝魂，謝謝無餘輝。", "如何不肖子，尚奮瘧鬼威。", "乘秋作寒熱，翁嫗所駡譏。", "求食歐泄間，不知臭穢非。", "醫師加百毒，熏灌無停機。", "灸師施艾炷，酷若獵火圍。", "詛師毒口牙，舌作霹靂飛。", "符師弄刀筆，丹墨交橫揮。", "咨汝之胄出，門戶何巍巍。", "祖軒而父頊，未沫於前徽。", "不修其操行，賤薄似汝稀。", "豈不忝厥祖，靦然不知歸。", "湛湛江水情，歸居安汝妃。", "清波爲裳衣，白石爲門畿。", "呼吸明月光，手掉芙蓉旂。", "降集隨九歌，飲芳而食菲。", "贈汝以好辭，咄汝去莫違。"]'),
('5895afcc-89a8-45f5-8257-3275ef3650d5','示兒','韓愈','唐','唐诗','tang','','[]','始我來京師，止攜一束書。',288,'全唐诗/poet.tang.18000.json','["始我來京師，止攜一束書。", "辛勤三十年，以有此屋廬。", "此屋豈爲華，於我自有餘。", "中堂高且新，四時登牢蔬。", "前榮饌賓親，冠婚之所於。", "庭內無所有，高樹八九株。", "有藤婁絡之，春華夏陰敷。", "東堂坐見山，雲風相吹噓。", "松果連南亭，外有瓜芋區。", "西偏屋不多，槐榆翳空虛。", "山鳥旦夕鳴，有類澗谷居。", "主婦治北堂，膳服適戚疎。", "恩封高平君，子孫從朝裾。", "開門問誰來，無非卿大夫。", "不知官高卑，玉帶懸金魚。", "問客之所爲，峨冠講唐虞。", "酒食罷無爲，棋槊以相娛。", "凡此座中人，十九持鈞樞。", "又問誰與頻，莫與張樊如。", "來過亦無事，考評道精麤。", "躚躚媚學子，牆屏日有徒。", "以能問不能，其蔽豈可祛。", "嗟我不修飾，事與庸人俱。", "安能坐如此，比肩於朝儒。"]'),
('e0f8e660-83be-456f-ae80-1afcc0cf63aa','庭楸','韓愈','唐','唐诗','tang','','[]','庭楸止五株，共生十步間。',180,'全唐诗/poet.tang.18000.json','["庭楸止五株，共生十步間。", "各有藤繞之，上各相鈎聯。", "下葉各垂地，樹顛各雲連。", "朝日出其東，我常坐西偏。", "夕日在其西，我常坐東邊。", "當晝日在上，我在中央間。", "仰視何青青，上不見纖穿。", "朝暮無日時，我且八九旋。", "濯濯晨露香，明珠何聯聯。", "夜月來照之，蒨蒨自生煙。", "我已自頑鈍，重遭五楸牽。", "客來尚不見，肯到權門前。", "權門衆所趨，有客動百千。", "九牛亡一毛，未在多少間。", "往既無可顧，不往自可憐。"]'),
('04d00831-5661-4ff2-894f-cd0f4951d6ba','翫月喜張十八員外以王六秘書至','韓愈','唐','唐诗','tang','','[]','前夕雖十五，月長未滿規。',84,'全唐诗/poet.tang.18000.json','["前夕雖十五，月長未滿規。", "君來晤我時，風露渺無涯。", "浮雲散白石，天宇開青池。", "孤質不自憚，中天爲君施。", "翫翫夜遂久，亭亭曙將披。", "況當今夕圓，又以嘉客隨。", "惜無酒食樂，但用歌嘲爲。"]'),
('b4434d99-ee2d-44b9-b4cb-99cb535043f1','和李相公攝事南郊覽物興懷呈一二知舊','韓愈','唐','唐诗','tang','','[]','燦燦辰角曙，亭亭寒露朝。',120,'全唐诗/poet.tang.18000.json','["燦燦辰角曙，亭亭寒露朝。", "川原共澄暎，雲日還浮飄。", "上宰嚴祀事，清途振華鑣。", "圓丘峻且坦，前對南山標。", "村樹黃復綠，中田稼何饒。", "顧瞻想巖谷，興歎倦塵囂。", "惟彼顛瞑者，去公豈不遼。", "爲仁朝自治，用靜兵以銷。", "勿憚吐捉勤，可歌風雨調。", "聖賢相遇少，功德今宣昭。"]'),
('09d2c2e6-b8a4-4b02-b837-8101ecde8dfd','和裴僕射相公假山十一韻','韓愈','唐','唐诗','tang','','[]','公乎真愛山，看山旦連夕。',132,'全唐诗/poet.tang.18000.json','["公乎真愛山，看山旦連夕。", "猶嫌山在眼，不得着脚歷。", "枉語山中人，匄我澗側石。", "有來應公須，歸必載金帛。", "當軒乍駢羅，隨勢忽開坼。", "有洞若神剜，有巖類天劃。", "終朝巖洞間，歌鼓燕賓戚。", "孰謂衡霍期，近在王侯宅。", "傅氏築已卑，磻溪釣何激。", "逍遙功德下，不與事相摭。", "樂我盛明朝，於焉傲今昔。"]'),
('82c880fc-b1f4-4249-997d-6710c1bd016c','與張十八同效阮步兵一日復一夕','韓愈','唐','唐诗','tang','','[]','一日復一日，一朝復一朝。',120,'全唐诗/poet.tang.18000.json','["一日復一日，一朝復一朝。", "秖見有不如，不見有所超。", "食作前日味，事作前日調。", "不知久不死，憫憫尚誰要。", "富貴自縶拘，貧賤亦煎焦。", "俯仰未得所，一世已解鑣。", "譬如籠中鶴，六翮無所搖。", "譬如兔得蹄，安用東西跳。", "還看古人書，復舉前人瓢。", "未知所究竟，且作新詩謠。"]'),
('d77c54d5-4723-40c8-bc09-d88eb1ff6aa9','送諸葛覺往隨州讀書','韓愈','唐','唐诗','tang','','[]','鄴侯家多書，插架三萬軸。',156,'全唐诗/poet.tang.18000.json','["鄴侯家多書，插架三萬軸。", "一一懸牙籤，新若手未觸。", "爲人強記覽，過眼不再讀。", "偉哉羣聖文，磊落載其腹。", "行年五十餘，出守數已六。", "京邑有舊廬，不容久食宿。", "臺閣多官員，無地寄一足。", "我雖官在朝，氣勢日局縮。", "屢爲丞相言，雖懇不見錄。", "送行過滻水，東望不轉目。", "今子從之遊，學問得所欲。", "入海觀龍魚，矯翮逐黃鵠。", "勉爲新詩章，月寄三四幅。"]'),
('ee595e38-1cc8-4833-bcae-8bea127dcd6f','南溪始泛三首 一','韓愈','唐','唐诗','tang','','[]','榜舟南山下，上上不得返。',96,'全唐诗/poet.tang.18000.json','["榜舟南山下，上上不得返。", "幽事隨去多，孰能量近遠。", "陰沈過連樹，藏昂抵橫坂。", "石麤肆磨礪，波惡厭牽挽。", "或倚偏岸漁，竟就平洲飯。", "點點暮雨飄，梢梢新月偃。", "餘年懍無幾，休日愴已晚。", "自是病使然，非由取高蹇。"]'),
('96480f47-9e04-41f4-865a-b836875cd349','南溪始泛三首 二','韓愈','唐','唐诗','tang','','[]','南溪亦清駛，而無檝與舟。',120,'全唐诗/poet.tang.18000.json','["南溪亦清駛，而無檝與舟。", "山農驚見之，隨我觀不休。", "不惟兒童輩，或有杖白頭。", "饋我籠中瓜，勸我此淹留。", "我云以病歸，此已頗自由。", "幸有用餘俸，置居在西疇。", "囷倉米穀滿，未有旦夕憂。", "上去無得得，下來亦悠悠。", "但恐煩里閭，時有緩急投。", "願爲同社人，雞豚燕春秋。"]'),
('6fc1fab1-a86c-4c8d-af6a-292ee64aa7cb','南溪始泛三首 三','韓愈','唐','唐诗','tang','','[]','足弱不能步，自宜收朝蹟。',96,'全唐诗/poet.tang.18000.json','["足弱不能步，自宜收朝蹟。", "羸形可輿致，佳觀安事擲。", "即此南坂下，久聞有水石。", "拕舟入其間，溪流正清激。", "隨波吾未能，峻瀨乍可刺。", "鷺起若導吾，前飛數十尺。", "亭亭柳帶沙，團團松冠壁。", "歸時還盡夜，誰謂非事役。"]'),
('1f1e1ecd-b0e5-4527-8ecf-7188263e4d17','題楚昭王廟','韓愈','唐','唐诗','tang','','[]','丘墳滿目衣冠盡，城闕連雲草樹荒。',32,'全唐诗/poet.tang.18000.json','["丘墳滿目衣冠盡，城闕連雲草樹荒。", "猶有國人懷舊德，一間茅屋祭昭王。"]'),
('29a10340-8b18-4b35-850d-ee23d7d2bd58','宿龍宮灘','韓愈','唐','唐诗','tang','','["\u63cf\u5199\u6c34", "\u6292\u6000", "\u5199\u6c34", "\u8ff0\u5fd7"]','浩浩復湯湯，灘聲抑更揚。',48,'全唐诗/poet.tang.18000.json','["浩浩復湯湯，灘聲抑更揚。", "奔流疑激電，驚浪似浮霜。", "夢覺燈生暈，宵殘雨送涼。", "如何連曉語，一半是思鄉。"]'),
('c4236e09-94df-410d-aa17-b0d27cf0205e','叉魚招張功曹','韓愈','唐','唐诗','tang','','[]','叉魚春岸闊，此興在中宵。',216,'全唐诗/poet.tang.18000.json','["叉魚春岸闊，此興在中宵。", "大炬然如晝，長船縛似橋。", "深窺沙可數，靜搒水無搖。", "刃下那能脫，波間或自跳。", "中鱗憐錦碎，當目訝珠銷。", "迷火逃翻近，驚人去暫遙。", "競多心轉細，得雋語時囂。", "潭罄知存寡，舷平覺獲饒。", "交頭疑湊餌，駢首類同條。", "濡沫情雖密，登門事已遼。", "盈車欺故事，飼犬驗今朝。", "血浪凝猶沸，腥風遠更飄。", "蓋江烟羃羃，拂棹影寥寥。", "獺去愁無食，龍疑懼見燒。", "如棠名既誤，釣渭日徒消。", "文客驚先賦，篙工喜盡謠。", "膾成思我友，觀樂憶吾僚。", "自可捐憂累，何須強問鴞。"]'),
('7c6556c5-ba74-473a-bb42-8fd55ade03b7','李員外寄紙筆','韓愈','唐','唐诗','tang','','[]','題是臨池後，分從起草餘。',36,'全唐诗/poet.tang.18000.json','["題是臨池後，分從起草餘。", "兔尖針莫竝，繭淨雪難如。", "莫怪殷勤謝，虞卿正著書。"]'),
('d9463fb8-d058-46d4-b14d-3cc1fe7337e7','次同冠峽','韓愈','唐','唐诗','tang','','[]','今日是何朝，天晴物色饒。',48,'全唐诗/poet.tang.18000.json','["今日是何朝，天晴物色饒。", "落英千尺墮，遊絲百丈飄。", "泄乳交巖脉，懸流揭浪標。", "無心思嶺北，猿鳥莫相撩。"]'),
('6ccb03d7-ae6f-4103-b4f3-e3b4f5c9e0b7','答張十一功曹','韓愈','唐','唐诗','tang','','["\u6292\u60c5", "\u5199\u666f"]','山淨江空水見沙，哀猿啼處兩三家。',64,'全唐诗/poet.tang.18000.json','["山淨江空水見沙，哀猿啼處兩三家。", "篔簹競長纖纖笋，躑躅閑開豔豔花。", "未報恩波知死所，莫令炎瘴送生涯。", "吟君詩罷看雙鬢，斗覺霜毛一半加。"]'),
('faf84775-3042-4ba1-964b-ab007504cf40','郴州祈雨','韓愈','唐','唐诗','tang','','[]','乞雨女郎魂，炰羞潔且繁。',48,'全唐诗/poet.tang.18000.json','["乞雨女郎魂，炰羞潔且繁。", "廟開鼯鼠呌，神降越巫言。", "旱氣期銷蕩，陰官想駿奔。", "行看五馬入，蕭颯已隨軒。"]'),
('783d570a-44b7-4d2e-82db-e6891538cd95','湘中酬張十一功曹','韓愈','唐','唐诗','tang','','[]','休垂絕徼千行淚，共泛清湘一葉舟。',32,'全唐诗/poet.tang.18000.json','["休垂絕徼千行淚，共泛清湘一葉舟。", "今日嶺猿兼越鳥，可憐同聽不知愁。"]'),
('97bf3efe-f55e-4ce4-babc-52bf38529b3e','郴口又贈二首 一','韓愈','唐','唐诗','tang','','[]','山作劍攢江寫鏡，扁舟斗轉疾於飛。',32,'全唐诗/poet.tang.18000.json','["山作劍攢江寫鏡，扁舟斗轉疾於飛。", "回頭笑向張公子，終日思歸此日歸。"]'),
('e9a4a6ca-5a49-4fff-ac07-7e7e4e888fa3','郴口又贈二首 二','韓愈','唐','唐诗','tang','','[]','雪颭霜翻看不分，雷驚電激語難聞。',32,'全唐诗/poet.tang.18000.json','["雪颭霜翻看不分，雷驚電激語難聞。", "沿涯宛轉到深處，何限青天無片雲。"]'),
('d61c8f59-fdd9-4c00-a75a-078c83959088','題木居士二首 一','韓愈','唐','唐诗','tang','','[]','火透波穿不計春，根如頭面榦如身。',32,'全唐诗/poet.tang.18000.json','["火透波穿不計春，根如頭面榦如身。", "偶然題作木居士，便有無窮求福人。"]'),
('cf16b1e2-b2fd-4b7e-9431-3df231c95038','題木居士二首 二','韓愈','唐','唐诗','tang','','[]','爲神詎比溝中斷，遇賞還同爨下餘。',32,'全唐诗/poet.tang.18000.json','["爲神詎比溝中斷，遇賞還同爨下餘。", "朽蠹不勝刀鋸力，匠人雖巧欲何如。"]'),
('52478b93-6c8a-4b4e-80f1-6eebb40437cf','晚泊江口','韓愈','唐','唐诗','tang','','[]','郡城朝解纜，江岸暮依村。',48,'全唐诗/poet.tang.18000.json','["郡城朝解纜，江岸暮依村。", "二女竹上淚，孤臣水底魂。", "雙雙歸蜇燕，一一呌羣猿。", "回首那聞語，空看別袖翻。"]'),
('923e2f27-fc95-4649-9442-1aeeb083da91','湘中','韓愈','唐','唐诗','tang','','[]','猿愁魚踊水翻波，自古流傳是汨羅。',32,'全唐诗/poet.tang.18000.json','["猿愁魚踊水翻波，自古流傳是汨羅。", "蘋藻滿盤無處奠，空聞漁父扣舷歌。"]'),
('e1bb2a42-9bb2-4c22-b16e-f86ac22a1a37','別盈上人','韓愈','唐','唐诗','tang','','[]','山僧愛山出無期，俗士牽俗來何時。',32,'全唐诗/poet.tang.18000.json','["山僧愛山出無期，俗士牽俗來何時。", "祝融峰下一回首，即是此生長別離。"]'),
('6838a513-72e8-47ce-a665-273205ad5e8d','喜雪獻裴尚書','韓愈','唐','唐诗','tang','','[]','宿雲寒不卷，春雪墮如簁。',240,'全唐诗/poet.tang.18000.json','["宿雲寒不卷，春雪墮如簁。", "騁巧先投隙，潛光半入池。", "喜深將策試，驚密仰簷窺。", "自下何曾汙，增高未覺危。", "比心明可燭，拂面愛還吹。", "妬舞時飄袖，欺梅併壓枝。", "地空迷界限，砌滿接高卑。", "浩蕩乾坤合，霏微物象移。", "爲祥矜大熟，布澤荷平施。", "已分年華晚，猶憐曙色隨。", "氣嚴當酒換，灑急聽窗知。", "照曜臨初日，玲瓏滴晚澌。", "聚庭看嶽聳，掃路見雲披。", "陣勢魚麗遠，書文鳥篆奇。", "縱歡羅豔黠，列賀擁熊螭。", "履敝行偏冷，門扃臥更羸。", "悲嘶聞病馬，浪走信嬌兒。", "竈靜愁煙絕，絲繁念鬢衰。", "擬鹽吟舊句，授簡慕前規。", "捧贈同燕石，多慚失所宜。"]'),
('af69bb7c-cfa9-4cfa-a341-d59331b53a2c','春雪','韓愈','唐','唐诗','tang','','[]','看雪乘清旦，無人坐獨謠。',122,'全唐诗/poet.tang.18000.json','["看雪乘清旦，無人坐獨謠。", "拂花輕尚起，落地煖初銷。", "已訝陵歌扇，還來伴舞腰。", "灑篁留密節，著柳送長條。", "入鏡鸞窺沼，行天馬度橋。", "徧堦憐可掬，滿樹戲成搖。", "江浪迎濤日，風毛縱獵朝。", "弄閑時細轉，爭急[忽]驚飄。", "城險疑懸布，砧寒未擣綃。", "莫愁陰景促，夜色自相饒。"]'),
('5cfff02d-2c43-4e77-867a-2d5101a05cc5','聞梨花發贈劉師命','韓愈','唐','唐诗','tang','','[]','桃溪惆悵不能過，紅豔紛紛落地多。',32,'全唐诗/poet.tang.18000.json','["桃溪惆悵不能過，紅豔紛紛落地多。", "聞道郭西千樹雪，欲將君去醉如何。"]'),
('4b13e5da-48ea-4213-9ede-dd8cec48c7c3','春雪間早梅','韓愈','唐','唐诗','tang','','[]','梅將雪共春，彩豔不相因。',120,'全唐诗/poet.tang.18000.json','["梅將雪共春，彩豔不相因。", "逐吹能爭密，排枝巧妬新。", "誰令香滿座，獨使淨無塵。", "芳意饒呈瑞，寒光助照人。", "𤫩瓏開已徧，點綴坐來頻。", "那是俱疑似，須知兩逼真。", "熒煌初亂眼，浩蕩忽迷神。", "未許瓊華比，從將玉樹親。", "先期迎獻歲，更伴占茲晨。", "願得長輝暎，輕微敢自珍。"]'),
('6c0ce25a-d4e2-4338-8fa7-903aa92e6872','早春雪中聞鶯','韓愈','唐','唐诗','tang','','[]','朝鶯雪裏新，雪樹眼前春。',72,'全唐诗/poet.tang.18000.json','["朝鶯雪裏新，雪樹眼前春。", "帶澀先迎氣，侵寒已報人。", "共矜初聽早，誰貴後聞頻。", "暫囀那成曲，孤鳴豈及辰。", "風霜徒自保，桃李詎相親。", "寄謝幽棲友，辛勤不爲身。"]'),
('deb3ec18-ec62-47b5-a65b-448018743e43','梨花下贈劉師命','韓愈','唐','唐诗','tang','','[]','洛陽城外清明節，百花寥落梨花發。',32,'全唐诗/poet.tang.18000.json','["洛陽城外清明節，百花寥落梨花發。", "今日相逢瘴海頭，共驚爛漫開正月。"]'),
('34780f4c-c222-41ea-86f4-ed0869a20970','和歸工部送僧約','韓愈','唐','唐诗','tang','','[]','早知皆是自拘囚，不學因循到白頭。',32,'全唐诗/poet.tang.18000.json','["早知皆是自拘囚，不學因循到白頭。", "汝既出家還擾擾，何人更得死前休。"]'),
('fe226f7b-e057-4298-b7d2-ba5a27feb1cf','入關詠馬','韓愈','唐','唐诗','tang','','[]','歲老豈能充上駟，力微當自慎前程。',32,'全唐诗/poet.tang.18000.json','["歲老豈能充上駟，力微當自慎前程。", "不知何故翻驤首，牽過關門妄一鳴。"]'),
('fddc2755-a080-41e0-a99d-7d9399dd98ff','木芙蓉','韓愈','唐','唐诗','tang','','[]','新開寒露叢，遠比水間紅。',48,'全唐诗/poet.tang.18000.json','["新開寒露叢，遠比水間紅。", "豔色寧相妬，嘉名偶自同。", "採江官渡晚，搴木古祠空。", "願得勤來看，無令便逐風。"]'),
('9b4b06ea-a08a-4b6d-b09e-abba3ffa3db0','題張十一旅舍三詠 榴花','韓愈','唐','唐诗','tang','','["\u548f\u7269", "\u6292\u60c5", "\u548f\u7269\u8bd7", "\u6000\u624d\u4e0d\u9047"]','五月榴花照眼明，枝間時見子初成。',32,'全唐诗/poet.tang.18000.json','["五月榴花照眼明，枝間時見子初成。", "可憐此地無車馬，顛倒青苔落絳英。"]'),
('1a0367f4-2ab9-4100-89f1-693f825b1809','題張十一旅舍三詠 井','韓愈','唐','唐诗','tang','','[]','賈誼宅中今始見，葛洪山下昔曾窺。',32,'全唐诗/poet.tang.18000.json','["賈誼宅中今始見，葛洪山下昔曾窺。", "寒泉百尺空看影，正是行人渴死時。"]'),
('a80c62cf-8e3b-4f89-9476-d7273ea5dfa7','題張十一旅舍三詠 蒲萄','韓愈','唐','唐诗','tang','','[]','新莖未徧半猶枯，高架支離倒復扶。',32,'全唐诗/poet.tang.18000.json','["新莖未徧半猶枯，高架支離倒復扶。", "若欲滿盤堆馬乳，莫辭添竹引龍鬚。"]'),
('c8685806-6dd3-4162-8a41-2ac6ce62727d','峽石西泉','韓愈','唐','唐诗','tang','','[]','居然鱗介不能容，石眼環環水一鍾。',32,'全唐诗/poet.tang.18000.json','["居然鱗介不能容，石眼環環水一鍾。", "聞說旱時求得雨，秖疑科斗是蛟龍。"]'),
('949dc32c-20b2-48e4-959c-7db9910de93d','梁國惠康公主挽歌二首 一','韓愈','唐','唐诗','tang','','[]','定諡芳聲遠，移封大國新。',50,'全唐诗/poet.tang.18000.json','["定諡芳聲遠，移封大國新。", "巽宮尊長女，台室屬良人。", "河漢重泉夜，梧桐半樹春。", "龍[轜]非厭翟，還輾禁城塵。"]'),
('26a07dcc-02d2-4188-902c-2f759d63f7ce','梁國惠康公主挽歌二首 二','韓愈','唐','唐诗','tang','','[]','秦地吹簫女，湘波鼓瑟妃。',48,'全唐诗/poet.tang.18000.json','["秦地吹簫女，湘波鼓瑟妃。", "佩蘭初應夢，奔月竟淪輝。", "夫族迎魂去，宮官會葬歸。", "從今沁園草，無復更芳菲。"]'),
('c72c7a3d-05f3-4e87-bc13-b303d6756ef7','和崔舍人詠月二十韻','韓愈','唐','唐诗','tang','','[]','三秋端正月，今夜出東溟。',240,'全唐诗/poet.tang.18000.json','["三秋端正月，今夜出東溟。", "對日猶分勢，騰天漸吐靈。", "未高烝遠氣，半上霽孤形。", "赫奕當躔次，虛徐度杳冥。", "長河晴散霧，列宿曙分螢。", "浩蕩英華溢，蕭疎物象泠。", "池邊臨倒照，簷際送橫經。", "花樹參差見，臯禽斷續聆。", "牖光窺寂寞，砧影伴娉婷。", "幽坐看侵戶，閑吟愛滿庭。", "輝斜通壁練，彩碎射沙星。", "清潔雲間路，空涼水上亭。", "淨堪分顧兔，細得數飄萍。", "山翠相凝綠，林煙共冪青。", "過隅驚桂側，當午覺輪停。", "屬思摛霞錦，追歡罄縹缾。", "郡樓何處望，隴笛此時聽。", "右掖連台座，重門限禁扃。", "風臺觀滉瀁，冰砌步青熒。", "獨有虞庠客，無由拾落蓂。"]'),
('e56f04e5-09b6-49df-a7df-d67658a5d2e2','詠雪贈張籍','韓愈','唐','唐诗','tang','','[]','只見縱橫落，寧知遠近來。',288,'全唐诗/poet.tang.18000.json','["只見縱橫落，寧知遠近來。", "飄颻還自弄，歷亂竟誰催。", "座暖銷那怪，池清失可猜。", "坳中初蓋成，垤處遂成堆。", "慢有先居後，輕多去却回。", "度前鋪瓦隴，發本積牆隈。", "穿細時雙透，乘危忽半摧。", "舞深逢坎井，集早值層臺。", "砧練終宜擣，階紈未暇裁。", "城寒裝睥睨，樹凍裹莓苔。", "片片勻如翦，紛紛碎若挼。", "定非燖鵠鷺，真是屑瓊瑰。", "緯繣觀朝萼，冥茫矚晚埃。", "當窗恒凜凜，出戶即皚皚。", "壓野榮芝菌，傾都委貨財。", "娥嬉華蕩瀁，胥怒浪崔嵬。", "磧迥疑浮地，雲平想輾雷。", "隨車翻縞帶，逐馬散銀桮。", "萬屋漫汗合，千株照曜開。", "松篁遭搓抑，糞壤獲饒培。", "隔絕門庭遽，擠排陛級纔。", "豈堪裨嶽鎮，強欲效鹽梅。", "隱匿瑕疵盡，包羅委瑣該。", "誤雞宵呃喔，驚雀暗裴回。"]'),
('b0ba8902-b105-43de-9d1e-1ce7dc9ecbac','酬王二十舍人雪中見寄','韓愈','唐','唐诗','tang','','["\u5199\u96ea", "\u96ea", "\u5b64\u5355"]','三日柴門擁不開，階平庭滿白皚皚。',32,'全唐诗/poet.tang.18000.json','["三日柴門擁不開，階平庭滿白皚皚。", "今朝蹋作瓊瑤跡，爲有詩從鳳沼來。"]'),
('99bdecd2-e80e-4559-85e7-f9ef036d1f5c','送侯喜','韓愈','唐','唐诗','tang','','[]','已作龍鍾後時者，懶於街裏蹋塵埃。',32,'全唐诗/poet.tang.18000.json','["已作龍鍾後時者，懶於街裏蹋塵埃。", "如今便別長官去，直到新年衙日來。"]'),
('4f5e4ab8-9181-4c44-8841-3fa737458123','學諸進士作精衛銜石填海','韓愈','唐','唐诗','tang','','[]','鳥有償冤者，終年抱寸誠。',72,'全唐诗/poet.tang.18000.json','["鳥有償冤者，終年抱寸誠。", "口銜山石細，心望海波平。", "渺渺功難見，區區命已輕。", "人皆譏造次，我獨賞專精。", "豈計休無日，惟應盡此生。", "何慙刺客傳，不著報讎名。"]'),
('4c0a08b4-2c3e-4252-9e9e-0afcb4aee945','奉酬振武胡十二丈大夫','韓愈','唐','唐诗','tang','','[]','傾朝共羨寵光頻，半歲遷騰作虎臣。',64,'全唐诗/poet.tang.18000.json','["傾朝共羨寵光頻，半歲遷騰作虎臣。", "戎斾暫停辭社樹，里門先下敬鄉人。", "橫飛玉盞家山曉，遠蹀金珂塞草春。", "自笑平生誇膽氣，不離文字鬢毛新。"]'),
('d6f0319f-8116-449e-9f70-9076852f4146','奉和庫部盧四兄曹長元日朝回','韓愈','唐','唐诗','tang','','[]','天仗宵嚴建羽旄，春雲送色曉雞號。',64,'全唐诗/poet.tang.18000.json','["天仗宵嚴建羽旄，春雲送色曉雞號。", "金爐香動螭頭暗，玉佩聲來雉尾高。", "戎服上趨承北極，儒冠列侍暎東曹。", "太平時節難身遇，郎署何須歎二毛。"]'),
('ab4f85b4-93fc-4040-85e4-0c28552e2407','寒食直歸遇雨','韓愈','唐','唐诗','tang','','[]','寒食時看度，春遊事已違。',48,'全唐诗/poet.tang.18000.json','["寒食時看度，春遊事已違。", "風光連日直，陰雨半朝歸。", "不見紅毬上，那論綵索飛。", "惟將新賜火，向曙著朝衣。"]'),
('b7c5aab1-a57d-492c-b43b-e03b9e1a72fc','送李六協律歸荆南','韓愈','唐','唐诗','tang','','[]','早日羈遊所，春風送客歸。',48,'全唐诗/poet.tang.18000.json','["早日羈遊所，春風送客歸。", "柳花還漠漠，江燕正飛飛。", "歌舞知誰在，賓僚逐使非。", "宋亭池水綠，莫忘蹋芳菲。"]'),
('245660c4-0496-46cf-a7f5-ad6dfffe8db9','題百葉桃花','韓愈','唐','唐诗','tang','','[]','百葉雙桃晚更紅，窺窗暎竹見玲瓏。',32,'全唐诗/poet.tang.18000.json','["百葉雙桃晚更紅，窺窗暎竹見玲瓏。", "應知侍史歸天上，故伴仙郎宿禁中。"]'),
('b7c13139-b250-4e7f-a708-3ec87d7be464','春雪','韓愈','唐','唐诗','tang','','["\u5199\u96ea", "\u6625\u5929", "\u96ea"]','新年都未有芳華，二月初驚見草芽。',32,'全唐诗/poet.tang.18000.json','["新年都未有芳華，二月初驚見草芽。", "白雪却嫌春色晚，故穿庭樹作飛花。"]'),
('3458aa79-b6e9-4ceb-96de-be31695a8156','戲題牡丹','韓愈','唐','唐诗','tang','','[]','幸自同開俱隱約，何須相倚鬬輕盈。',64,'全唐诗/poet.tang.18000.json','["幸自同開俱隱約，何須相倚鬬輕盈。", "陵晨併作新妝面，對客偏含不語情。", "雙燕無機還拂掠，遊蜂多思正經營。", "長年是事皆拋盡，今日欄邊暫眼明。"]'),
('25c5e784-2d4c-4b27-a7f7-e67c23188e2f','盆池五首 一','韓愈','唐','唐诗','tang','','[]','老翁真個似童兒，汲水埋盆作小池。',32,'全唐诗/poet.tang.18000.json','["老翁真個似童兒，汲水埋盆作小池。", "一夜青蛙鳴到曉，恰如方口釣魚時。"]'),
('000ed10b-40fb-43ce-be8c-e9809266398e','盆池五首 二','韓愈','唐','唐诗','tang','','[]','莫道盆池作不成，藕稍初種已齊生。',32,'全唐诗/poet.tang.18000.json','["莫道盆池作不成，藕稍初種已齊生。", "從今有雨君須記，來聽蕭蕭打葉聲。"]'),
('de94c121-1576-46c2-a1e2-2a33b810038c','盆池五首 三','韓愈','唐','唐诗','tang','','[]','瓦沼晨朝水自清，小蟲無數不知名。',32,'全唐诗/poet.tang.18000.json','["瓦沼晨朝水自清，小蟲無數不知名。", "忽然分散無蹤影，惟有魚兒作隊行。"]'),
('2e817089-e63f-4174-be73-dc739ddcc6d2','盆池五首 四','韓愈','唐','唐诗','tang','','[]','泥盆淺小詎成池，夜半青蛙聖得知。',34,'全唐诗/poet.tang.18000.json','["泥盆淺小詎成池，夜半青蛙聖得知。", "一聽暗來將伴侶，不煩鳴喚鬬[雄雌]。"]'),
('a2281075-39aa-469f-9a12-e27b951d2024','盆池五首 五','韓愈','唐','唐诗','tang','','[]','池光天影共青青，拍岸纔添水數缾。',32,'全唐诗/poet.tang.18000.json','["池光天影共青青，拍岸纔添水數缾。", "且待夜深明月去，試看涵泳幾多星。"]'),
('96c627b6-75cf-493f-b06f-2ed5fef037ad','芍藥','韓愈','唐','唐诗','tang','','[]','浩態狂香昔未逢，紅燈爍爍綠盤籠。',32,'全唐诗/poet.tang.18000.json','["浩態狂香昔未逢，紅燈爍爍綠盤籠。", "覺來獨對情驚恐，身在僊宮第幾重。"]'),
('18e9122d-09b7-4ac7-9f38-d529d486d607','奉和虢州劉給事使君三堂新題二十一詠 新亭','韓愈','唐','唐诗','tang','','[]','湖上新亭好，公來日出初。',24,'全唐诗/poet.tang.18000.json','["湖上新亭好，公來日出初。", "水文浮枕簟，瓦影蔭龜魚。"]'),
('51c0a45d-e396-4f44-a68b-9d8eaea52d33','奉和虢州劉給事使君三堂新題二十一詠 流水','韓愈','唐','唐诗','tang','','[]','汩汩幾時休，從春復到秋。',24,'全唐诗/poet.tang.18000.json','["汩汩幾時休，從春復到秋。", "只言池未滿，池滿強交流。"]'),
('ae1575a1-37c9-4f20-8db2-219565b17e43','奉和虢州劉給事使君三堂新題二十一詠 竹洞','韓愈','唐','唐诗','tang','','[]','竹洞何年有，公初斫竹開。',24,'全唐诗/poet.tang.18000.json','["竹洞何年有，公初斫竹開。", "洞門無鎖鑰，俗客不曾來。"]'),
('2a02a224-5cbb-4dd3-bd22-a4fe19ff1fab','奉和虢州劉給事使君三堂新題二十一詠 月臺','韓愈','唐','唐诗','tang','','[]','南館城陰闊，東湖水氣多。',24,'全唐诗/poet.tang.18000.json','["南館城陰闊，東湖水氣多。", "直須臺上看，始奈月明何。"]'),
('70f6084a-95fc-4be3-9c7e-26f03e4ecb1c','奉和虢州劉給事使君三堂新題二十一詠 渚亭','韓愈','唐','唐诗','tang','','[]','自有人知處，那無步往蹤。',24,'全唐诗/poet.tang.18000.json','["自有人知處，那無步往蹤。", "莫敎安四壁，面面看芙蓉。"]'),
('0cb1f27f-af8a-4ed5-abd5-22f43cb845eb','奉和虢州劉給事使君三堂新題二十一詠 竹溪','韓愈','唐','唐诗','tang','','[]','藹藹溪流慢，梢梢岸篠長。',24,'全唐诗/poet.tang.18000.json','["藹藹溪流慢，梢梢岸篠長。", "穿沙碧簳淨，落水紫苞香。"]'),
('2af68a89-61e9-444e-852c-d3e1d66af3e2','奉和虢州劉給事使君三堂新題二十一詠 北湖','韓愈','唐','唐诗','tang','','[]','聞說游湖棹，尋常到此回。',24,'全唐诗/poet.tang.18000.json','["聞說游湖棹，尋常到此回。", "應留醒心處，準擬醉時來。"]'),
('5e37bd22-2e01-4e61-85d5-621ac1941b72','奉和虢州劉給事使君三堂新題二十一詠 花島','韓愈','唐','唐诗','tang','','[]','蜂蝶去紛紛，香風隔岸聞。',24,'全唐诗/poet.tang.18000.json','["蜂蝶去紛紛，香風隔岸聞。", "欲知花島處，水上覓紅雲。"]'),
('eddc10d2-98b3-4dae-aa00-2683379da11b','奉和虢州劉給事使君三堂新題二十一詠 柳溪','韓愈','唐','唐诗','tang','','[]','柳樹誰人種，行行夾岸高。',24,'全唐诗/poet.tang.18000.json','["柳樹誰人種，行行夾岸高。", "莫將條繫纜，著處有蟬號。"]'),
('f3a3c4fd-ac69-4084-884b-887df01849f8','奉和虢州劉給事使君三堂新題二十一詠 西山','韓愈','唐','唐诗','tang','','[]','新月迎宵挂，晴雲到晚留。',24,'全唐诗/poet.tang.18000.json','["新月迎宵挂，晴雲到晚留。", "爲遮西望眼，終是懶回頭。"]'),
('b8f8d992-088f-4cdf-bef6-6690f55e6a8f','奉和虢州劉給事使君三堂新題二十一詠 竹逕','韓愈','唐','唐诗','tang','','[]','無塵從不掃，有鳥莫令彈。',24,'全唐诗/poet.tang.18000.json','["無塵從不掃，有鳥莫令彈。", "若要添風月，應除數百竿。"]'),
('43c9f1f6-3a24-489d-a8c9-552711348736','奉和虢州劉給事使君三堂新題二十一詠 荷池','韓愈','唐','唐诗','tang','','[]','風雨秋池上，高荷蓋水繁。',24,'全唐诗/poet.tang.18000.json','["風雨秋池上，高荷蓋水繁。", "未諳鳴摵摵，那似卷翻翻。"]'),
('155414a2-0f3e-4175-a08f-b962868a9be7','奉和虢州劉給事使君三堂新題二十一詠 稻畦','韓愈','唐','唐诗','tang','','[]','罫布畦堪數，枝分水莫尋。',24,'全唐诗/poet.tang.18000.json','["罫布畦堪數，枝分水莫尋。", "魚肥知已秀，鶴沒覺初深。"]'),
('3c4f3148-3d1c-4b37-906d-aac309850c25','奉和虢州劉給事使君三堂新題二十一詠 柳巷','韓愈','唐','唐诗','tang','','[]','柳巷還飛絮，春餘幾許時。',24,'全唐诗/poet.tang.18000.json','["柳巷還飛絮，春餘幾許時。", "吏人休報事，公作送春詩。"]'),
('20c7f738-6ca4-4131-9662-a8ad13182422','奉和虢州劉給事使君三堂新題二十一詠 花源','韓愈','唐','唐诗','tang','','[]','源上花初發，公應日日來。',24,'全唐诗/poet.tang.18000.json','["源上花初發，公應日日來。", "丁寧紅與紫，慎莫一時開。"]'),
('d659f265-3341-4969-862a-5b2ad242572c','奉和虢州劉給事使君三堂新題二十一詠 北樓','韓愈','唐','唐诗','tang','','[]','郡樓乘曉上，盡日不能回。',24,'全唐诗/poet.tang.18000.json','["郡樓乘曉上，盡日不能回。", "晚色將秋至，長風送月來。"]'),
('75abd02e-afa5-4e41-986c-605a46b0a525','奉和虢州劉給事使君三堂新題二十一詠 鏡潭','韓愈','唐','唐诗','tang','','[]','非鑄復非鎔，泓澄忽此逢。',24,'全唐诗/poet.tang.18000.json','["非鑄復非鎔，泓澄忽此逢。", "魚鰕不用避，只是照蛟龍。"]'),
('a7bdf539-2431-4980-9b85-09ccc6461824','奉和虢州劉給事使君三堂新題二十一詠 孤嶼','韓愈','唐','唐诗','tang','','[]','朝遊孤嶼南，暮戲孤嶼北。',24,'全唐诗/poet.tang.18000.json','["朝遊孤嶼南，暮戲孤嶼北。", "所以孤嶼鳥，與公盡相識。"]'),
('7c8d4b7d-45c0-439b-b1e2-b90a284e27a3','奉和虢州劉給事使君三堂新題二十一詠 方橋','韓愈','唐','唐诗','tang','','[]','非閣復非船，可居兼可過。',24,'全唐诗/poet.tang.18000.json','["非閣復非船，可居兼可過。", "君欲問方橋，方橋如此作。"]'),
('c07e4d69-ad6f-4c4a-a3d7-3bc9f14bf5bf','奉和虢州劉給事使君三堂新題二十一詠 梯橋','韓愈','唐','唐诗','tang','','[]','乍似上青冥，初疑躡菡萏。',24,'全唐诗/poet.tang.18000.json','["乍似上青冥，初疑躡菡萏。", "自無飛仙骨，欲度何由敢。"]'),
('a261570a-0dff-4b8e-bf08-cb39c7dcd9ea','奉和虢州劉給事使君三堂新題二十一詠 月池','韓愈','唐','唐诗','tang','','[]','寒池月下明，新月池邊曲。',24,'全唐诗/poet.tang.18000.json','["寒池月下明，新月池邊曲。", "若不妒清妍，却成相映燭。"]'),
('de458634-e334-4c79-9831-e38075501179','遊城南十六首 賽神','韓愈','唐','唐诗','tang','','[]','白布長衫紫領巾，差科未動是閑人。',32,'全唐诗/poet.tang.18000.json','["白布長衫紫領巾，差科未動是閑人。", "麥苗含穟桑生葚，共向田頭樂社神。"]'),
('6187a93e-9311-40dd-8243-c0fc9100aa26','遊城南十六首 題于賓客莊','韓愈','唐','唐诗','tang','','[]','榆莢車前蓋地皮，薔薇蘸水笋穿籬。',32,'全唐诗/poet.tang.18000.json','["榆莢車前蓋地皮，薔薇蘸水笋穿籬。", "馬蹄無入朱門跡，縱使春歸可得知。"]'),
('45415d34-7f13-4fcb-9f66-cf2b5ae980ad','遊城南十六首 晚春','韓愈','唐','唐诗','tang','','["\u54f2\u7406", "\u6625\u5929"]','草樹知春不久歸，百般紅紫鬬芳菲。',32,'全唐诗/poet.tang.18000.json','["草樹知春不久歸，百般紅紫鬬芳菲。", "楊花榆莢無才思，惟解漫天作雪飛。"]'),
('1896dfac-ff83-497b-a90e-79dbf0fb17ca','遊城南十六首 落花','韓愈','唐','唐诗','tang','','[]','已分將身著地飛，那羞踐踏損光暉。',32,'全唐诗/poet.tang.18000.json','["已分將身著地飛，那羞踐踏損光暉。", "無端又被春風誤，吹落西家不得歸。"]'),
('f035b6a0-ad2b-4b45-9d29-c24794b5b05e','遊城南十六首 楸樹二首 一','韓愈','唐','唐诗','tang','','[]','幾歲生成爲大樹，一朝纏繞困長藤。',32,'全唐诗/poet.tang.18000.json','["幾歲生成爲大樹，一朝纏繞困長藤。", "誰人與脫青羅帔，看吐高花萬萬層。"]'),
('d231d370-bc57-459b-bc6e-dd5278728d7e','遊城南十六首 楸樹二首 二','韓愈','唐','唐诗','tang','','[]','幸自枝條能樹立，可煩蘿蔓作交加。',32,'全唐诗/poet.tang.18000.json','["幸自枝條能樹立，可煩蘿蔓作交加。", "傍人不解尋根本，却道新花勝舊花。"]'),
('d12f8b82-814e-45df-87b8-6062b29bd2a4','遊城南十六首 風折花枝','韓愈','唐','唐诗','tang','','[]','浮豔侵天難就看，清香撲地只遙聞。',32,'全唐诗/poet.tang.18000.json','["浮豔侵天難就看，清香撲地只遙聞。", "春風也是多情思，故揀繁枝折贈君。"]'),
('4b3e7672-8d4b-4e9c-9768-82d7b3f5b758','遊城南十六首 贈同遊','韓愈','唐','唐诗','tang','','[]','喚起窗全曙，催歸日未西。',24,'全唐诗/poet.tang.18000.json','["喚起窗全曙，催歸日未西。", "無心花裏鳥，更與盡情啼。"]'),
('af9cb51e-80f1-4766-89f1-20c35e804f3c','遊城南十六首 贈張十八助敎','韓愈','唐','唐诗','tang','','[]','喜君眸子重清朗，攜手城南歷舊遊。',32,'全唐诗/poet.tang.18000.json','["喜君眸子重清朗，攜手城南歷舊遊。", "忽見孟生題竹處，相看淚落不能收。"]'),
('bf7afde3-6dc5-4fe0-bbb5-893fb5480453','遊城南十六首 題韋氏莊','韓愈','唐','唐诗','tang','','[]','昔者誰能比，今來事不同。',48,'全唐诗/poet.tang.18000.json','["昔者誰能比，今來事不同。", "寂寥青草曲，散漫白榆風。", "架倒藤全落，籬崩竹半空。", "寧須惆悵立，翻覆本無窮。"]'),
('cc6d23de-73bf-45a4-ac23-ae629b2312f1','遊城南十六首 晚雨','韓愈','唐','唐诗','tang','','[]','廉纖晚雨不能晴，池岸草間蚯蚓鳴。',32,'全唐诗/poet.tang.18000.json','["廉纖晚雨不能晴，池岸草間蚯蚓鳴。", "投竿跨馬蹋歸路，纔到城門打鼓聲。"]'),
('5be67cbc-90e8-484e-9b43-4cbbf935a398','遊城南十六首 出城','韓愈','唐','唐诗','tang','','[]','暫出城門蹋青草，遠於林下見春山。',32,'全唐诗/poet.tang.18000.json','["暫出城門蹋青草，遠於林下見春山。", "應須韋杜家家到，祗有今朝一日閑。"]'),
('966c9bb0-6642-4c60-8183-67eb80ac71a2','遊城南十六首 把酒','韓愈','唐','唐诗','tang','','[]','擾擾馳名者，誰能一日閑。',24,'全唐诗/poet.tang.18000.json','["擾擾馳名者，誰能一日閑。", "我來無伴侶，把酒對南山。"]'),
('ed678f60-9e43-47f5-aa99-fc476753503e','遊城南十六首 嘲少年','韓愈','唐','唐诗','tang','','[]','直把春償酒，都將命乞花。',24,'全唐诗/poet.tang.18000.json','["直把春償酒，都將命乞花。", "祗知閑信馬，不覺誤隨車。"]'),
('11185a07-9a7f-4091-a5f3-582b12a3c4ea','遊城南十六首 楸樹','韓愈','唐','唐诗','tang','','[]','青幢紫蓋立童童，細雨浮煙作綵籠。',32,'全唐诗/poet.tang.18000.json','["青幢紫蓋立童童，細雨浮煙作綵籠。", "不得畫師來貌取，定知難見一生中。"]'),
('cd542cb4-430d-4d1b-a085-4eeb4db324e1','遊城南十六首 遣興','韓愈','唐','唐诗','tang','','[]','斷送一生惟有酒，尋思百計不如閑。',32,'全唐诗/poet.tang.18000.json','["斷送一生惟有酒，尋思百計不如閑。", "莫憂世事兼身事，須著人間比夢間。"]'),
('3c802975-63a9-416c-ac3e-cad1d8bb50ab','送李尚書赴襄陽八韻得長字','韓愈','唐','唐诗','tang','','[]','帝憂南國切，改命付忠良。',96,'全唐诗/poet.tang.18000.json','["帝憂南國切，改命付忠良。", "壤畫星搖動，旗分獸簸揚。", "五營兵轉肅，千里地還方。", "控帶荆門遠，飄浮漢水長。", "賜書寬屬郡，戰馬隔鄰疆。", "縱獵雷霆迅，觀棊玉石忙。", "風流峴首客，花豔大堤倡。", "富貴由身致，誰敎不自強。"]'),
('b7b344b4-2f7a-48a0-97b1-50073a9263c8','和席八十二韻','韓愈','唐','唐诗','tang','','[]','絳闕銀河曙，東風右掖春。',144,'全唐诗/poet.tang.18000.json','["絳闕銀河曙，東風右掖春。", "官隨名共美，花與思俱新。", "綺陌朝遊間，綾衾夜直頻。", "橫門開日月，高閣切星辰。", "庭變寒前草，天銷霽後塵。", "溝聲通苑急，柳色壓城勻。", "綸綍謀猷盛，丹青步武親。", "芳菲含斧藻，光景暢形神。", "傍砌看紅藥，巡池詠白蘋。", "多情懷酒伴，餘事作詩人。", "倚玉難藏拙，吹竽久混真。", "坐慙空自老，江海未還身。"]'),
('a6f9692f-f0d6-4b32-8c0a-3dbbe3bc128a','和武相公早春聞鶯','韓愈','唐','唐诗','tang','','[]','早晚飛來入錦城，誰人敎解百般鳴。',32,'全唐诗/poet.tang.18000.json','["早晚飛來入錦城，誰人敎解百般鳴。", "春風紅樹驚眠處，似妬歌童作豔聲。"]'),
('20b51078-7016-481f-9e1d-977a76361984','遊太平公主山莊','韓愈','唐','唐诗','tang','','["\u8bbd\u523a", "\u5199\u4eba", "\u6000\u53e4", "\u5199\u4eba\u8bd7"]','公主當年欲占春，故將臺榭押城闉。',32,'全唐诗/poet.tang.18000.json','["公主當年欲占春，故將臺榭押城闉。", "欲知前面花多少，直到南山不屬人。"]'),
('f2b58be3-ba59-4df2-93a7-899916454dbf','晚春','韓愈','唐','唐诗','tang','','["\u6625\u5929", "\u666f\u7269"]','誰收春色將歸去，慢綠妖紅半不存。',32,'全唐诗/poet.tang.18000.json','["誰收春色將歸去，慢綠妖紅半不存。", "榆莢祗能隨柳絮，等閑撩亂走空園。"]'),
('91981995-3a0f-4aef-844e-288345da7d20','大行皇太后挽歌詞三首 一','韓愈','唐','唐诗','tang','','[]','一紀尊名正，三時孝養榮。',48,'全唐诗/poet.tang.18000.json','["一紀尊名正，三時孝養榮。", "高居朝聖主，厚德載羣生。", "武帳虛中禁，玄堂掩太平。", "秋天笳鼓歇，松柏徧山鳴。"]'),
('334ccae3-b3f8-4489-9d20-daf0cbd2e00a','大行皇太后挽歌詞三首 二','韓愈','唐','唐诗','tang','','[]','威儀備吉凶，文物雜軍容。',48,'全唐诗/poet.tang.18000.json','["威儀備吉凶，文物雜軍容。", "配地行新祭，因山託故封。", "鳳飛終不返，劒化會相從。", "無復臨長樂，空聞報曉鐘。"]'),
('2b334a0c-3897-4322-ba26-20e1f343d730','大行皇太后挽歌詞三首 三','韓愈','唐','唐诗','tang','','[]','追攀萬國來，警衛百神陪。',48,'全唐诗/poet.tang.18000.json','["追攀萬國來，警衛百神陪。", "畫翣登秋殿，容衣入夜臺。", "雲隨僊馭遠，風助聖情哀。", "只有朝陵日，妝匳一暫開。"]'),
('cab9c089-686b-400b-b75f-b180869c9c55','廣宣上人頻見過','韓愈','唐','唐诗','tang','','[]','三百六旬長擾擾，不衝風雨即塵埃。',64,'全唐诗/poet.tang.18000.json','["三百六旬長擾擾，不衝風雨即塵埃。", "久慙朝士無裨補，空愧高僧數往來。", "學道窮年何所得，吟詩竟日未能廻。", "天寒古寺遊人少，紅葉窗前有幾堆。"]'),
('b4cf3bfa-c6c8-4057-b0d0-f23700d69867','閑遊二首 一','韓愈','唐','唐诗','tang','','[]','雨後來更好，繞池徧青青。',48,'全唐诗/poet.tang.18000.json','["雨後來更好，繞池徧青青。", "柳花閑度竹，菱葉故穿萍。", "獨坐殊未厭，孤斟詎能醒。", "持竿至日暮，幽詠欲誰聽。"]'),
('7dfe15f9-43c2-4d0e-9635-fe2e424cc29a','閑遊二首 二','韓愈','唐','唐诗','tang','','[]','茲遊苦不數，再到遂經旬。',48,'全唐诗/poet.tang.18000.json','["茲遊苦不數，再到遂經旬。", "萍蓋汙池淨，藤籠老樹新。", "林烏鳴訝客，岸竹長遮鄰。", "子雲祗自守，奚事九衢塵。"]'),
('ee654644-02ba-487a-afbe-88c7f6e7bc62','酬馬侍郎寄酒','韓愈','唐','唐诗','tang','','[]','一壺情所寄，四句意能多。',24,'全唐诗/poet.tang.18000.json','["一壺情所寄，四句意能多。", "秋到無詩酒，其如月色何。"]'),
('4da3942e-f4e4-4d45-86de-c93a0fe8f411','和侯協律詠笋','韓愈','唐','唐诗','tang','','[]','竹亭人不到，新笋滿前軒。',288,'全唐诗/poet.tang.18000.json','["竹亭人不到，新笋滿前軒。", "乍出真堪賞，初多未覺煩。", "成行齊婢僕，環立比兒孫。", "驗長常攜尺，愁乾屢側盆。", "對吟忘膳飲，偶坐變朝昏。", "滯雨膏腴濕，驕陽氣候溫。", "得時方張王，挾勢欲騰騫。", "見角牛羊沒，看皮虎豹存。", "攢生猶有隙，散布忽無垠。", "詎可持籌算，誰能以理言。", "縱橫公占地，羅列暗連根。", "狂劇時穿壁，橫強幾觸藩。", "深潛如避逐，遠去若追奔。", "始訝妨人路，還驚入藥園。", "萌芽防寖大，覆載莫偏恩。", "已復侵危砌，非徒出短垣。", "身寧虞瓦礫，計擬揜蘭蓀。", "且歎高無數，庸知上幾番。", "短長終不校，先後竟誰論。", "外恨苞藏密，中仍節目繁。", "暫須廻步履，要取助盤飧。", "穰穰疑翻地，森森競塞門。", "戈矛頭戢戢，蛇虺首掀掀。", "婦懦咨料揀，兒癡謁盡髠。"]'),
('446d1d2b-2cc4-4d3e-a1fa-508377745433','過鴻溝','韓愈','唐','唐诗','tang','','[]','龍疲虎困割川原，億萬蒼生性命存。',32,'全唐诗/poet.tang.18000.json','["龍疲虎困割川原，億萬蒼生性命存。", "誰勸君王回馬首，真成一擲賭乾坤。"]'),
('1f5be867-3dfd-4c4e-8392-f3e16405658a','送張侍郎','韓愈','唐','唐诗','tang','','[]','司徒東鎮馳書謁，丞相西來走馬迎。',32,'全唐诗/poet.tang.18000.json','["司徒東鎮馳書謁，丞相西來走馬迎。", "兩府元臣今轉密，一方逋寇不難平。"]'),
('39e34419-dc6c-41bf-8bf4-b1190d566711','贈刑部馬侍郎','韓愈','唐','唐诗','tang','','[]','紅旗照海壓南荒，徵入中臺作侍郎。',32,'全唐诗/poet.tang.18000.json','["紅旗照海壓南荒，徵入中臺作侍郎。", "暫從相公平小寇，便歸天闕致時康。"]'),
('13e75ff2-c432-48b0-8543-20bcd4b7b3ed','奉和裴相公東征途經女几山下作','韓愈','唐','唐诗','tang','','[]','旗穿曉日雲霞雜，山倚秋空劍戟明。',32,'全唐诗/poet.tang.18000.json','["旗穿曉日雲霞雜，山倚秋空劍戟明。", "敢請相公平賊後，暫攜諸吏上崢嶸。"]'),
('90c06400-81aa-4f73-be70-8f8426c9345b','郾城晚飲奉贈副使馬侍郎及馮李二員外','韓愈','唐','唐诗','tang','','[]','城上赤雲呈勝氣，眉間黃色見歸期。',32,'全唐诗/poet.tang.18000.json','["城上赤雲呈勝氣，眉間黃色見歸期。", "幕中無事惟須飲，即是連鑣向闕時。"]'),
('c0925324-863d-4640-9fd9-3b8674bea909','酬別留後侍郎','韓愈','唐','唐诗','tang','','[]','爲文無出相如右，謀師難居卻縠先。',32,'全唐诗/poet.tang.18000.json','["爲文無出相如右，謀師難居卻縠先。", "歸去雪銷溱洧動，西來旌斾拂晴天。"]'),
('92ded1d1-ed42-47fb-b121-6c82304dfad4','同李二十八夜次襄城','韓愈','唐','唐诗','tang','','[]','周楚仍連接，川原乍屈盤。',48,'全唐诗/poet.tang.18000.json','["周楚仍連接，川原乍屈盤。", "雲垂天不暖，塵漲雪猶乾。", "印綬歸台室，旌旗別將壇。", "欲知迎候盛，騎火萬星攢。"]'),
('a5c97944-064e-449b-8717-c7d4f0dad847','同李二十八員外從裴相公野宿西界','韓愈','唐','唐诗','tang','','[]','四面星辰著地明，散燒煙火宿天兵。',32,'全唐诗/poet.tang.18000.json','["四面星辰著地明，散燒煙火宿天兵。", "不關破賊須歸奏，自趂新年賀太平。"]'),
('2dd38c1b-ca84-48f4-a731-d789a3c95176','過襄城','韓愈','唐','唐诗','tang','','[]','郾城辭罷過襄城，潁水嵩山刮眼明。',32,'全唐诗/poet.tang.18000.json','["郾城辭罷過襄城，潁水嵩山刮眼明。", "已去蔡州三百里，家人不用遠來迎。"]'),
('b768177b-5a26-4f53-b7e2-d2db2d362cbc','宿神龜招李二十八馮十七','韓愈','唐','唐诗','tang','','[]','荒山野水照斜暉，啄雪寒鴉趂始飛。',32,'全唐诗/poet.tang.18000.json','["荒山野水照斜暉，啄雪寒鴉趂始飛。", "夜宿驛亭愁不睡，幸來相就蓋征衣。"]'),
('77d3ff20-d7a6-4e36-a7d4-008df44f2503','次硤石','韓愈','唐','唐诗','tang','','[]','數日方離雪，今朝又出山。',24,'全唐诗/poet.tang.18000.json','["數日方離雪，今朝又出山。", "試憑高處望，隱約見潼關。"]'),
('6a94e28f-17a5-40a4-a690-b117747d78e4','和李司勳過連昌宮','韓愈','唐','唐诗','tang','','[]','夾道疎槐出老根，高甍巨桷壓山原。',32,'全唐诗/poet.tang.18000.json','["夾道疎槐出老根，高甍巨桷壓山原。", "宮前遺老來相問，今是開元幾葉孫。"]'),
('70a8fb4e-999a-4497-ae52-40bc78359a58','次潼關先寄張十二閣老使君','韓愈','唐','唐诗','tang','','["\u6292\u60c5"]','荆山已去華山來，日出潼關四扇開。',32,'全唐诗/poet.tang.18000.json','["荆山已去華山來，日出潼關四扇開。", "刺史莫辭迎候遠，相公親破蔡州廻。"]'),
('3ef8452e-67c9-46c4-bd17-8edfd80a7676','次潼關上都統相公','韓愈','唐','唐诗','tang','','[]','暫辭堂印執兵權，盡管諸軍破賊年。',32,'全唐诗/poet.tang.18000.json','["暫辭堂印執兵權，盡管諸軍破賊年。", "冠蓋相望催入相，待將功德格皇天。"]'),
('17a154bf-36c4-49cf-8091-105f48c9ec09','桃林夜賀晉公','韓愈','唐','唐诗','tang','','[]','西來騎火照山紅，夜宿桃林臘月中。',32,'全唐诗/poet.tang.18000.json','["西來騎火照山紅，夜宿桃林臘月中。", "手把命珪兼相印，一時重疊賞元功。"]'),
('23865eac-df6b-407d-acea-2544745a2611','送李員外院長分司東都','韓愈','唐','唐诗','tang','','[]','去年秋露下，羇旅逐東征。',48,'全唐诗/poet.tang.18000.json','["去年秋露下，羇旅逐東征。", "今歲春光動，驅馳別上京。", "飲中相顧色，送後獨歸情。", "兩地無千里，因風數寄聲。"]'),
('84de8581-250e-4a4e-9813-868067cc876a','晉公破賊回重拜台司以詩示幕中賓客愈奉和','韓愈','唐','唐诗','tang','','[]','南伐旋師太華東，天書夜到冊元功。',64,'全唐诗/poet.tang.18000.json','["南伐旋師太華東，天書夜到冊元功。", "將軍舊壓三司貴，相國新兼五等崇。", "鵷鷺欲歸仙仗裏，熊羆還入禁營中。", "長慙典午非材職，得就閑官即至公。"]'),
('96ff7a1f-7b2a-4127-b407-d03cfdcac921','獨釣四首 一','韓愈','唐','唐诗','tang','','[]','侯家林館勝，偶入得垂竿。',48,'全唐诗/poet.tang.18000.json','["侯家林館勝，偶入得垂竿。", "曲樹行藤角，平池散芡盤。", "羽沈知食駛，緡細覺牽難。", "聊取夸兒女，榆條繫從鞍。"]'),
('33b6328c-daa7-4137-bc4c-31789f6291ce','獨釣四首 二','韓愈','唐','唐诗','tang','','[]','一逕向池斜，池搪野草花。',48,'全唐诗/poet.tang.18000.json','["一逕向池斜，池搪野草花。", "雨多添柳耳，水長減蒲芽。", "坐厭親刑柄，偷來傍釣車。", "太平公事少，吏隱詎相賒。"]'),
('bddfa020-0ddc-46e9-b99d-df4088a2c418','獨釣四首 三','韓愈','唐','唐诗','tang','','[]','獨往南塘上，秋晨景氣醒。',48,'全唐诗/poet.tang.18000.json','["獨往南塘上，秋晨景氣醒。", "露排四岸草，風約半池萍。", "鳥下見人寂，魚來聞餌馨。", "所嗟無可召，不得倒吾缾。"]'),
('3fd92446-b46c-42e7-ab23-ce3ff3fe01a4','獨釣四首 四','韓愈','唐','唐诗','tang','','[]','秋半百物變，溪魚去不來。',48,'全唐诗/poet.tang.18000.json','["秋半百物變，溪魚去不來。", "風能坼芡觜，露亦染梨腮。", "遠岫重疊出，寒花散亂開。", "所期終莫至，日暮與誰廻。"]'),
('7931bd8a-db01-4e8e-aec3-9fcd1d452798','枯樹','韓愈','唐','唐诗','tang','','[]','老樹無枝葉，風霜不復侵。',48,'全唐诗/poet.tang.18000.json','["老樹無枝葉，風霜不復侵。", "腹穿人可過，皮剝蟻還尋。", "寄託惟朝菌，依投絕暮禽。", "猶堪持改火，未肯但空心。"]'),
('3e10c191-80af-40e3-b99b-7b4698c2dd0a','元日酬蔡州馬十二尚書去年蔡州元日見寄之什','韓愈','唐','唐诗','tang','','[]','元日新詩已去年，蔡州遙寄荷相憐。',32,'全唐诗/poet.tang.18000.json','["元日新詩已去年，蔡州遙寄荷相憐。", "今朝縱有誰人領，自是三峰不敢眠。"]'),
('0083cf89-9243-4765-8a97-a147ec34f3dd','詠燈花同侯十一','韓愈','唐','唐诗','tang','','[]','今夕知何夕，花然錦帳中。',48,'全唐诗/poet.tang.18000.json','["今夕知何夕，花然錦帳中。", "自能當雪暖，那肯待春紅。", "黃裏排金粟，釵頭綴玉蟲。", "更煩將喜事，來報主人公。"]'),
('b86d0d78-6f25-4416-a0a5-0616535d4e9f','祖席前字','韓愈','唐','唐诗','tang','','[]','祖席洛橋邊，親交共黯然。',48,'全唐诗/poet.tang.18000.json','["祖席洛橋邊，親交共黯然。", "野晴山簇簇，霜曉菊鮮鮮。", "書寄相思處，桮銜欲別前。", "淮陽知不薄，終願早廻船。"]'),
('231a4c73-c9df-482b-9980-caad78610d31','秋字','韓愈','唐','唐诗','tang','','[]','淮南悲木落，而我亦傷秋。',48,'全唐诗/poet.tang.18000.json','["淮南悲木落，而我亦傷秋。", "況與故人別，那堪羇宦愁。", "榮華今異路，風雨昔同憂。", "莫以宜春遠，江山多勝遊。"]'),
('eecadce0-6252-4216-aa60-df22b3b6c242','送鄭尚書赴南海','韓愈','唐','唐诗','tang','','[]','番禺軍府盛，欲說暫停桮。',72,'全唐诗/poet.tang.18000.json','["番禺軍府盛，欲說暫停桮。", "蓋海旂幢出，連天觀閣開。", "衙時龍戶集，上日馬人來。", "風靜鶢鶋去，官廉蚌蛤廻。", "貨通師子國，樂奏武王臺。", "事事皆殊異，無嫌屈大才。"]'),
('1b6621a9-58a8-44d1-a365-52e9feb3604f','答道士寄樹雞','韓愈','唐','唐诗','tang','','[]','軟濕青黃狀可猜，欲烹還喚木盤廻。',32,'全唐诗/poet.tang.18000.json','["軟濕青黃狀可猜，欲烹還喚木盤廻。", "煩君自入華陽洞，直割乖龍左耳來。"]'),
('861aac3a-3c3d-480c-bdb0-d0c25b7fbf14','左遷至藍關示姪孫湘','韓愈','唐','唐诗','tang','','[]','一封朝奏九重天，夕貶潮州路八千。',64,'全唐诗/poet.tang.18000.json','["一封朝奏九重天，夕貶潮州路八千。", "欲爲聖朝除弊事，肯將衰朽惜殘年。", "雲橫秦嶺家何在，雪擁藍關馬不前。", "知汝遠來應有意，好收吾骨瘴江邊。"]'),
('e9e4e3e7-ab3d-4eeb-968c-440e97f99b03','武關西逢配流吐蕃','韓愈','唐','唐诗','tang','','[]','嗟爾戎人莫慘然，湖南地近保生全。',32,'全唐诗/poet.tang.18000.json','["嗟爾戎人莫慘然，湖南地近保生全。", "我今罪重無歸望，直去長安路八千。"]'),
('0ef12f5c-3640-49fb-9d44-669fb27f6ea5','次鄧州界','韓愈','唐','唐诗','tang','','[]','潮陽南去倍長沙，戀闕那堪又憶家。',64,'全唐诗/poet.tang.18000.json','["潮陽南去倍長沙，戀闕那堪又憶家。", "心訝愁來惟貯火，眼知別後自添花。", "商顏暮雪逢人少，鄧鄙春泥見驛賒。", "早晚王師收海嶽，普將雷雨發萌芽。"]'),
('7c56658c-6928-42e3-ba7f-b2098a33453e','題臨瀧寺','韓愈','唐','唐诗','tang','','[]','不覺離家已五千，仍將衰病入瀧船。',32,'全唐诗/poet.tang.18000.json','["不覺離家已五千，仍將衰病入瀧船。", "潮陽未到吾能說，海氣昏昏水拍天。"]'),
('0a501890-4994-4da6-9620-5a6f80f41b8f','晚次宣溪辱韻州張端公使君惠書敘別酬以絕句二章 一','韓愈','唐','唐诗','tang','','[]','韶州南去接宣溪，雲水蒼茫日向西。',32,'全唐诗/poet.tang.18000.json','["韶州南去接宣溪，雲水蒼茫日向西。", "客淚數行先自落，鷓鴣休傍耳邊啼。"]'),
('939ab698-2ed2-4525-8577-45a8179cc842','晚次宣溪辱韻州張端公使君惠書敘別酬以絕句二章 二','韓愈','唐','唐诗','tang','','[]','兼金那足比清文，百首相隨媿使君。',32,'全唐诗/poet.tang.18000.json','["兼金那足比清文，百首相隨媿使君。", "俱是嶺南巡管內，莫欺荒僻斷知聞。"]'),
('f54b5e5c-f695-4bb7-8484-33650a82a1ab','題秀禪師房','韓愈','唐','唐诗','tang','','[]','橋夾水松行百步，竹牀莞席到僧家。',32,'全唐诗/poet.tang.18000.json','["橋夾水松行百步，竹牀莞席到僧家。", "暫拳一手支頭臥，還把魚竿下釣沙。"]'),
('3fa73cd3-703f-46cf-9eb5-8f628eb69947','將至韶州先寄張端公使君借圖經','韓愈','唐','唐诗','tang','','[]','曲江山水聞來久，恐不知名訪倍難。',32,'全唐诗/poet.tang.18000.json','["曲江山水聞來久，恐不知名訪倍難。", "願借圖經將入界，每逢佳處便開看。"]'),
('982364ab-2766-490e-8b90-88d9169c2fb5','過始興江口感懷','韓愈','唐','唐诗','tang','','[]','憶作兒童隨伯氏，南來今只一身存。',32,'全唐诗/poet.tang.18000.json','["憶作兒童隨伯氏，南來今只一身存。", "目前百口還相逐，舊事無人可共論。"]'),
('691adfca-49d9-429b-95f1-d23eccc452b4','韶州留別張端公使君','韓愈','唐','唐诗','tang','','[]','來往再逢梅柳新，別離一醉綺羅春。',64,'全唐诗/poet.tang.18000.json','["來往再逢梅柳新，別離一醉綺羅春。", "久欽江總文才妙，自歎虞翻骨相屯。", "鳴笛急吹爭落日，清歌緩送款行人。", "已知奏課當徵拜，那復淹留詠白蘋。"]'),
('5db93f1b-e79b-4322-9eef-4714a1b31681','從潮州量移袁州張韶州端公以詩相賀因酬之','韓愈','唐','唐诗','tang','','[]','明時遠逐事何如，遇赦移官罪未除。',64,'全唐诗/poet.tang.18000.json','["明時遠逐事何如，遇赦移官罪未除。", "北望詎令隨塞鴈，南遷纔免葬江魚。", "將經貴郡煩留客，先惠高文謝起予。", "暫欲繫船韶石下，上賓虞舜整冠裾。"]'),
('59f47b2d-ed9b-456c-9877-908f5f85e7dc','次石頭驛寄江西王十中丞閣老','韓愈','唐','唐诗','tang','','[]','憑高試廻首，一望豫章城。',48,'全唐诗/poet.tang.18000.json','["憑高試廻首，一望豫章城。", "人由戀德泣，馬亦別羣鳴。", "寒日夕始照，風江遠漸平。", "默然都不語，應識此時情。"]'),
('53f96ba9-eb8f-4293-9d1a-47bd07855c14','遊西林寺題蕭二兄郎中舊堂','韓愈','唐','唐诗','tang','','["\u5e90\u5c71"]','中郎有女能傳業，伯道無兒可保家。',32,'全唐诗/poet.tang.18000.json','["中郎有女能傳業，伯道無兒可保家。", "偶到匡山曾住處，幾行衰淚落煙霞。"]'),
('46e8a421-af5d-4785-af7d-443cdbfab7e9','自袁州還京行次安陸先寄隨州周員外','韓愈','唐','唐诗','tang','','[]','行行指漢東，暫喜笑言同。',48,'全唐诗/poet.tang.18000.json','["行行指漢東，暫喜笑言同。", "雨雪離江上，蒹葭出夢中。", "面猶含瘴色，眼已見華風。", "歲暮難相值，酣歌未可終。"]'),
('d978fb59-bb80-4d6c-a2e0-3beb10b68525','題廣昌館','韓愈','唐','唐诗','tang','','[]','白水龍飛已幾春，偶逢遺跡問耕人。',32,'全唐诗/poet.tang.18000.json','["白水龍飛已幾春，偶逢遺跡問耕人。", "丘墳發掘當官路，何處南陽有近親。"]'),
('57db46c4-7375-4705-ab9e-0c07e71b8cb2','寄隨州周員外','韓愈','唐','唐诗','tang','','[]','陸孟丘楊久作塵，同時存者更誰人。',32,'全唐诗/poet.tang.18000.json','["陸孟丘楊久作塵，同時存者更誰人。", "金丹別後知傳得，乞取刀圭救病身。"]'),
('8b7dc40f-abeb-4bbf-bc8f-6be1b25a4854','酒中留上襄陽李相公','韓愈','唐','唐诗','tang','','[]','濁水汙泥清路塵，還曾同制掌絲綸。',64,'全唐诗/poet.tang.18000.json','["濁水汙泥清路塵，還曾同制掌絲綸。", "眼穿長訝雙魚斷，耳熱何辭數爵頻。", "銀燭未銷窗送曙，金釵半醉座添春。", "知公不久歸鈞軸，應許閑官寄病身。"]'),
('20b7830c-2095-461d-ab54-97dff0c25a20','去歲自刑部侍郎以罪貶潮州刺史乘驛赴任其後家亦譴逐小女道死殯之層峰驛旁山下蒙恩還朝過其墓留題驛梁','韓愈','唐','唐诗','tang','','[]','數條藤束木皮棺，草殯荒山白骨寒。',64,'全唐诗/poet.tang.18000.json','["數條藤束木皮棺，草殯荒山白骨寒。", "驚恐入心身已病，扶舁沿路衆知難。", "繞墳不暇號三帀，設祭惟聞飯一盤。", "致汝無辜由我罪，百年慙痛淚闌干。"]'),
('c9604f42-9a59-48ac-9978-5c66dce7922d','賀張十八秘書得裴司空馬','韓愈','唐','唐诗','tang','','[]','司空遠寄養初成，毛色桃花眼鏡明。',64,'全唐诗/poet.tang.18000.json','["司空遠寄養初成，毛色桃花眼鏡明。", "落日已曾交轡語，春風還擬竝鞍行。", "長令奴僕知飢渴，須着賢良待性情。", "旦夕公歸伸拜謝，免勞騎去逐雙旌。"]'),
('c94b341b-494b-447d-a668-8bdd9193a338','杏園送張徹侍御歸使','韓愈','唐','唐诗','tang','','[]','東風花樹下，送爾出京城。',48,'全唐诗/poet.tang.18000.json','["東風花樹下，送爾出京城。", "久抱傷春意，新添惜別情。", "歸來身已病，相見眼還明。", "更遣將詩酒，誰家逐後生。"]'),
('fa54743c-d0e4-4112-893c-ca39716ea2ca','雨中寄張博士籍侯主簿喜','韓愈','唐','唐诗','tang','','[]','放朝還不報，半路蹋泥歸。',48,'全唐诗/poet.tang.18000.json','["放朝還不報，半路蹋泥歸。", "雨慣曾無節，雷頻自失威。", "見牆生菌徧，憂麥作蛾飛。", "歲晚偏蕭索，誰當救晉饑。"]'),
('795a1848-1768-460c-9ccb-082ee70bb11a','奉和兵部張侍郎酬鄆州馬尚書祗召途中見寄開緘之日馬帥已再領鄆州之作','韓愈','唐','唐诗','tang','','[]','來朝當路日，承詔改轅時。',48,'全唐诗/poet.tang.18000.json','["來朝當路日，承詔改轅時。", "再領須句國，仍遷少昊司。", "暖風抽宿麥，清雨卷歸旗。", "賴寄新珠玉，長吟慰我思。"]'),
('1dab9bf3-9d50-404f-a75c-04648fbcb9be','早春與張十八博士籍遊楊尚書林亭寄第三閣老兼呈白馮二閣老','韓愈','唐','唐诗','tang','','[]','牆下春渠入禁溝，渠冰初破滿渠浮。',32,'全唐诗/poet.tang.18000.json','["牆下春渠入禁溝，渠冰初破滿渠浮。", "鳳池近日長先暖，流到池時更不流。"]'),
('7187c16a-ee57-472a-8a26-5fb3675ed3ed','奉使常山早次太原呈副使吳郎中','韓愈','唐','唐诗','tang','','[]','朗朗聞街鼓，晨起似朝時。',48,'全唐诗/poet.tang.18000.json','["朗朗聞街鼓，晨起似朝時。", "翻翻走驛馬，春盡是歸期。", "地失嘉禾處，風存蟋蟀辭。", "暮齒良多感，無事涕垂頤。"]'),
('fd20e8ed-c177-4ea6-b751-1fd9515969a6','夕次壽陽驛題吳郎中詩後','韓愈','唐','唐诗','tang','','[]','風光欲動別長安，春半城邊特地寒。',32,'全唐诗/poet.tang.18000.json','["風光欲動別長安，春半城邊特地寒。", "不見園花兼巷柳，馬頭惟有月團團。"]'),
('8c5ec1ac-b70f-44cf-a41e-c5ebf6231b27','鎮州初歸','韓愈','唐','唐诗','tang','','[]','別來楊柳街頭樹，擺弄春風只欲飛。',32,'全唐诗/poet.tang.18000.json','["別來楊柳街頭樹，擺弄春風只欲飛。", "還有小園桃李在，留花不發待郎歸。"]'),
('84ad2115-65fa-4d8f-9d32-008443003d5d','同水部張員外籍曲江春遊寄白二十二舍人','韓愈','唐','唐诗','tang','','[]','漠漠輕陰晚自開，青天白日映樓臺。',32,'全唐诗/poet.tang.18000.json','["漠漠輕陰晚自開，青天白日映樓臺。", "曲江水滿花千樹，有底忙時不肯來。"]'),
('f7b65471-38e0-4be2-b932-87655d3edbfd','和水部張員外宣政衙賜百官櫻桃詩','韓愈','唐','唐诗','tang','','[]','漢家舊種明光殿，炎帝還書本草經。',64,'全唐诗/poet.tang.18000.json','["漢家舊種明光殿，炎帝還書本草經。", "豈似滿朝承雨露，共看傳賜出青冥。", "香隨翠籠擎初到，色暎銀盤寫未停。", "食罷自知無所報，空然慙汗仰皇扃。"]'),
('d7cb4244-143b-403b-8599-b10c6763d032','早春呈水部張十八員外二首 一','韓愈','唐','唐诗','tang','','["\u5199\u96e8", "\u6625\u5929", "\u516b\u5e74\u7ea7\u4e0b\u518c(\u8bfe\u5916)", "\u5199\u666f", "\u67f3\u6811", "\u521d\u4e2d\u53e4\u8bd7"]','天街小雨潤如酥，草色遙看近却無。',32,'全唐诗/poet.tang.18000.json','["天街小雨潤如酥，草色遙看近却無。", "最是一年春好處，絕勝煙柳滿皇都。"]'),
('8e522ba0-45e7-431c-84d0-07342a614318','早春呈水部張十八員外二首 二','韓愈','唐','唐诗','tang','','[]','莫道官忙身老大，即無年少逐春心。',32,'全唐诗/poet.tang.18000.json','["莫道官忙身老大，即無年少逐春心。", "憑君先到江頭看，柳色如今深未深。"]'),
('556900c5-7e75-4b5f-8c52-e32693953396','送桂州嚴大夫同用南字','韓愈','唐','唐诗','tang','','["\u9001\u522b", "\u5c71\u6c34", "\u666f\u70b9"]','蒼蒼森八桂，茲地在湘南。',48,'全唐诗/poet.tang.18000.json','["蒼蒼森八桂，茲地在湘南。", "江作青羅帶，山如碧玉篸。", "戶多輸翠羽，家自種黃甘。", "遠勝登僊去，飛鸞不假驂。"]'),
('263cca89-a600-405f-a0a8-d778ac99e5b8','奉酬天平馬十二僕射暇日言懷見寄之作','韓愈','唐','唐诗','tang','','[]','天平篇什外，政事亦無雙。',48,'全唐诗/poet.tang.18000.json','["天平篇什外，政事亦無雙。", "威令加徐土，儒風被魯邦。", "清爲公論重，寬得士心降。", "歲晏偏相憶，長謠坐北窗。"]'),
('531d9020-6b63-4b14-8605-9a779b2d2579','奉使鎮州行次承天行營奉酬裴司空','韓愈','唐','唐诗','tang','','[]','竄逐三年海上歸，逢公復此著征衣。',32,'全唐诗/poet.tang.18000.json','["竄逐三年海上歸，逢公復此著征衣。", "旋吟佳句還鞭馬，恨不身先去鳥飛。"]'),
('4e871e4a-9c45-4b79-93c6-a12e91f8ad34','鎮州路上謹酬裴司空相公重見寄','韓愈','唐','唐诗','tang','','[]','銜命山東撫亂師，日馳三百自嫌遲。',32,'全唐诗/poet.tang.18000.json','["銜命山東撫亂師，日馳三百自嫌遲。", "風霜滿面無人識，何處如今更有詩。"]'),
('5641c747-b437-4c50-b073-812cf05aec0e','奉和僕射裴相公感跨恩言志','韓愈','唐','唐诗','tang','','[]','文武功成後，居爲百辟師。',48,'全唐诗/poet.tang.18000.json','["文武功成後，居爲百辟師。", "林園窮勝事，鐘鼓樂清時。", "擺落遺高論，雕鐫出小詩。", "自然無不可，范蠡爾其誰。"]'),
('4a639502-2c63-4bd7-86d7-01edca3c50f6','和僕射相公朝廻見寄','韓愈','唐','唐诗','tang','','[]','盡瘁年將久，公今始暫閑。',48,'全唐诗/poet.tang.18000.json','["盡瘁年將久，公今始暫閑。", "事隨憂共減，詩與酒俱還。", "放意機衡外，收身矢石間。", "秋臺風日迥，正好看前山。"]'),
('20d878ef-3122-49aa-a5e9-311d5442c8d4','奉和李相公題蕭家林亭','韓愈','唐','唐诗','tang','','[]','山公自是林園主，歎惜前賢造作時。',32,'全唐诗/poet.tang.18000.json','["山公自是林園主，歎惜前賢造作時。", "巖洞幽深門盡鎖，不因丞相幾人知。"]'),
('736572d1-f38d-46aa-ba3d-8b895cf81011','奉和杜相公太清宮紀事陳誠上李相公十六韻','韓愈','唐','唐诗','tang','','[]','耒耜興姬國，輴欙建夏家。',192,'全唐诗/poet.tang.18000.json','["耒耜興姬國，輴欙建夏家。", "在功誠可尚，於道詎爲華。", "象帝威容大，僊宗寶曆賒。", "衛門羅戟槊，圖壁雜龍蛇。", "禮樂追尊盛，乾坤降福遐。", "四真皆齒列，二聖亦肩差。", "陽月時之首，陰泉氣未牙。", "殿階鋪水碧，庭炬坼金葩。", "紫極觀忘倦，青詞奏不譁。", "噌吰宮夜闢，嘈囐鼓晨撾。", "褻味陳奚取，名香薦孔嘉。", "垂祥紛可錄，俾壽浩無涯。", "貴相山瞻峻，清文玉絕瑕。", "代工聲問遠，攝事敬恭加。", "皎潔當天月，葳蕤捧日霞。", "唱妍酬亦麗，俛仰但稱嗟。"]'),
('9763af12-4206-43f2-ba3c-1dd4265b713e','鄆州谿堂詩','韓愈','唐','唐诗','tang','','[]','帝奠九廛，有葉有年。',240,'全唐诗/poet.tang.18000.json','["帝奠九廛，有葉有年。", "有荒不條，河岱之間。", "及我憲考，一收正之。", "視邦選侯，以公來尸。", "公來尸之，人始未信。", "公不飲食，以訓以徇。", "孰飢無食，孰呻孰歎。", "孰冤不問，不得分願。", "孰爲邦蟊，節根之螟。", "羊很狼貪，以口覆城。", "吹之喣之，摩手拊之。", "箴之石之，膊而磔之。", "凡公四封，既富以彊。", "謂公吾父，孰違公令。", "可以師征，不寧守邦。", "公作谿堂，播播流水。", "淺有蒲蓮，深有葭葦。", "公以賓燕，其鼓駭駭。", "公燕谿堂，賓校醉飽。", "流有跳魚，岸有集鳥。", "既歌以舞，其鼓考考。", "公在谿堂，公御琴瑟。", "公暨賓贊，稽經諏律。", "施用不差，人用不屈。"]'),
('23fbeeb1-832d-4c6d-a461-d06da393a4bf','送張道士','韓愈','唐','唐诗','tang','','[]','大匠無棄材，尋尺各有施。',276,'全唐诗/poet.tang.18000.json','["大匠無棄材，尋尺各有施。", "況當營都邑，杞梓用不疑。", "張侯嵩高來，面有熊豹姿。", "開口論利害，劒鋒白差差。", "恨無一尺捶，爲國笞羌夷。", "詣闕三上書，臣非黃冠師。", "臣有膽與氣，不忍死茅茨。", "又不媚笑語，不能伴兒嬉。", "乃著道士服，衆人莫臣知。", "臣有平賊策，狂童不難治。", "其言簡且要，陛下幸聽之。", "天空日月高，下照理不遺。", "或是章奏繁，裁擇未及斯。", "寧當不竢報，歸袖風披披。", "答我事不爾，吾親屬吾思。", "昨宵夢倚門，手取連環持。", "今日有書至，又言歸何時。", "霜天熟柿栗，收拾不可遲。", "嶺北梁可構，寒魚下清伊。", "既非公家用，且復還其私。", "從容進退間，無一不合宜。", "時有利不利，雖賢欲奚爲。", "但當勵前操，富貴非公誰。"]'),
('837ee663-d797-49f4-93b8-923d4baac950','送鄭十校理得洛字','韓愈','唐','唐诗','tang','','[]','相公倦台鼎，分正新邑洛。',60,'全唐诗/poet.tang.18000.json','["相公倦台鼎，分正新邑洛。", "才子富文華，校讐天祿閣。", "壽觴佳節過，歸騎春衫薄。", "鳥哢正交加，楊花共紛泊。", "親交誰不羨，去去翔寥廓。"]'),
('4196d48d-8b3d-4b74-b28c-1cecaa9f32fa','送陸歙州傪','韓愈','唐','唐诗','tang','','[]','我衣之華兮，我佩之光。',63,'全唐诗/poet.tang.18000.json','["我衣之華兮，我佩之光。", "陸君之去兮，誰與翺翔。", "斂此大惠兮，施於一州。", "今其去矣，胡不爲留。", "我作此詩，歌於遠道。", "無疾其驅，天子有詔。"]'),
('33f3bc50-8a7f-4445-995e-1d1af406ae26','送汴州監軍俱文珍','韓愈','唐','唐诗','tang','','[]','奉使羌池靜，臨戎汴水安。',48,'全唐诗/poet.tang.18000.json','["奉使羌池靜，臨戎汴水安。", "沖天鵬翅闊，報國劒鋩寒。", "曉日驅征騎，春風詠采蘭。", "誰言臣子道，忠孝兩全難。"]'),
('616dfb51-66c5-483f-b2a9-134e151c5009','贈崔立之','韓愈','唐','唐诗','tang','','[]','昔年十日雨，子桑苦寒飢。',132,'全唐诗/poet.tang.18000.json','["昔年十日雨，子桑苦寒飢。", "哀歌坐空室，不怨但自悲。", "其友名子輿，忽然憂且思。", "搴裳觸泥水，裹飯往食之。", "入門相對語，天命良不疑。", "好事漆園吏，書之存雄詞。", "千年事已遠，二子情可推。", "我讀此篇日，正當寒雪時。", "吾身固已困，吾友復何爲。", "薄粥不足裹，深泥諒難馳。", "曾無子輿事，空賦子桑詩。"]'),
('0c77b837-3be7-4296-b952-ce99dff4f622','海水','韓愈','唐','唐诗','tang','','[]','海水非不廣，鄧林豈無枝。',168,'全唐诗/poet.tang.18000.json','["海水非不廣，鄧林豈無枝。", "風波一蕩薄，魚鳥不可依。", "海水饒大波，鄧林多驚風。", "豈無魚與鳥，巨細各不同。", "海有吞舟鯨，鄧有垂天鵬。", "苟非鱗羽大，蕩薄不可能。", "我鱗不盈寸，我羽不盈尺。", "一木有餘陰，一泉有餘澤。", "我將辭海水，濯鱗清冷池。", "我將辭鄧林，刷羽蒙籠枝。", "海水非愛廣，鄧林非愛枝。", "風波亦常事，鱗魚自不宜。", "我鱗日已大，我羽日已修。", "風波無所苦，還作鯨鵬遊。"]'),
('28106f1b-3e27-4774-a357-7f4dba9cb7ca','贈河陽李大夫','韓愈','唐','唐诗','tang','','[]','四海失巢穴，兩都困塵埃。',48,'全唐诗/poet.tang.18000.json','["四海失巢穴，兩都困塵埃。", "感恩由未報，惆悵空一來。", "裘破氣不暖，馬羸鳴且哀。", "主人情更重，空使劒鋒摧。"]'),
('13931b8a-688a-4ebb-9354-b15490ba70c2','苦寒歌','韓愈','唐','唐诗','tang','','[]','黃昏苦寒歌，夜半不能休。',60,'全唐诗/poet.tang.18000.json','["黃昏苦寒歌，夜半不能休。", "豈不有陽春，節歲聿其周。", "君何愛重裘，兼味養大賢。", "冰食葛製神所憐，填窗塞戶慎勿出，暄風暖景明年日。"]'),
('fe4cef65-5782-4d2d-ba9e-7e956b2f0d55','芍藥歌','韓愈','唐','唐诗','tang','','[]','丈人庭中開好花，更無凡木爭春華。',128,'全唐诗/poet.tang.18000.json','["丈人庭中開好花，更無凡木爭春華。", "翠莖紅蘂天力與，此恩不屬黃鍾家。", "溫馨熟美鮮香起，似笑無言習君子。", "霜刀翦汝天女勞，何事低頭學桃李。", "嬌癡婢子無靈性，競挽春衫來比並。", "欲將雙頰一晞紅，綠窗磨徧青銅鏡。", "一尊春酒甘若飴，丈人此樂無人知。", "花前醉倒歌者誰，楚狂小子韓退之。"]'),
('bce64707-a533-438a-9d36-deb8520b13f7','贈徐州族姪','韓愈','唐','唐诗','tang','','[]','我年十八九，壯氣起胸中。',132,'全唐诗/poet.tang.18000.json','["我年十八九，壯氣起胸中。", "作書獻雲闕，辭家逐秋蓬。", "歲時易遷次，身命多厄窮。", "一名雖云就，片祿不足充。", "今者復何事，卑棲寄徐戎。", "蕭條資用盡，濩落門巷空。", "朝眠未能起，遠懷方鬱悰。", "擊門者誰子，問言乃吾宗。", "自云有奇術，探妙知天工。", "既往悵何及，將來喜還通。", "期我語非佞，當爲佐時雍。"]'),
('fee63cab-0d90-4fd0-b35f-116d0edede51','嘲鼾睡','韓愈','唐','唐诗','tang','','[]','澹師晝睡時，聲氣一何猥。',180,'全唐诗/poet.tang.18000.json','["澹師晝睡時，聲氣一何猥。", "頑飆吹肥脂，坑谷相嵬磊。", "雄哮乍咽絕，每發壯益倍。", "有如阿鼻尸，長喚忍衆罪。", "馬牛驚不食，百鬼聚相待。", "木枕十字裂，鏡面生痱癗。", "鐵佛聞皺眉，石人戰搖腿。", "孰云天地仁，吾欲責真宰。", "幽尋虱搜耳，猛作濤翻海。", "太陽不忍明，飛御皆惰怠。", "乍如彭與黥，呼冤受葅醢。", "又如圈中虎，號瘡兼吼餒。", "雖令伶倫吹，苦韻難可改。", "雖令巫咸招，魂爽難復在。", "何山有靈藥，療此願與採。"]'),
('780ee4b9-16db-4039-ae3c-2f393b1281ef','嘲鼾睡 二','韓愈','唐','唐诗','tang','','["\u9ec4\u6cb3"]','澹公坐臥時，長睡無不穩。',144,'全唐诗/poet.tang.18000.json','["澹公坐臥時，長睡無不穩。", "吾嘗聞其聲，深慮五藏損。", "黃河弄濆薄，梗澀連拙鮌。", "南帝初舊槌，鑿竅洩混沌。", "迥然忽長引，萬丈不可忖。", "謂言絕於斯，繼出方袞袞。", "幽幽寸喉中，草木森苯䔿。", "盜賊雖狡獪，亡魂敢窺閫。", "鴻蒙總合雜，詭譎騁戾很。", "乍如鬬呶呶，忽若怨懇懇。", "賦形苦不同，無路尋根本。", "何能堙其源，惟有土一畚。"]'),
('ff42e14b-b52e-42f4-99f5-271350ce688a','晝月','韓愈','唐','唐诗','tang','','[]','玉盌不磨著泥土，青天孔出白石補。',56,'全唐诗/poet.tang.18000.json','["玉盌不磨著泥土，青天孔出白石補。", "兔入臼藏蛙縮肚，桂樹枯株女閉戶。", "陰爲陽羞固自古，嗟汝下民或敢侮，戲嘲盜視汝目瞽。"]'),
('8f6c694c-c2d2-476c-a1ff-a43def1eede7','贈張徐州莫辭酒','韓愈','唐','唐诗','tang','','[]','莫辭酒，此會固難同。',54,'全唐诗/poet.tang.18000.json','["莫辭酒，此會固難同。", "請看女工機上帛，半作軍人旗上紅。", "莫辭酒，誰爲君王之爪牙。", "春雷三月不作響，戰士豈得來還家。"]'),
('bbbb3f85-f8bd-4e6c-8077-f7153f0b13f7','辭唱歌','韓愈','唐','唐诗','tang','','[]','抑逼敎唱歌，不解看豔詞。',132,'全唐诗/poet.tang.18000.json','["抑逼敎唱歌，不解看豔詞。", "坐中把酒人，豈有歡樂姿。", "幸有伶者婦，腰身如柳枝。", "但令送君酒，如醉如憨癡。", "聲自肉中出，使人能逶隨。", "復遣慳恡者，贈金不皺眉。", "豈有長直夫，喉中聲雌雌。", "君心豈無恥，君豈是女兒。", "君敎發直言，大聲無休時。", "君敎哭古恨，不肯復吞悲。", "乍可阻君意，豔歌難可爲。"]'),
('1cd60767-2951-4ad1-993d-cf1ff770aede','知音者誠希','韓愈','唐','唐诗','tang','','["\u670b\u53cb", "\u6292\u60c5", "\u60dc\u522b"]','知音者誠希，念子不能別。',24,'全唐诗/poet.tang.18000.json','["知音者誠希，念子不能別。", "行行天未曉，攜酒踏明月。"]'),
('9f900f9e-1045-42bf-a4e2-57e644560bc3','同竇韋尋劉尊師不遇','韓愈','唐','唐诗','tang','','[]','秦客何年駐，仙源此地深。',48,'全唐诗/poet.tang.18000.json','["秦客何年駐，仙源此地深。", "還隨躡鳧騎，來訪馭風襟。", "院閉青霞入，松高老鶴尋。", "猶疑隱形坐，敢起竊桃心。"]'),
('0b995b0e-aaf5-4332-9f95-ade8ac6d14ef','春雪','韓愈','唐','唐诗','tang','','[]','片片驅鴻急，紛紛逐吹斜。',72,'全唐诗/poet.tang.18000.json','["片片驅鴻急，紛紛逐吹斜。", "到江還作水，著樹漸成花。", "越喜飛排瘴，胡愁厚蓋砂。", "兼雲封洞口，助月照天涯。", "暝見迷巢鳥，朝逢失轍車。", "呈豐盡相賀，寧止力耕家。"]'),
('4824b743-c097-468f-8df4-3990f966d05f','酬藍田崔丞立之詠雪見寄','韓愈','唐','唐诗','tang','','[]','京城數尺雪，寒氣倍常年。',120,'全唐诗/poet.tang.18000.json','["京城數尺雪，寒氣倍常年。", "泯泯都無地，茫茫豈是天。", "崩奔驚亂射，揮霍訝相纏。", "不覺侵堂陛，方應折屋椽。", "出門愁落道，上馬恐平韉。", "朝鼓矜凌起，山齋酩酊眠。", "吾方嗟此役，君乃詠其妍。", "冰玉清顏隔，波濤盛句傳。", "朝飧思共飯，夜宿憶同氈。", "舉目無非白，雄文乃獨玄。"]'),
('8bb024e5-a471-4caf-8a56-6607196b8776','潭州泊船呈諸公','韓愈','唐','唐诗','tang','','[]','夜寒眠半覺，鼓笛鬧嘈嘈。',48,'全唐诗/poet.tang.18000.json','["夜寒眠半覺，鼓笛鬧嘈嘈。", "暗浪舂樓堞，驚風破竹篙。", "主人看使範，客子讀離騷。", "聞道松醪賤，何須恡錯刀。"]'),
('3b92f553-d6d8-46c7-898c-e441ffcf7192','飲城南道邊古墓上逢中丞過贈禮部衛員外少室張道士','韓愈','唐','唐诗','tang','','[]','偶上城南土骨堆，共傾春酒三五桮。',32,'全唐诗/poet.tang.18000.json','["偶上城南土骨堆，共傾春酒三五桮。", "爲逢桃樹相料理，不覺中丞喝道來。"]'),
('81454da0-d4c8-43a7-84e2-0224ebc041ef','池上絮','韓愈','唐','唐诗','tang','','[]','池上無風有落暉，楊花晴後自飛飛。',32,'全唐诗/poet.tang.18000.json','["池上無風有落暉，楊花晴後自飛飛。", "爲將纖質凌清鏡，濕却無窮不得歸。"]'),
('e5006eea-d3d2-4f5e-8cf7-f4eb89758fb0','贈賈島','韓愈','唐','唐诗','tang','','[]','孟郊死葬北邙山，從此風雲得暫閑。',32,'全唐诗/poet.tang.18000.json','["孟郊死葬北邙山，從此風雲得暫閑。", "天恐文章渾斷絕，更生賈島着人間。"]'),
('b7ed33f4-ad7a-4498-9554-f2a993b55868','贈賈島','韓愈','唐','唐诗','tang','','[]','孟郊死葬北邙山，從此風雲得暫閑。',32,'全唐诗/poet.tang.18000.json','["孟郊死葬北邙山，從此風雲得暫閑。", "世上不教才子絶，更生賈島着人間。"]'),
('1e9a731e-dbf1-4b4b-acae-f6b3b18646a4','贈譯經僧','韓愈','唐','唐诗','tang','','[]','萬里休言道路賒，有誰敎汝度流沙。',32,'全唐诗/poet.tang.18000.json','["萬里休言道路賒，有誰敎汝度流沙。", "只今中國方多事，不用無端更亂華。"]'),
('aafc4c1f-228d-4615-b3a2-0d634ac19607','享惠昭太子廟樂章','王涯','唐','唐诗','tang','','[]','威儀畢陳，備樂將闋。',40,'全唐诗/poet.tang.18000.json','["威儀畢陳，備樂將闋。", "苞茅酒縮，膋蕭香徹。", "宮臣展事，肅雍在列。", "迎精送往，厥鑒昭晰。"]'),
('dee0b55c-e436-41ab-980c-c6b609790ce5','望禁門松雪','王涯','唐','唐诗','tang','','[]','宿雲開霽景，佳氣此時濃。',72,'全唐诗/poet.tang.18000.json','["宿雲開霽景，佳氣此時濃。", "瑞雪凝清禁，祥煙冪小松。", "依稀鴛瓦出，隱映鳳樓重。", "金闕晴光照，瓊枝瑞色封。", "葉鋪全類玉，柯偃乍疑龍。", "詎比寒山上，風霜老昔容。"]'),
('c5eacd94-ff51-4cca-af84-dce680383b0a','廣宣上人以詩賀放榜和謝','王涯','唐','唐诗','tang','','[]','延英面奉入春闈，亦選功夫亦選奇。',64,'全唐诗/poet.tang.18000.json','["延英面奉入春闈，亦選功夫亦選奇。", "在冶只求金不耗，用心空學秤無私。", "龍門變化人皆望，鶯谷飛鳴自有時。", "獨喜至公誰是證，彌天上人與新詩。"]'),
('1f5d0bbe-5783-4352-84e2-56e01c1b3b4a','九月九日勤政樓下觀百僚獻壽','王涯','唐','唐诗','tang','','[]','御氣黃花節，臨軒紫陌頭。',72,'全唐诗/poet.tang.18000.json','["御氣黃花節，臨軒紫陌頭。", "早陽生綵仗，霽色入仙樓。", "獻壽皆鵷鷺，瞻天盡冕旒。", "菊樽過九日，鳳曆肇千秋。", "樂奏薰風起，盃酣瑞影收。", "年年歌舞度，此地慶皇休。"]'),
('55efc4cb-6eb0-46b4-babc-4caea0dba170','春遊曲二首 一','王涯','唐','唐诗','tang','','[]','萬樹江邊杏，新開一夜風。',24,'全唐诗/poet.tang.18000.json','["萬樹江邊杏，新開一夜風。", "滿園深淺色，照在綠波中。"]'),
('91c5aa16-1dd4-4958-b8f1-c813ccfd8022','春遊曲二首 二','王涯','唐','唐诗','tang','','[]','上苑何窮樹，花間次第新。',24,'全唐诗/poet.tang.18000.json','["上苑何窮樹，花間次第新。", "香車與絲騎，風靜亦生塵。"]'),
('70889241-0c17-4d61-af05-f7e9d3ca1936','太平詞','王涯','唐','唐诗','tang','','[]','風俗今和厚，君王在穆清。',24,'全唐诗/poet.tang.18000.json','["風俗今和厚，君王在穆清。", "行看采華曲，盡是泰階平。"]'),
('9910755c-0c3d-4b6d-bb66-ee175ed1d911','送春詞','王涯','唐','唐诗','tang','','[]','日日人空老，年年春更歸。',24,'全唐诗/poet.tang.18000.json','["日日人空老，年年春更歸。", "相歡在尊酒，不用惜花飛。"]'),
('d5099ed5-7f3a-44af-85fb-e2dde9286b3e','塞上曲二首 一','王涯','唐','唐诗','tang','','[]','天驕遠塞行，出鞘寶刀鳴。',24,'全唐诗/poet.tang.18000.json','["天驕遠塞行，出鞘寶刀鳴。", "定是酬恩日，今朝覺命輕。"]'),
('f6ea7318-bbea-409d-8efb-9b47e6d277a1','塞上曲二首 二','王涯','唐','唐诗','tang','','[]','塞虜常爲敵，邊風已報秋。',24,'全唐诗/poet.tang.18000.json','["塞虜常爲敵，邊風已報秋。", "平生多志氣，箭底覓封侯。"]'),
('86a4b793-07df-4a30-993d-fb6fe576feab','隴上行','王涯','唐','唐诗','tang','','[]','負羽到邊州，鳴笳度隴頭。',24,'全唐诗/poet.tang.18000.json','["負羽到邊州，鳴笳度隴頭。", "雲黃知塞近，草白見邊秋。"]'),
('c256a4bd-24ad-41cf-a750-6619b87c8954','思君恩','王涯','唐','唐诗','tang','','[]','雞鳴天漢曉，鶯語禁林春。',24,'全唐诗/poet.tang.18000.json','["雞鳴天漢曉，鶯語禁林春。", "誰入巫山夢，唯應洛水神。"]'),
('9e31a8dc-5ff5-4c8a-a147-ba7522847298','春閨思','王涯','唐','唐诗','tang','','[]','雪盡萱抽葉，風輕水變苔。',24,'全唐诗/poet.tang.18000.json','["雪盡萱抽葉，風輕水變苔。", "玉關音信斷，又見發庭梅。"]'),
('9f7081f4-71d3-4bd6-a190-749e3d272ae2','春江曲','王涯','唐','唐诗','tang','','[]','搖漾越江春，相將采白蘋。',24,'全唐诗/poet.tang.18000.json','["搖漾越江春，相將采白蘋。", "歸時不覺夜，出浦月隨人。"]'),
('91e8eb3b-b379-4f52-becc-c128dfabd4fd','閨人贈遠五首 一','王涯','唐','唐诗','tang','','[]','花明綺陌春，柳拂御溝新。',24,'全唐诗/poet.tang.18000.json','["花明綺陌春，柳拂御溝新。", "爲報遼陽客，流芳不待人。"]'),
('e67b7d02-22c8-4304-9194-64ac25bb6523','閨人贈遠五首 二','王涯','唐','唐诗','tang','','[]','遠戍功名薄，幽閨年貌傷。',24,'全唐诗/poet.tang.18000.json','["遠戍功名薄，幽閨年貌傷。", "妝成對春樹，不語淚千行。"]'),
('db545213-177e-446c-84ae-f5c9630132eb','閨人贈遠五首 三','王涯','唐','唐诗','tang','','[]','形影一朝別，煙波千里分。',24,'全唐诗/poet.tang.18000.json','["形影一朝別，煙波千里分。", "君看望君處，祗是起行雲。"]'),
('54c8c58e-4b0e-413e-bdc6-5b3509e80d0d','閨人贈遠五首 四','王涯','唐','唐诗','tang','','[]','啼鶯綠樹深，語燕雕梁晚。',24,'全唐诗/poet.tang.18000.json','["啼鶯綠樹深，語燕雕梁晚。", "不省出門行，沙場知近遠。"]'),
('d0e937a7-e3f1-4fed-949e-24d1d15bf71e','閨人贈遠五首 五','王涯','唐','唐诗','tang','','[]','洞房今夜月，如練復如霜。',24,'全唐诗/poet.tang.18000.json','["洞房今夜月，如練復如霜。", "爲照離人恨，亭亭到曉光。"]'),
('a3e1e10b-a2e0-46b6-9f3e-d389972ea4b5','從軍詞三首 一','王涯','唐','唐诗','tang','','[]','戈甲從軍久，風雲識陣難。',24,'全唐诗/poet.tang.18000.json','["戈甲從軍久，風雲識陣難。", "今朝拜韓信，計日斬成安。"]'),
('198bac3e-2bb0-4fd1-bd41-60b80b10bebd','從軍詞三首 二','王涯','唐','唐诗','tang','','[]','燕頷多奇相，狼頭敢犯邊。',24,'全唐诗/poet.tang.18000.json','["燕頷多奇相，狼頭敢犯邊。", "寄言班定遠，正是立功年。"]'),
('628b303b-4725-47e9-b676-dd017de3787d','從軍詞三首 三','王涯','唐','唐诗','tang','','[]','旄頭夜落捷書飛，來奏金門著賜衣。',32,'全唐诗/poet.tang.18000.json','["旄頭夜落捷書飛，來奏金門著賜衣。", "白馬將軍頻破敵，黃龍戍卒幾時歸。"]'),
('c18cd25f-f291-411b-9f7c-22cf9013a11a','塞下曲二首 一','王涯','唐','唐诗','tang','','[]','辛勤幾出黃花戍，迢遰初隨細柳營。',32,'全唐诗/poet.tang.18000.json','["辛勤幾出黃花戍，迢遰初隨細柳營。", "塞晚每愁殘月苦，邊愁更逐斷篷驚。"]'),
('85077c6f-9548-43fd-82e7-726a9cfd759d','塞下曲二首 二','王涯','唐','唐诗','tang','','["\u7231\u56fd", "\u8fb9\u585e", "\u5199\u4eba", "\u8d5e\u7f8e"]','年少辭家從冠軍，金妝寶劒去邀勳。',32,'全唐诗/poet.tang.18000.json','["年少辭家從冠軍，金妝寶劒去邀勳。", "不知馬骨傷寒水，唯見龍城起暮雲。"]'),
('ca7a8f95-8421-45b7-837b-e7465157a3c7','平戎辭','王涯','唐','唐诗','tang','','[]','太白秋高助發兵，長風夜卷虜塵清。',32,'全唐诗/poet.tang.18000.json','["太白秋高助發兵，長風夜卷虜塵清。", "男兒解却腰間劒，喜見從王道化平。"]'),
