('73bea1b1-961a-4774-b78b-9123a9a17136','宮詞三十首 十六','王涯','唐','唐诗','tang','','[]','牆牆不斷接宮城，金榜皆書殿院名。',32,'全唐诗/poet.tang.18000.json','["牆牆不斷接宮城，金榜皆書殿院名。", "萬轉千回相隔處，各調弦管對聞聲。"]'),
('dc6fb581-65bb-4a7d-beda-0f5c94a93c11','宮詞三十首 十七','王涯','唐','唐诗','tang','','[]','霏霏春雨九重天，漸暖龍池御柳煙。',32,'全唐诗/poet.tang.18000.json','["霏霏春雨九重天，漸暖龍池御柳煙。", "玉輦遊時應不避，千廊萬屋自相連。"]'),
('49304717-3975-4599-aa06-a88e82169958','宮詞三十首 十八','王涯','唐','唐诗','tang','','[]','禁門煙起紫沉沉，樓閣當中複道深。',32,'全唐诗/poet.tang.18000.json','["禁門煙起紫沉沉，樓閣當中複道深。", "長入暮天凝不散，掖庭宮裏動秋砧。"]'),
('b3a53c3d-5cd2-4a9d-918f-e7052d9dcadc','宮詞三十首 十九','王涯','唐','唐诗','tang','','[]','炎炎夏日滿天時，桐葉交加覆玉墀。',32,'全唐诗/poet.tang.18000.json','["炎炎夏日滿天時，桐葉交加覆玉墀。", "向晚移鐙上銀簟，叢叢綠鬢坐彈棋。"]'),
('c89fc398-d01c-4d20-a847-88a6428b8c15','宮詞三十首 二十','王涯','唐','唐诗','tang','','[]','瞳瞳日出大明宮，天樂遙聞在碧空。',32,'全唐诗/poet.tang.18000.json','["瞳瞳日出大明宮，天樂遙聞在碧空。", "禁樹無風正和暖，玉樓金殿曉光中。"]'),
('99c57fb0-4d0e-47f6-95a6-ef1769ddb878','宮詞三十首 二十一','王涯','唐','唐诗','tang','','[]','迥出芙蓉閣上頭，九天懸處正當秋。',32,'全唐诗/poet.tang.18000.json','["迥出芙蓉閣上頭，九天懸處正當秋。", "年年七夕晴光裏，宮女穿針盡上樓。"]'),
('6a752946-4b1b-4cfb-ac10-e86155e27a52','宮詞三十首 二十二','王涯','唐','唐诗','tang','','[]','教來鸚鵡語初成，久閉金籠慣認名。',32,'全唐诗/poet.tang.18000.json','["教來鸚鵡語初成，久閉金籠慣認名。", "總向春園看花去，獨於深院笑人聲。"]'),
('38a421b9-e9aa-4bef-be8a-9def1dfc0442','宮詞三十首 二十三','王涯','唐','唐诗','tang','','[]','銀瓶瀉水欲朝妝，燭焰紅高粉壁光。',32,'全唐诗/poet.tang.18000.json','["銀瓶瀉水欲朝妝，燭焰紅高粉壁光。", "共怪滿衣珠翠冷，黃花瓦上有新霜。"]'),
('d3d1c087-8884-44bd-96c1-6c970e86c3b1','宮詞三十首 二十四','王涯','唐','唐诗','tang','','[]','迎風殿裏罷雲和，起聽新蟬布淺莎。',32,'全唐诗/poet.tang.18000.json','["迎風殿裏罷雲和，起聽新蟬布淺莎。", "爲愛九天和露滴，萬年枝上最聲多。"]'),
('6d130481-5efe-4c51-b80d-a7a9cd1eba20','宮詞三十首 二十五','王涯','唐','唐诗','tang','','[]','御果收時屬內官，傍簷低壓玉闌干。',32,'全唐诗/poet.tang.18000.json','["御果收時屬內官，傍簷低壓玉闌干。", "明朝摘向金華殿，盡日枝邊次第看。"]'),
('70ee5b8e-aa3e-4270-aec0-adca994e1d39','宮詞三十首 二十六','王涯','唐','唐诗','tang','','[]','內裏松香滿殿聞，四行階下暖氤氳。',32,'全唐诗/poet.tang.18000.json','["內裏松香滿殿聞，四行階下暖氤氳。", "春深欲取黃金粉，繞樹宮娥著絳裙。"]'),
('143b2241-60ea-42f9-ba42-b6d267dd3438','宮詞三十首 二十七','王涯','唐','唐诗','tang','','[]','禁樹傳聲在九霄，內中殘火獨遙遙。',32,'全唐诗/poet.tang.18000.json','["禁樹傳聲在九霄，內中殘火獨遙遙。", "千官待取門猶閉，未到宮前下馬橋。"]'),
('15ec394c-fd55-41fd-a677-c683c1fcb166','御溝新柳','賈稜','唐','唐诗','tang','','[]','御苑陽和早，章溝柳色新。',72,'全唐诗/poet.tang.18000.json','["御苑陽和早，章溝柳色新。", "託根偏近日，布葉乍迎春。", "秀質方含翠，清陰欲庇人。", "輕雲度斜景，多露滴行塵。", "褭褭堪離贈，依依獨望頻。", "王孫如可賞，攀折在芳辰。"]'),
('92cfdebd-aee0-4974-8a58-7471eec4f11e','御溝新柳','劉遵古','唐','唐诗','tang','','[]','韶光先禁柳，幾處覆溝新。',72,'全唐诗/poet.tang.18000.json','["韶光先禁柳，幾處覆溝新。", "映水疑分翠，含煙欲占春。", "悠悠遲日晚，褭褭好風頻。", "吐節茸猶嫩，通條澤稍均。", "遠和瑤草色，暗拂玉樓塵。", "願假騫飛便，歸棲及此辰。"]'),
('3a2fb093-b148-4321-9a22-dcc07ff38680','洛陽清明日雨霽','李正封','唐','唐诗','tang','','[]','曉日清明天，夜來嵩少雨。',48,'全唐诗/poet.tang.18000.json','["曉日清明天，夜來嵩少雨。", "千門尚煙火，九陌無塵土。", "酒綠河橋春，漏閑宮殿午。", "遊人戀芳草，半犯嚴城鼓。"]'),
('f1956d4c-ddf4-4319-be2c-0d5bd34e84b4','詠露','李正封','唐','唐诗','tang','','[]','霏霏靈液重，雲表無聲落。',60,'全唐诗/poet.tang.18000.json','["霏霏靈液重，雲表無聲落。", "霑樹急玄蟬，灑池棲皓鶴。", "流塵清遠陌，飛月澄高閣。", "宵潤玉堂簾，曙寒金井索。", "佳人比珠淚，坐感紅綃薄。"]'),
('46c89814-2b61-4d20-be11-98ba356bf244','夏遊招隱寺暴雨晚晴','李正封','唐','唐诗','tang','','[]','竹柏風雨過，蕭疎臺殿涼。',48,'全唐诗/poet.tang.18000.json','["竹柏風雨過，蕭疎臺殿涼。", "石渠寫奔溜，金剎照頹陽。", "鶴飛巖煙碧，鹿鳴澗草香。", "山僧引清梵，幡蓋繞迴廊。"]'),
('df4bc9cb-7d7b-45d7-96f4-ad157f39ac3a','禪門寺暮鐘','李正封','唐','唐诗','tang','','[]','簨𥲤高懸于闐鐘，黃昏發地殷龍宮。',32,'全唐诗/poet.tang.18000.json','["簨𥲤高懸于闐鐘，黃昏發地殷龍宮。", "遊人憶到嵩山夜，疊閣連樓倚太空。"]'),
('3e76f468-b3a7-49ce-8d15-d9c83f589209','貢院樓北新栽小松','李正封','唐','唐诗','tang','','[]','青蒼初得地，華省植來新。',72,'全唐诗/poet.tang.18000.json','["青蒼初得地，華省植來新。", "尚帶山中色，猶含洞裏春。", "近樓依北戶，隱砌淨遊塵。", "鶴壽應成蓋，龍形未有鱗。", "爲梁資大廈，封爵恥嬴秦。", "幸此觀光日，清風屢得親。"]'),
('2252b33d-7087-4c95-a17c-df14bb749eb4','南至隔仗望含元殿香爐','崔立之','唐','唐诗','tang','','[]','千官望長至，萬國拜含元。',72,'全唐诗/poet.tang.18000.json','["千官望長至，萬國拜含元。", "隔仗爐光出，浮霜煙氣翻。", "飄飄縈內殿，漠漠澹前軒。", "聖日開如捧，卿雲近欲渾。", "輪囷灑宮闕，蕭索散乾坤。", "願倚天風便，披香奉至尊。"]'),
('ca9ed607-5da1-4d4f-beef-3bb225f92093','曲池潔寒流','崔立之','唐','唐诗','tang','','[]','閑尋欹岸步，因向曲池看。',72,'全唐诗/poet.tang.18000.json','["閑尋欹岸步，因向曲池看。", "透底何澄徹，迴流乍屈盤。", "稍隨高樹古，迥與遠天寒。", "月入鏡華轉，星臨珠影攢。", "纖鱗時蔽石，轉吹或生瀾。", "願假涓微效，來濡拙筆端。"]'),
('24f4ea24-e884-46cd-9ed3-4e738e28eb92','賦得春風扇微和','崔立之','唐','唐诗','tang','','[]','時令忽已變，年光俄又春。',72,'全唐诗/poet.tang.18000.json','["時令忽已變，年光俄又春。", "高低惠風入，遠近芳氣新。", "靡靡纔偃草，泠泠不動塵。", "溫和乍扇物，煦嫗偏感人。", "去出桂林漫，來過蕙圃頻。", "晨輝正澹蕩，披拂長相親。"]'),
('9b82e073-dbfd-4e9c-bc7a-f187032b9304','南至日隔仗望含元殿香爐','郭遵','唐','唐诗','tang','','[]','冕旒親負扆，卉服盡朝天。',72,'全唐诗/poet.tang.18000.json','["冕旒親負扆，卉服盡朝天。", "暘谷移初日，金爐出御煙。", "芬馨流遠近，散漫入貂蟬。", "霜仗凝逾白，朱欄映轉鮮。", "如看浮闕在，稍覺逐風遷。", "爲沐皇家慶，來瞻羽衛前。"]'),
('a3ffd773-6a24-46b5-b689-be27ea626d02','賦得春風扇微和','郭遵','唐','唐诗','tang','','[]','微風飄淑氣，散漫及茲晨。',72,'全唐诗/poet.tang.18000.json','["微風飄淑氣，散漫及茲晨。", "習習何處至，熙熙與春親。", "曖空看早辨，映日度逾頻。", "高拂非煙雜，低垂衆卉新。", "霽天輕有靄，綺陌盡無塵。", "還似登臺意，元和欲煦人。"]'),
('0a7d1083-d5c9-425f-9b47-b89acfd2ef9c','賦得風動萬年枝','韋紓','唐','唐诗','tang','','[]','嘉名標萬祀，擢秀出深宮。',72,'全唐诗/poet.tang.18000.json','["嘉名標萬祀，擢秀出深宮。", "嫩葉含煙靄，芳柯振惠風。", "參差搖翠色，綺靡舞晴空。", "氣稟禎祥異，榮霑雨露同。", "天年方未極，聖壽比應崇。", "幸列華林裏，知殊衆木中。"]'),
('7a5ee012-5f28-4729-9ce8-0825ffdfb77f','賦得風動萬年枝','樊陽源','唐','唐诗','tang','','[]','珍木羅前殿，乘春任好風。',72,'全唐诗/poet.tang.18000.json','["珍木羅前殿，乘春任好風。", "振柯方褭褭，舒葉乍濛濛。", "影動丹墀上，聲傳紫禁中。", "離披偏向日，凌亂半分空。", "輕拂祥煙散，低搖翠色同。", "長令占天眷，四氣借全功。"]'),
('4980291e-c2e1-4813-ac37-2ef1d7783be8','賦得風動萬年枝','許稷','唐','唐诗','tang','','[]','瓊樹偏春早，光飛處處宜。',72,'全唐诗/poet.tang.18000.json','["瓊樹偏春早，光飛處處宜。", "曉浮三殿日，暗度萬年枝。", "婀娜搖仙禁，繽翻映玉池。", "含芳煙乍和，拂砌影初移。", "爲近韶陽煦，皆先衆卉垂。", "成陰知可待，不與衆芳隨。"]'),
('bb1f05e4-cb3d-4102-bc6b-712bbdd45261','閏月定四時','許稷','唐','唐诗','tang','','[]','玉律窮三紀，推爲積閏期。',72,'全唐诗/poet.tang.18000.json','["玉律窮三紀，推爲積閏期。", "月餘因妙算，歲遍自成時。", "乍覺年華改，翻憐物候遲。", "六旬知不惑，四氣本無欺。", "月桂虧還正，階蓂落復滋。", "從斯分曆象，共仰定毫釐。"]'),
('37913ab2-eb18-4641-ad0d-482c67481b1d','謝真人還舊山','范傳正','唐','唐诗','tang','','[]','麾蓋從仙府，笙歌入舊山。',72,'全唐诗/poet.tang.18000.json','["麾蓋從仙府，笙歌入舊山。", "水流丹竈缺，雲起草堂關。", "白鹿行爲衛，青鸞舞自閑。", "種松鱗未立，移石蘚仍斑。", "望路煙霞外，迴輿巖岫間。", "豈唯遼海鶴，空歎令威還。"]'),
('f0742d32-6da9-436e-993c-1b6bda3211bf','范成君撃洞陰磬','范傳正','唐','唐诗','tang','','[]','歷歷聞金奏，微微下玉京。',72,'全唐诗/poet.tang.18000.json','["歷歷聞金奏，微微下玉京。", "爲祥家諜久，偏識洞陰名。", "澹佇人聞聽，鏗鏘古曲成。", "何須百獸舞，自暢九天情。", "注目看無見，留心記未精。", "雲霄如可托，借鶴向層城。"]'),
('7154a5db-41bc-4df9-922b-e904b3bbafc2','賦得春風扇微和','范傳正','唐','唐诗','tang','','[]','曖曖當遲日，微微扇好風。',72,'全唐诗/poet.tang.18000.json','["曖曖當遲日，微微扇好風。", "吹搖新葉上，光動淺花中。", "澹蕩凝清晝，氤氳曖碧空。", "稍看生綠水，已覺散芳叢。", "徙倚情偏適，裴回賞未窮。", "妍華不可狀，竟夕氣融融。"]'),
('b287e0db-32ab-4568-b439-41640dc329ae','賦得春風扇微和','豆盧榮','唐','唐诗','tang','','[]','春晴生縹緲，軟吹和初徧。',72,'全唐诗/poet.tang.18000.json','["春晴生縹緲，軟吹和初徧。", "池影動淵淪，山容發蔥蒨。", "遲遲入綺閣，習習流芳甸。", "樹杪颺鶯啼，階前落花片。", "韶光恐閑放，旭日宜游宴。", "文客拂塵衣，仁風願迴扇。"]'),
('d631b56a-25d8-4561-8bf3-25cfbc823e4a','賦得春風扇微和','邵偃','唐','唐诗','tang','','[]','微風扇和氣，韶景共芳晨。',72,'全唐诗/poet.tang.18000.json','["微風扇和氣，韶景共芳晨。", "始見郊原綠，旋過御苑春。", "三條開廣陌，八水泛通津。", "煙動花間葉，香流馬上人。", "逶迤雲彩曙，嘹唳鳥聲頻。", "爲報東堂客，明朝桂樹新。"]'),
('e0c79dfa-3ac9-4afc-ba7a-4655ce481c89','賦得春風扇微和','柳道倫','唐','唐诗','tang','','[]','青陽初入律，淑氣應春風。',72,'全唐诗/poet.tang.18000.json','["青陽初入律，淑氣應春風。", "始辨梅花裏，俄分柳色中。", "依微開夕照，澹蕩媚晴空。", "拂水生蘋末，經巖觸桂叢。", "稍抽蘭葉紫，微吐杏花紅。", "願逐仁風布，將俾生植功。"]'),
('adece3fe-ce58-4106-b748-37624f2c1d5b','賦得春風扇微和','陳九流','唐','唐诗','tang','','[]','喜見陽和至，遙知橐籥功。',72,'全唐诗/poet.tang.18000.json','["喜見陽和至，遙知橐籥功。", "遲遲散南陌，褭褭逐東風。", "暗入芳園裏，潛吹草木中。", "蘭蓀纔有綠，桃杏未成紅。", "已覺寒光盡，還看淑氣通。", "由來榮與悴，今日發應同。"]'),
('ddf23ee0-203d-453f-867b-84ded73ac2e0','謝真人仙駕還舊山','夏方慶','唐','唐诗','tang','','[]','何年成道去，綽約化童顏。',72,'全唐诗/poet.tang.18000.json','["何年成道去，綽約化童顏。", "天上辭仙侶，人間憶舊山。", "滄桑今已變，蘿蔓尚堪攀。", "雲覆瑤壇淨，苔生丹竈閑。", "逍遙堪白石，寂寞閉玄關。", "應是悲塵世，思將羽駕還。"]'),
('af3a0afc-c631-45ef-b15e-096d5c9cd40b','公子行','陳羽','唐','唐诗','tang','','[]','金羈白面郎，何處蹋青來。',48,'全唐诗/poet.tang.18000.json','["金羈白面郎，何處蹋青來。", "馬嬌郎半醉，躞蹀望樓臺。", "似見樓上人，玲瓏窗戶開。", "隔花聞一笑，落日不知回。"]'),
('f72e2e68-150e-486e-a538-38dd5a66f2aa','古意','陳羽','唐','唐诗','tang','','[]','十三學繡羅衣裳，自憐紅袖聞馨香。',290,'全唐诗/poet.tang.18000.json','["十三學繡羅衣裳，自憐紅袖聞馨香。", "人言此是嫁時服，含笑不刺雙鴛鴦。", "郎年十九髭未生，拜官天下聞郎名。", "車馬駢闐賀門館，自然不失爲公卿。", "是時妾家猶未貧，兄弟出入雙車輪。", "繁華全盛兩相敵，與郎年少爲婚姻。", "郎家居近御溝水，豪門客盡躡珠履。", "雕盤酒器常不干，曉入中廚妾先起。", "姑嫜嚴肅有規矩，小姑嬌憨意難取。", "朝參暮拜白玉堂，繡衣著盡黃金縷。", "妾貌漸衰郎漸薄，時時強笑意索寞。", "知郎本來無歲寒，幾回掩淚看花落。", "妾年四十絲滿頭，郎年五十封公侯。", "男兒全盛日忘舊，銀牀羽帳空颼飀。", "庭花紅遍蝴蝶飛，看郎佩玉下朝時。", "歸來略略不相顧，却令侍婢生光輝。", "郎恨婦人易衰老，妾亦恨深不忍道。", "看郎強健能幾時，年過六十還枯[槁]。"]'),
('3c2af986-90f5-4aa2-a182-4ca643dc9649','長相思','陳羽','唐','唐诗','tang','','[]','相思長相思，相思無限極。',64,'全唐诗/poet.tang.18000.json','["相思長相思，相思無限極。", "相思苦相思，相思損容色。", "容色真可惜，相思不可徹。", "日日長相思，相思腸斷絕。", "腸斷絕，淚還續，閑人莫作相思曲。"]'),
('6a1270c8-1e48-4402-8221-804a30a8f444','送戴端公赴容州','陳羽','唐','唐诗','tang','','[]','分命諸侯重，葳蕤繡服香。',48,'全唐诗/poet.tang.18000.json','["分命諸侯重，葳蕤繡服香。", "八蠻治險阻，千騎蹋繁霜。", "山斷旌旗出，天晴劒珮光。", "還將小戴禮，遠出化南方。"]');
